# ─── ЦВЕТА (ANSI) ────────────────────────────────────────────────────────────

class C:
    RESET  = "\033[0m"
    BOLD   = "\033[1m"
    RED    = "\033[91m"
    GOLD   = "\033[93m"
    YELLOW = GOLD
    GREEN  = "\033[92m"
    BLUE   = "\033[94m"
    CYAN   = "\033[96m"
    GRAY   = "\033[90m"
    WHITE  = "\033[97m"
    PURPLE = "\033[95m"

def clr(text, color):
    return f"{color}{text}{C.RESET}"

def hr(char="─", width=60, color=C.GOLD):
    return clr(char * width, color)

def pause(msg="Нажмите Enter, чтобы продолжить..."):
    input(f"\n{clr(msg, C.GRAY)}")

def clear():
    os.system("cls" if os.name == "nt" else "clear")


# ─── КЛАСС ПРИЛОЖЕНИЯ / ЛОГИРОВАНИЕ ────────────────────────────────────────
# Глобальные алиасы ниже оставлены только для совместимости со старым кодом:
# фактическое состояние приложения хранится в RomaApplication.

@dataclass
class AppPaths:
    script_dir: str
    settings_file: str
    debug_log_file: str
    image_assets_dir: str


@dataclass
class AppUIConfig:
    width: int = 52
    icons: dict[str, str] = field(default_factory=dict)


@dataclass
class AppConfig:
    version: str
    default_settings: dict[str, Any]
    settings: dict[str, Any] = field(default_factory=dict)
    debug: bool = False


@dataclass
class RomaApplication:
    config: AppConfig
    paths: AppPaths
    ui: AppUIConfig
    logger: logging.Logger = field(default_factory=lambda: logging.getLogger("roma_aeterna"))

    @classmethod
    def create(cls) -> "RomaApplication":
        script_dir = os.path.dirname(os.path.abspath(__file__))
        return cls(
            config=AppConfig(version=GAME_VERSION, default_settings={}),
            paths=AppPaths(
                script_dir=script_dir,
                settings_file=os.path.join(script_dir, "roma_settings.json"),
                debug_log_file=os.path.join(script_dir, "roma_debug.log"),
                image_assets_dir=os.path.join(script_dir, "assets", "images"),
            ),
            ui=AppUIConfig(width=52),
        )

    def setup_logging(self, debug: bool = False, log_file: str | None = None) -> logging.Logger:
        """Настраивает ротируемый технический лог приложения."""
        self.config.debug = debug
        log_file = log_file or self.paths.debug_log_file
        self.logger.setLevel(logging.DEBUG if debug else logging.INFO)
        self.logger.propagate = False
        if not self.logger.handlers:
            try:
                handler = RotatingFileHandler(log_file, maxBytes=512_000, backupCount=2, encoding="utf-8")
                handler.setFormatter(logging.Formatter("%(asctime)s [%(levelname)s] %(name)s: %(message)s"))
                self.logger.addHandler(handler)
            except OSError:
                self.logger.addHandler(logging.NullHandler())
        return self.logger

    def set_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        self.config.settings = settings
        return self.config.settings

    def log(self, level: int, message: str, *args, exc_info=False) -> None:
        if not self.logger.handlers:
            self.logger.addHandler(logging.NullHandler())
        self.logger.log(level, message, *args, exc_info=exc_info)


APP = RomaApplication.create()
ROMA_DEBUG_LOG_FILE = APP.paths.debug_log_file
LOGGER = APP.logger


def setup_logging(debug: bool = False, log_file: str = ROMA_DEBUG_LOG_FILE) -> logging.Logger:
    return APP.setup_logging(debug=debug, log_file=log_file)


def debug_log(message: str, *args, exc_info=False, level: int = logging.DEBUG) -> None:
    """Пишет техническую диагностику, не ломая игру при проблемах с файловой системой."""
    APP.log(level, message, *args, exc_info=exc_info)


# ─── DELUXE: оформление терминала v1.4 ───────────────────────────────────
