def terminal_ui_width(default: int = 52) -> int:
    """Ширина интерфейса для Pydroid/Termux: узкая, без автопереноса слов."""
    try:
        cols = os.get_terminal_size().columns
    except OSError:
        cols = default
    return max(42, min(default, cols - 2))

APP.ui.width = terminal_ui_width()
UI_WIDTH = APP.ui.width

def ui_wrap(text: str, indent: str = "  ", subsequent: str | None = None, color=C.WHITE, width: int | None = None):
    """Печатает текст с переносом по словам, чтобы мобильный терминал не рвал строки."""
    if subsequent is None:
        subsequent = indent
    wrap_width = max(24, (width or UI_WIDTH) - len(subsequent))
    lines = textwrap.wrap(
        str(text),
        width=wrap_width,
        break_long_words=False,
        break_on_hyphens=False,
        replace_whitespace=False,
    ) or [""]
    for i, line in enumerate(lines):
        prefix = indent if i == 0 else subsequent
        print(clr(prefix + line, color))

