def ui_line(char="═", color=C.GOLD, width=UI_WIDTH):
    return clr(char * width, color)

def ui_center(text: str, width: int =UI_WIDTH) -> str:
    return text.center(width)

def ui_panel(title: str, icon: str = "🏛", color=C.GOLD):
    print(clr("\n╔" + "═" * (UI_WIDTH - 2) + "╗", color))
    clean = f" {icon}  {title} "
    print(clr("║" + ui_center(clean,UI_WIDTH - 2) + "║", color))
    print(clr("╚" + "═" * (UI_WIDTH - 2) + "╝", color))

def ui_subtitle(text: str, icon: str = "•", color=C.CYAN):
    print(clr(f"\n  {icon} {text}", C.BOLD + color))
    print(clr("  " + "─" * min(UI_WIDTH - 4, max(28, len(text) + 16)), color))

def ui_meter(value: int, width: int = 14, good_high: bool = True) -> str:
    value = max(0, min(100, int(value)))
    filled = int(round(value / 100 * width))
    if good_high:
        color = C.GREEN if value >= 70 else C.GOLD if value >= 40 else C.RED
    else:
        color = C.GREEN if value <= 30 else C.GOLD if value <= 60 else C.RED
    return clr("█" * filled, color) + clr("░" * (width - filled), C.GRAY) + f" {value:>3}"

def ui_delta(value: int, suffix: str = "") -> str:
    color = C.GREEN if value >= 0 else C.RED
    sign = "+" if value >= 0 else ""
    return clr(f"{sign}{value}{suffix}", color)

def ui_card(label: str, value, icon: str = "", color=C.WHITE, note: str = ""):
    left = f"{icon} {label}" if icon else label
    right = clr(str(value), color)
    note_part = clr(f"  {note}", C.GRAY) if note else ""
    print(f"  {left:<22} {right:>12}{note_part}")

def _visible_len(text: str) -> int:
    """Длина строки без ANSI-кодов: нужна для ровного меню."""
    return len(re.sub(r"\033\[[0-9;]*m", "", str(text)))

@dataclass(frozen=True)
class MenuItem:
    key: str
    title: str
    hint: str = ""
    icon: str = ""


@dataclass(frozen=True)
class MenuSection:
    title: str
    icon: str = "•"
    color: str = C.CYAN
    items: tuple[MenuItem, ...] = ()


def render_classic_menu_sections(sections: list[MenuSection]) -> None:
    """Единый рендер секций ANSI-меню вместо ручных повторов ui_menu_item."""
    for section in sections:
        ui_menu_section(section.title, section.icon, section.color)
        for item in section.items:
            ui_menu_item(item.key, item.title, item.hint, item.icon, section.color)


def menu_valid_keys(sections: list[MenuSection]) -> list[str]:
    return [item.key for section in sections for item in section.items]


def ui_menu_section(title: str, icon: str = "•", color=C.CYAN):
    """Компактный раздел меню."""
    label = f" {icon} {title} "
    line_width = max(10,UI_WIDTH - _visible_len(label) - 4)
    print(clr(f"\n  {label}" + "─" * line_width, color))

def ui_menu_item(key: str, title: str, hint: str = "", icon: str = "", color=C.GOLD):
    """Удобная кнопка меню: крупный ключ, понятное действие и короткая подсказка."""
    key_box = clr(f" {str(key).upper():^3} ", C.BOLD + color)
    icon_part = f"{icon} " if icon else ""
    title_part = f"{icon_part}{title}"
    max_title = 28
    if _visible_len(title_part) > max_title:
        title_part = title_part[:max_title - 1] + "…"
    dots = " " * max(1, max_title - _visible_len(title_part))
    hint_part = clr(f"— {hint}", C.GRAY) if hint else ""
    print(f"  {key_box} {title_part}{dots} {hint_part}")


