    def _rich_bar(value: int, width: int = 14, good_high: bool = True) -> str:
        """Мини-индикатор для Rich без зависимости от старых ANSI-функций."""
        value = max(0, min(100, safe_int(value, 0)))
        filled = int(round(value / 100 * width))
        color = "green" if (value >= 70 if good_high else value <= 30) else "yellow" if (value >= 40 if good_high else value <= 60) else "red"
        return f"[{color}]{'█' * filled}[/][bright_black]{'░' * (width - filled)}[/] [bold]{value:>3}[/]"

