def read_choice(prompt: str, valid_options) -> str:
    """Безопасный выбор из непустого набора вариантов."""
    if valid_options is None:
        raise ValueError("read_choice: valid_options не задан")
    try:
        valid_upper = {str(v).strip().upper() for v in valid_options if str(v).strip()}
    except TypeError as exc:
        raise TypeError("read_choice: valid_options должен быть итерируемым") from exc
    if not valid_upper:
        raise ValueError("read_choice: список допустимых вариантов пуст")

    shown = ", ".join(sorted(valid_upper, key=lambda x: (len(x), x)))
    while True:
        try:
            ch = input(prompt).strip().upper()
        except EOFError:
            if "Q" in valid_upper:
                return "Q"
            raise
        if ch in valid_upper:
            return ch
        print(clr(f"  Не распознано «{ch}». Доступно: {shown}", C.RED))


def read_int(prompt: str, min_value: int = 0, max_value: int | None = None, allow_cancel: bool = True):
    """Безопасный ввод числа. Возвращает None при отмене через Q."""
    while True:
        raw = input(prompt).strip().upper()
        if allow_cancel and raw == "Q":
            return None
        try:
            value = int(raw)
        except ValueError:
            print(clr("  Нужно ввести число." + (" Или Q для отмены." if allow_cancel else ""), C.RED))
            continue
        if value < min_value:
            print(clr(f"  Минимум: {min_value}.", C.RED))
            continue
        if max_value is not None and value > max_value:
            print(clr(f"  Максимум: {max_value}.", C.RED))
            continue
        return value


PLAYER_NAME_RE = re.compile(r"^[\wА-Яа-яЁё .\-]{1,24}$", re.UNICODE)


def validate_player_name(name: str, default: str = "Maximus") -> str:
    """Проверяет имя полководца: без управляющих символов и слишком длинных строк."""
    if not isinstance(name, str):
        return default
    cleaned = " ".join(name.strip().split())
    if not cleaned:
        return default
    if not PLAYER_NAME_RE.fullmatch(cleaned):
        raise ValueError("Имя: 1–24 символа; разрешены буквы, цифры, пробел, точка и дефис.")
    return cleaned


def read_player_name(prompt: str, default: str = "Maximus") -> str:
    """Ввод имени с явной валидацией вместо принятия любой строки."""
    while True:
        raw = input(prompt).strip()
        try:
            return validate_player_name(raw or default, default=default)
        except ValueError as e:
            print(clr(f"  {e}", C.RED))


