def _latinize_name_part(value: str, default: str) -> str:
    cleaned = re.sub(r"[^A-Za-z]", "", str(value or "")).strip()
    if not cleaned:
        return default
    return cleaned[:1].upper() + cleaned[1:24].lower()


def _letter_index(letter: str, salt: int, modulo: int) -> int:
    if modulo <= 0:
        return 0
    return (ord(letter.upper()[0]) + salt) % modulo


def generate_roman_full_name(praenomen: str) -> dict[str, str]:
    praenomen = _latinize_name_part(praenomen, "Lucius")
    first = praenomen[0].upper()
    last = praenomen[-1].upper()
    nomina = ROMAN_NOMINA_BY_LETTER.get(first, ROMAN_NOMINA_BY_LETTER["M"])
    cognomina = ROMAN_COGNOMINA_BY_LETTER.get(last, ROMAN_COGNOMINA_BY_LETTER["S"])
    nomen = nomina[_letter_index(first, len(praenomen), len(nomina))]
    cognomen = cognomina[_letter_index(last, len(praenomen) * 3, len(cognomina))]
    full = f"{praenomen} {nomen} {cognomen}"
    gens = f"gens {nomen[:-2]}a" if nomen.endswith("ius") else f"gens {nomen}"
    return {"praenomen": praenomen, "nomen": nomen, "cognomen": cognomen, "full": full, "gens": gens}


def generate_random_roman_name(exclude: set[str] | None = None) -> str:
    """Создаёт полное римское имя для ежегодных консулов Республики."""
    exclude = exclude or set()
    for _ in range(80):
        praenomen = random.choice(ROMAN_PRAENOMINA)
        first = random.choice(list(ROMAN_NOMINA_BY_LETTER.keys()))
        last = random.choice(list(ROMAN_COGNOMINA_BY_LETTER.keys()))
        nomen = random.choice(ROMAN_NOMINA_BY_LETTER[first])
        cognomen = random.choice(ROMAN_COGNOMINA_BY_LETTER[last])
        full = f"{praenomen} {nomen} {cognomen}"
        if full not in exclude:
            return full
    return generate_roman_full_name(random.choice(ROMAN_PRAENOMINA))["full"]


def refresh_consular_pair(player: "Player") -> None:
    """Обновляет пару консулов на год.

    Если игрок сам стартовал консулом, он занимает одно из двух консульских
    мест, а второе получает случайный коллега. Если игрок не консул,
    Республика ежегодно получает двух случайных консулов. Поле player.consul
    сохраняется для совместимости со старыми экранами и сейвами.
    """
    player_name = getattr(player, "name", "") or "Roma"
    is_player_consul = getattr(player, "starting_office", "") == "consul"
    if is_player_consul:
        colleague = generate_random_roman_name({player_name})
        player.consul_a = player_name
        player.consul_b = colleague
    else:
        first = generate_random_roman_name({player_name})
        second = generate_random_roman_name({player_name, first})
        player.consul_a = first
        player.consul_b = second
    player.consul = f"{player.consul_a} • {player.consul_b}"


def consuls_display(player: "Player") -> str:
    """Краткая строка консулов для шапок интерфейса."""
    a = getattr(player, "consul_a", "")
    b = getattr(player, "consul_b", "")
    if not a or not b:
        refresh_consular_pair(player)
        a = getattr(player, "consul_a", "")
        b = getattr(player, "consul_b", "")
    return f"Консулы: {a} • {b}"


def player_status_display(player: "Player") -> str:
    """Строка роли игрока: должность + имя, если игрок не консул."""
    if getattr(player, "starting_office", "") == "consul":
        return consuls_display(player)
    return f"{player_office_title(player)}: {getattr(player, 'name', 'Roma')}  •  {consuls_display(player)}"

def normalize_praenomen(raw: str) -> str:
    """Принимает только настоящий римский преномен из ROMAN_PRAENOMINA."""
    cleaned = re.sub(r"[^A-Za-z]", "", str(raw or "")).strip()
    if not cleaned:
        return random.choice(ROMAN_PRAENOMINA)
    canonical = cleaned[:1].upper() + cleaned[1:].lower()
    allowed = {name.lower(): name for name in ROMAN_PRAENOMINA}
    if canonical.lower() not in allowed:
        raise ValueError("Это не римский преномен.")
    return allowed[canonical.lower()]


def show_allowed_praenomina() -> None:
    """Показывает список допустимых преноменов компактными строками."""
    names = ", ".join(ROMAN_PRAENOMINA)
    ui_wrap(f"Разрешены только: {names}", color=C.GRAY)


def read_roman_player_name() -> dict[str, str]:
    """Ритуализованный ввод имени: игрок входит в игру как римский гражданин.

    На мобильном экране сухое «введите имя» выбивало из атмосферы. Здесь
    используется тон вступительного экрана исторической стратегии: цензор
    просит назвать praenomen, а игра сама создаёт nomen, cognomen и gens.
    """
    mobile_box("Tabula Censoria", [
        "Цензор раскрывает восковую табличку и заносит новое имя в списки граждан.",
        "Назови только praenomen — личное имя гражданина. Род и прозвище будут выведены по обычаю предков.",
        "Примеры: Lucius, Marcus, Gaius. Пустая строка — жребий Фортуны.",
    ], color=C.GOLD, icon="🪶")
    while True:
        raw = input(f"\n{clr('  Praenomen civis Romani: ', C.GOLD)}").strip()
        try:
            praenomen = normalize_praenomen(raw)
            parts = generate_roman_full_name(praenomen)
            mobile_box("Nomen Acceptum", [
                f"Полное имя: {parts['full']}",
                f"Род: {parts['gens']}",
                "Отныне это имя будет звучать в донесениях Сената, на триумфальных арках и в мрачных списках потерь.",
            ], color=C.GREEN, icon="✓")
            bonus = GENS_BONUSES.get(parts["nomen"])
            if bonus:
                ui_wrap(f"Родовое влияние: {bonus}", color=C.CYAN)
            return parts
        except ValueError as e:
            print(clr(f"  ❌ {e}", C.RED))
            show_allowed_praenomina()


def choose_starting_office() -> str:
    """Выбор стартовой должности как сенатское назначение, а не сухой пункт меню."""
    mobile_box("Senatus Consultum", [
        "Сенат собрался в курии. Старшие мужи Республики решают, с каким imperium ты вступишь в историю.",
        "Выбор должности определит первый темп кампании: война, порядок, снабжение или престиж.",
    ], color=C.GOLD, icon="🏛")
    if RICH_AVAILABLE:
        rows = []
        for num, office in STARTING_OFFICES.items():
            rows.append((f"[gold1]{num}[/]", office["title"], office["latin"], office["hint"]))
        rui_table("Таблички назначения", ["#", "Магистратура", "Формула", "Что даёт Риму"], rows, color=C.GOLD, show_header=False)
    else:
        mobile_box("Таблички назначения", [
            "1 — Консул: высшее imperium, слава и второй легион",
            "2 — Легат пропретор: военный наместник и опытная армия",
            "3 — Ликтор: порядок улиц, фасции и дисциплина",
            "4 — Претор: закон, суд и спокойствие провинций",
            "5 — Префект: склады, гарнизоны и снабжение",
            "6 — Проконсул: провинциальное богатство, но рост смуты",
            "7 — Консулярный трибун: народная опора и резервы",
        ], color=C.GOLD, icon="📜")
    choice = read_choice(f"\n{clr('  Tabella magistratus (1-7): ', C.CYAN)}", list(STARTING_OFFICES.keys()))
    office = STARTING_OFFICES[choice]
    mobile_box("Mandatum Acceptum", [
        f"{office['title']} ({office['latin']})",
        office["desc"],
    ], color=C.GREEN, icon="✓")
    return office["key"]


def player_office_title(player: "Player") -> str:
    key = getattr(player, "starting_office", "")
    for office in STARTING_OFFICES.values():
        if office["key"] == key:
            return office["title"]
    return getattr(player, "office_title", "Полководец")


def apply_gens_bonus(player: "Player") -> None:
    nomen = getattr(player, "nomen", "")
    if nomen == "Aemilius":
        player.gold += 50
    elif nomen == "Claudius":
        player.unrest = max(0, player.unrest - 5)
    elif nomen == "Cornelius":
        player.morale = min(100, player.morale + 5)
    elif nomen == "Fabius":
        player.senate_rep = min(100, player.senate_rep + 5)
    elif nomen == "Julius":
        player.glory += 5
    elif nomen == "Valerius":
        player.glory += 5


def apply_starting_office(player: "Player") -> None:
    office = getattr(player, "starting_office", "")
    if office == "consul":
        player.senate_rep = min(100, player.senate_rep + 15)
        player.glory += 60
        player.morale = min(100, player.morale + 5)
        player.legions.append(Legion("Legio II Consularis", quality=4))
    elif office == "legatus_pro_praetore":
        player.morale = min(100, player.morale + 10)
        if player.legions:
            player.legions[0].quality = min(10, player.legions[0].quality + 2)
            player.legions[0].general = General(f"{player.name}", "veteran", loyalty=78)
        player.glory += 25
    elif office == "lictor":
        player.people_rep = min(100, player.people_rep + 10)
        player.senate_rep = min(100, player.senate_rep + 5)
        player.unrest = max(0, player.unrest - 8)
        player.gold = max(50, player.gold - game_price(player, 40, market=True))
    elif office == "praetor":
        player.senate_rep = min(100, player.senate_rep + 10)
        player.unrest = max(0, player.unrest - 15)
        player.glory += 20
    elif office == "praefectus":
        player.gold += 60
        player.grain += 120
        player.morale = min(100, player.morale + 4)
        if hasattr(player, "metals"):
            player.metals["iron"] = player.metals.get("iron", 0) + 2
            player.metals["copper"] = player.metals.get("copper", 0) + 2
    elif office == "proconsul":
        player.gold += 120
        player.glory += 40
        player.unrest = min(100, player.unrest + 6)
        if not any(p.get("name") == "Etruria" for p in player.provinces):
            player.provinces.append(captured_province_copy("Etruria"))
    elif office == "tribunus_consularis":
        player.people_rep = min(100, player.people_rep + 15)
        player.grain += 70
        player.legions.append(Legion("Legio II Tribunicia", quality=3))
        player.glory += 15
    apply_gens_bonus(player)
    log_event(player, f"Стартовая должность: {player_office_title(player)}")


def safe_save_path(filename: str, default: str = "roma_save.json") -> str:
    """Ограничивает имя сейва текущей папкой игры и JSON-файлами."""
    if not isinstance(filename, str) or not filename.strip():
        filename = default
    base = os.path.basename(filename.strip())
    if not base.lower().endswith(".json"):
        base += ".json"
    if base in (".json", "..json"):
        base = default
    return os.path.join(SCRIPT_DIR, base)


def safe_int(value, default: int = 0, min_value: int | None = None, max_value: int | None = None) -> int:
    """Безопасно приводит значение из сохранения/настроек к int с ограничениями."""
    try:
        if isinstance(value, bool):
            value = int(value)
        elif isinstance(value, float) and math.isnan(value):
            raise ValueError
        value = int(value)
    except (TypeError, ValueError, OverflowError):
        value = default
    if min_value is not None:
        value = max(min_value, value)
    if max_value is not None:
        value = min(max_value, value)
    return value

def safe_list(value) -> list:
    """Возвращает список или пустой список, если в сохранении мусор."""
    return value if isinstance(value, list) else []

def safe_dict(value) -> dict:
    """Возвращает dict или пустой dict, если в сохранении мусор."""
    return value if isinstance(value, dict) else {}

