def _coerce_setting_value(key: str, value, default):
    """Приводит пользовательские настройки к безопасному типу и диапазону.
    Файл roma_settings.json остаётся удобным для ручной правки, но мусорные
    значения больше не ломают игру в середине хода.
    """
    if isinstance(default, int) and not isinstance(default, bool):
        try:
            value = int(value)
        except (TypeError, ValueError):
            return default
        return max(0, value)
    if isinstance(default, float):
        try:
            value = float(value)
        except (TypeError, ValueError):
            return default
        if "chance" in key or key == "great_person_pity_step":
            return max(0.0, min(1.0, value))
        return max(0.0, value)
    return value if isinstance(value, type(default)) else default

def sanitize_settings(raw: dict) -> dict:
    settings = DEFAULT_SETTINGS.copy()
    if isinstance(raw, dict):
        for key, default in DEFAULT_SETTINGS.items():
            if key in raw:
                settings[key] = _coerce_setting_value(key, raw[key], default)
    return settings

def load_settings(path: str = SETTINGS_FILE) -> dict:
    """
    Загружает настройки баланса из JSON. Если файла нет — создаёт его
    с дефолтами. Если файл есть, но в нём не хватает ключей (например,
    после обновления игры) — дополняет недостающие значения, не трогая остальное.
    Повреждённый файл не перезатирается молча: используем дефолты в памяти
    и предупреждаем, оставляя файл как есть для ручного разбора.
    """
    loaded = {}
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                loaded = json.load(f)
        except (json.JSONDecodeError, OSError) as e:
            print(clr(f"  ⚠ {path} повреждён ({e}), использую встроенные значения.", C.RED))
    settings = sanitize_settings(loaded)
    # Файл обновляется только недостающими/новыми ключами и безопасными типами.
    # Это чинит старые settings после патча, но не уничтожает файл при JSON-ошибке.
    if not os.path.exists(path) or isinstance(loaded, dict):
        try:
            with open(path, "w", encoding="utf-8") as f:
                json.dump(settings, f, ensure_ascii=False, indent=2)
        except OSError:
            pass
    return settings

# При импорте модуль больше не пишет roma_settings.json. Это устраняет
# побочный эффект для тестов/линтеров: файл настроек читается в main().
SETTINGS = DEFAULT_SETTINGS.copy()


def init_runtime_settings(path: str = SETTINGS_FILE) -> dict:
    """Загружает настройки только при реальном запуске игры."""
    global SETTINGS
    SETTINGS = APP.set_settings(load_settings(path))
    return SETTINGS

