GREAT_PERSON_CATEGORY_BONUSES = {'statesman': {'gold_percent': 0.06, 'province_unrest_control': 1}, 'general': {'battle_attack': 3, 'battle_defense': 2}, 'philosopher': {'gold_percent': 0.04, 'glory_per_turn': 3}, 'engineer': {'garrison_discount': 0.08, 'romanization_discount': 0.08}, 'merchant': {'gold_percent': 0.08}, 'agronomist': {'grain_per_province': 2, 'grain_flat': 20}, 'admiral': {'gold_per_province': 2, 'upkeep_percent': -0.03}, 'diplomat': {'governor_loyalty_bonus': 5, 'unrest_reduction': 2}, 'jurist': {'unrest_reduction': 3, 'governor_loyalty_bonus': 3}, 'architect': {'glory_per_turn': 3, 'gold_per_province': 1}, 'prophet': {'unrest_reduction': 4, 'province_unrest_control': 1}, 'writer': {'glory_per_turn': 5}}
GREAT_PERSON_FINAL_BONUS = {'gold_percent': 0.25, 'battle_attack': 5, 'battle_defense': 3, 'glory_per_turn': 10, 'unrest_reduction': 5, 'province_unrest_control': 2, 'governor_loyalty_bonus': 5, 'grain_per_province': 2}
GREAT_PERSON_EFFECT_LABELS = {'battle_attack':'атака легионов','battle_defense':'защита легионов','battle_siege':'осады','province_unrest_control':'контроль волнений провинций','upkeep_percent':'содержание армии','morale_cap_bonus':'предел морали','gold_per_province':'золото за провинцию','gold_percent':'общий доход золота','gold_flat':'золото за ход','grain_flat':'зерно за ход','grain_per_province':'зерно за провинцию','grain_upkeep_flat':'зерновое содержание','unrest_reduction':'волнения в Риме','garrison_discount':'скидка гарнизонов','senate_law_bonus':'бонус законов','romanization_discount':'скидка романизации','governor_loyalty_bonus':'лояльность наместников','glory_per_turn':'слава за ход'}


# Эффекты, у которых положительное число — это УЛУЧШЕНИЕ через УМЕНЬШЕНИЕ
# негативного показателя (волнений, содержания и т.п.), а не его рост.
# Для них в карточке показываем явный знак «−» перед величиной показателя,
# чтобы не читалось как «волнения растут».
GREAT_PERSON_INVERTED_DISPLAY_KEYS = {
    "unrest_reduction",
}

def format_effects_dict(effects: dict) -> str:
    parts = []
    for key, value in effects.items():
        label = GREAT_PERSON_EFFECT_LABELS.get(key, key)
        inverted = key in GREAT_PERSON_INVERTED_DISPLAY_KEYS
        if isinstance(value, float):
            pct = int(round(value * 100))
            if inverted:
                # положительное значение = снижение показателя на pct%
                sign = "−" if pct > 0 else "+"
                parts.append(f"{label}: {sign}{abs(pct)}%")
            else:
                sign = "+" if pct > 0 else ""
                parts.append(f"{label}: {sign}{pct}%")
        else:
            if inverted:
                sign = "−" if value > 0 else "+"
                parts.append(f"{label}: {sign}{abs(value)}")
            else:
                sign = "+" if value > 0 else ""
                parts.append(f"{label}: {sign}{value}")
    return "; ".join(parts) if parts else "особый эффект"



def format_reward(reward: dict) -> str:
    if not isinstance(reward, dict):
        return str(reward)
    names={"gold":"💰 Золото","grain":"🌾 Зерно","glory":"🏆 Слава","morale":"🔥 Мораль","faith":"✨ Вера","senate_rep":"🏛 Репутация Сената","people_rep":"👥 Репутация народа"}
    parts=[]
    for k,v in reward.items():
        s="+" if isinstance(v,(int,float)) and v>=0 else ""
        parts.append(f"{names.get(k,k)} {s}{v}")
    return "; ".join(parts)
def great_person_effect(player: "Player", effect_key: str, default=0):
    total = default
    obtained = set(getattr(player, "great_people_obtained", []))
    for gid in obtained:
        total += GREAT_PEOPLE.get(gid, {}).get("effects", {}).get(effect_key, 0)
    completed = set(getattr(player, "great_people_completed_categories", []))
    for cat in completed:
        total += GREAT_PERSON_CATEGORY_BONUSES.get(cat, {}).get(effect_key, 0)
    if len(obtained) >= len(GREAT_PEOPLE):
        total += GREAT_PERSON_FINAL_BONUS.get(effect_key, 0)
    return total

def great_people_category_counts(player: "Player"):
    obtained = set(getattr(player, "great_people_obtained", []))
    counts = {cat: 0 for cat in GREAT_PERSON_CATEGORIES}
    totals = {cat: 0 for cat in GREAT_PERSON_CATEGORIES}
    for gid, person in GREAT_PEOPLE.items():
        cat = person["category"]
        totals[cat] += 1
        if gid in obtained:
            counts[cat] += 1
    return counts, totals

def great_person_available_ids(player: "Player"):
    obtained = set(getattr(player, "great_people_obtained", []))
    return [gid for gid in GREAT_PEOPLE if gid not in obtained]

def choose_great_person(player: "Player"):
    available = great_person_available_ids(player)
    if not available:
        return None
    weights = {"common": 70, "rare": 22, "epic": 7, "legendary": 1}
    return random.choices(available, weights=[weights.get(GREAT_PEOPLE[g].get("rarity", "common"), 50) for g in available], k=1)[0]

def apply_great_person_direct_rewards(player: "Player", person: dict):
    effects = person.get("effects", {})
    # Постоянные числовые эффекты читаются через great_person_effect().
    # Здесь только небольшие торжественные разовые бонусы, чтобы событие ощущалось сразу.
    rarity = person.get("rarity", "common")
    glory_bonus = {"common": 10, "rare": 20, "epic": 35, "legendary": 60}.get(rarity, 10)
    player.glory += glory_bonus
    if person.get("category") == "merchant":
        player.gold += 40
    elif person.get("category") == "agronomist":
        player.grain += 50
    elif person.get("category") == "general":
        player.morale = min(100 + tech_effect(player, "morale_cap_bonus"), player.morale + 5)
    log_event(player, f"Великий человек: {person['name']} (+{glory_bonus} славы)")

def show_great_person_card(player: "Player", gid: str):
    person = GREAT_PEOPLE[gid]
    cat = GREAT_PERSON_CATEGORIES[person["category"]]
    rarity = GREAT_PERSON_RARITY_NAMES.get(person.get("rarity", "common"), person.get("rarity", "common"))
    if RICH_AVAILABLE:
        body = (
            f"[bold magenta]{cat['icon']} {cat['label'].upper()}  •  {rarity.upper()}[/]\n\n"
            f"[bold gold1]{person['name']}[/]\n\n"
            f"[cyan]{person['bio']}[/]\n\n"
            f"[italic white]❝ {person['quote']} ❞[/]\n"
            f"[bright_black]— {person['source']}[/]\n\n"
            f"[green]Эффекты: {format_effects_dict(person.get('effects', {}))}[/]\n"
            f"[gold1]Разовый престиж: +слава при появлении[/]"
        )
        console.print(Panel(body, title="⭐ ВЕЛИКИЙ ЧЕЛОВЕК", border_style="gold1", box=box.DOUBLE))
    else:
        ui_panel("ВЕЛИКИЙ ЧЕЛОВЕК", cat["icon"], C.GOLD)
        print(clr(f"  {cat['icon']} {cat['label'].upper()}  •  {rarity.upper()}", C.BOLD + C.PURPLE))
        print(clr(f"\n  {person['name']}", C.BOLD + C.GOLD))
        print(clr("\n  " + person["bio"], C.CYAN))
        print(clr("\n  ────────────────────────────────────────────────────────────", C.GOLD))
        print(clr(f"  ❝ {person['quote']} ❞", C.WHITE))
        print(clr(f"\n  — {person['source']}", C.GRAY))
        print(clr("\n  Эффекты: " + format_effects_dict(person.get("effects", {})), C.GREEN))
        print(clr("  Разовый престиж: +слава при появлении", C.GOLD))
        print(clr("  ────────────────────────────────────────────────────────────", C.GOLD))

def award_great_person(player: "Player", gid: str):
    if not hasattr(player, "great_people_obtained") or not isinstance(player.great_people_obtained, list):
        player.great_people_obtained = []
    if gid in player.great_people_obtained:
        return False
    person = GREAT_PEOPLE[gid]
    player.great_people_obtained.append(gid)
    apply_great_person_direct_rewards(player, person)
    show_great_person_card(player, gid)
    maybe_award_great_people_collection_bonus(player, person["category"])
    return True

def maybe_award_great_people_collection_bonus(player: "Player", category: str):
    if not hasattr(player, "great_people_completed_categories") or not isinstance(player.great_people_completed_categories, list):
        player.great_people_completed_categories = []
    if category in player.great_people_completed_categories:
        return
    counts, totals = great_people_category_counts(player)
    if totals.get(category, 0) and counts.get(category, 0) >= totals.get(category, 0):
        player.great_people_completed_categories.append(category)
        cat = GREAT_PERSON_CATEGORIES[category]
        ui_panel("КОЛЛЕКЦИЯ ЗАВЕРШЕНА", cat["icon"], C.PURPLE)
        print(clr(f"  Собраны все: {cat['label']} ({counts[category]}/{totals[category]})", C.BOLD + C.GOLD))
        print(clr("  Постоянный бонус: " + format_effects_dict(GREAT_PERSON_CATEGORY_BONUSES.get(category, {})), C.GREEN))
        log_event(player, f"Собрана категория Великих людей: {cat['label']}")
    if len(getattr(player, "great_people_obtained", [])) >= len(GREAT_PEOPLE) and not getattr(player, "great_people_final_bonus_awarded", False):
        player.great_people_final_bonus_awarded = True
        ui_panel("ЗОЛОТОЙ ВЕК ЧЕЛОВЕЧЕСТВА", "👑", C.GOLD)
        print(clr("  Все Великие люди собраны. Рим стал хранилищем памяти мира.", C.BOLD + C.GOLD))
        print(clr("  Финальный бонус: " + format_effects_dict(GREAT_PERSON_FINAL_BONUS), C.GREEN))
        log_event(player, "Собраны все Великие люди")

def current_great_person_chance(player: "Player") -> float:
    """Реальный шанс появления Великого человека в этот ход с учётом
    pity-системы: чем дольше нет выпадения, тем выше шанс, до гарантии."""
    base = SETTINGS.get("great_person_chance", GREAT_PEOPLE_CHANCE_DEFAULT)
    step = SETTINGS.get("great_person_pity_step", 0.0)
    cap_turns = SETTINGS.get("great_person_pity_cap_turns", 0)
    streak = max(0, int(getattr(player, "great_person_dry_streak", 0)))
    chance = base + step * streak
    if cap_turns and streak >= cap_turns - 1:
        chance = 1.0
    return max(0.0, min(1.0, chance))

def maybe_spawn_great_person(player: "Player"):
    if not hasattr(player, "great_people_obtained") or not isinstance(player.great_people_obtained, list):
        player.great_people_obtained = []
    if not hasattr(player, "great_person_dry_streak"):
        player.great_person_dry_streak = 0
    if len(player.great_people_obtained) >= len(GREAT_PEOPLE):
        return False
    chance = current_great_person_chance(player)
    if random.random() >= chance:
        player.great_person_dry_streak = getattr(player, "great_person_dry_streak", 0) + 1
        return False
    gid = choose_great_person(player)
    if not gid:
        return False
    player.great_person_dry_streak = 0
    award_great_person(player, gid)
    return True

def show_great_people_menu(player: "Player"):
    if not hasattr(player, "great_people_obtained") or not isinstance(player.great_people_obtained, list):
        player.great_people_obtained = []
    while True:
        rui_screen_start()
        counts, totals = great_people_category_counts(player)
        rui_header("ВЕЛИКИЕ ЛЮДИ ИМПЕРИИ", ICONS.get("great_person", "⭐"), C.GOLD)
        rui_info(f"Собрано: {len(player.great_people_obtained)} / {len(GREAT_PEOPLE)}", C.CYAN)
        cur_chance = current_great_person_chance(player)
        streak = max(0, int(getattr(player, "great_person_dry_streak", 0)))
        cap_turns = SETTINGS.get("great_person_pity_cap_turns", 0)
        streak_word = '' if streak == 1 else 'а' if 2 <= streak <= 4 else 'ов'
        rui_info(f"Шанс появления после хода: {int(round(cur_chance*100))}% (сухая серия: {streak} ход{streak_word})", C.GRAY)
        if cap_turns:
            left = max(0, cap_turns - 1 - streak)
            if left == 0:
                rui_info("Гарантированное появление в этот ход!", C.GOLD)
            else:
                left_word = '' if left == 1 else 'а' if 2 <= left <= 4 else 'ов'
                rui_info(f"Гарантия появления через {left} ход{left_word} без выпадения.", C.GRAY)

        cat_keys = list(GREAT_PERSON_CATEGORIES)
        if RICH_AVAILABLE:
            rows = []
            for i, cat_key in enumerate(cat_keys, 1):
                cat = GREAT_PERSON_CATEGORIES[cat_key]
                done = counts[cat_key] >= totals[cat_key]
                mark = "✓" if done else "•"
                style = "green" if done else "white"
                rows.append((str(i), f"[{style}]{mark} {cat['icon']} {cat['label']}[/]", f"{counts[cat_key]}/{totals[cat_key]}"))
            rui_table("Категории", ["#", "Категория", "Прогресс"], rows, color=C.GOLD)
        else:
            print(clr("\n  Категории:", C.BOLD + C.GOLD))
            for i, cat_key in enumerate(cat_keys, 1):
                cat = GREAT_PERSON_CATEGORIES[cat_key]
                done = counts[cat_key] >= totals[cat_key]
                mark = "✓" if done else "•"
                color = C.GREEN if done else C.WHITE
                print(clr(f"  {i:>2}. {mark} {cat['icon']} {cat['label']:<28} {counts[cat_key]:>2}/{totals[cat_key]}", color))
        rui_info("Введите номер категории, чтобы увидеть карточки. Q — назад.", C.GRAY)
        choice = input(clr("\n  ➤ Выбор: ", C.CYAN)).strip().upper()
        if choice == "Q":
            return
        if not choice.isdigit() or not (1 <= int(choice) <= len(cat_keys)):
            continue
        selected = cat_keys[int(choice)-1]
        show_great_people_category(player, selected)

def show_great_people_category(player: "Player", category: str):
    obtained = set(getattr(player, "great_people_obtained", []))
    ids = [gid for gid, p in GREAT_PEOPLE.items() if p["category"] == category]
    cat = GREAT_PERSON_CATEGORIES[category]
    while True:
        rui_screen_start()
        rui_header(cat["label"], cat["icon"], C.PURPLE)
        if RICH_AVAILABLE:
            rows = []
            for i, gid in enumerate(ids, 1):
                p = GREAT_PEOPLE[gid]
                have = gid in obtained
                name = p["name"] if have else "???"
                style = "green" if have else "bright_black"
                mark = "✓" if have else "·"
                rows.append((str(i), f"[{style}]{mark} {name}[/]", GREAT_PERSON_RARITY_NAMES.get(p['rarity'], p['rarity'])))
            rui_table("", ["#", "Личность", "Редкость"], rows, color=C.PURPLE, show_header=False)
        else:
            for i, gid in enumerate(ids, 1):
                p = GREAT_PEOPLE[gid]
                have = gid in obtained
                name = p["name"] if have else "???"
                color = C.GREEN if have else C.GRAY
                print(clr(f"  {i:>2}. {'✓' if have else '·'} {name}  [{GREAT_PERSON_RARITY_NAMES.get(p['rarity'], p['rarity'])}]", color))
        rui_info("Номер — открыть карточку полученного человека. Q — назад.", C.GRAY)
        ch = input(clr("\n  ➤ Выбор: ", C.CYAN)).strip().upper()
        if ch == "Q":
            return
        if ch.isdigit() and 1 <= int(ch) <= len(ids):
            gid = ids[int(ch)-1]
            if gid in obtained:
                rui_screen_start(); show_great_person_card(player, gid); pause()
            else:
                print(clr("  Эта личность ещё не появилась в вашей истории.", C.RED)); pause()

