# ─── ПАССИВНАЯ ЭКОНОМИКА v1.4 ─────────────────────────────────────────────
# Доход теперь считается не одной мутной суммой, а через подробный отчёт.
# Это позволяет безопасно расширять экономику: новые источники добавляются
# как данные/строки отчёта, а не как десятки разрозненных if по всему коду.

CITY_GOLD_YIELDS = {
    "столица": 6,
    "порт": 5,
    "торговый": 5,
    "рудники": 6,
    "ремесленный": 3,
    "административный": 3,
    "культурный": 3,
    "речной": 3,
    "религиозный": 2,
    "военный": 2,
    "крепость": 1,
    "осадный": 1,
    "пограничный": 1,
    "земледельческий": 1,
    "племенной": 1,
    "центр провинции": 4,
}

METAL_GOLD_YIELDS = {
    "iron": 1,
    "copper": 1,
    "silver": 4,
    "gold_ore": 7,
}

TRADE_PACT_BASE_GOLD = 8
BARBARIAN_PACT_GOLD = 4
OCCUPIED_CITY_INCOME_RATIO = 0.45


def _city_gold_value(city: dict, owned: bool = True) -> int:
    """Пассивный налог с города: население + роль города. Частично взятые
    города дают урезанную оккупационную дань, чтобы фронтир не был пустым."""
    try:
        population = int(city.get("population", 0))
    except (TypeError, ValueError):
        population = 0
    city_type = city.get("type", "")
    value = max(1, population // 50) + CITY_GOLD_YIELDS.get(city_type, 1)
    if not owned:
        value = max(1, int(round(value * OCCUPIED_CITY_INCOME_RATIO)))
    return value


def _province_metal_gold(province_name: str) -> int:
    deposits = PROVINCE_METALS.get(province_name, {})
    return sum(METAL_GOLD_YIELDS.get(k, 0) * int(v) for k, v in deposits.items())

