# ─── ИСТОРИЧЕСКИЕ ЭПОХИ ───────────────────────────────────────────────────────
# Чисто по номеру хода: эпоха не хранится в сохранении явно (производное от
# turn), поэтому не может разойтись с фактическим прогрессом при загрузке.

ERAS = [
    {"key": "early_republic",  "name": "Ранняя Республика", "min_turn": 1,
     "enemy_mult": 1.0, "desc": "Рим утверждает власть в Италии."},
    {"key": "punic_wars",      "name": "Пунические войны", "min_turn": 11,
     "enemy_mult": 1.15, "desc": "Карфаген — главный соперник за Средиземноморье."},
    {"key": "republic_crisis", "name": "Кризис Республики", "min_turn": 26,
     "enemy_mult": 1.3, "desc": "Сенат раздираем интригами, легионы преданы полководцам."},
    {"key": "empire",          "name": "Империя", "min_turn": 41,
     "enemy_mult": 1.5, "desc": "Республика мертва, но Рим живёт под властью императоров."},
]

def get_era(player) -> dict:
    """Текущая историческая эпоха на основе номера хода (монотонно растёт)."""
    current = ERAS[0]
    for era in ERAS:
        if player.turn >= era["min_turn"]:
            current = era
    return current



