# Эксклюзивные таланты — не входят в пул обычного случайного найма (General()
# без явного talent_key никогда их не выбирает), доступны только через
# наборы роста / баттл-пасс.
EXCLUSIVE_TALENTS = {
    "veteran": {"name": "Ветеран", "atk": 2, "def_": 2, "loyalty_decay": 0, "upkeep_mult": 0.95,
                "desc": "+2 атака, +2 защита, -5% содержание (эксклюзив стартового легата)"},
    "legendary": {"name": "Легендарный", "atk": 5, "def_": 3, "loyalty_decay": -1, "upkeep_mult": 0.9,
                  "desc": "+5 атака, +3 защита, +1 лояльность/ход, -10% содержание (эксклюзив)"},
}
ALL_TALENTS = {**GENERAL_TALENTS, **EXCLUSIVE_TALENTS}

@dataclass(init=False)
class General:
    name: str
    talent_key: str
    loyalty: int

    def __init__(self, name=None, talent_key=None, loyalty=None):
        self.name = name or f"{random.choice(GENERAL_FIRST_NAMES)} {random.choice(GENERAL_SURNAMES)}"
        requested_talent = str(talent_key or "").strip()
        if requested_talent in ALL_TALENTS:
            self.talent_key = requested_talent
        else:
            self.talent_key = random.choice(list(GENERAL_TALENTS.keys()))
            if requested_talent:
                debug_log(
                    "Unknown general talent %r for %s; fallback=%s",
                    requested_talent,
                    self.name,
                    self.talent_key,
                    level=logging.WARNING,
                )
        self.loyalty = safe_int(
            loyalty if loyalty is not None else SETTINGS.get("general_loyalty_start", 70),
            SETTINGS.get("general_loyalty_start", 70),
            0,
            100,
        )

    def talent(self):
        talent = ALL_TALENTS.get(self.talent_key)
        if talent is not None:
            return talent

        fallback_key = "tactician" if "tactician" in ALL_TALENTS else next(iter(ALL_TALENTS), None)
        debug_log(
            "Invalid talent_key=%r on general %s; repaired to %r",
            self.talent_key,
            self.name,
            fallback_key,
            level=logging.WARNING,
        )
        self.talent_key = fallback_key or ""
        return ALL_TALENTS.get(
            self.talent_key,
            {
                "name": "Без таланта",
                "atk": 0,
                "def_": 0,
                "loyalty_decay": 0,
                "upkeep_mult": 1.0,
                "desc": "Без модификаторов",
            },
        )

    def atk_bonus(self):
        return self.talent().get("atk", 0)

    def def_bonus(self):
        return self.talent().get("def_", 0)

    def upkeep_mult(self):
        return self.talent().get("upkeep_mult", 1.0)

    def tick_loyalty(self):
        """Раз в ход: применяет decay/бонус таланта (charismatic decay<0 -> рост)."""
        self.loyalty = max(0, min(100, self.loyalty - self.talent().get("loyalty_decay", 0)))

    def adjust_loyalty(self, delta):
        self.loyalty = max(0, min(100, self.loyalty + delta))

    def description(self):
        t = self.talent()
        loy_color = C.GREEN if self.loyalty >= 60 else C.GOLD if self.loyalty >= 30 else C.RED
        warn = clr(" ⚠ риск мятежа!", C.RED) if self.loyalty <= SETTINGS.get("general_mutiny_loyalty_threshold", 15) else ""
        return (f"{clr(self.name, C.WHITE)} [{clr(t['name'], C.CYAN)}] "
                f"Лояльность: {clr(str(self.loyalty), loy_color)}{warn}")

    def to_dict(self):
        return self.__dict__.copy()

    @staticmethod
    def from_dict(d):
        if not isinstance(d, dict):
            return General()
        talent_key = d.get("talent_key") if d.get("talent_key") in ALL_TALENTS else None
        g = General(d.get("name"), talent_key, safe_int(d.get("loyalty", SETTINGS.get("general_loyalty_start", 70)), SETTINGS.get("general_loyalty_start", 70), 0, 100))
        g.__dict__.update({k: v for k, v in d.items() if k in ("name", "talent_key", "loyalty")})
        if g.talent_key not in ALL_TALENTS:
            g.talent_key = random.choice(list(GENERAL_TALENTS.keys()))
        g.loyalty = safe_int(g.loyalty, SETTINGS.get("general_loyalty_start", 70), 0, 100)
        return g

# ─── КЛАСС: ЛЕГИОН ───────────────────────────────────────────────────────────

@dataclass(init=False)
class Legion:
    name: str
    quality: int
    morale: int
    strength: int
    location: str
    battles: int
    veterans: bool
    general: General
    elite: bool
    action_points: int
    fatigue: int

    def __init__(self, name, quality=5, general=None, elite=False):
        self.name    = name
        self.quality = quality          # 1–10
        self.morale  = 80              # 0–100
        self.strength = quality * 10   # 10–100
        self.location = "Roma"
        self.battles  = 0
        self.veterans = False
        self.general  = general or General()
        self.elite    = elite           # уникальные легионы наборов/баттл-пасса
        # Логистика v2.8.2: очки действий и усталость сбрасываются/лечатся на новом ходу.
        self.action_points = SETTINGS.get("legion_action_points_per_turn", 5)
        self.fatigue = 0

    def description(self):
        vet = clr(" [ВЕТЕРАНЫ]", C.GOLD) if self.veterans else ""
        elite_tag = clr(" [ЭЛИТНЫЙ]", C.PURPLE) if self.elite else ""
        return (
            f"  {clr(self.name, C.RED)}{vet}{elite_tag}\n"
            f"    Сила: {self.strength:<4}  Мораль: {self.morale:<4}  "
            f"ОД: {getattr(self, 'action_points', SETTINGS.get('legion_action_points_per_turn', 5)):<2}  "
            f"Усталость: {getattr(self, 'fatigue', 0):<3}  "
            f"Позиция: {clr(self.location, C.CYAN)}  "
            f"Сражений: {self.battles}\n"
            f"    Командир: {self.general.description()}"
        )

    def train(self):
        self.quality  = min(10, self.quality + 1)
        self.strength = min(100, self.strength + 10)
        self.morale   = min(100, self.morale + 15)
        self.general.adjust_loyalty(5)
        return f"{self.name} прошёл учения. Качество: {self.quality}/10"

    def after_battle_xp(self, won):
        self.battles += 1
        if won:
            self.morale = min(100, self.morale + 5)
            self.general.adjust_loyalty(5)
            if self.battles >= 3:
                self.veterans = True
        else:
            self.morale = max(10, self.morale - 20)
            self.strength = max(10, self.strength - 15)
            self.general.adjust_loyalty(-10)

    def to_dict(self):
        d = self.__dict__.copy()
        d["general"] = self.general.to_dict()
        return d

    @staticmethod
    def from_dict(d):
        if not isinstance(d, dict):
            return Legion("Legio Restituta", quality=3)
        data = d.copy()
        l = Legion(data.get("name", "Legio Restituta"), data.get("quality", 3))
        general_data = data.pop("general", None)
        l.__dict__.update({k: v for k, v in data.items() if k in ("name", "quality", "morale", "strength", "location", "battles", "veterans", "elite", "action_points", "fatigue")})
        l.quality = safe_int(getattr(l, "quality", 3), 3, 1, 10)
        l.strength = safe_int(getattr(l, "strength", l.quality * 10), l.quality * 10, 1, 100)
        l.morale = safe_int(getattr(l, "morale", 80), 80, 0, 100)
        l.battles = safe_int(getattr(l, "battles", 0), 0, 0, 100000)
        l.location = str(getattr(l, "location", "Roma") or "Roma")
        l.veterans = bool(getattr(l, "veterans", False))
        l.elite = bool(getattr(l, "elite", False))
        l.action_points = safe_int(getattr(l, "action_points", SETTINGS.get("legion_action_points_per_turn", 5)), SETTINGS.get("legion_action_points_per_turn", 5), 0, 20)
        l.fatigue = safe_int(getattr(l, "fatigue", 0), 0, 0, 100)
        l.general = General.from_dict(general_data) if general_data else General()
        return l

# ─── КЛАСС: AI-ФРАКЦИЯ (для гражданской войны) ───────────────────────────────

@dataclass(init=False)
class AIFaction:
    name: str
    influence: int
    strength: int
    at_war: bool
    defeated: bool

    """
    Соперничающая политическая партия внутри Рима. Растёт во влиянии
    (influence) каждый ход. Если влияние превышает контроль игрока
    над Сенатом — фракция может объявить открытый мятеж.
    """
    def __init__(self, name):
        self.name       = name
        self.influence  = random.randint(10, 25)
        self.strength   = random.randint(15, 35)   # военная сила, если дойдёт до войны
        self.at_war      = False
        self.defeated    = False

    def grow(self, player_senate_rep):
        if self.defeated:
            return None
        # Чем слабее контроль игрока в Сенате, тем быстрее растут соперники
        growth = random.randint(2, 6) + max(0, (50 - player_senate_rep) // 10)
        self.influence = min(100, self.influence + growth)
        self.strength  = min(100, self.strength + random.randint(0, 3))
        return growth

    def should_revolt(self, player_senate_rep):
        return (not self.defeated) and (not self.at_war) and self.influence >= 70 and player_senate_rep < 60

    def description(self):
        status = clr(" [МЯТЕЖ]", C.RED) if self.at_war else (clr(" [разбита]", C.GRAY) if self.defeated else "")
        bar_len = int(self.influence / 100 * 10)
        bar = clr("█" * bar_len, C.PURPLE) + clr("░" * (10 - bar_len), C.GRAY)
        return f"  {clr(self.name, C.PURPLE)}{status}  Влияние: {bar} {self.influence:>3}  Сила: {self.strength}"

    def to_dict(self):
        return self.__dict__.copy()

    @staticmethod
    def from_dict(d):
        if not isinstance(d, dict):
            return AIFaction(random.choice(AI_FACTION_NAMES))
        f = AIFaction(d.get("name") or random.choice(AI_FACTION_NAMES))
        f.__dict__.update({k: v for k, v in d.items() if k in ("name", "influence", "strength", "at_war", "defeated")})
        f.influence = safe_int(getattr(f, "influence", 10), 10, 0, 100)
        f.strength = safe_int(getattr(f, "strength", 15), 15, 0, 100)
        f.at_war = bool(getattr(f, "at_war", False))
        f.defeated = bool(getattr(f, "defeated", False))
        return f


