def _normalize_ai_doctrine_key(key: str | None) -> str:
    key = str(key or "generic")
    return AI_DOCTRINE_ALIASES.get(key, key if key in AI_DOCTRINES else "generic")

def _ai_doctrine_def(key: str | None) -> dict:
    return AI_DOCTRINES.get(_normalize_ai_doctrine_key(key), AI_DOCTRINES["generic"])

def _ai_doctrine_key(name: str) -> str:
    name_l = str(name or "").lower()
    if any(x in name_l for x in ("карф", "carth", "пуник", "punic")):
        return "carthaginian"
    if any(x in name_l for x in ("gall", "галл", "кельт", "aquit", "belg")):
        return "gallic"
    if any(x in name_l for x in ("german", "герман", "teut", "тевтон", "sueb")):
        return "germanic"
    if any(x in name_l for x in ("maced", "макед", "achaea", "аха", "epirus", "эпир", "грек", "hellen")):
        return "hellenic"
    if any(x in name_l for x in ("parth", "парф", "syria", "сир", "egypt", "егип", "asia", "armenia", "mesopot", "pont", "cappad", "judaea", "иуде")):
        return "eastern"
    if any(x in name_l for x in ("партия", "мятеж", "crass", "cato", "clodi")):
        return "roman_rebel"
    return "generic"

def _battle_memory(player: "Player") -> dict:
    mem = getattr(player, "ai_battle_memory", None)
    if not isinstance(mem, dict):
        mem = {"player_tactics": {}, "enemy_tactics": {}, "wins": 0, "losses": 0, "enemy_margins": []}
        setattr(player, "ai_battle_memory", mem)
    mem.setdefault("player_tactics", {})
    mem.setdefault("enemy_tactics", {})
    mem.setdefault("wins", 0)
    mem.setdefault("losses", 0)
    mem.setdefault("enemy_margins", [])
    return mem

def remember_ai_battle(player: "Player", player_tactic: str, enemy_tactic: str, won: bool, margin: int):
    """Постоянная память ИИ в сохранении: враги учатся не только в рамках одной сессии."""
    mem = _battle_memory(player)
    pt = _PLAYER_TACTIC_MAP.get(str(player_tactic), str(player_tactic))
    mem["player_tactics"][pt] = safe_int(mem["player_tactics"].get(pt, 0), 0) + 1
    mem["enemy_tactics"][enemy_tactic] = safe_int(mem["enemy_tactics"].get(enemy_tactic, 0), 0) + 1
    if won:
        mem["wins"] = safe_int(mem.get("wins", 0), 0) + 1
    else:
        mem["losses"] = safe_int(mem.get("losses", 0), 0) + 1
    margins = safe_list(mem.get("enemy_margins", []))
    margins.append(int(margin))
    mem["enemy_margins"] = margins[-12:]

def _weighted_choice(candidates: list[tuple[str, int]]) -> str:
    candidates = [(name, max(0, int(weight))) for name, weight in candidates if name in ENEMY_TACTICS]
    if not candidates:
        return "cautious"
    names = [name for name, _ in candidates]
    weights = [weight for _, weight in candidates]
    total = sum(weights)
    if total <= 0:
        return random.choice(names)
    return random.choices(names, weights=weights, k=1)[0]

def enemy_ai_decide_tactic(player: "Player", legion: Legion, enemy: dict, battle_history: list | None = None, player_tactic: str | None = None) -> tuple:
    """
    Адаптивный боевой ИИ v2.11.
    Учитывает доктрину врага, текущую тактику игрока, постоянную память сохранения,
    усталость легиона, мораль, сложность, эпоху и серию побед/поражений игрока.
    Возвращает: (бонус_к_атаке_врага, бонус_к_защите_врага, описание, ключ_тактики).
    """
    if battle_history is None:
        battle_history = BATTLE_HISTORY

    enemy_name = enemy.get("name", "Hostes")
    doctrine_key = _normalize_ai_doctrine_key(_ai_doctrine_key(enemy_name))
    doctrine = _ai_doctrine_def(doctrine_key)
    doctrine_battle_mods = AI_DOCTRINE_BATTLE_MODS.get(doctrine_key, {})

    power_ratio = enemy.get("strength", 10) / max(1, getattr(legion, "strength", 1))
    fatigue_penalty = legion_fatigue_penalty(legion) if hasattr(legion, "fatigue") else 0
    morale_factor = getattr(legion, "morale", 80) / 100.0
    difficulty_mult = player.diff().get("enemy_strength_mult", 1.0)
    era_mult = get_era(player).get("enemy_mult", 1.0) if "get_era" in globals() else 1.0
    current = _PLAYER_TACTIC_MAP.get(str(player_tactic), player_tactic or "")

    candidates: list[tuple[str, int]] = []

    # 1) Базовая оценка сил. Слабый враг чаще хитрит, сильный — давит.
    if power_ratio > 1.35:
        candidates += [("frontal", 35), ("encirclement", 28), ("flanking", 22), ("desperate", 12), ("cautious", 10)]
    elif power_ratio < 0.75:
        candidates += [("defensive", 32), ("feigned_retreat", 28), ("harassment", 26), ("ambush", 18), ("cautious", 16)]
    else:
        candidates += [("flanking", 24), ("cautious", 22), ("discipline", 20), ("feigned_retreat", 18), ("harassment", 16)]

    # 2) Доктрина конкретного культурно-политического противника.
    for t in doctrine.get("favored", []):
        candidates.append((t, 18))
    counter = doctrine.get("counters", {}).get(current)
    if counter:
        candidates.append((counter, 34))

    # 3) Непосредственная реакция на тактику игрока.
    direct_counters = {
        "frontal": [("defensive", 24), ("discipline", 18), ("feigned_retreat", 14)],
        "manipular": [("flanking", 18), ("discipline", 16), ("harassment", 12)],
        "flanking": [("defensive", 20), ("discipline", 18), ("ambush", 14)],
        "defensive": [("harassment", 24), ("encirclement", 18), ("cautious", 14)],
        "testudo": [("harassment", 28), ("feigned_retreat", 18), ("encirclement", 16)],
    }
    candidates += direct_counters.get(current, [])

    # 4) Краткая память текущей сессии + постоянная память из save.
    player_tendencies = {"frontal": 0, "defensive": 0, "flanking": 0, "testudo": 0, "manipular": 0}
    for entry in battle_history[-8:]:
        if not isinstance(entry, dict):
            continue
        tactic = _PLAYER_TACTIC_MAP.get(str(entry.get("player_tactic", "")), entry.get("player_tactic", ""))
        if tactic in player_tendencies:
            player_tendencies[tactic] += 1
    mem = _battle_memory(player)
    for tactic, count in mem.get("player_tactics", {}).items():
        if tactic in player_tendencies:
            player_tendencies[tactic] += min(5, safe_int(count, 0))
    if current in player_tendencies:
        player_tendencies[current] += 2

    favorite_player_tactic = max(player_tendencies.items(), key=lambda kv: kv[1])[0]
    if player_tendencies[favorite_player_tactic] >= 3:
        learned_counter = doctrine.get("counters", {}).get(favorite_player_tactic) or {
            "frontal": "discipline", "manipular": "flanking", "flanking": "defensive", "defensive": "harassment", "testudo": "feigned_retreat"
        }.get(favorite_player_tactic, "cautious")
        candidates.append((learned_counter, 22 + player_tendencies[favorite_player_tactic] * 2))

    # 5) Состояние легиона. Усталые и деморализованные легионы ИИ добивает.
    if fatigue_penalty >= 12:
        candidates += [("harassment", 26), ("encirclement", 18), ("ambush", 14)]
    if morale_factor < 0.55:
        candidates += [("desperate", 18), ("frontal", 16), ("encirclement", 14)]
    if getattr(legion, "veterans", False) or getattr(legion, "elite", False):
        candidates += [("harassment", 18), ("feigned_retreat", 16), ("defensive", 12)]

    # 6) Сложность и эпоха: чем позднее игра и выше сложность, тем меньше тупого рандома.
    if difficulty_mult >= 1.25 or era_mult >= 1.35:
        candidates += [("ambush", 14), ("harassment", 14), ("encirclement", 12), ("discipline", 10)]
    elif difficulty_mult <= 0.8:
        candidates += [("frontal", 22), ("desperate", 10)]

    for t, bonus in doctrine_battle_mods.items():
        if t in ENEMY_TACTICS:
            candidates.append((t, 10 + safe_int(bonus, 0) * 6))

    chosen = _weighted_choice(candidates)
    tactic = ENEMY_TACTICS[chosen]
    atk_penalty = max(0, fatigue_penalty // 3)
    def_penalty = max(0, fatigue_penalty // 4)

    # Враг получает небольшой интеллектуальный бонус, если доктрина идеально
    # контрит текущий приказ игрока. На easy почти не чувствуется, на hard — больно.
    doctrine_bonus = 0
    if counter == chosen:
        doctrine_bonus = 1 + int(difficulty_mult >= 1.2) + int(era_mult >= 1.25)

    desc = f"{tactic['desc']} ({doctrine['label']})"
    return (
        tactic["atk_bonus"] + atk_penalty + doctrine_bonus,
        tactic["def_bonus"] - def_penalty + doctrine_bonus,
        desc,
        chosen,
    )

@dataclass(init=False)
class ImprovedAIFaction(AIFaction):
    strategy: str
    resources: int
    allies: list[str]
    last_action_turn: int
    goal: str | None
    difficulty: str
    suspicion: int
    patience: int
    action_history: list[str]
    target_province: str | None

    """Улучшенная AI-фракция с доктриной, памятью угрозы, ресурсами и активными интригами."""

    STRATEGIES = {"aggressive", "diplomatic", "subversive", "military", "economic"}

    def __init__(self, name):
        super().__init__(name)
        if "Красс" in str(name):
            self.strategy = "economic"
        elif "Катон" in str(name):
            self.strategy = "diplomatic"
        elif "Клод" in str(name):
            self.strategy = "subversive"
        else:
            self.strategy = random.choice(["aggressive", "diplomatic", "subversive", "military"])
        self.resources = random.randint(10, 30)
        self.allies = []
        self.last_action_turn = 0
        self.goal = None
        self.difficulty = "normal"
        self.suspicion = random.randint(5, 20)      # насколько фракция боится игрока
        self.patience = random.randint(2, 5)        # как часто она готова действовать
        self.action_history = []
        self.target_province = None

    def _stability(self, player_senate_rep, player_people_rep, player_morale) -> float:
        return (player_senate_rep + player_people_rep + player_morale) / 3

    def _choose_goal(self, player):
        if self.goal and random.random() < 0.65:
            return self.goal
        weak_army = len(getattr(player, "legions", [])) <= 1
        rich = getattr(player, "gold", 0) >= 250
        unstable = player.effective_unrest() >= 35 or player.people_rep < 45
        if self.strategy == "economic" or rich:
            self.goal = "drain_treasury"
        elif self.strategy == "subversive" or unstable:
            self.goal = "raise_unrest"
        elif self.strategy in {"aggressive", "military"} or weak_army:
            self.goal = "prepare_revolt"
        else:
            self.goal = "undermine_senate"
        return self.goal

    def grow(self, player_senate_rep, player_people_rep=None, player_morale=None, turn=None):
        if self.defeated:
            return None
        player_people_rep = 50 if player_people_rep is None else player_people_rep
        player_morale = 70 if player_morale is None else player_morale
        self.last_action_turn = safe_int(turn, self.last_action_turn) if turn is not None else self.last_action_turn

        base_growth = random.randint(1, 4)
        instability = max(0, int((65 - self._stability(player_senate_rep, player_people_rep, player_morale)) // 8))
        if self.strategy == "aggressive":
            growth_mod = 2 + max(0, (55 - player_morale) // 10)
        elif self.strategy == "diplomatic":
            growth_mod = 1 + max(0, (55 - player_senate_rep) // 12)
        elif self.strategy == "subversive":
            growth_mod = 3 + max(0, (55 - player_people_rep) // 9)
        elif self.strategy == "economic":
            growth_mod = 1 + (1 if player_senate_rep < 55 else 0)
        else:
            growth_mod = 2 + max(0, (50 - player_morale) // 12)

        diff_mult = DIFFICULTY_PRESETS.get(self.difficulty, {}).get("ai_faction_growth_mult", 1.0)
        growth = int(round((base_growth + growth_mod + instability) * diff_mult))
        self.influence = min(100, self.influence + growth)
        self.strength = min(100, self.strength + random.randint(0, 2) + (1 if self.goal == "prepare_revolt" else 0))
        self.resources = min(100, self.resources + random.randint(1, 4) + (1 if self.strategy == "economic" else 0))
        self.suspicion = min(100, self.suspicion + max(0, growth - 3))
        return growth

    def should_revolt(self, player_senate_rep, player_people_rep=None, player_morale=None, turn=None):
        if self.defeated or self.at_war:
            return False
        player_people_rep = 50 if player_people_rep is None else player_people_rep
        player_morale = 70 if player_morale is None else player_morale
        turn = 999 if turn is None else turn
        if turn < 8:
            return False

        threshold = {
            "aggressive": 60, "military": 62, "subversive": 58 if player_people_rep < 45 else 72,
            "economic": 76, "diplomatic": 70,
        }.get(self.strategy, 70)
        if self.goal == "prepare_revolt":
            threshold -= 5
        if self.resources >= 70 and self.strength >= 55:
            threshold -= 4

        if self.influence >= threshold:
            stability = self._stability(player_senate_rep, player_people_rep, player_morale)
            revolt_chance = min(0.85, max(0.08, (105 - stability + self.suspicion / 3) / 170))
            return random.random() < revolt_chance
        return False

    def choose_action(self, player, turn):
        if self.defeated or self.at_war:
            return None
        if turn - safe_int(getattr(self, "last_action_turn", 0), 0) < max(1, safe_int(getattr(self, "patience", 3), 3)):
            return None
        self._choose_goal(player)
        actions = []
        stability = self._stability(player.senate_rep, player.people_rep, player.morale)
        diff_mult = DIFFICULTY_PRESETS.get(self.difficulty, {}).get("ai_faction_growth_mult", 1.0)

        def add(name, effect, cost, weight):
            if self.resources >= cost:
                actions.append((name, effect, cost, max(1, int(weight * diff_mult))))

        if self.goal == "undermine_senate" or self.strategy == "diplomatic":
            add("bribe_senate", -random.randint(4, 8), 18, 28 + max(0, 65 - player.senate_rep))
        if self.goal == "raise_unrest" or self.strategy == "subversive":
            add("agitate_people", -random.randint(3, 7), 14, 24 + max(0, 60 - player.people_rep))
            add("fund_unrest", random.randint(1, 3), 22, 18 + player.effective_unrest() // 2)
        if self.goal == "prepare_revolt" or self.strategy in {"aggressive", "military"}:
            add("recruit", random.randint(5, 9), 24, 24 + max(0, 55 - player.morale))
            add("propaganda_morale", -random.randint(3, 7), 16, 14 + max(0, 65 - player.morale))
        if self.goal == "drain_treasury" or self.strategy == "economic":
            add("sabotage_treasury", -random.randint(15, 35), 20, 18 + min(25, player.gold // 20))
        if self.influence >= 55 and self.resources >= 30:
            add("forge_alliance", random.randint(3, 6), 30, 12 + int(stability < 55) * 20)

        if not actions:
            return None
        names, effects, costs, weights = zip(*actions)
        idx = random.choices(range(len(actions)), weights=weights, k=1)[0]
        action, effect, cost, _weight = actions[idx]
        self.resources = max(0, self.resources - cost)
        self.last_action_turn = turn
        self.action_history = (safe_list(getattr(self, "action_history", [])) + [{"turn": turn, "action": action}])[-12:]
        return {"action": action, "effect": effect, "cost": cost, "goal": self.goal}

    def to_dict(self):
        d = super().to_dict()
        d.update({
            "strategy": self.strategy,
            "resources": self.resources,
            "allies": self.allies,
            "last_action_turn": self.last_action_turn,
            "goal": self.goal,
            "difficulty": self.difficulty,
            "suspicion": self.suspicion,
            "patience": self.patience,
            "action_history": self.action_history,
            "target_province": self.target_province,
        })
        return d

    @staticmethod
    def from_dict(d):
        if not isinstance(d, dict):
            return ImprovedAIFaction(random.choice(AI_FACTION_NAMES))
        f = ImprovedAIFaction(d.get("name") or random.choice(AI_FACTION_NAMES))
        for key in ("name", "influence", "strength", "at_war", "defeated"):
            if key in d:
                setattr(f, key, d[key])
        f.influence = safe_int(getattr(f, "influence", 10), 10, 0, 100)
        f.strength = safe_int(getattr(f, "strength", 15), 15, 0, 100)
        f.at_war = bool(getattr(f, "at_war", False))
        f.defeated = bool(getattr(f, "defeated", False))
        strategy = d.get("strategy", "aggressive")
        if strategy == "aggresive":
            strategy = "aggressive"
        f.strategy = strategy if strategy in ImprovedAIFaction.STRATEGIES else "aggressive"
        f.resources = safe_int(d.get("resources", 20), 20, 0, 100)
        f.allies = safe_list(d.get("allies", []))
        f.last_action_turn = safe_int(d.get("last_action_turn", 0), 0)
        f.goal = d.get("goal")
        f.difficulty = d.get("difficulty", "normal") if d.get("difficulty", "normal") in DIFFICULTY_PRESETS else "normal"
        f.suspicion = safe_int(d.get("suspicion", 10), 10, 0, 100)
        f.patience = safe_int(d.get("patience", 3), 3, 1, 8)
        f.action_history = safe_list(d.get("action_history", []))[-12:]
        f.target_province = d.get("target_province")
        return f


def barbarian_ai_tick(player: "Player"):
    """Варварские племена активнее реагируют на отношения и собственную силу."""
    ensure_expansion_state(player)
    for key, tribe in getattr(player, "barbarian_tribes", {}).items():
        if not isinstance(tribe, dict):
            continue
        drift = random.randint(-2, 2)
        if tribe.get("pact"):
            drift += 1
        if safe_int(tribe.get("strength", 0), 0) > 6:
            drift -= 1
        tribe["relation"] = max(0, min(100, safe_int(tribe.get("relation", 50), 50) + drift))

        roll = random.random()
        if roll < 0.04 and tribe["relation"] < 30 and safe_int(tribe.get("strength", 0), 0) > 5:
            candidates = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
            if candidates:
                target = random.choice(candidates)
                damage = random.randint(1, 4)
                target["unrest"] = min(10, target.get("unrest", 0) + damage)
                player.gold = max(0, player.gold - random.randint(5, 20))
                print(clr(f"\n  🐺 {tribe['name']} совершили набег на {target['name']}!", C.RED))
                log_event(player, f"Набег {tribe['name']} на {target['name']}")
        elif roll < 0.07 and tribe["relation"] > 60 and not tribe.get("pact"):
            print(clr(f"\n  🪓 {tribe['name']} предлагают военный союз против общих врагов.", C.CYAN))
            if read_choice(f"  {clr('Принять союз? (Y/N): ', C.CYAN)}", ["Y", "N"]) == "Y":
                tribe["pact"] = True
                player.morale = min(100, player.morale + 5)
                log_event(player, f"Военный союз с {tribe['name']}")


