def _enemy_ai_setting(key: str, default):
    return SETTINGS.get(key, default)

def is_madness_mode(player: "Player") -> bool:
    return getattr(player, "difficulty", "normal") == "madness"

def _enemy_ai_setting_player(player: "Player", key: str, default):
    """Настройки стратегического ИИ с особым режимом «Безумие».

    В обычных режимах возвращает значения из roma_settings.json.
    В Безумии именно вероятности/частоты ИИ выкручиваются до ×20, но
    боевые числа остаются ограниченными, чтобы это была мясорубка поведения,
    а не снова d20 + 142.
    """
    value = _enemy_ai_setting(key, default)
    if not is_madness_mode(player):
        return value
    mult = safe_int(SETTINGS.get("enemy_ai_madness_multiplier", 20), 20, 1, 100)
    if "chance" in key or key in {"enemy_ai_coalition_threshold"}:
        try:
            v = float(value)
        except (TypeError, ValueError):
            v = float(default)
        if key == "enemy_ai_coalition_threshold":
            return max(0.02, v / mult)
        return min(1.0, v * mult)
    if key == "enemy_ai_army_cap_base":
        return min(85, max(18, safe_int(value, default) * 4))
    if key == "enemy_ai_great_campaign_interval":
        return max(3, safe_int(value, default) // mult)
    if key == "enemy_ai_mobilization_threshold":
        try:
            return max(0.04, float(value) / mult)
        except (TypeError, ValueError):
            return 0.04
    return value

def _enemy_clamp(value, low, high):
    return max(low, min(high, safe_int(value, low)))

def ensure_enemy_grand_ai_state(player: "Player"):
    if not isinstance(getattr(player, "enemy_armies", None), list):
        player.enemy_armies = []
    if not isinstance(getattr(player, "enemy_ai_lost_cities", None), dict):
        player.enemy_ai_lost_cities = {}
    if not isinstance(getattr(player, "enemy_ai_sieges", None), list):
        player.enemy_ai_sieges = []
    if not isinstance(getattr(player, "enemy_ai_commanders_alive", None), list):
        player.enemy_ai_commanders_alive = [c["name"] for c in ENEMY_AI_COMMANDERS]
    if not isinstance(getattr(player, "enemy_ai_commander_graveyard", None), list):
        player.enemy_ai_commander_graveyard = []
    if not isinstance(getattr(player, "enemy_ai_coalition", None), dict):
        player.enemy_ai_coalition = {"active": False, "turns": 0, "members": []}
    if not isinstance(getattr(player, "enemy_ai_patrols", None), dict):
        player.enemy_ai_patrols = {}
    if not isinstance(getattr(player, "enemy_ai_fortifications", None), dict):
        player.enemy_ai_fortifications = {}
    if not isinstance(getattr(player, "enemy_ai_traps", None), dict):
        player.enemy_ai_traps = {}
    if not isinstance(getattr(player, "enemy_ai_campaigns", None), list):
        player.enemy_ai_campaigns = []
    player.enemy_ai_counter_raid_network = safe_int(getattr(player, "enemy_ai_counter_raid_network", 0), 0, 0, 12)
    player.enemy_ai_recon_level = safe_int(getattr(player, "enemy_ai_recon_level", 0), 0, 0, 3)
    player.enemy_ai_last_great_campaign = safe_int(getattr(player, "enemy_ai_last_great_campaign", 0), 0, 0)
    player.enemy_ai_pressure = safe_int(getattr(player, "enemy_ai_pressure", 0), 0, 0, 100)
    cleaned = []
    for a in player.enemy_armies:
        if not isinstance(a, (dict, EnemyArmy)):
            continue
        a.setdefault("id", f"EA-{player.turn}-{random.randint(1000,9999)}")
        a.setdefault("province", "Hostes")
        a.setdefault("owner", _ai_doctrine_key(a.get("province", "")))
        a["strength"] = safe_int(a.get("strength", 25), 25, 5, 125)
        a["morale"] = safe_int(a.get("morale", 70), 70, 5, 120)
        a["faith"] = safe_int(a.get("faith", 20), 20, 0, 110)
        a["blessing_turns"] = safe_int(a.get("blessing_turns", 0), 0, 0, 6)
        a["experience"] = safe_int(a.get("experience", 0), 0, 0, 160)
        a["supply"] = safe_int(a.get("supply", 80), 80, 0, 120)
        a["cooldown"] = safe_int(a.get("cooldown", 0), 0, 0, 4)
        a.setdefault("order", "recon")
        a.setdefault("target", None)
        a.setdefault("unit_type", "infantry")
        a.setdefault("unit_name", ENEMY_FORCE_ARCHETYPES.get(a["unit_type"], ENEMY_FORCE_ARCHETYPES["infantry"])["label"])
        a.setdefault("commander", None)
        a.setdefault("campaign_id", None)
        a.setdefault("ai_focus", "probing")
        cleaned.append(a)
    player.enemy_armies = cleaned[-55:]
    # чистим осады по существующим провинциям
    owned = {p.get("name") for p in getattr(player, "provinces", [])}
    player.enemy_ai_sieges = [
        s for s in player.enemy_ai_sieges
        if isinstance(s, dict) and s.get("province") in owned and s.get("province") != "Latium"
    ][-12:]
    # чистим кампании: только валидные словари, с живыми армиями, ссылки на них согласованы
    live_ids = {a.get("id") for a in player.enemy_armies}
    valid_campaigns = []
    for c in player.enemy_ai_campaigns:
        if not isinstance(c, dict):
            continue
        c["army_ids"] = [i for i in safe_list(c.get("army_ids", [])) if i in live_ids]
        if not c["army_ids"]:
            continue
        c.setdefault("phase", "muster")
        c.setdefault("turns_in_phase", 0)
        c.setdefault("threat", 0)
        valid_campaigns.append(c)
    player.enemy_ai_campaigns = valid_campaigns[-6:]

def _province_aux_candidates(province_name: str) -> list[dict]:
    try:
        enrich_provincial_auxilia()
        return [u for u in UNIQUE_AUXILIARY_UNITS.get(province_name, []) if isinstance(u, dict)]
    except (KeyError, TypeError, ValueError) as e:
        debug_log("Aux candidates build failed for %s: %s", province_name, e, exc_info=True, level=logging.WARNING)
        return []

def enemy_strong_unit_for_province(province_name: str) -> dict:
    """Берёт сильнейший провинциальный отряд из списка ауксилии."""
    units = _province_aux_candidates(province_name)
    if units:
        unit = max(units, key=lambda u: safe_int(u.get("strength", 0), 0))
        unit_type = "infantry"
        utype = str(unit.get("type", "")).lower()
        uname = str(unit.get("name", "")).lower()
        if "кон" in utype or "кавал" in utype:
            unit_type = "cavalry"
        elif "луч" in utype or "пращ" in utype or "стрел" in utype:
            unit_type = "archers"
        elif "осад" in utype or "инжен" in utype:
            unit_type = "siege"
        elif "свящ" in uname or "жр" in uname:
            unit_type = "sacred"
        elif "гвард" in uname or "элит" in uname:
            unit_type = "elite"
        strength = safe_int(unit.get("strength", 20), 20, 10, 80)
        return {
            "unit_type": unit_type,
            "unit_name": unit.get("name", f"Элитный отряд {province_name}"),
            "aux_key": unit.get("key"),
            # v2.14: база ниже, чтобы отряды были страшны качеством, а не бездонной арифметикой.
            "base_strength": min(112, 18 + int(strength * 0.70) + safe_int(unit.get("attack", 0), 0) // 2 + safe_int(unit.get("defense", 0), 0) // 2),
        }
    t, name = random.choice(ENEMY_PROVINCE_UNIT_FALLBACKS)
    return {"unit_type": t, "unit_name": f"{name} {province_name}", "aux_key": None, "base_strength": random.randint(20, 34)}

def _enemy_army_name(province_name: str, unit_name: str) -> str:
    prefixes = ["Войско", "Дружина", "Союзный отряд", "Карательная рать", "Военный стан"]
    return f"{random.choice(prefixes)} {province_name}: {unit_name}"

def _doctrine_for_commander(province_name: str) -> str:
    key = _ai_doctrine_key(province_name)
    # _ai_doctrine_key уже возвращает близкую культурную доктрину; здесь только
    # мягкая нормализация для легендарных командиров.
    if key in {"punic", "gallic", "germanic", "hellenic", "eastern", "dacian", "iberian"}:
        return key
    if province_name in {"Carthago", "Numidia", "Mauretania", "Sardinia et Corsica"}:
        return "punic"
    if "Gallia" in province_name or province_name in {"Belgica", "Aquitania"}:
        return "gallic"
    if "Germania" in province_name or province_name in {"Britannia", "Caledonia", "Hibernia"}:
        return "germanic"
    if province_name in {"Achaea", "Macedonia", "Epirus", "Asia Minor", "Bithynia", "Galatia"}:
        return "hellenic"
    if province_name in {"Syria", "Judaea", "Armenia", "Mesopotamia", "Pontus", "Cappadocia", "Cilicia"}:
        return "eastern"
    if province_name in {"Hispania", "Lusitania", "Baetica"}:
        return "iberian"
    if province_name in {"Dacia", "Thracia"}:
        return "dacian"
    return key

def _maybe_assign_enemy_commander(player: "Player", army: dict, reason: str = "reinforcement"):
    alive = [c for c in ENEMY_AI_COMMANDERS if c["name"] in getattr(player, "enemy_ai_commanders_alive", [])]
    if not alive:
        return
    doctrine = _doctrine_for_commander(army.get("province", ""))
    fitting = [c for c in alive if c.get("culture") == doctrine] or alive
    chance = 0.05
    if reason in {"great_campaign", "mobilization"}:
        chance = 0.18
    elif reason == "recapture":
        chance = 0.10
    if random.random() < chance:
        cmd = random.choice(fitting)
        army["commander"] = cmd["name"]
        army["commander_trait"] = cmd["trait"]
        army["morale"] = min(120, safe_int(army.get("morale", 70), 70) + 8)
        if cmd["name"] in player.enemy_ai_commanders_alive:
            player.enemy_ai_commanders_alive.remove(cmd["name"])
        print(clr(f"\n  👑 Вражеский полководец вступает в кампанию: {cmd['name']} — {cmd['trait']}.", C.BOLD + C.RED))
        log_event(player, f"Враг выставил полководца: {cmd['name']}")

def _enemy_commander_data(name: str | None):
    if not name:
        return None
    return next((c for c in ENEMY_AI_COMMANDERS if c["name"] == name), None)

@dataclass
class EnemyArmy(MutableMapping):
    """Типизированная вражеская армия с dict-совместимостью для старых экранов."""
    id: str
    name: str
    province: str
    owner: str
    unit_type: str
    unit_name: str
    aux_key: str | None = None
    strength: int = 25
    morale: int = 70
    faith: int = 0
    experience: int = 0
    supply: int = 80
    blessing_turns: int = 0
    order: str = "recon"
    target: str | None = None
    cooldown: int = 0
    spawn_reason: str = "reinforcement"
    commander: str | None = None
    campaign_id: str | None = None
    commander_trait: str | None = None
    ai_focus: str = "probing"

    def __getitem__(self, key: str) -> Any:
        if not hasattr(self, key):
            raise KeyError(key)
        return getattr(self, key)

    def __setitem__(self, key: str, value: Any) -> None:
        if not hasattr(self, key):
            raise KeyError(key)
        setattr(self, key, value)

    def __delitem__(self, key: str) -> None:
        if not hasattr(self, key):
            raise KeyError(key)
        setattr(self, key, None)

    def __iter__(self):
        return iter(asdict(self))

    def __len__(self) -> int:
        return len(asdict(self))

    def get(self, key: str, default: Any = None) -> Any:
        return getattr(self, key, default)

    def setdefault(self, key: str, default: Any = None) -> Any:
        if not hasattr(self, key) or getattr(self, key) is None:
            if hasattr(self, key):
                setattr(self, key, default)
            return default
        return getattr(self, key)

    def update(self, other=(), /, **kwargs) -> None:
        data = dict(other, **kwargs)
        for key, value in data.items():
            if hasattr(self, key):
                setattr(self, key, value)

    def to_dict(self) -> dict[str, Any]:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: EnemyArmy | dict[str, Any]) -> "EnemyArmy":
        if isinstance(data, cls):
            return data
        if not isinstance(data, dict):
            data = {}
        defaults = {
            "id": data.get("id", f"EA-legacy-{random.randint(100,999)}"),
            "name": data.get("name", "Hostes Ignoti"),
            "province": data.get("province", "Latium"),
            "owner": data.get("owner", "barbarian"),
            "unit_type": data.get("unit_type", "infantry"),
            "unit_name": data.get("unit_name", "Вражеский отряд"),
        }
        allowed = set(cls.__dataclass_fields__)
        payload = {k: v for k, v in data.items() if k in allowed}
        payload.update({k: v for k, v in defaults.items() if k not in payload})
        return cls(**payload)


def spawn_enemy_army(player: "Player", province_name: str | None = None, reason: str = "reinforcement") -> EnemyArmy | None:
    ensure_enemy_grand_ai_state(player)
    owned = {p.get("name") for p in getattr(player, "provinces", [])}
    candidate_names = [p["name"] for p in PROVINCES_DATA if p["name"] not in owned]
    if not candidate_names and province_name is None:
        candidate_names = [p.get("name") for p in getattr(player, "provinces", []) if p.get("name") != "Latium"] or ["Latium"]
    province_name = province_name or random.choice(candidate_names)
    unit = enemy_strong_unit_for_province(province_name)
    arch = ENEMY_FORCE_ARCHETYPES.get(unit["unit_type"], ENEMY_FORCE_ARCHETYPES["infantry"])
    era = get_era(player)
    diff = player.diff().get("enemy_strength_mult", 1.0)
    # v2.14: коэффициент сложности действует мягче. Hard всё ещё опасен,
    # но не превращает каждый отряд в математический каток.
    strength = int(round(unit["base_strength"] * era.get("enemy_mult", 1.0) * (0.82 + diff * 0.16)))
    if reason in {"great_campaign", "mobilization", "recapture"}:
        strength += random.randint(5, 14)
    army = EnemyArmy(
        id=f"EA-{player.turn}-{len(player.enemy_armies)+1}-{random.randint(100,999)}",
        name=_enemy_army_name(province_name, unit["unit_name"]),
        province=province_name,
        owner=_ai_doctrine_key(province_name),
        unit_type=unit["unit_type"],
        unit_name=unit["unit_name"],
        aux_key=unit.get("aux_key"),
        strength=max(10, min(150 if is_madness_mode(player) else 125, strength + (8 if is_madness_mode(player) else 0))),
        morale=max(35, min(120, 64 + arch.get("morale", 0) + random.randint(-7, 10))),
        faith=random.randint(12, 58),
        experience=random.randint(0, 14),
        supply=random.randint(70, 105),
        blessing_turns=0,
        order="recon",
        target=None,
        cooldown=random.randint(0, 1),
        spawn_reason=reason,
        commander=None,
        campaign_id=None,
    )
    _maybe_assign_enemy_commander(player, army, reason)
    player.enemy_armies.append(army)
    return army

def enemy_army_battle_power(army: EnemyArmy | dict) -> int:
    arch = ENEMY_FORCE_ARCHETYPES.get(army.get("unit_type"), ENEMY_FORCE_ARCHETYPES["infantry"])
    value = int(safe_int(army.get("strength", 25), 25) * 0.62)
    value += safe_int(army.get("experience", 0), 0) // 7
    value += arch.get("atk", 0) + arch.get("def", 0)
    value += max(0, safe_int(army.get("morale", 70), 70) - 60) // 10
    value -= max(0, 55 - safe_int(army.get("supply", 80), 80)) // 10
    if safe_int(army.get("blessing_turns", 0), 0) > 0:
        value += 4
    cmd = _enemy_commander_data(army.get("commander"))
    if cmd:
        value += 4 + cmd.get("bonus", {}).get(army.get("unit_type"), 0)
    return max(5, min(92, value))

def _enemy_armies_cap(player: "Player") -> int:
    base = safe_int(_enemy_ai_setting_player(player, "enemy_ai_army_cap_base", 7), 7, 1, 90)
    coalition = getattr(player, "enemy_ai_coalition", {})
    extra = 2 if isinstance(coalition, dict) and coalition.get("active") else 0
    return min(85 if is_madness_mode(player) else 42, base + extra + player.turn // 10 + len(getattr(player, "provinces", [])) // 5)


def ensure_ai_memory_state(player: "Player") -> dict:
    """Единая память ИИ: совместима со старым ai_battle_memory и новым ai_memory."""
    legacy = _battle_memory(player)
    mem = getattr(player, "ai_memory", None)
    if not isinstance(mem, dict):
        mem = {}
        setattr(player, "ai_memory", mem)
    mem.setdefault("player_tactics", legacy.setdefault("player_tactics", {}))
    mem.setdefault("failed_targets", {})
    mem.setdefault("province_pressure", {})
    mem.setdefault("last_orders", {})
    return mem

def _difficulty_ai_memory_factor(player: "Player") -> float:
    diff = getattr(player, "difficulty", "normal")
    return {"easy": 0.35, "normal": 0.65, "hard": 1.0, "hardcore": 1.2, "madness": 1.55}.get(diff, 0.75)

def _top_player_tactic(player: "Player") -> str | None:
    mem = ensure_ai_memory_state(player)
    tactics = safe_dict(mem.get("player_tactics"))
    if not tactics:
        return None
    return max(tactics, key=lambda k: safe_int(tactics.get(k, 0), 0))

def _score_noise(player: "Player") -> int:
    return safe_int(_enemy_ai_setting_player(player, "enemy_ai_order_noise", 7), 7, 0, 25)

def _reserve_power_safe(player: "Player", province_name: str) -> int:
    if "_reserve_power_for_province" in globals():
        return _reserve_power_for_province(player, province_name)
    reserves = getattr(player, "enemy_ai_reserves", {})
    if isinstance(reserves, dict) and isinstance(reserves.get(province_name), dict):
        return safe_int(reserves[province_name].get("power", 0), 0, 0, 90)
    return 0

def _strategic_province_value(player: "Player", prov: dict | None) -> int:
    if not prov:
        return 0
    name = prov.get("name")
    owned = {p.get("name") for p in getattr(player, "provinces", [])}
    neighbors = set(prov.get("neighbors", []))
    frontier = bool(neighbors - owned)
    value = safe_int(prov.get("wealth", 0), 0) * 8
    value += safe_int(prov.get("unrest", 0), 0) * 7
    value += max(0, 65 - safe_int(prov.get("romanization", 50), 50)) // 3
    value += 14 if frontier else 0
    value -= safe_int(prov.get("garrison", 0), 0) * 5
    value -= _reserve_power_safe(player, name) // 3
    mem = ensure_ai_memory_state(player)
    value -= min(24, safe_int(safe_dict(mem.get("failed_targets")).get(name, 0), 0) * 6)
    return value

def _rich_or_unrest_provinces_smart(player: "Player") -> list[dict]:
    owned = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
    return sorted(owned, key=lambda p: _strategic_province_value(player, p), reverse=True)

def _weak_legions_sorted(player: "Player") -> list:
    legions = [l for l in getattr(player, "legions", []) if getattr(l, "strength", 0) > 0]
    def vulnerability(l):
        fatigue = safe_int(getattr(l, "fatigue", 0), 0)
        elite_penalty = 25 if getattr(l, "elite", False) else 0
        veteran_penalty = 12 if getattr(l, "veterans", False) else 0
        loc = getattr(l, "location", "")
        reserve_penalty = _reserve_power_safe(player, loc) // 4
        mem = ensure_ai_memory_state(player)
        recent_fail = safe_int(safe_dict(mem.get("failed_targets")).get(l.name, 0), 0)
        return (100 - safe_int(l.strength, 50)) + fatigue // 2 + (70 - safe_int(l.morale, 70)) // 2 - elite_penalty - veteran_penalty - reserve_penalty - min(25, recent_fail * 7)
    return sorted(legions, key=vulnerability, reverse=True)

def _situation_snapshot(player: "Player") -> dict:
    provinces = _rich_or_unrest_provinces_smart(player)
    weak_legions = _weak_legions_sorted(player)
    return {
        "rich_targets": provinces,
        "weak_legions": weak_legions,
        "top_player_tactic": _top_player_tactic(player),
        "coalition_active": bool(isinstance(getattr(player, "enemy_ai_coalition", {}), dict) and getattr(player, "enemy_ai_coalition", {}).get("active")),
        "low_roman_morale": safe_int(getattr(player, "morale", 50), 50) < 45,
    }

def _calculate_order_score(army: dict, player: "Player", situation: dict) -> dict:
    """Возвращает словарь {order: score}; дальше добавляется небольшой шум."""
    strength = safe_int(army.get("strength", 25), 25)
    morale = safe_int(army.get("morale", 70), 70)
    supply = safe_int(army.get("supply", 80), 80)
    cmd = _enemy_commander_data(army.get("commander"))
    doctrine_key = _normalize_ai_doctrine_key(army.get("owner") or _ai_doctrine_key(army.get("province", "")))
    scores = {"recon": 18, "regroup": 0, "raid": 10, "siege": 8, "strike": 12, "ambush": 8}

    if strength < 25 or morale < 35 or supply < 40:
        scores["regroup"] = 100 + (cmd.get("bonus", {}).get("retreat", 0) * 4 if cmd else 0)
        return scores

    for order, bonus in AI_DOCTRINE_ORDER_BIASES.get(doctrine_key, {}).items():
        scores[order] = scores.get(order, 0) + safe_int(bonus, 0)

    if cmd:
        pref = cmd.get("style", "")
        aggression = safe_int(cmd.get("aggression", 50), 50)
        caution = safe_int(cmd.get("caution", 50), 50)
        siege_skill = safe_int(cmd.get("siege", 40), 40)
        if pref in {"raid", "attrition"}:
            scores["raid"] += 35 + aggression // 4 + cmd.get("bonus", {}).get("raid", 0) * 5
        elif pref in {"fortified"}:
            scores["siege"] += 40 + siege_skill // 3 + cmd.get("bonus", {}).get("siege", 0) * 5
            scores["regroup"] += caution // 8
        elif pref in {"ambush", "forest_ambush"}:
            scores["ambush"] += 35 + cmd.get("bonus", {}).get("ambush", 0) * 5
        elif pref in {"shock", "coalition"}:
            scores["strike"] += 26 + aggression // 5

    rich_targets = situation.get("rich_targets") or []
    weak_legions = situation.get("weak_legions") or []
    if rich_targets:
        best = rich_targets[0]
        pvalue = _strategic_province_value(player, best)
        scores["raid"] += 14 + pvalue // 5
        scores["siege"] += 10 + pvalue // 4
    else:
        scores["raid"] -= 25
        scores["siege"] -= 25

    if weak_legions:
        w = weak_legions[0]
        vuln = max(0, 100 - safe_int(getattr(w, "strength", 50), 50)) + safe_int(getattr(w, "fatigue", 0), 0) // 2
        scores["strike"] += 22 + vuln // 2
        scores["ambush"] += 16 + vuln // 3
    else:
        scores["strike"] -= 20
        scores["ambush"] -= 15

    if situation.get("coalition_active"):
        scores["strike"] += 10
        scores["siege"] += 8
    if situation.get("low_roman_morale"):
        scores["strike"] += 12
        scores["raid"] += 8

    top = situation.get("top_player_tactic")
    factor = _difficulty_ai_memory_factor(player)
    if top == "defensive":
        scores["raid"] += int(14 * factor)
        scores["siege"] += int(10 * factor)
    elif top in {"frontal", "manipular"}:
        scores["ambush"] += int(16 * factor)
        scores["strike"] += int(8 * factor)
    elif top == "flanking":
        scores["regroup"] += int(8 * factor)
        scores["ambush"] += int(10 * factor)
    elif top == "testudo":
        scores["raid"] += int(12 * factor)
        scores["siege"] += int(8 * factor)

    if supply < 60:
        scores["siege"] = int(scores.get("siege", 0) * 0.60)
        scores["strike"] = int(scores.get("strike", 0) * 0.75)
        scores["raid"] = int(scores.get("raid", 0) * 0.85)
        scores["regroup"] += 18
    if morale < 55:
        scores["ambush"] += 8
        scores["regroup"] += 10

    return {k: max(-50, int(v)) for k, v in scores.items()}

def _choose_scored_order(scores: dict, player: "Player") -> str:
    noise = _score_noise(player)
    noisy = {k: v + (random.randint(-noise, noise) if noise else 0) for k, v in scores.items()}
    return max(noisy, key=noisy.get)

def _target_for_order(player: "Player", order: str, situation: dict):
    if order in {"raid", "siege"}:
        provinces = situation.get("rich_targets") or []
        return provinces[0].get("name") if provinces else None
    if order in {"strike", "ambush"}:
        legions = situation.get("weak_legions") or []
        return legions[0].name if legions else None
    return None

def _remember_failed_ai_target(player: "Player", target: str | None, amount: int = 1):
    if not target:
        return
    mem = ensure_ai_memory_state(player)
    failed = safe_dict(mem.get("failed_targets"))
    failed[target] = min(8, safe_int(failed.get(target, 0), 0) + amount)
    mem["failed_targets"] = failed

def _decay_ai_memory(player: "Player"):
    mem = ensure_ai_memory_state(player)
    failed = safe_dict(mem.get("failed_targets"))
    mem["failed_targets"] = {k: max(0, safe_int(v, 0) - 1) for k, v in failed.items() if safe_int(v, 0) > 1}

def _choose_legion_target(player: "Player"):
    legions = _weak_legions_sorted(player)
    return legions[0] if legions else None

def enemy_ai_recon_and_orders(player: "Player"):
    """Поведенческий слой v2.20: приказы выбираются скорингом, а не цепочкой random.random()."""
    ensure_enemy_grand_ai_state(player)
    ensure_ai_memory_state(player)
    situation = _situation_snapshot(player)
    for army in player.enemy_armies:
        if safe_int(army.get("cooldown", 0), 0) > 0:
            army["cooldown"] = max(0, safe_int(army.get("cooldown", 0), 0) - 1)
        if army.get("campaign_id"):
            continue

        strength = safe_int(army.get("strength", 25), 25)
        morale = safe_int(army.get("morale", 70), 70)
        supply = safe_int(army.get("supply", 80), 80)
        cmd = _enemy_commander_data(army.get("commander"))

        scores = _calculate_order_score(army, player, situation)
        order = _choose_scored_order(scores, player)
        target = _target_for_order(player, order, situation)

        if order in {"raid", "siege", "strike", "ambush"} and not target:
            order, target = "recon", None

        army["order"] = order
        army["target"] = target

        if order == "regroup":
            heal = 4 + (cmd.get("bonus", {}).get("retreat", 0) if cmd else 0)
            army["strength"] = min(125, strength + random.randint(2, max(2, heal)))
            army["morale"] = min(120, morale + random.randint(4, 10))
            army["supply"] = min(120, supply + random.randint(8, 18))
        elif order in {"raid", "siege", "ambush", "strike"}:
            army["supply"] = max(0, supply - random.randint(2, 7))

        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {"order": order, "target": target, "turn": getattr(player, "turn", 0), "score": scores.get(order, 0)}

def enemy_ai_pray_and_buff(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_prayer_chance", 0.16))
    for army in player.enemy_armies:
        cmd = _enemy_commander_data(army.get("commander"))
        prayer_pull = (cmd.get("prayer", 40) - 40) / 300 if cmd else 0
        army["faith"] = min(110, safe_int(army.get("faith", 0), 0) + random.randint(1, 5))
        if army.get("blessing_turns", 0) > 0:
            army["blessing_turns"] = max(0, safe_int(army.get("blessing_turns", 0), 0) - 1)
            continue
        if army["faith"] >= 30 and random.random() < max(0.04, chance + prayer_pull):
            cost = random.randint(18, 30)
            army["faith"] = max(0, army["faith"] - cost)
            army["blessing_turns"] = random.randint(1, 3)
            army["morale"] = min(120, safe_int(army.get("morale", 70), 70) + random.randint(4, 10))
            army["supply"] = min(120, safe_int(army.get("supply", 80), 80) + random.randint(4, 10))
            if random.random() < 0.38:
                print(clr(f"\n  🕯 {army['name']} совершает обет: мораль и снабжение укреплены на {army['blessing_turns']} хода.", C.PURPLE))
                log_event(player, f"Вражеское войско молится и готовится к бою: {army['province']}")

def enemy_ai_spawn_reinforcements(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    cap = _enemy_armies_cap(player)
    if len(player.enemy_armies) >= cap:
        return
    owned_ratio = len(getattr(player, "provinces", [])) / max(1, len(PROVINCES_DATA))
    coalition = getattr(player, "enemy_ai_coalition", {})
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_spawn_chance", 0.25)) + min(0.16, owned_ratio * 0.18)
    if isinstance(coalition, dict) and coalition.get("active"):
        chance += 0.06
    if random.random() < chance:
        count = 1 + int(random.random() < 0.12 + owned_ratio * 0.18)
        spawned = []
        for _ in range(count):
            if len(player.enemy_armies) >= cap:
                break
            army = spawn_enemy_army(player, reason="reinforcement")
            if army:
                spawned.append(army)
        if spawned and random.random() < 0.55:
            names = ", ".join(a["unit_name"] for a in spawned[:3])
            print(clr(f"\n  ⚔ Враги стягивают подкрепления: {names}.", C.RED))
            log_event(player, f"Враги выставили подкрепления: {len(spawned)} отряд(а)")

def enemy_ai_coalition_tick(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    owned_ratio = len(getattr(player, "provinces", [])) / max(1, len(PROVINCES_DATA))
    threshold = float(_enemy_ai_setting_player(player, "enemy_ai_coalition_threshold", 0.36))
    coalition = player.enemy_ai_coalition
    if coalition.get("active"):
        coalition["turns"] = max(0, safe_int(coalition.get("turns", 0), 0) - 1)
        if coalition["turns"] <= 0:
            coalition["active"] = False
            coalition["members"] = []
            log_event(player, "Антиримская коалиция распалась")
        return
    if owned_ratio >= threshold and random.random() < 0.08 + min(0.12, owned_ratio * 0.12):
        members = random.sample(["Карфаген", "Галлы", "Германцы", "Эллинистические цари", "Восточные сатрапы"], k=random.randint(2, 4))
        coalition.update({"active": True, "turns": random.randint(8, 14), "members": members})
        print(clr(f"\n  🌍 АНТИРИМСКАЯ КОАЛИЦИЯ: {' + '.join(members)} согласовали действия против Рима.", C.BOLD + C.RED))
        log_event(player, f"Создана антиримская коалиция: {', '.join(members)}")
        for _ in range(random.randint(1, 2)):
            spawn_enemy_army(player, reason="coalition")

def enemy_ai_mobilization(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    owned_ratio = len(getattr(player, "provinces", [])) / max(1, len(PROVINCES_DATA))
    interval = safe_int(_enemy_ai_setting_player(player, "enemy_ai_great_campaign_interval", 28), 28, 3, 1000)
    if player.turn - safe_int(getattr(player, "enemy_ai_last_great_campaign", 0), 0) >= interval:
        player.enemy_ai_last_great_campaign = player.turn
        spawned = []
        for _ in range(random.randint(2, 4)):
            army = spawn_enemy_army(player, reason="great_campaign")
            if army:
                army["blessing_turns"] = max(army.get("blessing_turns", 0), 1)
                spawned.append(army)
        print(clr(f"\n  🔥 ВЕЛИКИЙ ПОХОД ВРАГОВ! {len(spawned)} армии собираются против Рима.", C.BOLD + C.RED))
        log_event(player, f"Великий поход врагов: {len(spawned)} новых армий")
    threshold = float(_enemy_ai_setting_player(player, "enemy_ai_mobilization_threshold", 0.70))
    if owned_ratio >= threshold and random.random() < 0.14:
        spawned = []
        for _ in range(random.randint(2, 4)):
            army = spawn_enemy_army(player, reason="mobilization")
            if army:
                spawned.append(army)
        if spawned:
            print(clr(f"\n  ☠ Всеобщая мобилизация врагов: {len(spawned)} новых отрядов ценой их экономики.", C.BOLD + C.RED))
            log_event(player, f"Всеобщая мобилизация врагов: {len(spawned)} отрядов")

def enemy_ai_raid_event(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_raid_chance", 0.16))
    raiders = [a for a in player.enemy_armies if a.get("order") == "raid" and safe_int(a.get("cooldown", 0), 0) <= 0]
    if not raiders or random.random() >= chance:
        return
    army = max(raiders, key=enemy_army_battle_power)
    target_name = army.get("target")
    target = next((p for p in getattr(player, "provinces", []) if p.get("name") == target_name), None)
    if not target:
        return
    power = enemy_army_battle_power(army)
    defense = 25 + safe_int(target.get("garrison", 0), 0) * 10 + safe_int(target.get("romanization", 0), 0) // 6
    patrol_bonus = 0
    if safe_int(getattr(player, "enemy_ai_counter_raid_network", 0), 0) > 0:
        patrol_bonus += 22
    if safe_int(getattr(player, "enemy_ai_patrols", {}).get(target_name, 0), 0) > 0:
        patrol_bonus += 28
    if safe_int(getattr(player, "enemy_ai_traps", {}).get(target_name, 0), 0) > 0:
        trap_damage = random.randint(10, 22)
        army["strength"] = max(6, safe_int(army.get("strength", 25), 25) - trap_damage)
        army["morale"] = max(8, safe_int(army.get("morale", 70), 70) - random.randint(10, 20))
        army["cooldown"] = 2
        player.enemy_ai_traps.pop(target_name, None)
        player.glory += 12
        print(clr(f"\n  🕳 ЛОВУШКА В {target_name}: ложное отступление заманило рейдеров под удар. Сила врага -{trap_damage}, слава +12.", C.BOLD + C.GREEN))
        log_event(player, f"Ловушка сорвала вражеский рейд в {target_name}")
        return
    defense += patrol_bonus
    print(clr(f"\n  🐺 ВРАЖЕСКИЙ РЕЙД: {army['unit_name']} грабят окрестности {target_name}.", C.BOLD + C.RED))
    if patrol_bonus:
        print(clr(f"  Контрмеры Рима: оборона рейда +{patrol_bonus}.", C.CYAN))
    if power + random.randint(1, 30) > defense:
        gold_loss = random.randint(20, 70)
        grain_loss = random.randint(20, 90)
        player.gold = max(0, player.gold - gold_loss)
        player.grain = max(0, player.grain - grain_loss)
        target["unrest"] = min(10, safe_int(target.get("unrest", 0), 0) + random.randint(1, 3))
        army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + 5)
        army["cooldown"] = 2
        print(clr(f"  ✗ Рейд успешен: золото -{gold_loss}, зерно -{grain_loss}, волнения растут.", C.RED))
        log_event(player, f"Вражеский рейд в {target_name}: потеряны золото и зерно")
    else:
        army["strength"] = max(8, safe_int(army.get("strength", 25), 25) - random.randint(5, 13))
        army["morale"] = max(10, safe_int(army.get("morale", 70), 70) - random.randint(5, 12))
        player.glory += 8
        print(clr(f"  ✓ Местный гарнизон рассеял налётчиков. Слава +8.", C.GREEN))
        _remember_failed_ai_target(player, target_name)
        log_event(player, f"Гарнизон отбил вражеский рейд в {target_name}")


# ─── v2.23.2: реальная оккупация городов врагом ─────────────────────────────


def _legacy_enemy_ai_register_city_capture_core_v2232(player: "Player", province_name: str, city_name: str | None, *, source: str = "осада") -> bool:
    """
    Фикс v2.23.2: успешная осада/реванш теперь меняет карту.
    Возвращает True, если после потери городов отпала вся провинция.
    """
    if not province_name or province_name == "Latium":
        return False
    target = next((p for p in getattr(player, "provinces", []) if p.get("name") == province_name), None)
    if not target:
        return False

    _enemy_ai_forget_roman_city(player, province_name, city_name)
    lost = safe_list(player.enemy_ai_lost_cities.get(province_name, []))
    if city_name and city_name not in lost:
        lost.append(city_name)
    player.enemy_ai_lost_cities[province_name] = lost[-15:]

    total = max(1, _enemy_ai_total_cities(province_name))
    held = len(safe_list(player.city_campaigns.get(province_name, [])))
    lost_count = len(player.enemy_ai_lost_cities.get(province_name, []))
    unrest = safe_int(target.get("unrest", 0), 0)
    garrison = safe_int(target.get("garrison", 0), 0)

    # Провинция отпадает не по редкому 8–10% броску, а когда враг реально откусил
    # существенную часть городов или когда местная смута уже разрушила управление.
    collapse_score = lost_count * 16 + unrest * 6 - garrison * 12
    should_collapse = held <= max(1, total // 2) or lost_count >= max(4, total // 3) or collapse_score >= 110
    if should_collapse:
        try:
            player.provinces.remove(target)
        except ValueError:
            pass
        player.governors.pop(province_name, None)
        player.city_campaigns.pop(province_name, None)
        player.enemy_ai_lost_cities.pop(province_name, None)
        player.unrest = min(100, safe_int(getattr(player, "unrest", 0), 0) + 8)
        print(clr(f"  ☠ {province_name} отпала: враг закрепился в городах и выбил римскую администрацию.", C.BOLD + C.RED))
        log_event(player, f"Провинция {province_name} потеряна после {source}")
        return True

    print(clr(f"  ⚠ Карта изменилась: {city_name} больше не считается удержанным Римом ({held}/{total} городов под контролем).", C.GOLD))
    log_event(player, f"Враг удерживает {city_name} в {province_name}; римский контроль ослаб")
    return False


def enemy_ai_execute_operational_orders(player: "Player"):
    """Исполнительный слой: приказы штаба теперь чаще превращаются в осады/давление на карте."""
    ensure_enemy_grand_ai_state(player)
    active = {s.get("province") for s in getattr(player, "enemy_ai_sieges", []) if isinstance(s, dict)}
    siege_armies = [a for a in player.enemy_armies
                    if a.get("order") == "siege" and a.get("target")
                    and a.get("target") not in active
                    and safe_int(a.get("cooldown", 0), 0) <= 0
                    and safe_int(a.get("strength", 0), 0) >= 18]
    # Не все сразу: иначе будет каша сообщений. Но хотя бы 1–2 реальные осады за ход при наличии приказов.
    limit = 2 if is_madness_mode(player) or len(getattr(player, "provinces", [])) >= 5 else 1
    for army in sorted(siege_armies, key=enemy_army_battle_power, reverse=True)[:limit]:
        enemy_ai_start_siege(player, army.get("target"), army)
        army["cooldown"] = max(safe_int(army.get("cooldown", 0), 0), 1)

def enemy_ai_start_siege(player: "Player", province_name: str | None = None, army: dict | None = None):
    ensure_enemy_grand_ai_state(player)
    owned = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
    if not owned:
        return
    if province_name is None:
        target = max(owned, key=lambda p: safe_int(p.get("unrest", 0), 0) * 2 + safe_int(p.get("wealth", 0), 0) + random.randint(0, 5))
        province_name = target.get("name")
    owned_names = {p.get("name") for p in owned}
    if province_name not in owned_names:
        return
    if any(s.get("province") == province_name for s in player.enemy_ai_sieges):
        return
    if army is None:
        candidates = [a for a in player.enemy_armies if a.get("order") == "siege" and a.get("target") == province_name]
        army = max(candidates, key=enemy_army_battle_power, default=None)
    if army is None:
        army = spawn_enemy_army(player, province_name, reason="recapture")
    if not army:
        return
    ensure_city_campaigns(player)
    held_cities = safe_list(player.city_campaigns.get(province_name, []))
    city_defs = CITY_ROSTERS.get(province_name, [])
    if held_cities:
        city = random.choice(held_cities)
    else:
        city = random.choice(city_defs)[0] if city_defs else province_name
    siege = {
        "province": province_name,
        "city": city,
        "army_id": army.get("id"),
        "progress": 0,
        "turns": 0,
        "power": enemy_army_battle_power(army),
    }
    print(clr(f"\n  🏗 Враг начинает осаду: {army['unit_name']} окружает {city} ({province_name}).", C.BOLD + C.RED))
    print(clr("  Сенат требует решения: бросить ауксилию на деблокаду или затерпеть потери казны.", C.GRAY))
    resolved = enemy_ai_auxiliary_siege_response(player, siege, army, target_province=province_name)
    if resolved:
        return
    player.enemy_ai_sieges.append(siege)
    print(clr("  Осада продолжается: у Рима есть время усилить гарнизон или подавить смуту до штурма.", C.GRAY))
    log_event(player, f"Враг начал осаду {city} в провинции {province_name}")

def enemy_ai_siege_tick(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    siege_armies = [a for a in player.enemy_armies if a.get("order") == "siege" and safe_int(a.get("cooldown", 0), 0) <= 0]
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_siege_chance", 0.14))
    chance += min(0.35, len(siege_armies) * 0.08)
    chance += min(0.15, safe_int(getattr(player, "enemy_ai_pressure", 0), 0) / 500)
    if siege_armies and random.random() < chance:
        army = max(siege_armies, key=enemy_army_battle_power)
        enemy_ai_start_siege(player, army.get("target"), army)
    if not player.enemy_ai_sieges:
        return
    remaining = []
    for siege in player.enemy_ai_sieges:
        province_name = siege.get("province")
        target = next((p for p in getattr(player, "provinces", []) if p.get("name") == province_name), None)
        if not target:
            continue
        army = next((a for a in player.enemy_armies if a.get("id") == siege.get("army_id")), None)
        power = enemy_army_battle_power(army) if army else safe_int(siege.get("power", 30), 30)
        garrison = safe_int(target.get("garrison", 0), 0)
        romanization = safe_int(target.get("romanization", 0), 0)
        defense = 28 + garrison * 9 + romanization // 7 + player.morale // 7
        fort_turns = safe_int(getattr(player, "enemy_ai_fortifications", {}).get(province_name, 0), 0)
        if fort_turns > 0:
            defense += 34
        if safe_int(getattr(player, "enemy_ai_traps", {}).get(province_name, 0), 0) > 0 and army:
            trap_damage = random.randint(8, 18)
            army["strength"] = max(6, safe_int(army.get("strength", 25), 25) - trap_damage)
            army["morale"] = max(8, safe_int(army.get("morale", 70), 70) - random.randint(8, 16))
            player.enemy_ai_traps.pop(province_name, None)
            player.glory += 10
            print(clr(f"\n  🕳 Вылазка из {province_name}: ловушка бьёт по осадному лагерю. Сила врага -{trap_damage}, слава +10.", C.GREEN))
        siege["turns"] = safe_int(siege.get("turns", 0), 0) + 1
        progress_gain = max(8, power // 4 + safe_int(target.get("unrest", 0), 0) * 2 - garrison * 2)
        if fort_turns > 0:
            progress_gain = max(2, progress_gain - 8)
        siege["progress"] = safe_int(siege.get("progress", 0), 0) + progress_gain
        print(clr(f"\n  🏰 Осада {siege.get('city', province_name)}: ход {siege['turns']}, давление {siege['progress']} / оборона {defense}.", C.GOLD))
        if fort_turns > 0:
            print(clr(f"  Укрепления действуют ещё {fort_turns} ход.: оборона выше, давление растёт медленнее.", C.CYAN))
        if siege["turns"] < 2 and siege["progress"] < defense:
            remaining.append(siege)
            continue
        attack = siege["progress"] + random.randint(10, 45)
        if attack > defense:
            target["unrest"] = min(10, safe_int(target.get("unrest", 0), 0) + random.randint(2, 4))
            player.unrest = min(100, player.unrest + random.randint(3, 8))
            collapsed = enemy_ai_register_city_capture(player, province_name, siege.get("city"), source="осады")
            if not collapsed:
                print(clr(f"  ✗ {siege.get('city')} потерян: враг закрепился в городе, провинция в смуте.", C.RED))
                log_event(player, f"Враг взял и удерживает город {siege.get('city')} после осады")
            if army:
                army["cooldown"] = 2
                army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + 7)
        else:
            player.glory += 14
            target["unrest"] = max(0, safe_int(target.get("unrest", 0), 0) - 1)
            if army:
                army["strength"] = max(8, safe_int(army.get("strength", 25), 25) - random.randint(7, 18))
                army["morale"] = max(10, safe_int(army.get("morale", 70), 70) - random.randint(8, 16))
            print(clr(f"  ✓ Осада {siege.get('city')} сорвана. Слава +14.", C.GREEN))
            _remember_failed_ai_target(player, province_name)
            log_event(player, f"Осада {siege.get('city')} сорвана")
    player.enemy_ai_sieges = remaining[-12:]

def _build_joint_enemy(armies: list[dict]) -> dict:
    armies = sorted(armies, key=enemy_army_battle_power, reverse=True)
    powers = [enemy_army_battle_power(a) for a in armies]
    if not powers:
        total_power = 20
    else:
        total_power = powers[0] + int(sum(powers[1:]) * 0.42)  # не 1:1, а поддержка союзников
    avg_morale = sum(safe_int(a.get("morale", 70), 70) for a in armies) // max(1, len(armies))
    blessed = sum(1 for a in armies if safe_int(a.get("blessing_turns", 0), 0) > 0)
    commanders = [a.get("commander") for a in armies if a.get("commander")]
    commander_bonus = min(8, len(commanders) * 3)
    names = ", ".join(a.get("unit_name", a.get("name", "отряд")) for a in armies[:4])
    battle_mod = min(12, blessed * 3 + max(0, avg_morale - 70) // 12 + commander_bonus)
    return {
        "name": f"Союзная армия ({names})",
        "strength": max(10, min(145, total_power)),
        "army_ids": [a.get("id") for a in armies],
        "battle_mod": battle_mod,
        "counter_mod": min(14, 4 + len(armies) * 2 + blessed * 2 + commander_bonus // 2),
        "joint_attack": True,
        "unit_summary": names,
        "commanders": commanders,
    }

def enemy_ai_joint_attack(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    if len(player.enemy_armies) < 2 or not getattr(player, "legions", []):
        return
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_joint_attack_chance", 0.18))
    chance += min(0.12, len(player.enemy_armies) * 0.010)
    if player.morale < 45:
        chance += 0.07
    coalition = getattr(player, "enemy_ai_coalition", {})
    if isinstance(coalition, dict) and coalition.get("active"):
        chance += 0.04
    if random.random() >= chance:
        return
    target = _choose_legion_target(player)
    if not target:
        return
    available = [a for a in player.enemy_armies if a.get("order") in {"strike", "ambush", "recon"} and safe_int(a.get("cooldown", 0), 0) <= 0 and safe_int(a.get("strength", 0), 0) >= 18]
    if len(available) < 2:
        return
    max_count = min(4, len(available))
    # осторожный ИИ атакует только если имеет хотя бы разумный шанс
    armies = sorted(available, key=enemy_army_battle_power, reverse=True)[:random.randint(2, max_count)]
    enemy = _build_joint_enemy(armies)
    legion_estimate = safe_int(target.strength, 50) + safe_int(target.morale, 70) // 3 + safe_int(getattr(target, "quality", 1), 1) * 8
    if enemy["strength"] < legion_estimate * 0.55 and random.random() < 0.65:
        for a in armies:
            a["order"] = "regroup"
        return
    print(clr(f"\n  ⚔ ВРАЖЕСКАЯ КООРДИНАЦИЯ: {len(armies)} армии наваливаются на {target.name}!", C.BOLD + C.RED))
    print(clr(f"  Состав: {enemy['unit_summary']}", C.GRAY))
    if enemy.get("commanders"):
        print(clr(f"  Полководцы: {', '.join(enemy['commanders'])}", C.PURPLE))
    trap_province = None
    traps = getattr(player, "enemy_ai_traps", {})
    for a in armies:
        if safe_int(traps.get(a.get("target"), 0), 0) > 0:
            trap_province = a.get("target")
            break
    if trap_province:
        enemy["strength"] = max(10, safe_int(enemy.get("strength", 40), 40) - 18)
        enemy["battle_mod"] = max(0, safe_int(enemy.get("battle_mod", 0), 0) - 5)
        player.enemy_ai_traps.pop(trap_province, None)
        print(clr(f"  🕳 Римская ловушка у {trap_province}: координация врага нарушена, сила и модификаторы снижены.", C.GREEN))
    log_event(player, f"Совместная атака {len(armies)} вражеских армий на {target.name}")
    won = resolve_battle(player, target, enemy, is_civil_war=False)
    if won:
        _remember_failed_ai_target(player, target.name)
        enemy_ai_apply_army_losses(player, enemy, victory=True)
    else:
        enemy_ai_pursuit_counterattack(player, target, enemy)
        enemy_ai_apply_army_losses(player, enemy, victory=False)

def enemy_ai_apply_army_losses(player: "Player", enemy: dict, victory: bool):
    ids = set(enemy.get("army_ids", []))
    if not ids:
        return
    survivors = []
    for army in player.enemy_armies:
        if army.get("id") not in ids:
            survivors.append(army)
            continue
        if victory:
            # При победе Рима командир может погибнуть/быть пленён.
            cmd_name = army.get("commander")
            if cmd_name and random.random() < 0.45:
                print(clr(f"  ☠ Вражеский полководец {cmd_name} выведен из войны.", C.BOLD + C.GOLD))
                player.enemy_ai_commander_graveyard.append(cmd_name)
                army["commander"] = None
                log_event(player, f"Полководец врага {cmd_name} выведен из войны")
            if random.random() < 0.50:
                continue
            army["strength"] = max(8, safe_int(army.get("strength", 20), 20) - random.randint(10, 22))
            army["morale"] = max(10, safe_int(army.get("morale", 70), 70) - random.randint(14, 28))
            army["order"] = "regroup"
            army["cooldown"] = 2
        else:
            army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + random.randint(5, 12))
            army["morale"] = min(120, safe_int(army.get("morale", 70), 70) + random.randint(3, 9))
            army["strength"] = max(8, safe_int(army.get("strength", 20), 20) - random.randint(2, 7))
            army["cooldown"] = 1
        survivors.append(army)
    player.enemy_armies = survivors

def enemy_ai_pursuit_counterattack(player: "Player", legion: "Legion", enemy: dict):
    if legion not in getattr(player, "legions", []):
        return
    counter_mod = min(14, safe_int(enemy.get("counter_mod", 5), 5))
    severity = random.randint(3, 9) + counter_mod
    legion.strength = max(5, legion.strength - severity)
    legion.morale = max(5, legion.morale - random.randint(5, 12))
    player.gold = max(0, player.gold - random.randint(5, 28))
    player.morale = max(0, player.morale - random.randint(2, 7))
    print(clr(f"\n  ☠ Враг развивает успех и преследует {legion.name}: сила легиона -{severity}.", C.BOLD + C.RED))
    if legion.strength <= 8 and random.random() < 0.25:
        print(clr(f"  Знамёна {legion.name} едва спасены из окружения.", C.RED))
    log_event(player, f"Вражеская контратака против {legion.name}")

def enemy_ai_recapture_city_event(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    recapture_chance = float(_enemy_ai_setting_player(player, "enemy_ai_city_recapture_chance", 0.12)) + min(0.22, safe_int(getattr(player, "enemy_ai_pressure", 0), 0) / 450)
    if random.random() >= recapture_chance:
        return
    provinces = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
    if not provinces:
        return
    target = max(provinces, key=lambda p: p.get("unrest", 0) + random.randint(0, 4))
    province_name = target.get("name")
    # v2.14: реванш теперь чаще стартует как осада на несколько ходов.
    if random.random() < 0.70:
        enemy_ai_start_siege(player, province_name)
        return
    ensure_city_campaigns(player)
    held_cities = safe_list(player.city_campaigns.get(province_name, []))
    city_defs = CITY_ROSTERS.get(province_name, [])
    if held_cities:
        city = random.choice(held_cities)
    else:
        city = random.choice(city_defs)[0] if city_defs else province_name
    army = spawn_enemy_army(player, province_name, reason="recapture")
    if army:
        army["blessing_turns"] = max(army.get("blessing_turns", 0), 1)
    garrison = safe_int(target.get("garrison", 0), 0)
    romanization = safe_int(target.get("romanization", 0), 0)
    defense = 28 + garrison * 9 + romanization // 7 + player.morale // 7
    attack = (enemy_army_battle_power(army) if army else 35) + target.get("unrest", 0) * 5 + random.randint(10, 42)
    print(clr(f"\n  🏙 ВРАЖЕСКИЙ РЕВАНШ: {army['unit_name'] if army else 'вражеский отряд'} пытается отбить {city} ({province_name})!", C.BOLD + C.RED))
    print(clr(f"  Оборона Рима: {defense}  Натиск врага: {attack}", C.GRAY))
    if attack > defense:
        target["unrest"] = min(10, safe_int(target.get("unrest", 0), 0) + random.randint(1, 3))
        player.unrest = min(100, player.unrest + random.randint(3, 7))
        collapsed = enemy_ai_register_city_capture(player, province_name, city, source="реванша")
        if not collapsed:
            print(clr(f"  ✗ {city} отбит врагом: город потерян на карте, в провинции растёт смута.", C.RED))
            log_event(player, f"Враг отбил и удерживает город {city} в провинции {province_name}")
    else:
        target["unrest"] = max(0, safe_int(target.get("unrest", 0), 0) - 1)
        player.glory += 12
        print(clr(f"  ✓ Гарнизон удержал {city}. Слава +12.", C.GREEN))
        log_event(player, f"Гарнизон удержал {city} от вражеского реванша")

# ─── КАМПАНИИ ВТОРЖЕНИЯ v2.19 ────────────────────────────────────────────────
# Раньше вражеские армии действовали поодиночке: каждая сама раз в ход выбирала
# рейд/осаду/удар, а координация (enemy_ai_joint_attack) была разовым шансом
# без предупреждения. Теперь доктрина может провести полноценный многоходовой
# поход: сбор сил (muster) → выдвижение (advancing, видно игроку заранее по
# докладу штаба) → скоординированный удар (strike) — полевой бой или
# массированная осада. Игрок получает окно на контригру: превентивный удар и
# саботаж теперь умеют целенаправленно срывать именно назревающий поход.

def _campaign_armies(player: "Player", campaign: dict) -> list[dict]:
    ids = set(safe_list(campaign.get("army_ids", [])))
    return [a for a in player.enemy_armies if a.get("id") in ids]

def _rich_or_unrest_provinces(player: "Player") -> list[dict]:
    return _rich_or_unrest_provinces_smart(player)

def _campaign_target_strength(player: "Player", camp: dict) -> int:
    """Грубая оценка силы цели, чтобы кампания знала, когда собранных войск уже хватит."""
    if camp.get("target_type") == "legion":
        legion = next((l for l in getattr(player, "legions", []) if l.name == camp.get("target")), None)
        if legion and legion.strength > 0:
            return safe_int(legion.strength, 50) + safe_int(getattr(legion, "morale", 70), 70) // 3 + safe_int(getattr(legion, "quality", 1), 1) * 8
        return 0
    prov = next((p for p in getattr(player, "provinces", []) if p.get("name") == camp.get("target")), None)
    if prov:
        garrison = safe_int(prov.get("garrison", 0), 0)
        romanization = safe_int(prov.get("romanization", 0), 0)
        return 38 + garrison * 12 + romanization // 5
    return 0

def enemy_ai_campaign_start(player: "Player"):
    """Доктрина с достаточным числом простаивающих армий может начать сбор похода."""
    ensure_enemy_grand_ai_state(player)
    campaigns = player.enemy_ai_campaigns
    if len(campaigns) >= (4 if is_madness_mode(player) else 2):
        return
    idle = [a for a in player.enemy_armies
            if not a.get("campaign_id") and a.get("order") in {"recon", "regroup", "raid", "strike"}
            and safe_int(a.get("cooldown", 0), 0) <= 0 and safe_int(a.get("strength", 0), 0) >= 18]
    if len(idle) < 3:
        return
    by_doctrine: dict[str, list[dict]] = {}
    for a in idle:
        by_doctrine.setdefault(a.get("owner", "generic"), []).append(a)
    pool = [(k, v) for k, v in by_doctrine.items() if len(v) >= 2]
    if not pool:
        return
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_campaign_start_chance", 0.16))
    coalition = getattr(player, "enemy_ai_coalition", {})
    if isinstance(coalition, dict) and coalition.get("active"):
        chance += 0.08
    if random.random() >= chance:
        return
    doctrine_key, armies_pool = max(pool, key=lambda kv: sum(enemy_army_battle_power(a) for a in kv[1]))
    doctrine_def = _ai_doctrine_def(doctrine_key)
    muster = sorted(armies_pool, key=enemy_army_battle_power, reverse=True)[:random.randint(2, min(3, len(armies_pool)))]

    # Эллины и восток предпочитают осады; галлы/германцы охотнее ловят легион в поле.
    siege_leaning = doctrine_key in {"hellenic", "eastern"}
    target = None
    target_type = "legion"
    if not siege_leaning or random.random() < 0.4:
        target = _choose_legion_target(player)
        target_type = "legion"
    if target is None:
        provinces = _rich_or_unrest_provinces(player)
        if not provinces:
            return
        target = provinces[0]
        target_type = "province"

    cid = f"CMP-{player.turn}-{random.randint(1000, 9999)}"
    for a in muster:
        a["campaign_id"] = cid
        a["order"] = "muster"
        a["target"] = None
    campaign = {
        "id": cid,
        "doctrine": doctrine_key,
        "phase": "muster",
        "target_type": target_type,
        "target": target.name if target_type == "legion" else target.get("name"),
        "goal": "target_legion" if target_type == "legion" else ("weaken_economy" if safe_int(target.get("wealth", 0), 0) >= 6 else "target_province"),
        "army_ids": [a.get("id") for a in muster],
        "initial_strength": {a.get("id"): safe_int(a.get("strength", 25), 25) for a in muster},
        "setbacks": 0,
        "turns_in_phase": 0,
        "threat": sum(enemy_army_battle_power(a) for a in muster),
        "started_turn": player.turn,
    }
    campaigns.append(campaign)
    print(clr(f"\n  🚩 Разведка доносит: {doctrine_def['label']} стягивает войска для похода на {campaign['target']}.", C.GOLD))
    log_event(player, f"Враг начал сбор кампании против {campaign['target']} ({doctrine_def['label']})")

def _resolve_campaign_strike(player: "Player", camp: dict, armies: list[dict]):
    doctrine_def = _ai_doctrine_def(camp.get("doctrine"))
    if camp.get("target_type") == "legion":
        legion = next((l for l in getattr(player, "legions", []) if l.name == camp.get("target")), None)
        if not legion or legion.strength <= 0:
            for a in armies:
                a["campaign_id"] = None
                a["order"] = "regroup"
            return
        enemy = _build_joint_enemy(armies)
        # Поход приходит собранным и подготовленным — небольшая премия к скоординированному удару.
        enemy["strength"] = min(150, safe_int(enemy.get("strength", 40), 40) + 8)
        enemy["battle_mod"] = min(16, safe_int(enemy.get("battle_mod", 0), 0) + 3)
        enemy["name"] = f"Поход {doctrine_def['label']}: {enemy.get('unit_summary', 'войско')}"
        print(clr(f"\n  ⚔ УДАР КАМПАНИИ: {doctrine_def['label']} обрушивается на {legion.name}!", C.BOLD + C.RED))
        log_event(player, f"Кампания врага ({doctrine_def['label']}) атакует {legion.name}")
        enemy["force_auxiliary_defense"] = True
        enemy["aux_context"] = "кампания"
        won = resolve_battle(player, legion, enemy, is_civil_war=False)
        for a in armies:
            a["campaign_id"] = None
        if won:
            _remember_failed_ai_target(player, legion.name, 2)
            enemy_ai_apply_army_losses(player, enemy, victory=True)
        else:
            enemy_ai_pursuit_counterattack(player, legion, enemy)
            enemy_ai_apply_army_losses(player, enemy, victory=False)
    else:
        province_name = camp.get("target")
        if not any(p.get("name") == province_name for p in getattr(player, "provinces", [])):
            for a in armies:
                a["campaign_id"] = None
                a["order"] = "regroup"
            return
        lead_army = max(armies, key=enemy_army_battle_power)
        support = [a for a in armies if a is not lead_army]
        for a in armies:
            a["campaign_id"] = None
        for a in support:
            a["order"] = "siege"
            a["target"] = province_name
        print(clr(f"\n  🏗 УДАР КАМПАНИИ: {doctrine_def['label']} начинает массированную осаду {province_name}.", C.BOLD + C.RED))
        log_event(player, f"Кампания врага ({doctrine_def['label']}) начала осаду {province_name}")
        enemy_ai_start_siege(player, province_name, lead_army)
        siege = next((s for s in player.enemy_ai_sieges if s.get("province") == province_name), None)
        if siege and support:
            siege["power"] = min(170, safe_int(siege.get("power", 30), 30) + sum(enemy_army_battle_power(a) for a in support) // 2)
            siege["progress"] = safe_int(siege.get("progress", 0), 0) + max(10, sum(enemy_army_battle_power(a) for a in support) // 4)


def enemy_ai_grand_strategy_tick(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    # Патрули — активная контригра игрока против рейдов. Они живут несколько ходов.
    if isinstance(getattr(player, "enemy_ai_patrols", None), dict):
        player.enemy_ai_patrols = {k: max(0, safe_int(v, 0) - 1) for k, v in player.enemy_ai_patrols.items() if safe_int(v, 0) > 1}
    if isinstance(getattr(player, "enemy_ai_fortifications", None), dict):
        player.enemy_ai_fortifications = {k: max(0, safe_int(v, 0) - 1) for k, v in player.enemy_ai_fortifications.items() if safe_int(v, 0) > 1}
    if isinstance(getattr(player, "enemy_ai_traps", None), dict):
        player.enemy_ai_traps = {k: max(0, safe_int(v, 0) - 1) for k, v in player.enemy_ai_traps.items() if safe_int(v, 0) > 1}
    player.enemy_ai_counter_raid_network = max(0, safe_int(getattr(player, "enemy_ai_counter_raid_network", 0), 0) - 1)
    # Если список пуст, создаём стартовые армии на границах/в непокорённых провинциях.
    if not player.enemy_armies:
        initial_armies = 14 if is_madness_mode(player) else 3
        for _ in range(min(initial_armies, _enemy_armies_cap(player))):
            spawn_enemy_army(player, reason="initial")
    _decay_ai_memory(player)
    enemy_ai_coalition_tick(player)
    enemy_ai_recon_and_orders(player)
    enemy_ai_execute_operational_orders(player)
    enemy_ai_pray_and_buff(player)
    enemy_ai_spawn_reinforcements(player)
    enemy_ai_mobilization(player)
    enemy_ai_campaign_start(player)
    enemy_ai_campaign_tick(player)
    enemy_ai_raid_event(player)
    enemy_ai_siege_tick(player)
    enemy_ai_recapture_city_event(player)
    enemy_ai_joint_attack(player)
    player.enemy_ai_pressure = min(100, len(player.enemy_armies) * 3 + sum(enemy_army_battle_power(a) for a in player.enemy_armies) // 26)


# ─── ВРАЖЕСКИЙ ШТАБ: АКТИВНОЕ ВЗАИМОДЕЙСТВИЕ С ИИ v2.16 ─────────────────────
# Этап 1: игрок получает не только события, но и инструменты ответа.
# Z-экран показывает вражеские армии, осады, коалиции и даёт контрмеры.

def _enemy_order_label(order: str) -> str:
    return {
        "recon": "разведка", "raid": "рейд", "siege": "осада", "ambush": "засада",
        "strike": "удар по легиону", "regroup": "перегруппировка",
        "muster": "сбор в кампанию", "advance": "выдвижение (кампания)",
    }.get(str(order), str(order))

def _enemy_ai_visible_armies(player: "Player") -> list[dict]:
    ensure_enemy_grand_ai_state(player)
    # При низкой разведке показываем только самые опасные армии; после разведки — больше деталей.
    armies = sorted(getattr(player, "enemy_armies", []), key=enemy_army_battle_power, reverse=True)
    recon = safe_int(getattr(player, "enemy_ai_recon_level", 0), 0)
    if recon <= 0 and len(armies) > 8:
        return armies[:8]
    if recon == 1 and len(armies) > 14:
        return armies[:14]
    return armies

def show_enemy_ai_report(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    rui_screen_start()
    rui_header("ВРАЖЕСКИЙ ШТАБ", "☠", C.RED, "разведка, осады, рейды, коалиции и полководцы")
    pressure = safe_int(getattr(player, "enemy_ai_pressure", 0), 0, 0, 100)
    coalition = getattr(player, "enemy_ai_coalition", {})
    coalition_text = "нет"
    if isinstance(coalition, dict) and coalition.get("active"):
        coalition_text = f"{', '.join(coalition.get('members', []))}; осталось {safe_int(coalition.get('turns', 0), 0)} ход."
    rui_info(f"Давление врага: {pressure}/100. Активных армий: {len(getattr(player, 'enemy_armies', []))}. Коалиция: {coalition_text}", C.GOLD)
    if is_madness_mode(player):
        rui_info("Режим Безумие: вероятности ИИ умножены, но боевые числа ограничены.", C.PURPLE)

    campaigns = safe_list(getattr(player, "enemy_ai_campaigns", []))
    if campaigns:
        rows = []
        phase_label = {"muster": "сбор сил", "advancing": "выдвижение", "strike": "удар"}
        for c in campaigns:
            doctrine_def = AI_DOCTRINES.get(c.get("doctrine"), AI_DOCTRINES["generic"])
            rows.append([
                doctrine_def["label"],
                phase_label.get(c.get("phase", "muster"), c.get("phase", "?")),
                str(c.get("target", "?")),
                str(safe_int(c.get("threat", 0), 0)),
                str(len(safe_list(c.get("army_ids", [])))),
            ])
        rui_table("🚩 Назревающие кампании вторжения", ["Доктрина", "Стадия", "Цель", "Угроза", "Армий"], rows, C.RED)
        rui_info("Пока поход на стадии сбора — превентивный удар или саботаж по его армиям срывают его дешевле всего.", C.GRAY)
    else:
        rui_info("Крупных кампаний вторжения не собирается.", C.GREEN)

    sieges = safe_list(getattr(player, "enemy_ai_sieges", []))
    if sieges:
        rows = []
        for s in sieges:
            rows.append([
                str(s.get("city", s.get("province", "?"))),
                str(s.get("province", "?")),
                f"{safe_int(s.get('turns',0),0)} ход.",
                f"{safe_int(s.get('progress',0),0)}/{safe_int(s.get('defense',0),0)}",
            ])
        rui_table("🏰 Активные осады", ["Город", "Провинция", "Длительность", "Давление"], rows, C.RED)
    else:
        rui_info("Активных осад нет.", C.GREEN)

    armies = _enemy_ai_visible_armies(player)
    if armies:
        rows = []
        for i, a in enumerate(armies, 1):
            detail = a.get("commander") or "—"
            if safe_int(getattr(player, "enemy_ai_recon_level", 0), 0) >= 1:
                detail += f"; снабж. {safe_int(a.get('supply',0),0)}, опыт {safe_int(a.get('experience',0),0)}"
            rows.append([
                str(i),
                a.get("province", "?"),
                a.get("unit_name", a.get("name", "отряд")),
                _enemy_order_label(a.get("order", "recon")),
                str(enemy_army_battle_power(a)),
                detail,
            ])
        rui_table("⚔ Замеченные армии", ["№", "Провинция", "Отряд", "Приказ", "Мощь", "Полководец/данные"], rows, C.GOLD)
    else:
        rui_info("Разведка не видит активных армий врага.", C.GRAY)

    patrols = getattr(player, "enemy_ai_patrols", {})
    active_patrols = {k:v for k,v in patrols.items() if safe_int(v,0)>0}
    if active_patrols:
        rui_info("Патрули: " + ", ".join(f"{k} ({v} ход.)" for k, v in active_patrols.items()), C.CYAN)
    forts = {k:v for k,v in getattr(player, "enemy_ai_fortifications", {}).items() if safe_int(v,0)>0}
    if forts:
        rui_info("Укрепления: " + ", ".join(f"{k} ({v} ход.)" for k, v in forts.items()), C.GREEN)
    traps = {k:v for k,v in getattr(player, "enemy_ai_traps", {}).items() if safe_int(v,0)>0}
    if traps:
        rui_info("Ловушки/ложные отступления: " + ", ".join(f"{k} ({v} ход.)" for k, v in traps.items()), C.PURPLE)
    network = safe_int(getattr(player, "enemy_ai_counter_raid_network", 0), 0)
    if network > 0:
        rui_info(f"Сеть контрразведки против рейдов: действует ещё {network} ход.", C.CYAN)


def _choose_player_legion_for_enemy_action(player: "Player"):
    legions = [l for l in getattr(player, "legions", []) if safe_int(getattr(l, "strength", 0), 0) > 0]
    if not legions:
        print(clr("  Нет боеспособных легионов.", C.RED))
        return None
    for i, l in enumerate(legions, 1):
        fatigue = safe_int(getattr(l, "fatigue", 0), 0)
        print(f"  {clr(str(i), C.GOLD)} {l.name}: сила {l.strength}, мораль {l.morale}, качество {l.quality}, усталость {fatigue}")
    idx = read_int(f"\n{clr('  Выберите легион (Q — отмена): ', C.CYAN)}", 1, len(legions), allow_cancel=True)
    if idx is None:
        return None
    return legions[idx-1]

def enemy_ai_buy_recon(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    cost = game_price(player, safe_int(SETTINGS.get("enemy_ai_recon_cost", 35), 35, 0), market=True)
    if player.gold < cost:
        print(clr(f"  Нужно {cost} золота на лазутчиков.", C.RED)); return
    player.gold -= cost
    player.enemy_ai_recon_level = min(3, safe_int(getattr(player, "enemy_ai_recon_level", 0), 0) + 1)
    # Разведка сбивает часть засад и уменьшает давление на текущий ход.
    exposed = 0
    for a in getattr(player, "enemy_armies", []):
        if a.get("order") == "ambush" and random.random() < 0.55:
            a["order"] = "recon"; a["cooldown"] = 1; exposed += 1
    player.enemy_ai_pressure = max(0, safe_int(getattr(player, "enemy_ai_pressure", 0), 0) - 8 - exposed * 2)
    print(clr(f"  Лазутчики вернулись с картами. Уровень разведки: {player.enemy_ai_recon_level}/3. Раскрыто засад: {exposed}.", C.GREEN))
    log_event(player, f"Разведка врага: уровень {player.enemy_ai_recon_level}, раскрыто засад {exposed}")

def enemy_ai_set_patrol(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    provinces = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
    if not provinces:
        print(clr("  Нет провинций для патрулирования.", C.GRAY)); return
    cost_g = game_price(player, safe_int(SETTINGS.get("enemy_ai_patrol_cost_gold", 45), 45, 0), market=True)
    cost_gr = safe_int(SETTINGS.get("enemy_ai_patrol_cost_grain", 40), 40, 0)
    if player.gold < cost_g or player.grain < cost_gr:
        print(clr(f"  Нужно {cost_g} золота и {cost_gr} зерна.", C.RED)); return
    provinces = sorted(provinces, key=lambda p: (safe_int(p.get("unrest",0),0), safe_int(p.get("wealth",0),0)), reverse=True)
    for i, p in enumerate(provinces[:20], 1):
        print(f"  {clr(str(i), C.GOLD)} {p['name']}: волнения {p.get('unrest',0)}, гарнизон {p.get('garrison',0)}, богатство {p.get('wealth',0)}")
    idx = read_int(f"\n{clr('  Где поставить патрули? ', C.CYAN)}", 1, min(20, len(provinces)), allow_cancel=True)
    if idx is None: return
    target = provinces[idx-1]
    player.gold -= cost_g; player.grain -= cost_gr
    duration = safe_int(SETTINGS.get("enemy_ai_patrol_duration", 3), 3, 1, 12)
    player.enemy_ai_patrols[target["name"]] = duration
    target["unrest"] = max(0, safe_int(target.get("unrest",0),0) - 1)
    print(clr(f"  Патрули выставлены в {target['name']} на {duration} ход. Рейды туда будет труднее провести.", C.GREEN))
    log_event(player, f"Патрули против рейдов в {target['name']}")

def enemy_ai_relieve_siege_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    sieges = safe_list(getattr(player, "enemy_ai_sieges", []))
    if not sieges:
        print(clr("  Активных осад нет.", C.GRAY)); return
    for i, s in enumerate(sieges, 1):
        print(f"  {clr(str(i), C.GOLD)} {s.get('city', s.get('province'))} ({s.get('province')}): давление {safe_int(s.get('progress',0),0)}/{safe_int(s.get('defense',0),0)}, ход {safe_int(s.get('turns',0),0)}")
    idx = read_int(f"\n{clr('  Какую осаду снимать? ', C.CYAN)}", 1, len(sieges), allow_cancel=True)
    if idx is None: return
    siege = sieges[idx-1]
    legion = _choose_player_legion_for_enemy_action(player)
    if not legion: return
    army = next((a for a in getattr(player, "enemy_armies", []) if a.get("id") == siege.get("army_id")), None)
    enemy = {
        "name": f"Осаждающая армия у {siege.get('city', siege.get('province'))}",
        "strength": min(125, enemy_army_battle_power(army) + safe_int(siege.get("progress", 0), 0)//3) if army else min(110, safe_int(siege.get("power", 35),35)+20),
        "battle_mod": 5,
        "counter_mod": 8,
        "army_ids": [army.get("id")] if army else [],
    }
    print(clr(f"\n  🛡 {legion.name} идёт на выручку {siege.get('city', siege.get('province'))}!", C.BOLD + C.CYAN))
    won = resolve_battle(player, legion, enemy, is_civil_war=False)
    if won:
        player.enemy_ai_sieges = [s for s in player.enemy_ai_sieges if s is not siege]
        enemy_ai_apply_army_losses(player, enemy, victory=True)
        player.glory += 18
        print(clr("  ✓ Осада снята. Слава +18.", C.GREEN))
        log_event(player, f"Игрок снял осаду {siege.get('city', siege.get('province'))}")
    else:
        siege["progress"] = safe_int(siege.get("progress", 0), 0) + random.randint(8, 18)
        # resolve_battle уже наносит преследование сам (counter_mod задан, joint_attack нет) —
        # повторный вызов здесь удваивал урон легиону при поражении.
        print(clr("  ✗ Попытка снять осаду провалилась; давление осады выросло.", C.RED))
        log_event(player, f"Неудачная попытка снять осаду {siege.get('city', siege.get('province'))}")

def enemy_ai_hunt_commander_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    armies = [a for a in getattr(player, "enemy_armies", []) if a.get("commander")]
    if not armies:
        print(clr("  Разведка не видит вражеских полководцев в поле.", C.GRAY)); return
    armies = sorted(armies, key=enemy_army_battle_power, reverse=True)
    for i, a in enumerate(armies, 1):
        cmd = _enemy_commander_data(a.get("commander")) or {}
        print(f"  {clr(str(i), C.GOLD)} {a.get('commander')} — {cmd.get('trait','полководец')}; {a.get('unit_name')} в {a.get('province')}; мощь {enemy_army_battle_power(a)}")
    idx = read_int(f"\n{clr('  На кого охотиться? ', C.CYAN)}", 1, len(armies), allow_cancel=True)
    if idx is None: return
    army = armies[idx-1]
    legion = _choose_player_legion_for_enemy_action(player)
    if not legion: return
    enemy = {
        "name": f"Ставка {army.get('commander')}: {army.get('unit_name')}",
        "strength": min(130, enemy_army_battle_power(army) + 18),
        "battle_mod": 8,
        "counter_mod": 10,
        "army_ids": [army.get("id")],
        "commanders": [army.get("commander")],
    }
    print(clr(f"\n  ⚔ Охота на полководца: {army.get('commander')}!", C.BOLD + C.RED))
    won = resolve_battle(player, legion, enemy, is_civil_war=False)
    if won:
        cmd_name = army.get("commander")
        if cmd_name:
            if cmd_name in getattr(player, "enemy_ai_commanders_alive", []):
                player.enemy_ai_commanders_alive.remove(cmd_name)
            if cmd_name not in getattr(player, "enemy_ai_commander_graveyard", []):
                player.enemy_ai_commander_graveyard.append(cmd_name)
        enemy_ai_apply_army_losses(player, enemy, victory=True)
        player.glory += 30
        print(clr(f"  ☠ {cmd_name} выведен из войны. Слава +30.", C.BOLD + C.GOLD))
        log_event(player, f"Игрок вывел из войны полководца {cmd_name}")
    else:
        # resolve_battle уже наносит преследование сам (counter_mod задан, joint_attack нет).
        print(clr("  ✗ Полководец ускользнул и нанёс ответный удар.", C.RED))

def enemy_ai_break_coalition_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    coalition = getattr(player, "enemy_ai_coalition", {})
    if not isinstance(coalition, dict) or not coalition.get("active"):
        print(clr("  Активной антиримской коалиции нет.", C.GRAY)); return
    cost = game_price(player, safe_int(SETTINGS.get("enemy_ai_counterintelligence_cost", 90), 90, 0), market=True)
    if player.gold < cost:
        print(clr(f"  Нужно {cost} золота на дипломатов, подкуп и дезинформацию.", C.RED)); return
    player.gold -= cost
    roll = random.randint(1, 100) + player.senate_rep//5 + player.people_rep//8 + safe_int(getattr(player, "enemy_ai_recon_level",0),0)*8
    difficulty_penalty = 18 if is_madness_mode(player) else 0
    if roll - difficulty_penalty >= 62:
        print(clr("  ✓ Коалиция расколота интригами и взаимным недоверием.", C.GREEN))
        coalition["active"] = False; coalition["turns"] = 0; coalition["members"] = []
        player.glory += 10
        log_event(player, "Игрок сорвал антиримскую коалицию")
    else:
        coalition["turns"] = max(1, safe_int(coalition.get("turns", 0), 0) - 3)
        print(clr("  Частичный успех: коалиция ослаблена, но не распалась.", C.GOLD))
        log_event(player, "Игрок ослабил антиримскую коалицию")


def _choose_owned_province_for_enemy_countermeasure(player: "Player", title: str = "Выберите провинцию"):
    provinces = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
    if not provinces:
        print(clr("  Нет провинций для приказа.", C.GRAY)); return None
    provinces = sorted(provinces, key=lambda p: (safe_int(p.get("unrest",0),0), safe_int(p.get("wealth",0),0)), reverse=True)
    for i, p in enumerate(provinces[:24], 1):
        name = p.get("name", "?")
        siege_mark = " 🏰" if any(s.get("province") == name for s in safe_list(getattr(player, "enemy_ai_sieges", []))) else ""
        print(f"  {clr(str(i), C.GOLD)} {name}{siege_mark}: волнения {p.get('unrest',0)}, гарнизон {p.get('garrison',0)}, романизация {p.get('romanization',0)}")
    idx = read_int(f"\n{clr('  ' + title + ': ', C.CYAN)}", 1, min(24, len(provinces)), allow_cancel=True)
    if idx is None:
        return None
    return provinces[idx-1]

def enemy_ai_fortify_province_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    cost_g = game_price(player, safe_int(SETTINGS.get("enemy_ai_fortify_cost_gold", 70), 70, 0), market=True)
    cost_gr = safe_int(SETTINGS.get("enemy_ai_fortify_cost_grain", 60), 60, 0)
    if player.gold < cost_g or player.grain < cost_gr:
        print(clr(f"  Нужно {cost_g} золота и {cost_gr} зерна на укрепления.", C.RED)); return
    target = _choose_owned_province_for_enemy_countermeasure(player, "Где строить срочные укрепления")
    if not target: return
    name = target.get("name")
    player.gold -= cost_g; player.grain -= cost_gr
    duration = safe_int(SETTINGS.get("enemy_ai_fortify_duration", 4), 4, 1, 12)
    player.enemy_ai_fortifications[name] = duration
    target["unrest"] = max(0, safe_int(target.get("unrest",0),0) - 1)
    # Если уже идёт осада, сразу сбиваем часть давления.
    for s in safe_list(getattr(player, "enemy_ai_sieges", [])):
        if s.get("province") == name:
            s["progress"] = max(0, safe_int(s.get("progress",0),0) - random.randint(12, 24))
    print(clr(f"  ✓ {name} укреплена на {duration} ход.: осады там идут медленнее, оборона выше.", C.GREEN))
    log_event(player, f"Срочные укрепления в {name}")

def enemy_ai_set_trap_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    cost_g = game_price(player, safe_int(SETTINGS.get("enemy_ai_trap_cost_gold", 65), 65, 0), market=True)
    cost_gr = safe_int(SETTINGS.get("enemy_ai_trap_cost_grain", 45), 45, 0)
    if player.gold < cost_g or player.grain < cost_gr:
        print(clr(f"  Нужно {cost_g} золота и {cost_gr} зерна на ложное отступление и засаду.", C.RED)); return
    target = _choose_owned_province_for_enemy_countermeasure(player, "Где устроить ловушку")
    if not target: return
    name = target.get("name")
    player.gold -= cost_g; player.grain -= cost_gr
    duration = safe_int(SETTINGS.get("enemy_ai_trap_duration", 3), 3, 1, 10)
    player.enemy_ai_traps[name] = duration
    print(clr(f"  ✓ В {name} подготовлена ловушка на {duration} ход.: может сорвать рейд, осаду или совместную атаку.", C.GREEN))
    log_event(player, f"Подготовлена ловушка против ИИ в {name}")

def enemy_ai_sabotage_army_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    armies = _enemy_ai_visible_armies(player)
    if not armies:
        print(clr("  Разведка не видит целей для саботажа.", C.GRAY)); return
    cost = game_price(player, safe_int(SETTINGS.get("enemy_ai_sabotage_cost", 85), 85, 0), market=True)
    if player.gold < cost:
        print(clr(f"  Нужно {cost} золота на подкуп проводников, яд для фуража и диверсантов.", C.RED)); return
    for i, a in enumerate(armies, 1):
        print(f"  {clr(str(i), C.GOLD)} {a.get('unit_name', a.get('name','отряд'))} в {a.get('province')}: приказ {_enemy_order_label(a.get('order','recon'))}, мощь {enemy_army_battle_power(a)}, снабж. {a.get('supply','?')}")
    idx = read_int(f"\n{clr('  Какую армию саботировать? ', C.CYAN)}", 1, len(armies), allow_cancel=True)
    if idx is None: return
    army = armies[idx-1]
    player.gold -= cost
    recon = safe_int(getattr(player, "enemy_ai_recon_level", 0), 0)
    roll = random.randint(1, 100) + recon * 10 + player.senate_rep // 8
    if is_madness_mode(player):
        roll -= 12
    if roll >= 54:
        strength_loss = random.randint(8, 18) + recon * 2
        supply_loss = random.randint(12, 28)
        army["strength"] = max(6, safe_int(army.get("strength",25),25) - strength_loss)
        army["supply"] = max(0, safe_int(army.get("supply",60),60) - supply_loss)
        army["morale"] = max(8, safe_int(army.get("morale",70),70) - random.randint(5, 14))
        army["cooldown"] = max(1, safe_int(army.get("cooldown",0),0) + 2)
        army["order"] = "regroup"
        print(clr(f"  ✓ Саботаж успешен: сила -{strength_loss}, снабжение -{supply_loss}, армия уходит на перегруппировку.", C.GREEN))
        log_event(player, f"Саботаж против {army.get('unit_name','вражеской армии')}")
        campaign_id = army.get("campaign_id")
        if campaign_id:
            campaign = next((c for c in getattr(player, "enemy_ai_campaigns", []) if c.get("id") == campaign_id), None)
            if campaign:
                army["campaign_id"] = None
                campaign["army_ids"] = [i for i in safe_list(campaign.get("army_ids", [])) if i != army.get("id")]
                if not campaign["army_ids"] and campaign in player.enemy_ai_campaigns:
                    player.enemy_ai_campaigns.remove(campaign)
                    print(clr("  ✓ Без этой армии поход теряет смысл — доктрина отменяет кампанию.", C.GREEN))
                    log_event(player, "Саботаж развалил кампанию врага")
                else:
                    print(clr("  ✓ Диверсия выбила отряд из назревающего похода — угроза кампании ослабла.", C.CYAN))
    else:
        player.enemy_ai_pressure = min(100, safe_int(getattr(player, "enemy_ai_pressure",0),0) + 5)
        print(clr("  ✗ Диверсанты раскрыты. Враг насторожился, давление выросло.", C.RED))
        log_event(player, "Провал саботажа против вражеской армии")

def enemy_ai_counter_raid_network_action(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    cost = game_price(player, safe_int(SETTINGS.get("enemy_ai_counter_raid_network_cost", 120), 120, 0), market=True)
    if player.gold < cost:
        print(clr(f"  Нужно {cost} золота на сеть дозоров, информаторов и караульных постов.", C.RED)); return
    player.gold -= cost
    duration = safe_int(SETTINGS.get("enemy_ai_counter_raid_network_duration", 3), 3, 1, 10)
    player.enemy_ai_counter_raid_network = max(safe_int(getattr(player, "enemy_ai_counter_raid_network",0),0), duration)
    # Рейдеры получают задержку: караваны уходят под охрану, броды перекрыты.
    delayed = 0
    for a in getattr(player, "enemy_armies", []):
        if a.get("order") == "raid" and random.random() < 0.55:
            a["cooldown"] = max(1, safe_int(a.get("cooldown",0),0) + 1)
            delayed += 1
    print(clr(f"  ✓ Сеть контррейдовой обороны действует {duration} ход. Задержано рейдерских отрядов: {delayed}.", C.GREEN))
    log_event(player, f"Создана сеть контррейдовой обороны на {duration} ход.")

def enemy_ai_headquarters_menu(player: "Player"):
    while True:
        show_enemy_ai_report(player)
        rui_menu([
            ("1", "Послать лазутчиков", f"{SETTINGS.get('enemy_ai_recon_cost',35)} золота: больше данных, шанс раскрыть засады", "🕵"),
            ("2", "Патрули против рейдов", "защитить провинцию на несколько ходов", "🐺"),
            ("3", "Снять осаду", "выбрать осаду и отправить легион", "🏰"),
            ("4", "Охота на полководца", "удар по армии с легендарным командиром", "☠"),
            ("5", "Сорвать коалицию", "подкуп, дипломатия и дезинформация", "🌍"),
            ("6", "Саботировать армию", "ослабить конкретный отряд и сорвать приказ", "🗡"),
            ("7", "Укрепить провинцию", "замедлить осады и повысить оборону", "🧱"),
            ("8", "Ложное отступление", "ловушка против рейда, осады или совместной атаки", "🕳"),
            ("9", "Сеть против рейдов", "общая защита экономики на несколько ходов", "🕵"),
            ("Q", "Назад", "вернуться в главное меню", "🚪"),
        ], "Ваш ответ на действия ИИ", C.RED)
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", ["1","2","3","4","5","6","7","8","9","Q"])
        if ch == "Q": return
        if ch == "1": enemy_ai_buy_recon(player)
        elif ch == "2": enemy_ai_set_patrol(player)
        elif ch == "3": enemy_ai_relieve_siege_action(player)
        elif ch == "4": enemy_ai_hunt_commander_action(player)
        elif ch == "5": enemy_ai_break_coalition_action(player)
        elif ch == "6": enemy_ai_sabotage_army_action(player)
        elif ch == "7": enemy_ai_fortify_province_action(player)
        elif ch == "8": enemy_ai_set_trap_action(player)
        elif ch == "9": enemy_ai_counter_raid_network_action(player)
        pause()


# ─── ВРАЖЕСКИЙ ШТАБ: ФИНАЛЬНЫЙ ЭТАП v2.18 ────────────────────────────────────
# Этот слой делает взаимодействие с поведенческим ИИ не только реактивным
# (снять осаду/поймать рейд), но и стратегическим: резерв, контробряды,
# удары по снабжению, превентивное наступление и доклад по доктринам.

# Сохраняем реализации v2.17, чтобы аккуратно обернуть их дополнительной логикой.
_enemy_ai_pray_and_buff_v217 = enemy_ai_pray_and_buff
_enemy_ai_raid_event_v217 = enemy_ai_raid_event
_enemy_ai_siege_tick_v217 = enemy_ai_siege_tick
_enemy_ai_recapture_city_event_v217 = enemy_ai_recapture_city_event
_enemy_ai_joint_attack_v217 = enemy_ai_joint_attack
_enemy_ai_grand_strategy_tick_v217 = enemy_ai_grand_strategy_tick
_show_enemy_ai_report_v217 = show_enemy_ai_report
_enemy_ai_headquarters_menu_v217 = enemy_ai_headquarters_menu


def ensure_enemy_final_stage_state(player: "Player"):
    ensure_enemy_grand_ai_state(player)
    if not isinstance(getattr(player, "enemy_ai_reserves", None), dict):
        player.enemy_ai_reserves = {}
    player.enemy_ai_reserves = {
        str(k): v for k, v in player.enemy_ai_reserves.items()
        if isinstance(v, dict) and safe_int(v.get("turns", 0), 0) > 0
    }
    player.enemy_ai_counter_ritual = safe_int(getattr(player, "enemy_ai_counter_ritual", 0), 0, 0, 12)
    player.enemy_ai_supply_pressure = safe_int(getattr(player, "enemy_ai_supply_pressure", 0), 0, 0, 100)
    player.enemy_ai_last_doctrine_report_turn = safe_int(getattr(player, "enemy_ai_last_doctrine_report_turn", 0), 0, 0)
    ensure_ai_memory_state(player)


def _reserve_power_for_province(player: "Player", province_name: str) -> int:
    ensure_enemy_final_stage_state(player)
    data = getattr(player, "enemy_ai_reserves", {}).get(province_name)
    if not isinstance(data, dict):
        return 0
    return safe_int(data.get("power", 0), 0, 0, 90)


def _consume_reserve_turns(player: "Player"):
    ensure_enemy_final_stage_state(player)
    new_reserves = {}
    for prov, data in getattr(player, "enemy_ai_reserves", {}).items():
        turns = safe_int(data.get("turns", 0), 0) - 1
        if turns > 0:
            data["turns"] = turns
            new_reserves[prov] = data
    player.enemy_ai_reserves = new_reserves
    player.enemy_ai_counter_ritual = max(0, safe_int(getattr(player, "enemy_ai_counter_ritual", 0), 0) - 1)
    player.enemy_ai_supply_pressure = max(0, safe_int(getattr(player, "enemy_ai_supply_pressure", 0), 0) - 5)


def _choose_visible_enemy_army(player: "Player", title: str = "Выберите армию врага"):
    armies = _enemy_ai_visible_armies(player)
    if not armies:
        print(clr("  Разведка не видит подходящих целей.", C.GRAY))
        return None
    for i, a in enumerate(armies, 1):
        cmd = f", командир {a.get('commander')}" if a.get("commander") else ""
        print(f"  {clr(str(i), C.GOLD)} {a.get('unit_name', a.get('name','отряд'))} в {a.get('province')}: приказ {_enemy_order_label(a.get('order','recon'))}, мощь {enemy_army_battle_power(a)}, снабж. {a.get('supply','?')}{cmd}")
    idx = read_int(f"\n{clr('  ' + title + ': ', C.CYAN)}", 1, len(armies), allow_cancel=True)
    if idx is None:
        return None
    return armies[idx-1]


def enemy_ai_assign_reserve_action(player: "Player"):
    ensure_enemy_final_stage_state(player)
    cost_g = game_price(player, safe_int(SETTINGS.get("enemy_ai_reserve_cost_gold", 90), 90, 0), market=True)
    cost_gr = safe_int(SETTINGS.get("enemy_ai_reserve_cost_grain", 70), 70, 0)
    if player.gold < cost_g or player.grain < cost_gr:
        print(clr(f"  Нужно {cost_g} золота и {cost_gr} зерна на стратегический резерв.", C.RED)); return
    target = _choose_owned_province_for_enemy_countermeasure(player, "Куда поставить стратегический резерв")
    if not target: return
    legion = _choose_player_legion_for_enemy_action(player)
    if not legion: return
    name = target.get("name")
    duration = safe_int(SETTINGS.get("enemy_ai_reserve_duration", 4), 4, 1, 12)
    power = min(90, 18 + safe_int(getattr(legion, "strength", 50), 50)//2 + safe_int(getattr(legion, "quality", 1), 1)*5 + safe_int(getattr(legion, "morale", 70), 70)//6)
    player.gold -= cost_g; player.grain -= cost_gr
    player.enemy_ai_reserves[name] = {"turns": duration, "legion": legion.name, "power": power}
    # Резерв не телепортирует легион и не блокирует его обычные действия, но добавляет
    # абстрактное прикрытие: дороги, дозоры, конные разъезды, сигнальные посты.
    print(clr(f"  ✓ {legion.name} назначен стратегическим резервом для {name} на {duration} ход. Сила прикрытия: {power}.", C.GREEN))
    log_event(player, f"Стратегический резерв в {name}: {legion.name}")


def enemy_ai_counter_ritual_action(player: "Player"):
    ensure_enemy_final_stage_state(player)
    if "ensure_religion_state" in globals():
        ensure_religion_state(player)
    cost_g = game_price(player, safe_int(SETTINGS.get("enemy_ai_counter_ritual_cost_gold", 60), 60, 0), market=True)
    cost_f = safe_int(SETTINGS.get("enemy_ai_counter_ritual_cost_faith", 80), 80, 0)
    if player.gold < cost_g or safe_int(getattr(player, "faith", 0), 0) < cost_f:
        print(clr(f"  Нужно {cost_g} золота и {cost_f} веры на контробряд.", C.RED)); return
    player.gold -= cost_g; player.faith -= cost_f
    duration = safe_int(SETTINGS.get("enemy_ai_counter_ritual_duration", 3), 3, 1, 10)
    player.enemy_ai_counter_ritual = max(safe_int(getattr(player, "enemy_ai_counter_ritual", 0), 0), duration)
    broken = 0
    for a in getattr(player, "enemy_armies", []):
        if safe_int(a.get("blessing_turns", 0), 0) > 0 and random.random() < 0.55:
            a["blessing_turns"] = 0
            a["morale"] = max(8, safe_int(a.get("morale", 70), 70) - random.randint(4, 10))
            broken += 1
    print(clr(f"  ✨ Контробряд совершён на {duration} ход.: сорвано активных благословений врага: {broken}.", C.PURPLE))
    log_event(player, f"Контробряд против вражеских молитв: {duration} ход.")


def enemy_ai_supply_strike_action(player: "Player"):
    ensure_enemy_final_stage_state(player)
    cost = game_price(player, safe_int(SETTINGS.get("enemy_ai_supply_strike_cost", 110), 110, 0), market=True)
    if player.gold < cost:
        print(clr(f"  Нужно {cost} золота на удар по снабжению.", C.RED)); return
    army = _choose_visible_enemy_army(player, "По чьему снабжению ударить")
    if not army: return
    player.gold -= cost
    recon = safe_int(getattr(player, "enemy_ai_recon_level", 0), 0)
    roll = random.randint(1, 100) + recon * 9 + player.people_rep // 10
    if is_madness_mode(player):
        roll -= 10
    if roll >= 50:
        loss = random.randint(24, 42) + recon * 4
        army["supply"] = max(0, safe_int(army.get("supply", 80), 80) - loss)
        army["morale"] = max(8, safe_int(army.get("morale", 70), 70) - random.randint(6, 14))
        army["cooldown"] = max(1, safe_int(army.get("cooldown", 0), 0) + 2)
        army["order"] = "regroup"
        player.enemy_ai_supply_pressure = min(100, safe_int(getattr(player, "enemy_ai_supply_pressure", 0), 0) + 18)
        print(clr(f"  ✓ Караваны, фуражиры и мосты врага поражены: снабжение -{loss}, армия уходит на перегруппировку.", C.GREEN))
        log_event(player, f"Удар по снабжению: {army.get('unit_name','вражеская армия')}")
    else:
        army["morale"] = min(120, safe_int(army.get("morale", 70), 70) + 4)
        print(clr("  ✗ Удар сорвался: враг усилил охрану обозов.", C.RED))
        log_event(player, "Провален удар по снабжению врага")


def enemy_ai_preemptive_offensive_action(player: "Player"):
    ensure_enemy_final_stage_state(player)
    cost_g = game_price(player, safe_int(SETTINGS.get("enemy_ai_preemptive_offensive_cost_gold", 120), 120, 0), market=True)
    cost_gr = safe_int(SETTINGS.get("enemy_ai_preemptive_offensive_cost_grain", 80), 80, 0)
    if player.gold < cost_g or player.grain < cost_gr:
        print(clr(f"  Нужно {cost_g} золота и {cost_gr} зерна на превентивное наступление.", C.RED)); return
    army = _choose_visible_enemy_army(player, "Кого атаковать превентивно")
    if not army: return
    legion = _choose_player_legion_for_enemy_action(player)
    if not legion: return
    player.gold -= cost_g; player.grain -= cost_gr
    campaign_id = army.get("campaign_id")
    campaign = next((c for c in getattr(player, "enemy_ai_campaigns", []) if c.get("id") == campaign_id), None) if campaign_id else None
    enemy = {
        "name": f"Превентивный удар по {army.get('unit_name', army.get('name','отряду'))}",
        "strength": min(130, enemy_army_battle_power(army) + 6),
        "battle_mod": max(0, safe_int(army.get("blessing_turns", 0), 0) * 2),
        "counter_mod": 6,
        "army_ids": [army.get("id")],
        "commanders": [army.get("commander")] if army.get("commander") else [],
    }
    if campaign:
        print(clr(f"\n  ⚔ {legion.name} бьёт на упреждение по назревающему походу ({AI_DOCTRINES.get(campaign.get('doctrine'), AI_DOCTRINES['generic'])['label']}).", C.BOLD + C.RED))
    else:
        print(clr(f"\n  ⚔ {legion.name} наносит превентивный удар до того, как враг успеет объединиться.", C.BOLD + C.RED))
    won = resolve_battle(player, legion, enemy, is_civil_war=False)
    if won:
        enemy_ai_apply_army_losses(player, enemy, victory=True)
        player.glory += 20
        player.enemy_ai_pressure = max(0, safe_int(getattr(player, "enemy_ai_pressure", 0), 0) - 10)
        print(clr("  ✓ Превентивное наступление сорвало планы врага. Слава +20, давление снижено.", C.GREEN))
        log_event(player, "Успешное превентивное наступление против ИИ")
        if campaign:
            # Удар по армии на стадии сбора рушит весь ещё не окрепший поход:
            # чем раньше вмешаться, тем дешевле сорвать кампанию целиком.
            break_chance = 0.75 if campaign.get("phase") == "muster" else 0.40
            if random.random() < break_chance:
                remaining_ids = [i for i in safe_list(campaign.get("army_ids", [])) if i != army.get("id")]
                for a in player.enemy_armies:
                    if a.get("id") in remaining_ids:
                        a["campaign_id"] = None
                        a["order"] = "regroup"
                        a["morale"] = max(10, safe_int(a.get("morale", 70), 70) - random.randint(6, 14))
                if campaign in player.enemy_ai_campaigns:
                    player.enemy_ai_campaigns.remove(campaign)
                player.glory += 10
                print(clr("  ✓ Поход врага рассыпался: остальные его силы разбегаются на перегруппировку. Слава +10.", C.BOLD + C.GREEN))
                log_event(player, f"Превентивный удар сорвал кампанию врага ({AI_DOCTRINES.get(campaign.get('doctrine'), AI_DOCTRINES['generic'])['label']})")
    else:
        # resolve_battle уже наносит преследование сам (counter_mod задан, joint_attack нет) —
        # раньше здесь был повторный вызов, и легион терял силу от преследования дважды.
        army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + 8)
        print(clr("  ✗ Враг выдержал удар и получил боевой опыт.", C.RED))
        log_event(player, "Неудачное превентивное наступление против ИИ")


def enemy_ai_doctrine_dossier_action(player: "Player"):
    ensure_enemy_final_stage_state(player)
    rui_screen_start()
    rui_header("ДОКЛАД ПО ДОКТРИНАМ ВРАГА", "📜", C.PURPLE, "кто жив, как воюет и чем контрить")
    alive = [c for c in ENEMY_AI_COMMANDERS if c["name"] in getattr(player, "enemy_ai_commanders_alive", [])]
    dead = safe_list(getattr(player, "enemy_ai_commander_graveyard", []))
    rows = []
    for c in alive:
        rows.append([c["name"], c.get("culture", "?"), c.get("trait", "?"), c.get("style", "?")])
    if rows:
        rui_table("👑 Живые легендарные полководцы", ["Имя", "Культура", "Черта", "Стиль"], rows, C.RED)
    else:
        rui_info("Живых легендарных полководцев разведка не знает.", C.GREEN)
    if dead:
        rui_info("Выведены из войны: " + ", ".join(dead), C.GOLD)
    tips = [
        ["Пунийцы", "рейды, наёмники, снабжение", "патрули + удар по снабжению"],
        ["Галлы", "засады и быстрый натиск", "разведка + ложное отступление"],
        ["Германцы", "затяжное давление и добивание слабых", "резерв + превентивный удар"],
        ["Эллины", "осады и дисциплина", "укрепления + снятие осады"],
        ["Восток", "молитвы, конница, истощение", "контробряд + саботаж"],
        ["Даки/Иберы", "рейды, горные удары, ловушки", "контррейдовая сеть + резерв"],
    ]
    rui_table("🧠 Контригра", ["Доктрина", "Чем опасна", "Чем отвечать"], tips, C.CYAN)
    player.enemy_ai_last_doctrine_report_turn = player.turn
    log_event(player, "Изучен доклад по доктринам врага")


def enemy_ai_pray_and_buff(player: "Player"):
    ensure_enemy_final_stage_state(player)
    before = [(a.get("id"), safe_int(a.get("blessing_turns", 0), 0)) for a in getattr(player, "enemy_armies", [])]
    _enemy_ai_pray_and_buff_v217(player)
    shield = safe_int(getattr(player, "enemy_ai_counter_ritual", 0), 0)
    if shield <= 0:
        return
    suppressed = 0
    before_map = dict(before)
    for a in getattr(player, "enemy_armies", []):
        old = before_map.get(a.get("id"), 0)
        new = safe_int(a.get("blessing_turns", 0), 0)
        if new > old and random.random() < 0.70:
            a["blessing_turns"] = max(0, new - 1)
            a["morale"] = max(8, safe_int(a.get("morale", 70), 70) - random.randint(2, 6))
            suppressed += 1
    if suppressed:
        print(clr(f"  ✨ Контробряды Рима ослабили новых вражеских благословений: {suppressed}.", C.PURPLE))


def enemy_ai_raid_event(player: "Player"):
    ensure_enemy_final_stage_state(player)
    # Стратегические резервы превращаем в дополнительное прикрытие: часть рейдеров
    # получает задержку ещё до старого расчёта события.
    for prov, data in list(getattr(player, "enemy_ai_reserves", {}).items()):
        power = safe_int(data.get("power", 0), 0)
        for a in getattr(player, "enemy_armies", []):
            if a.get("order") == "raid" and a.get("target") == prov and random.randint(1, 100) <= min(75, 25 + power // 2):
                a["cooldown"] = max(1, safe_int(a.get("cooldown", 0), 0) + 1)
                a["supply"] = max(0, safe_int(a.get("supply", 80), 80) - random.randint(5, 14))
                if random.random() < 0.35:
                    print(clr(f"\n  🛡 Резерв {data.get('legion','легиона')} в {prov} задержал рейдеров врага.", C.CYAN))
    _enemy_ai_raid_event_v217(player)


def enemy_ai_siege_tick(player: "Player"):
    ensure_enemy_final_stage_state(player)
    # Резерв заранее бьёт по осадным обозам и замедляет рост давления.
    for s in safe_list(getattr(player, "enemy_ai_sieges", [])):
        prov = s.get("province")
        reserve = getattr(player, "enemy_ai_reserves", {}).get(prov)
        if isinstance(reserve, dict):
            reduction = random.randint(4, 10) + safe_int(reserve.get("power", 0), 0)//12
            s["progress"] = max(0, safe_int(s.get("progress", 0), 0) - reduction)
            if random.random() < 0.30:
                print(clr(f"  🛡 Резерв {reserve.get('legion','легиона')} мешает осаде {prov}: давление -{reduction}.", C.CYAN))
    _enemy_ai_siege_tick_v217(player)


def enemy_ai_recapture_city_event(player: "Player"):
    ensure_enemy_final_stage_state(player)
    # Резервы в неспокойных провинциях снижают шанс мгновенного реванша: часть
    # попыток переводится в обычную разведку/перегруппировку врага.
    guarded = [p for p in getattr(player, "enemy_ai_reserves", {})]
    if guarded and random.random() < 0.22:
        prov = random.choice(guarded)
        player.enemy_ai_pressure = max(0, safe_int(getattr(player, "enemy_ai_pressure", 0), 0) - 3)
        if random.random() < 0.45:
            print(clr(f"\n  🛡 Резерв в {prov} отпугнул отряды, готовившие реванш.", C.CYAN))
        return
    _enemy_ai_recapture_city_event_v217(player)


def enemy_ai_joint_attack(player: "Player"):
    ensure_enemy_final_stage_state(player)
    # Глобальная контрмерная логика: если есть резервы, часть совместных атак
    # сбивается на этапе координации, особенно если разведка уже развита.
    reserves = getattr(player, "enemy_ai_reserves", {})
    if reserves:
        recon = safe_int(getattr(player, "enemy_ai_recon_level", 0), 0)
        block_chance = min(0.55, 0.10 + 0.05 * recon + sum(safe_int(v.get("power", 0), 0) for v in reserves.values()) / 600)
        if random.random() < block_chance:
            disrupted = 0
            for a in sorted(getattr(player, "enemy_armies", []), key=enemy_army_battle_power, reverse=True)[:3]:
                if a.get("order") in {"strike", "ambush", "recon"}:
                    a["cooldown"] = max(1, safe_int(a.get("cooldown", 0), 0) + 1)
                    a["supply"] = max(0, safe_int(a.get("supply", 80), 80) - random.randint(3, 9))
                    disrupted += 1
            if disrupted:
                print(clr(f"\n  🛡 Стратегический резерв сорвал координацию врага: задержано отрядов {disrupted}.", C.CYAN))
                log_event(player, f"Резерв сорвал совместную атаку врага: {disrupted} отрядов")
                return
    _enemy_ai_joint_attack_v217(player)


