# ─── ВРАЖЕСКИЙ ИИ v2.23: WAR COUNCIL / СОВЕТ ВОЖДЕЙ ───────────────────────
# Этот слой не ломает старый ИИ, а надстраивает над ним «штабное мышление»:
#  • ИИ распознаёт слабости игрока: бедность, смуту, усталые легионы, раздувшуюся империю.
#  • Несколько армий умеют фокусировать одну цель, но не залипают навечно в одном приказе.
#  • Приказы получают стратегический контекст: рейды бьют по богатству, осады — по смуте,
#    засады — по привычке игрока ходить фронтальным ударом, удар — по усталым легионам.
#  • Кампании вторжения выбирают цель не случайно, а по профилю слабости Рима.

_enemy_ai_calculate_order_score_v2226 = _calculate_order_score
_enemy_ai_target_for_order_v2226 = _target_for_order
_enemy_ai_recon_and_orders_v2226 = enemy_ai_recon_and_orders
_enemy_ai_campaign_start_v2226 = enemy_ai_campaign_start
_enemy_ai_show_report_v2226 = show_enemy_ai_report


def _ai_effective_unrest_safe(player: "Player") -> int:
    try:
        return safe_int(player.effective_unrest(), 0, 0, 100)
    except Exception:
        return safe_int(getattr(player, "unrest", 0), 0, 0, 100)


def _ai_player_weakness_profile(player: "Player") -> dict:
    """Краткая разведсводка о слабых местах Рима для стратегического ИИ."""
    provinces = list(getattr(player, "provinces", []))
    legions = [l for l in getattr(player, "legions", []) if safe_int(getattr(l, "strength", 0), 0) > 0]
    weak_legions = _weak_legions_sorted(player)
    unrest = _ai_effective_unrest_safe(player)
    gold = safe_int(getattr(player, "gold", 0), 0)
    grain = safe_int(getattr(player, "grain", 0), 0)
    morale = safe_int(getattr(player, "morale", 50), 50)
    ungarrisoned = [p for p in provinces if p.get("name") != "Latium" and safe_int(p.get("garrison", 0), 0) <= 0]
    frontier = [p for p in provinces if p.get("name") != "Latium" and set(p.get("neighbors", [])) - {x.get("name") for x in provinces}]
    avg_garrison = sum(safe_int(p.get("garrison", 0), 0) for p in provinces) / max(1, len(provinces))
    overextension = len(provinces) >= max(7, len(legions) * 3) or (len(frontier) >= 4 and avg_garrison < 1.5)
    richest = max(provinces, key=lambda p: safe_int(p.get("wealth", 0), 0), default=None)
    most_unrest = max(provinces, key=lambda p: safe_int(p.get("unrest", 0), 0), default=None)
    return {
        "gold": gold,
        "grain": grain,
        "morale": morale,
        "unrest": unrest,
        "low_gold": gold < 120,
        "low_grain": grain < 120,
        "rich_rome": gold > 450 or grain > 520,
        "overextended": overextension,
        "thin_garrisons": len(ungarrisoned) >= max(2, len(provinces)//5),
        "many_frontiers": len(frontier) >= 4,
        "weak_legion_count": len([l for l in weak_legions if safe_int(getattr(l, "strength", 50), 50) < 55 or safe_int(getattr(l, "fatigue", 0), 0) >= 45]),
        "richest_province": richest.get("name") if isinstance(richest, dict) else None,
        "most_unrest_province": most_unrest.get("name") if isinstance(most_unrest, dict) else None,
    }


def _ai_update_war_council_memory(player: "Player") -> dict:
    mem = ensure_ai_memory_state(player)
    council = safe_dict(mem.get("war_council"))
    profile = _ai_player_weakness_profile(player)
    turn = safe_int(getattr(player, "turn", 0), 0)
    old_focus = council.get("focus")
    # Фокус живёт несколько ходов, чтобы враг не дёргался каждый год как пьяный авгур.
    if not old_focus or turn >= safe_int(council.get("expires", 0), 0):
        if profile["unrest"] >= 45 or profile["thin_garrisons"]:
            focus = "revolt_pressure"
        elif profile["weak_legion_count"] >= 2 or profile["morale"] < 45:
            focus = "hunt_legions"
        elif profile["rich_rome"]:
            focus = "economic_warfare"
        elif profile["overextended"] or profile["many_frontiers"]:
            focus = "frontier_breakthrough"
        else:
            focus = random.choice(["probing", "economic_warfare", "hunt_legions"])
        council.update({"focus": focus, "expires": turn + random.randint(3, 6), "profile": profile})
    else:
        council["profile"] = profile
    mem["war_council"] = council
    return council


def _ai_focus_label(focus: str) -> str:
    return {
        "revolt_pressure": "разжечь смуту и сорвать управление",
        "hunt_legions": "добить усталые легионы",
        "economic_warfare": "выжечь казну и зерно",
        "frontier_breakthrough": "продавить растянутый фронтир",
        "probing": "разведка боем и поиск слабого места",
    }.get(str(focus), str(focus))


def _ai_order_target_pressure(player: "Player", target: str | None) -> int:
    if not target:
        return 0
    mem = ensure_ai_memory_state(player)
    last = safe_dict(mem.get("last_orders"))
    pressure = 0
    current_turn = safe_int(getattr(player, "turn", 0), 0)
    for entry in last.values():
        if isinstance(entry, dict) and entry.get("target") == target:
            age = max(0, current_turn - safe_int(entry.get("turn", current_turn), current_turn))
            if age <= 2:
                pressure += 1
    return pressure


def _ai_pick_from_candidates(player: "Player", candidates: list, score_func, limit: int = 4):
    """Выбор не строго первого кандидата: ИИ умный, но не всеведущий."""
    if not candidates:
        return None
    ranked = sorted(candidates, key=score_func, reverse=True)[:max(1, limit)]
    total = sum(max(1, score_func(x)) for x in ranked)
    roll = random.randint(1, max(1, total))
    acc = 0
    for item in ranked:
        acc += max(1, score_func(item))
        if roll <= acc:
            return item
    return ranked[0]


def _calculate_order_score(army: dict, player: "Player", situation: dict) -> dict:
    scores = _enemy_ai_calculate_order_score_v2226(army, player, situation)
    council = _ai_update_war_council_memory(player)
    profile = safe_dict(council.get("profile"))
    focus = council.get("focus", "probing")
    power = enemy_army_battle_power(army)
    strength = safe_int(army.get("strength", 25), 25)
    morale = safe_int(army.get("morale", 70), 70)
    supply = safe_int(army.get("supply", 80), 80)

    if focus == "economic_warfare":
        scores["raid"] += 22
        scores["ambush"] += 6
    elif focus == "revolt_pressure":
        scores["siege"] += 20
        scores["raid"] += 14
    elif focus == "hunt_legions":
        scores["strike"] += 22
        scores["ambush"] += 16
    elif focus == "frontier_breakthrough":
        scores["siege"] += 16
        scores["strike"] += 10
    else:
        scores["recon"] += 8

    if profile.get("low_gold") or profile.get("low_grain"):
        scores["raid"] += 12  # добить экономику, когда она уже трещит
    if profile.get("thin_garrisons"):
        scores["siege"] += 14
        scores["raid"] += 8
    if profile.get("overextended"):
        scores["siege"] += 10
        scores["ambush"] += 8
    if profile.get("weak_legion_count", 0) >= 1:
        scores["strike"] += 8 + safe_int(profile.get("weak_legion_count", 0), 0) * 5

    # Сильные и снабжённые армии чаще идут на решительное действие; потрёпанные — не самоубиваются.
    if power >= 55 and strength >= 55 and morale >= 60 and supply >= 55:
        scores["strike"] += 8
        scores["siege"] += 8
        scores["recon"] -= 6
    if supply < 48 or morale < 42:
        scores["regroup"] += 22
        scores["strike"] -= 10
        scores["siege"] -= 8

    return {k: max(-60, int(v)) for k, v in scores.items()}


def _target_for_order(player: "Player", order: str, situation: dict):
    council = _ai_update_war_council_memory(player)
    profile = safe_dict(council.get("profile"))
    focus = council.get("focus", "probing")
    mem = ensure_ai_memory_state(player)
    failed = safe_dict(mem.get("failed_targets"))

    if order in {"raid", "siege"}:
        provinces = situation.get("rich_targets") or []
        if not provinces:
            return None
        def pscore(p):
            name = p.get("name")
            score = _strategic_province_value(player, p)
            score += _ai_order_target_pressure(player, name) * 10  # фокус нескольких армий
            score -= safe_int(failed.get(name, 0), 0) * 8
            if order == "raid":
                score += safe_int(p.get("wealth", 0), 0) * 8
                if profile.get("richest_province") == name:
                    score += 18
            if order == "siege":
                score += safe_int(p.get("unrest", 0), 0) * 10
                score -= safe_int(p.get("garrison", 0), 0) * 6
                if profile.get("most_unrest_province") == name:
                    score += 18
            if focus == "frontier_breakthrough" and set(p.get("neighbors", [])) - {x.get("name") for x in getattr(player, "provinces", [])}:
                score += 12
            return max(1, score)
        picked = _ai_pick_from_candidates(player, provinces, pscore, limit=5)
        return picked.get("name") if isinstance(picked, dict) else None

    if order in {"strike", "ambush"}:
        legions = situation.get("weak_legions") or []
        if not legions:
            return None
        def lscore(l):
            name = getattr(l, "name", "")
            fatigue = safe_int(getattr(l, "fatigue", 0), 0)
            score = (100 - safe_int(getattr(l, "strength", 50), 50)) + fatigue
            score += max(0, 60 - safe_int(getattr(l, "morale", 70), 70))
            score += _ai_order_target_pressure(player, name) * 12
            score -= safe_int(failed.get(name, 0), 0) * 9
            if getattr(l, "elite", False):
                score -= 18
            if getattr(l, "veterans", False):
                score -= 10
            return max(1, score)
        picked = _ai_pick_from_candidates(player, legions, lscore, limit=4)
        return picked.name if picked else None
    return None


def enemy_ai_recon_and_orders(player: "Player"):
    """v2.23: старый скоринг + общий штабный фокус и координация целей."""
    ensure_enemy_grand_ai_state(player)
    ensure_ai_memory_state(player)
    council = _ai_update_war_council_memory(player)
    situation = _situation_snapshot(player)
    target_load: dict[str, int] = {}
    armies = sorted(getattr(player, "enemy_armies", []), key=enemy_army_battle_power, reverse=True)
    for army in armies:
        if safe_int(army.get("cooldown", 0), 0) > 0:
            army["cooldown"] = max(0, safe_int(army.get("cooldown", 0), 0) - 1)
        if army.get("campaign_id"):
            continue

        strength = safe_int(army.get("strength", 25), 25)
        morale = safe_int(army.get("morale", 70), 70)
        supply = safe_int(army.get("supply", 80), 80)
        cmd = _enemy_commander_data(army.get("commander"))
        scores = _calculate_order_score(army, player, situation)

        # Если одна цель уже выбрана сильным отрядом, соседние армии получают премию к совместному давлению,
        # но лимит не даёт всем войскам бессмысленно наваливаться на один объект.
        order = _choose_scored_order(scores, player)
        target = _target_for_order(player, order, situation)
        if target and target_load.get(target, 0) >= (3 if is_madness_mode(player) else 2):
            alt_scores = dict(scores)
            alt_scores[order] = int(alt_scores.get(order, 0) * 0.45)
            order = _choose_scored_order(alt_scores, player)
            target = _target_for_order(player, order, situation)
        if order in {"raid", "siege", "strike", "ambush"} and not target:
            order, target = "recon", None

        if target:
            target_load[target] = target_load.get(target, 0) + 1
        army["order"] = order
        army["target"] = target
        army["ai_focus"] = council.get("focus", "probing")

        if order == "regroup":
            heal = 5 + (cmd.get("bonus", {}).get("retreat", 0) if cmd else 0)
            army["strength"] = min(125, strength + random.randint(3, max(3, heal + 2)))
            army["morale"] = min(120, morale + random.randint(5, 11))
            army["supply"] = min(120, supply + random.randint(10, 20))
        elif order in {"raid", "siege", "ambush", "strike"}:
            army["supply"] = max(0, supply - random.randint(2, 7))
            if order in {"strike", "siege"} and enemy_army_battle_power(army) >= 60:
                army["morale"] = min(120, morale + random.randint(0, 3))

        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {
            "order": order,
            "target": target,
            "turn": getattr(player, "turn", 0),
            "score": scores.get(order, 0),
            "focus": council.get("focus", "probing"),
        }


def enemy_ai_campaign_start(player: "Player"):
    """v2.23: кампании выбирают цель по слабости Рима, а не только по доктрине."""
    ensure_enemy_grand_ai_state(player)
    campaigns = player.enemy_ai_campaigns
    if len(campaigns) >= (4 if is_madness_mode(player) else 2):
        return
    idle = [a for a in player.enemy_armies
            if not a.get("campaign_id") and a.get("order") in {"recon", "regroup", "raid", "strike", "siege"}
            and safe_int(a.get("cooldown", 0), 0) <= 0 and safe_int(a.get("strength", 0), 0) >= 18]
    if len(idle) < 3:
        return
    by_doctrine: dict[str, list[dict]] = {}
    for a in idle:
        by_doctrine.setdefault(a.get("owner", "generic"), []).append(a)
    pool = [(k, v) for k, v in by_doctrine.items() if len(v) >= 2]
    if not pool:
        return
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_campaign_start_chance", 0.16))
    council = _ai_update_war_council_memory(player)
    focus = council.get("focus", "probing")
    if focus in {"hunt_legions", "frontier_breakthrough", "revolt_pressure"}:
        chance += 0.05
    coalition = getattr(player, "enemy_ai_coalition", {})
    if isinstance(coalition, dict) and coalition.get("active"):
        chance += 0.08
    if random.random() >= chance:
        return

    doctrine_key, armies_pool = max(pool, key=lambda kv: sum(enemy_army_battle_power(a) for a in kv[1]))
    doctrine_def = _ai_doctrine_def(doctrine_key)
    muster = sorted(armies_pool, key=enemy_army_battle_power, reverse=True)[:random.randint(2, min(4 if is_madness_mode(player) else 3, len(armies_pool)))]

    target = None
    target_type = "legion"
    if focus == "hunt_legions":
        target = _choose_legion_target(player)
        target_type = "legion"
    elif focus in {"revolt_pressure", "frontier_breakthrough", "economic_warfare"}:
        provinces = _rich_or_unrest_provinces(player)
        target = provinces[0] if provinces else None
        target_type = "province"
    else:
        if doctrine_key in {"hellenic", "eastern"} and random.random() < 0.70:
            provinces = _rich_or_unrest_provinces(player)
            target = provinces[0] if provinces else None
            target_type = "province"
        else:
            target = _choose_legion_target(player)
            target_type = "legion"
    if target is None:
        provinces = _rich_or_unrest_provinces(player)
        if not provinces:
            return
        target = provinces[0]
        target_type = "province"

    cid = f"CMP-{player.turn}-{random.randint(1000, 9999)}"
    for a in muster:
        a["campaign_id"] = cid
        a["order"] = "muster"
        a["target"] = None
    target_name = target.name if target_type == "legion" else target.get("name")
    campaign = {
        "id": cid,
        "doctrine": doctrine_key,
        "phase": "muster",
        "target_type": target_type,
        "target": target_name,
        "goal": "target_legion" if target_type == "legion" else ("weaken_economy" if focus == "economic_warfare" else "target_province"),
        "army_ids": [a.get("id") for a in muster],
        "initial_strength": {a.get("id"): safe_int(a.get("strength", 25), 25) for a in muster},
        "setbacks": 0,
        "turns_in_phase": 0,
        "threat": sum(enemy_army_battle_power(a) for a in muster),
        "started_turn": player.turn,
        "war_council_focus": focus,
    }
    campaigns.append(campaign)
    print(clr(f"\n  🚩 Военный совет врага ({_ai_focus_label(focus)}): {doctrine_def['label']} стягивает войска против {target_name}.", C.GOLD))
    log_event(player, f"Военный совет врага начал кампанию против {target_name}: {_ai_focus_label(focus)}")


def show_enemy_ai_report(player: "Player"):
    ensure_enemy_final_stage_state(player)
    _enemy_ai_show_report_v2226(player)
    council = safe_dict(ensure_ai_memory_state(player).get("war_council"))
    if council:
        focus = council.get("focus", "probing")
        expires = safe_int(council.get("expires", 0), 0)
        left = max(0, expires - safe_int(getattr(player, "turn", 0), 0))
        rui_info(f"Военный совет врага: {_ai_focus_label(focus)}; прогнозируемая линия ещё {left} ход.", C.RED)

