def _ru_aux_description(unit: dict) -> str:
    province = unit.get("province", "провинция")
    ability = unit.get("ability", "провинциальная выучка")
    return f"{unit['name']} из провинции {province}: {unit['type']}. Особенность: {ability}."

def enrich_provincial_auxilia() -> None:
    """Дополняет 88 провинциальных юнитов боевыми полями без ломки старых сейвов."""
    for province, units in UNIQUE_AUXILIARY_UNITS.items():
        for unit in units:
            profile = AUX_TYPE_PROFILE.get(unit.get("type"), AUX_TYPE_PROFILE["пехота"])
            strength = safe_int(unit.get("strength", 20), 20, 1, 120)
            unit.setdefault("category", "провинциальная ауксилия")
            unit.setdefault("attack", profile["attack"] + max(0, strength - 20) // 5)
            unit.setdefault("defense", profile["defense"] + max(0, strength - 20) // 6)
            unit.setdefault("morale", profile["morale"] + max(0, strength - 20) // 4)
            unit.setdefault("upkeep", profile["upkeep"])
            unit.setdefault("ability", profile["ability"])
            unit.setdefault("description", _ru_aux_description(unit))

def provincial_aux_unit_defs() -> list[dict]:
    """Возвращает только провинциальные ауксилии: 44 × 2 = 88."""
    enrich_provincial_auxilia()
    units = []
    for province in (p["name"] for p in PROVINCES_DATA):
        units.extend(UNIQUE_AUXILIARY_UNITS.get(province, []))
    return units

def validate_provincial_auxilia() -> tuple[bool, str]:
    """Проверка целостности формулы 1 провинция × 2 уникальных юнита."""
    province_names = [p["name"] for p in PROVINCES_DATA]
    missing = [name for name in province_names if len(UNIQUE_AUXILIARY_UNITS.get(name, [])) != 2]
    total = sum(len(UNIQUE_AUXILIARY_UNITS.get(name, [])) for name in province_names)
    keys = [u.get("key") for u in provincial_aux_unit_defs()]
    names = [u.get("name", "") for u in provincial_aux_unit_defs()]
    latin_names = [n for n in names if re.search(r"[A-Za-z]", n)]
    if missing:
        return False, "Провинции без двух ауксилий: " + ", ".join(missing)
    if total != 88:
        return False, f"Неверное число провинциальных ауксилий: {total}/88"
    if len(keys) != len(set(keys)):
        return False, "Есть повторяющиеся key у ауксилий"
    if latin_names:
        return False, "Есть нерусские названия: " + ", ".join(latin_names[:5])
    return True, "Провинциальная ауксилия проверена: 44 провинции × 2 юнита = 88."

