def unlock_tech_aux_units(player):
    """Открывает вспомогательные юниты за уже изученные технологии.
    Безопасно вызывать повторно — не дублирует уже открытые ключи."""
    if not hasattr(player, "unlocked_aux_units") or not isinstance(player.unlocked_aux_units, list):
        player.unlocked_aux_units = []
    newly = []
    for tech_key, unit in TECH_UNLOCKED_AUX_UNITS.items():
        if tech_key in player.tech_researched and unit["key"] not in player.unlocked_aux_units:
            player.unlocked_aux_units.append(unit["key"])
            newly.append(unit["name"])
    return newly

