def ensure_expansion_state(player):
    if not hasattr(player, "metals") or not isinstance(player.metals, dict):
        player.metals = {k: 0 for k in METAL_TYPES}
    for k in METAL_TYPES:
        player.metals.setdefault(k, 0)
    if not hasattr(player, "aux_units") or not isinstance(player.aux_units, list):
        player.aux_units = []
    if not hasattr(player, "unlocked_aux_units") or not isinstance(player.unlocked_aux_units, list):
        player.unlocked_aux_units = []
    for prov in getattr(player, "provinces", []):
        for unit in UNIQUE_AUXILIARY_UNITS.get(prov.get("name"), []):
            if unit["key"] not in player.unlocked_aux_units:
                player.unlocked_aux_units.append(unit["key"])
    unlock_tech_aux_units(player)
    if not hasattr(player, "barbarian_tribes") or not isinstance(player.barbarian_tribes, dict):
        player.barbarian_tribes = {
            t["key"]: {"name": t["name"], "chief": t["chief"], "strength": t["strength"],
                       "relation": t["relation"], "gift": t["gift"], "pact": False}
            for t in BARBARIAN_TRIBES_DATA
        }
    for t in BARBARIAN_TRIBES_DATA:
        player.barbarian_tribes.setdefault(t["key"], {"name": t["name"], "chief": t["chief"], "strength": t["strength"], "relation": t["relation"], "gift": t["gift"], "pact": False})

def ensure_all_states(player):
    """Единая точка миграции/нормализации состояния игрока.

    Раньше экраны меню вручную дублировали ensure_* вызовы. Теперь достаточно
    вызвать эту функцию после загрузки и перед главным меню. Вызовы через
    globals() оставляют файл совместимым с частичными сборками/старыми ветками.
    """
    if player is None:
        return None
    for fn_name in (
        "ensure_city_campaigns",
        "ensure_city_siege_damage",
        "ensure_province_details",
        "ensure_expansion_state",
        "ensure_wonders_state",
        "ensure_religion_state",
        "ensure_legion_logistics",
        "ensure_victory_state",
        "ensure_prophecy_state",
        "ensure_v24_state",
        "ensure_external_policy_state",
        "ensure_enemy_grand_ai_state",
        "ensure_ai_memory_state",
        "ensure_enemy_final_stage_state",
    ):
        fn = globals().get(fn_name)
        if callable(fn):
            try:
                fn(player)
            except (AttributeError, KeyError, TypeError, ValueError) as e:
                # ensure_* не должен валить экран меню: конкретный модуль
                # восстановится при своём штатном входе или при загрузке сейва.
                debug_log("State initializer %s failed: %s", fn_name, e, exc_info=True, level=logging.WARNING)
    return player

def invalidate_city_cache(player):
    """Сбрасывает кэш городов. Можно вызывать после захвата/потери провинции."""
    if player is not None and hasattr(player, "_cached_cities"):
        try:
            delattr(player, "_cached_cities")
        except AttributeError as e:
            debug_log("City cache invalidation failed: %s", e, exc_info=True, level=logging.WARNING)

def metal_line(player) -> str:
    ensure_expansion_state(player)
    return "  " + "  ".join(f"{METAL_NAMES[k]}: {player.metals.get(k, 0)}" for k in METAL_TYPES)

def province_metal_income(player) -> dict:
    income = {k: 0 for k in METAL_TYPES}
    for prov in getattr(player, "provinces", []):
        for k, v in PROVINCE_METALS.get(prov.get("name"), {}).items():
            income[k] += v
    return income

def apply_metal_income(player):
    """Legacy-мост: физическую добычу металлов ведёт Opes Imperii."""
    ensure_expansion_state(player)
    if RESOURCE_ECONOMY is not None:
        try:
            RESOURCE_ECONOMY.ensure_state(player, resource_economy_context(player))
        except Exception as exc:
            debug_log("Legacy metal sync failed: %s", exc, exc_info=True, level=logging.DEBUG)
        return {key: 0 for key in METAL_TYPES}
    income = province_metal_income(player)
    for key, value in income.items():
        player.metals[key] += value
    return income

def all_aux_unit_defs():
    enrich_provincial_auxilia()
    units = []
    for arr in UNIQUE_AUXILIARY_UNITS.values():
        units.extend(arr)
    units.extend(BARBARIAN_UNITS)
    units.extend(TECH_UNLOCKED_AUX_UNITS.values())
    return units

def aux_def_by_key(key: str):
    return next((u for u in all_aux_unit_defs() if u["key"] == key), None)

def add_aux_unit(player, unit_def: dict, free: bool = False) -> bool:
    """Нанимает ауксилию как отдельный боевой отряд.

    Сохраняем не только силу, но и максимум силы, опыт и провинцию происхождения:
    это позволяет сражаться купленными ауксилиями как самостоятельными юнитами.
    """
    ensure_expansion_state(player)
    if not unit_def or not isinstance(unit_def, dict):
        return False
    if not free:
        gold_cost = game_price(player, unit_def.get("cost_gold", 0), market=True)
        if player.gold < gold_cost:
            return False
        if player.metals.get("iron", 0) < unit_def.get("cost_iron", 0):
            return False
        if player.metals.get("copper", 0) < unit_def.get("cost_copper", 0):
            return False
        player.gold -= gold_cost
        player.metals["iron"] -= unit_def.get("cost_iron", 0)
        player.metals["copper"] -= unit_def.get("cost_copper", 0)

    strength = safe_int(unit_def.get("strength", 10), 10, 1, 120)
    player.aux_units.append({
        "key": unit_def["key"],
        "name": unit_def["name"],
        "type": unit_def["type"],
        "province": unit_def.get("province", "особый источник"),
        "category": unit_def.get("category", "ауксилия"),
        "strength": strength,
        "max_strength": strength,
        "attack": safe_int(unit_def.get("attack", strength // 3), strength // 3, 0, 50),
        "defense": safe_int(unit_def.get("defense", strength // 4), strength // 4, 0, 50),
        "upkeep": safe_int(unit_def.get("upkeep", 2), 2, 0, 20),
        "ability": unit_def.get("ability", "провинциальная выучка"),
        "description": unit_def.get("description", ""),
        "morale": safe_int(unit_def.get("morale", 70), 70, 0, 100),
        "xp": 0,
        "battles": 0,
        "veterans": False,
    })
    return True

def auxiliary_battle_bonus(player) -> int:
    ensure_expansion_state(player)
    # v1.5.1: раньше сила делилась на 10 — даже большой арсенал ауксилии
    # давал +1..+3 к бою, что было незаметно на фоне бонусов легиона (10-30+).
    # Теперь сила идёт в бонус почти напрямую (делитель 3), потолок поднят
    # пропорционально, чтобы ауксилия ощущалась как реальная подмога в бою.
    return min(60, sum(u.get("strength", 0) for u in player.aux_units) // 3)

def tick_aux_after_battle(player, won: bool):
    ensure_expansion_state(player)
    for u in player.aux_units[:]:
        if won:
            u["morale"] = min(100, u.get("morale", 70) + 4)
            if random.random() < 0.12:
                u["veterans"] = True
        else:
            loss = random.randint(5, 18)
            u["strength"] = max(1, u.get("strength", 1) - loss)
            u["morale"] = max(10, u.get("morale", 70) - 15)
            if u["strength"] <= 5 or random.random() < 0.08:
                print(clr(f"  ⚰ Вспомогательный отряд уничтожен: {u['name']}", C.RED))
                player.aux_units.remove(u)

def maybe_destroy_legion_after_battle(player, legion, won: bool, margin: int) -> bool:
    if legion not in player.legions:
        return False
    chance = 0.0
    if not won:
        chance = SETTINGS.get("legion_destroy_chance_loss", 0.18) + max(0, margin - 10) * 0.025
        if margin >= 15 or legion.strength <= 20:
            chance = max(chance, SETTINGS.get("legion_destroy_chance_catastrophe", 0.45))
        if player.difficulty == "hardcore":
            chance *= 1.35
    elif legion.strength <= 12:
        chance = 0.08
    loss_reduction = max(0.0, min(0.75, tech_effect(player, "army_loss_reduction")))
    if loss_reduction:
        chance *= (1.0 - loss_reduction)
    chance = min(0.90, chance)
    if chance > 0 and random.random() < chance:
        player.legions.remove(legion)
        player.morale = max(0, player.morale - 12)
        print(clr(f"\n  ☠ AQUILA PERDITA! {legion.name} уничтожен в битве. Орёл потерян.", C.BOLD + C.RED))
        print(clr("  Боевой дух всей армии падает на 12.", C.RED))
        log_event(player, f"{legion.name} уничтожен в битве")
        return True
    elif chance > 0:
        print(clr(f"  {legion.name} избежал уничтожения. Риск был {int(chance*100)}%.", C.GRAY))
    return False

def handle_foreign_and_governor_gifts(player):
    ensure_expansion_state(player)
    if random.random() < SETTINGS.get("gift_event_chance", 0.25):
        candidates = [(k, d) for k, d in player.diplomacy.items() if d.get("disposition", 0) >= 55 or d.get("alliance")]
        if candidates:
            k, d = random.choice(candidates)
            gift_gold = random.randint(25, 90) + max(0, d.get("disposition", 0) - 50)
            player.gold += gift_gold
            print(clr(f"\n  🎁 {d['name']} присылает дар Риму: +{gift_gold} золота.", C.GREEN))
            log_event(player, f"Дар от державы {d['name']}: +{gift_gold} золота")
    if player.provinces and random.random() < SETTINGS.get("gift_event_chance", 0.25):
        prov = random.choice(player.provinces)
        gov = player.governors.get(prov.get("name")) if hasattr(player, "governors") else None
        if gov and gov.loyalty >= 60:
            amount = random.randint(15, 60) + prov.get("wealth", 1) * 5
            if gov.trait_key == "corrupt" and random.random() < 0.55:
                stolen = amount
                gov.adjust_loyalty(-5)
                prov["unrest"] = min(10, prov.get("unrest", 0) + 1)
                print(clr(f"\n  🐍 Наместник {gov.name} в {prov['name']} присвоил сборы: -{stolen} потенциального дохода.", C.RED))
                log_event(player, f"Коррупция в {prov['name']}: {gov.name} присвоил сборы")
            else:
                player.gold += amount
                gov.adjust_loyalty(2)
                print(clr(f"\n  🎁 Наместник {gov.name} отправил сборы из {prov['name']}: +{amount} золота.", C.GREEN))
                log_event(player, f"Дар наместника {gov.name}: +{amount} золота")

def maybe_barbarian_gifts(player):
    ensure_expansion_state(player)
    friendly = [t for t in player.barbarian_tribes.values() if t.get("relation", 0) >= 60 or t.get("pact")]
    if friendly and random.random() < SETTINGS.get("barbarian_gift_chance", 0.18):
        t = random.choice(friendly)
        kind = t.get("gift", "gold")
        if kind == "gold":
            amount = random.randint(30, 100)
            player.gold += amount
            msg = f"{t['name']} прислали дар: +{amount} золота"
        elif kind in ("iron", "copper", "silver"):
            amount = random.randint(2, 6)
            player.metals[kind] += amount
            msg = f"{t['name']} прислали металл: +{amount} {METAL_NAMES[kind]}"
        elif kind == "unit":
            unit = random.choice(BARBARIAN_UNITS)
            add_aux_unit(player, unit, free=True)
            msg = f"{t['name']} прислали отряд: {unit['name']}"
        else:
            available = [k for k in TECH_TREE if k not in player.tech_researched and player.tech_available(k)]
            if available:
                tech = random.choice(available)
                player.tech_researched.append(tech)
                msg = f"{t['name']} поделились знанием: {TECH_TREE[tech]['name']}"
            else:
                player.gold += 50
                msg = f"{t['name']} прислали заменяющий дар: +50 золота"
        print(clr(f"\n  🪓 Варварский дар: {msg}.", C.GREEN))
        log_event(player, f"Варварский дар: {msg}")


AUXILIARY_RANKS = [
    {"name": "Новобранцы", "xp": 0, "power": 0, "attack": 0, "defense": 0, "morale": 0},
    {"name": "Закалённые", "xp": 5, "power": 2, "attack": 1, "defense": 1, "morale": 3},
    {"name": "Ветераны", "xp": 12, "power": 5, "attack": 2, "defense": 2, "morale": 6},
    {"name": "Элита", "xp": 25, "power": 9, "attack": 4, "defense": 3, "morale": 10},
    {"name": "Легендарный отряд", "xp": 45, "power": 14, "attack": 6, "defense": 5, "morale": 15},
]

def aux_rank(unit: dict) -> dict:
    """Текущий ранг ауксилии по опыту."""
    xp = safe_int(unit.get("xp", 0), 0, 0, 999)
    rank = AUXILIARY_RANKS[0]
    for candidate in AUXILIARY_RANKS:
        if xp >= candidate["xp"]:
            rank = candidate
        else:
            break
    return rank

def aux_next_rank(unit: dict):
    """Следующий ранг или None, если отряд уже максимального ранга."""
    xp = safe_int(unit.get("xp", 0), 0, 0, 999)
    for candidate in AUXILIARY_RANKS:
        if xp < candidate["xp"]:
            return candidate
    return None

def aux_rank_label(unit: dict) -> str:
    rank = aux_rank(unit)
    nxt = aux_next_rank(unit)
    if nxt:
        return f"{rank['name']} ({unit.get('xp', 0)}/{nxt['xp']} XP)"
    return f"{rank['name']} ({unit.get('xp', 0)} XP)"

def aux_training_cost(unit: dict, player: Player | None = None) -> int:
    """Цена тренировки зависит от ранга, силы, инфляции и общей дороговизны."""
    rank_index = AUXILIARY_RANKS.index(aux_rank(unit))
    max_strength = safe_int(unit.get("max_strength", unit.get("strength", 10)), 10, 1, 120)
    base = 25 + rank_index * 25 + max_strength // 3
    return game_price(player, base, market=player is not None)

def aux_apply_rank_bonuses(unit: dict) -> None:
    """Мягкая миграция: ветеранский флаг синхронизируется с рангами."""
    if safe_int(unit.get("xp", 0), 0) >= 12:
        unit["veterans"] = True

def train_auxiliary_unit(player, unit: dict) -> bool:
    """Тренирует один купленный отряд: XP, мораль и пополнение силы."""
    normalize_aux_army(player)
    if unit not in player.aux_units:
        return False
    cost = aux_training_cost(unit, player)
    if player.gold < cost:
        return False
    player.gold -= cost
    before_rank = aux_rank(unit)["name"]

    unit["xp"] = safe_int(unit.get("xp", 0), 0, 0, 999) + random.randint(2, 4)
    unit["morale"] = min(100, safe_int(unit.get("morale", 70), 70) + random.randint(4, 8))
    max_strength = safe_int(unit.get("max_strength", unit.get("strength", 1)), 1, 1, 120)
    unit["strength"] = min(max_strength, safe_int(unit.get("strength", 1), 1) + random.randint(1, 3))
    aux_apply_rank_bonuses(unit)

    after_rank = aux_rank(unit)["name"]
    if after_rank != before_rank:
        log_event(player, f"Ауксилия повысила ранг: {unit['name']} — {after_rank}")
    else:
        log_event(player, f"Тренировка ауксилии: {unit['name']}")
    return True

def aux_rank_bonus_text(unit: dict) -> str:
    rank = aux_rank(unit)
    return f"+{rank['power']} мощь, +{rank['attack']} атака, +{rank['defense']} защита, +{rank['morale']} мораль"

def aux_unit_power(unit: dict) -> int:
    """Боевая сила отдельного отряда ауксилии."""
    base = safe_int(unit.get("strength", 1), 1, 1, 120)
    morale = safe_int(unit.get("morale", 70), 70, 0, 100)
    xp = safe_int(unit.get("xp", 0), 0, 0, 999)
    attack = safe_int(unit.get("attack", 0), 0, 0, 50)
    defense = safe_int(unit.get("defense", 0), 0, 0, 50)
    aux_apply_rank_bonuses(unit)
    rank = aux_rank(unit)
    veteran_bonus = 6 if unit.get("veterans") else 0
    rank_bonus = rank.get("power", 0) + rank.get("attack", 0) + rank.get("defense", 0)
    return max(1, base + morale // 10 + attack // 2 + defense // 3 + xp // 2 + veteran_bonus + rank_bonus)



def normalize_aux_unit(unit: dict) -> dict:
    """Миграция старых сохранений: старые ауксилии получают недостающие поля."""
    if not isinstance(unit, dict):
        return {}
    key = unit.get("key")
    unit_def = aux_def_by_key(key) if key else None
    base_strength = safe_int(unit.get("strength", (unit_def or {}).get("strength", 10)), 10, 1, 120)
    unit.setdefault("name", (unit_def or {}).get("name", "Вспомогательный отряд"))
    unit.setdefault("type", (unit_def or {}).get("type", "пехота"))
    unit.setdefault("province", (unit_def or {}).get("province", "особый источник"))
    unit.setdefault("category", (unit_def or {}).get("category", "ауксилия"))
    unit.setdefault("ability", (unit_def or {}).get("ability", "провинциальная выучка"))
    unit.setdefault("description", (unit_def or {}).get("description", ""))
    unit["strength"] = base_strength
    unit["max_strength"] = safe_int(unit.get("max_strength", max(base_strength, (unit_def or {}).get("strength", base_strength))), base_strength, base_strength, 120)
    unit["attack"] = safe_int(unit.get("attack", (unit_def or {}).get("attack", base_strength // 3)), base_strength // 3, 0, 50)
    unit["defense"] = safe_int(unit.get("defense", (unit_def or {}).get("defense", base_strength // 4)), base_strength // 4, 0, 50)
    unit["upkeep"] = safe_int(unit.get("upkeep", (unit_def or {}).get("upkeep", 2)), 2, 0, 20)
    unit["morale"] = safe_int(unit.get("morale", (unit_def or {}).get("morale", 70)), 70, 0, 100)
    unit["xp"] = safe_int(unit.get("xp", 0), 0, 0, 999)
    unit["battles"] = safe_int(unit.get("battles", 0), 0, 0, 999)
    unit["veterans"] = bool(unit.get("veterans", False))
    aux_apply_rank_bonuses(unit)
    return unit

def normalize_aux_army(player):
    ensure_expansion_state(player)
    fixed = []
    for unit in player.aux_units:
        normalized = normalize_aux_unit(unit)
        if normalized:
            fixed.append(normalized)
    player.aux_units = fixed

def auxiliary_upkeep(player) -> int:
    normalize_aux_army(player)
    raw = sum(safe_int(u.get("upkeep", 0), 0, 0, 20) for u in player.aux_units)
    return game_price(player, raw, upkeep=True, market=True, minimum=0)

def apply_auxiliary_upkeep(player) -> int:
    """Содержание купленных ауксилий в золоте за ход."""
    cost = auxiliary_upkeep(player)
    if cost:
        player.gold -= cost
        log_event(player, f"Содержание ауксилии: -{cost} золота")
    return cost

def show_provincial_auxilia_codex(player=None):
    """Справочник 88 провинциальных ауксилий на русском языке."""
    ok, msg = validate_provincial_auxilia()
    owned = {p.get("name") for p in getattr(player, "provinces", [])} if player else set()
    while True:
        clear()
        ui_panel("ПРОВИНЦИАЛЬНАЯ АУКСИЛИЯ", "🏹", C.CYAN)
        print(clr(f"  {msg}", C.GREEN if ok else C.RED))
        print(clr("  Формула: 1 провинция × 2 уникальных отряда = 88.", C.GRAY))
        for province in (p["name"] for p in PROVINCES_DATA):
            status = clr("открыта", C.GREEN) if province in owned else clr("закрыта", C.GRAY)
            print(clr(f"\n  {province} [{status}]", C.GOLD))
            for unit in UNIQUE_AUXILIARY_UNITS.get(province, []):
                print(f"    • {unit['name']} — {unit['type']}, сила {unit['strength']}, "
                      f"атака {unit.get('attack', 0)}, защита {unit.get('defense', 0)}, "
                      f"содержание {unit.get('upkeep', 0)}, умение: {unit.get('ability', '-')}")
        print(f"\n  {clr('Q', C.GOLD)} Назад")
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", ["Q"])
        if ch == "Q":
            return

def auxiliary_enemy_options(player) -> list[dict]:
    """Цели для самостоятельных боёв ауксилии."""
    ensure_province_details(player)
    owned = {p.get("name") for p in player.provinces}
    frontier = [p for p in PROVINCES_DATA if p["name"] not in owned and any(n in owned for n in p.get("neighbors", []))]
    options = []
    for prov in frontier[:8]:
        options.append({
            "name": f"Дозор у границы: {prov['name']}",
            "strength": max(12, prov.get("wealth", 3) * 5 + prov.get("unrest", 0) * 2),
            "reward_gold": 20 + prov.get("wealth", 3) * 5,
            "reward_glory": 8 + prov.get("wealth", 3) * 2,
            "kind": "frontier",
        })
    if maximum_province_unrest(player) >= 4:
        hot = max(player.provinces, key=lambda p: p.get("unrest", 0))
        options.append({
            "name": f"Подавление смуты: {hot.get('name', 'провинция')}",
            "strength": 10 + hot.get("unrest", 0) * 6,
            "reward_gold": 10,
            "reward_glory": 10 + hot.get("unrest", 0) * 2,
            "kind": "unrest",
            "province": hot.get("name"),
        })
    options.append({
        "name": "Разбойничий лагерь",
        "strength": random.randint(18, 34),
        "reward_gold": random.randint(25, 75),
        "reward_glory": random.randint(8, 20),
        "kind": "bandits",
    })
    return options

def auxiliary_unit_after_battle(player, unit: dict, won: bool, margin: int):
    unit["battles"] = safe_int(unit.get("battles", 0), 0) + 1
    if won:
        before_rank = aux_rank(unit)["name"]
        unit["xp"] = safe_int(unit.get("xp", 0), 0) + max(1, margin // 4 + 1)
        unit["morale"] = min(100, safe_int(unit.get("morale", 70), 70) + 6)
        if unit["battles"] >= 3 or unit["xp"] >= 8:
            unit["veterans"] = True
        aux_apply_rank_bonuses(unit)
        after_rank = aux_rank(unit)["name"]
        if after_rank != before_rank:
            print(clr(f"  ⭐ Ранг повышен: {unit['name']} теперь {after_rank}.", C.GOLD))
            log_event(player, f"Ауксилия повысила ранг: {unit['name']} — {after_rank}")
        if random.random() < 0.25:
            unit["strength"] = min(safe_int(unit.get("max_strength", unit.get("strength", 1)), 1), safe_int(unit.get("strength", 1), 1) + 1)
    else:
        loss = random.randint(4, 14) + max(0, -margin // 3)
        unit["strength"] = max(0, safe_int(unit.get("strength", 1), 1) - loss)
        unit["morale"] = max(5, safe_int(unit.get("morale", 70), 70) - random.randint(12, 25))
        if unit["strength"] <= 3:
            print(clr(f"  ⚰ Отряд уничтожен: {unit['name']}", C.RED))
            if unit in player.aux_units:
                player.aux_units.remove(unit)

def auxiliary_unit_battle(player):
    normalize_aux_army(player)
    if not player.aux_units:
        print(clr("\n  Нет купленных отрядов ауксилии.", C.RED))
        pause()
        return

    while True:
        clear()
        ui_panel("БОЙ АУКСИЛИИ", "🏹", C.RED)
        print(clr("  Выберите самостоятельный отряд:", C.CYAN))
        for i, unit in enumerate(player.aux_units, 1):
            vet = clr(" [ВЕТ]", C.GOLD) if unit.get("veterans") else ""
            print(f"  {i}. {unit['name']}{vet} — {unit['type']}, ранг: {aux_rank_label(unit)}, сила {unit['strength']}, мораль {unit['morale']}, мощь {aux_unit_power(unit)}")
        print(f"  {clr('Q', C.GOLD)} Назад")
        ch = read_choice(f"\n{clr('  Отряд: ', C.CYAN)}", [str(i) for i in range(1, len(player.aux_units)+1)] + ["Q"])
        if ch == "Q":
            return
        unit = player.aux_units[int(ch)-1]

        enemies = auxiliary_enemy_options(player)
        clear()
        ui_panel(f"{unit['name']} — цель", "🎯", C.RED)
        for i, enemy in enumerate(enemies, 1):
            print(f"  {i}. {enemy['name']} — сила {enemy['strength']}, награда: +{enemy['reward_gold']} зол., +{enemy['reward_glory']} славы")
        print(f"  {clr('Q', C.GOLD)} Назад")
        pick = read_choice(f"\n{clr('  Цель: ', C.CYAN)}", [str(i) for i in range(1, len(enemies)+1)] + ["Q"])
        if pick == "Q":
            continue

        enemy = enemies[int(pick)-1]
        print(f"\n{hr('═')}")
        print(clr(f"  ⚔  {unit['name']} против {enemy['name']}", C.BOLD + C.RED))
        print(hr('═'))

        type_bonus = 0
        if "конница" in unit.get("type", "") and enemy["kind"] in ("bandits", "frontier"):
            type_bonus += 3
        if "стрел" in unit.get("type", "") or "пращ" in unit.get("name", "").lower():
            type_bonus += 2
        if "коп" in unit.get("type", "") and enemy["strength"] >= 30:
            type_bonus += 2

        aux_raw_power = aux_unit_power(unit)
        aux_power = max(8, aux_raw_power // 4 + safe_int(unit.get("morale", 70), 70) // 12 + type_bonus + player.battle_tech_bonus() // 4)
        enemy_power = max(10, safe_int(enemy.get("strength", 20), 20) // 3 + 10)
        if enemy.get("kind") == "unrest":
            enemy_power += 2
        print_table_3d6_forecast("Прогноз ауксилии 3d6", aux_power, enemy_power)
        roman_total, roman_dice, enemy_total, enemy_dice, margin = table_3d6_duel_totals(aux_power, enemy_power)
        print(f"  Бросок ауксилии: {format_3d6(roman_dice)} ×3 + {aux_power} = {clr(str(roman_total), C.GREEN)}")
        print(f"  Бросок врага:    {format_3d6(enemy_dice)} ×3 + {enemy_power} = {clr(str(enemy_total), C.RED)}")

        if roman_total >= enemy_total:
            player.gold += enemy["reward_gold"]
            player.glory += enemy["reward_glory"] + margin
            auxiliary_unit_after_battle(player, unit, True, margin)
            if enemy.get("kind") == "unrest" and enemy.get("province"):
                for p in player.provinces:
                    if p.get("name") == enemy["province"]:
                        p["unrest"] = max(0, p.get("unrest", 0) - 1)
                        break
            add_battlepass_xp(player, 8)
            print(clr(f"\n  ✓ Победа ауксилии! +{enemy['reward_gold']} золота, +{enemy['reward_glory'] + margin} славы.", C.GREEN))
            log_event(player, f"Ауксилия победила: {unit['name']} разгромил {enemy['name']}")
        else:
            margin = roman_total - enemy_total
            auxiliary_unit_after_battle(player, unit, False, margin)
            player.unrest = min(100, player.unrest + 2)
            print(clr("\n  ✗ Поражение ауксилии. Беспорядки в Риме +2.", C.RED))
            log_event(player, f"Ауксилия проиграла бой: {unit.get('name', 'отряд')} против {enemy['name']}")
        pause()
        return

