# для следующего крупного патча, чтобы ядро v1.6 было стабильным.

RELIGION_CHOICES = {
    "judaism": {"icon": "✡", "name": "Иудаизм", "desc": "Завет, Закон, мудрость и устойчивость."},
    "christianity": {"icon": "✝", "name": "Христианство", "desc": "Милосердие, единство и прочность державы."},
    "paganism": {"icon": "🏛", "name": "Язычество", "desc": "Боги Империи, армия, флот и экспансия."},
}

RELIGION_EFFECT_LABELS = dict(GREAT_PERSON_EFFECT_LABELS)
RELIGION_EFFECT_LABELS.update({
    "faith_flat": "вера за ход", "faith_percent": "прирост веры", "population_growth_percent": "рост населения",
    "trade_income_percent": "торговля", "naval_power_percent": "сила флота", "army_morale_percent": "мораль армии",
    "army_loss_reduction": "снижение потерь армии", "diplomacy_bonus": "дипломатия", "event_good_chance": "добрые события",
    "epidemic_resist": "сопротивление эпидемиям", "city_loyalty": "лояльность городов", "religion_institute_discount": "стоимость институтов",
    "religion_institute_power": "сила институтов", "sacred_general_chance_bonus": "шанс священного генерала",
})
RELIGION_INVERTED_DISPLAY_KEYS = set(GREAT_PERSON_INVERTED_DISPLAY_KEYS) | {"army_loss_reduction", "epidemic_resist", "religion_institute_discount"}

def religion_effects_text(effects: dict) -> str:
    parts = []
    for key, value in effects.items():
        label = RELIGION_EFFECT_LABELS.get(key, key)
        inverted = key in RELIGION_INVERTED_DISPLAY_KEYS
        if isinstance(value, float):
            pct = int(round(value * 100))
            sign = "−" if inverted and pct > 0 else "+" if pct > 0 else ""
            parts.append(f"{label}: {sign}{abs(pct) if inverted else pct}%")
        else:
            sign = "−" if inverted and value > 0 else "+" if value > 0 else ""
            parts.append(f"{label}: {sign}{abs(value) if inverted else value}")
    return "; ".join(parts) if parts else "особый эффект"

