def ensure_religion_state(player: "Player"):
    if not hasattr(player, "religion"):
        player.religion = None
    if not hasattr(player, "faith"):
        player.faith = 0
    if not hasattr(player, "religious_institutes") or not isinstance(getattr(player, "religious_institutes"), list):
        player.religious_institutes = []
    if not hasattr(player, "religion_event_log") or not isinstance(getattr(player, "religion_event_log"), list):
        player.religion_event_log = []
    if not hasattr(player, "sacred_generals") or not isinstance(getattr(player, "sacred_generals"), list):
        player.sacred_generals = []
    player.religious_institutes = [iid for iid in player.religious_institutes if iid in RELIGIOUS_INSTITUTES]
    player.sacred_generals = [g for g in player.sacred_generals if player.religion in SACRED_GENERALS and g in SACRED_GENERALS[player.religion]] if player.religion else []


def religion_effect(player: "Player", effect_key: str, default=0):
    ensure_religion_state(player)
    total = default
    power = 1.0
    for iid in player.religious_institutes:
        effects = RELIGIOUS_INSTITUTES.get(iid, {}).get("effects", {})
        if effect_key != "religion_institute_power":
            total += effects.get(effect_key, 0)
        power += effects.get("religion_institute_power", 0)
    for _g in getattr(player, "sacred_generals", []):
        total += SACRED_GENERAL_EFFECTS.get(player.religion, {}).get(effect_key, 0)
    if effect_key in {"gold_percent", "faith_percent", "population_growth_percent", "trade_income_percent", "battle_attack", "battle_defense", "province_unrest_control", "unrest_reduction", "glory_per_turn", "faith_flat"}:
        # Усиление институтов применяется только к религиозным бонусам, но без рекурсивного фанатизма.
        if power > 1.0 and total:
            total *= min(power, 1.5)
            if isinstance(total, float) and effect_key not in {"gold_percent", "faith_percent", "population_growth_percent", "trade_income_percent"}:
                total = int(round(total))
    return total


def choose_religion(player: "Player"):
    ensure_religion_state(player)
    if player.religion:
        print(clr("  Государственная религия уже выбрана и не может быть изменена.", C.RED)); pause(); return
    rui_screen_start(); rui_header("ВЫБОР ГОСУДАРСТВЕННОЙ РЕЛИГИИ", "🕯", C.GOLD)
    if RICH_AVAILABLE:
        rows = []
        for i, (key, info) in enumerate(RELIGION_CHOICES.items(), 1):
            rows.append((str(i), f"[bold gold1]{info['icon']} {info['name']}[/]", info['desc']))
        rui_table("", ["#", "Религия", "Описание"], rows, color=C.GOLD, show_header=False)
    else:
        for i, (key, info) in enumerate(RELIGION_CHOICES.items(), 1):
            print(clr(f"  {i}. {info['icon']} {info['name']}", C.BOLD + C.GOLD))
            ui_wrap(info['desc'], indent="     ", subsequent="     ", color=C.CYAN)
    ch = read_choice(f"\n{clr('  Выбор религии: ', C.CYAN)}", ["1","2","3","Q"])
    if ch == "Q": return
    key = list(RELIGION_CHOICES)[int(ch)-1]
    player.religion = key; player.faith = max(0, int(getattr(player, "faith", 0))) + 80; player.religious_institutes = []; player.religion_event_log = []; player.sacred_generals = []
    info = RELIGION_CHOICES[key]
    if RICH_AVAILABLE:
        body = f"[cyan]{info['desc']}[/]\n\n[green]Получено 80 очков веры. Откройте первый институт в меню религии.[/]"
        console.print(Panel(body, title=f"{info['icon']} ПРИНЯТА РЕЛИГИЯ: {info['name'].upper()}", border_style="magenta", box=box.ROUNDED))
    else:
        ui_panel(f"ПРИНЯТА РЕЛИГИЯ: {info['name'].upper()}", info['icon'], C.PURPLE)
        ui_wrap(info['desc'], indent="  ", subsequent="  ", color=C.CYAN)
        print(clr("  Получено 80 очков веры. Откройте первый институт в меню религии.", C.GREEN))
    log_event(player, f"Государственная религия: {info['name']}")
    add_battlepass_xp(player, 10)
    pause()


def next_religious_institute(player: "Player"):
    ensure_religion_state(player)
    if not player.religion: return None
    owned = set(player.religious_institutes)
    rows = sorted([x for x in RELIGIOUS_INSTITUTES.values() if x["religion"] == player.religion], key=lambda x: x["order"])
    for inst in rows:
        if inst["id"] not in owned:
            return inst
    return None


def show_religious_institute_card(inst: dict):
    info = RELIGION_CHOICES[inst["religion"]]
    if RICH_AVAILABLE:
        body = (
            f"[bold gold1]{inst['order']:02d}/30  {inst['name']}[/]\n\n"
            f"[italic white]❝ {inst['quote']} ❞[/]\n"
            f"[bright_black]— {inst['source']}[/]\n\n"
            f"[green]Эффект: {religion_effects_text(inst.get('effects', {}))}[/]"
        )
        console.print(Panel(body, title=f"{info['icon']} ИНСТИТУТ ОТКРЫТ", border_style="magenta", box=box.ROUNDED))
    else:
        ui_panel(f"ИНСТИТУТ ОТКРЫТ: {inst['name']}", info["icon"], C.PURPLE)
        print(clr(f"  {inst['order']:02d}/30  {inst['name']}", C.BOLD + C.GOLD))
        print()
        ui_wrap(f"❝ {inst['quote']} ❞", indent="  ", subsequent="  ", color=C.WHITE)
        print(clr(f"\n  — {inst['source']}", C.GRAY))
        print()
        ui_wrap(f"Эффект: {religion_effects_text(inst.get('effects', {}))}", indent="  ", subsequent="  ", color=C.GREEN)


def unlock_next_religious_institute(player: "Player"):
    ensure_religion_state(player)
    if not player.religion:
        choose_religion(player); return
    inst = next_religious_institute(player)
    if not inst:
        print(clr("  Все институты этой религии уже открыты.", C.GOLD)); pause(); return
    discount = min(0.60, max(0.0, religion_effect(player, "religion_institute_discount", 0)))
    cost = game_price(player, max(1, int(round(inst["cost"] * (1.0 - discount)))), market=True)
    if player.faith < cost:
        print(clr(f"  Недостаточно веры: нужно {cost}, есть {player.faith}.", C.RED)); pause(); return
    player.faith -= cost; player.religious_institutes.append(inst["id"])
    show_religious_institute_card(inst)
    log_event(player, f"Открыт религиозный институт: {inst['name']}")
    add_battlepass_xp(player, 6)
    pause()


def show_religion_menu(player: "Player"):
    ensure_religion_state(player)
    while True:
        rui_screen_start(); rui_header("РЕЛИГИЯ", "🕯", C.GOLD)
        if not player.religion:
            rui_info("Государственная религия ещё не выбрана.", C.CYAN)
            rui_menu([("1", "Выбрать религию", "один раз за партию", "🕯"), ("Q", "Назад", "", "↩")])
            ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", ["1","Q"])
            if ch == "1": choose_religion(player)
            else: return
            continue
        info = RELIGION_CHOICES[player.religion]
        count = len(player.religious_institutes)
        next_inst = next_religious_institute(player)
        rui_info(f"{info['icon']} {info['name']} — {info['desc']}", C.CYAN)
        rui_info(f"✨ Вера: {player.faith}  •  Институты: {count}/30  •  Священные полководцы: {len(player.sacred_generals)}/10", C.GOLD)
        if next_inst:
            discount = min(0.60, max(0.0, religion_effect(player, "religion_institute_discount", 0)))
            cost = game_price(player, max(1, int(round(next_inst["cost"] * (1.0 - discount)))), market=True)
            rui_info(f"Следующий институт: {next_inst['name']} — {cost} веры")
            rui_info(f"Эффект: {religion_effects_text(next_inst['effects'])}", C.GREEN)
        rui_menu([
            ("1", "Открыть следующий институт", "последовательное древо", "📜"),
            ("2", "Список институтов", "открытые и закрытые", "📚"),
            ("3", "Священные полководцы", "религиозный список", "⚔"),
            ("4", "Лог религиозных событий", "последние чудеса и испытания", "🕯"),
            ("Q", "Назад", "", "↩"),
        ])
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", ["1","2","3","4","Q"])
        if ch == "Q": return
        if ch == "1": unlock_next_religious_institute(player)
        elif ch == "2": show_religious_institutes_list(player)
        elif ch == "3": show_sacred_generals(player)
        elif ch == "4": show_religion_event_log(player)


def show_religious_institutes_list(player: "Player"):
    rui_screen_start(); info = RELIGION_CHOICES[player.religion]; rui_header(f"ИНСТИТУТЫ: {info['name'].upper()}", info["icon"], C.GOLD)
    owned = set(player.religious_institutes)
    items = sorted([x for x in RELIGIOUS_INSTITUTES.values() if x["religion"] == player.religion], key=lambda x: x["order"])
    if RICH_AVAILABLE:
        rows = []
        for inst in items:
            have = inst["id"] in owned
            mark = "✓" if have else "·"
            style = "green" if have else "bright_black"
            rows.append((f"[{style}]{mark}[/]", f"{inst['order']:02d}", f"[{style}]{inst['name']}[/]", religion_effects_text(inst['effects'])))
        rui_table("", ["", "№", "Институт", "Эффект"], rows, color=C.GOLD, show_header=False)
    else:
        for inst in items:
            mark = "✓" if inst["id"] in owned else "·"
            color = C.GREEN if mark == "✓" else C.GRAY
            print(clr(f"  {mark} {inst['order']:02d}. {inst['name']:<28} {religion_effects_text(inst['effects'])}", color))
    pause()


def show_sacred_generals(player: "Player"):
    rui_screen_start(); info = RELIGION_CHOICES[player.religion]; rui_header("СВЯЩЕННЫЕ ПОЛКОВОДЦЫ", info["icon"], C.GOLD)
    owned = set(player.sacred_generals)
    if RICH_AVAILABLE:
        rows = []
        for name in SACRED_GENERALS[player.religion]:
            have = name in owned
            mark = "✓" if have else "·"
            style = "green" if have else "bright_black"
            rows.append((f"[{style}]{mark}[/]", f"[{style}]{name}[/]"))
        rui_table("", ["", "Полководец"], rows, color=C.GOLD, show_header=False)
    else:
        for name in SACRED_GENERALS[player.religion]:
            mark = "✓" if name in owned else "·"
            print(clr(f"  {mark} {name}", C.GREEN if mark == "✓" else C.GRAY))
    rui_info(f"Общий эффект каждого полученного полководца: {religion_effects_text(SACRED_GENERAL_EFFECTS[player.religion])}", C.CYAN)
    pause()


def show_religion_event_log(player: "Player"):
    rui_screen_start(); rui_header("РЕЛИГИОЗНЫЕ СОБЫТИЯ", "🕯", C.GOLD)
    for line in player.religion_event_log[-12:] or ["Событий ещё не было."]:
        rui_info(line, C.CYAN)
    pause()


def apply_religion_event_reward(player: "Player", reward: dict):
    player.gold += int(reward.get("gold", 0)); player.grain = max(0, player.grain + int(reward.get("grain", 0)))
    player.faith += int(reward.get("faith", 0)); player.glory += int(reward.get("glory", 0))
    player.people_rep = max(0, min(100, player.people_rep + int(reward.get("people", 0))))
    player.senate_rep = max(0, min(100, player.senate_rep + int(reward.get("senate", 0))))
    player.morale = max(0, min(100 + int(tech_effect(player,"morale_cap_bonus")), player.morale + int(reward.get("morale", 0))))
    if reward.get("unrest"):
        player.unrest = max(0, min(100, player.unrest + int(reward["unrest"])))
    if reward.get("metals_iron"):
        player.metals["iron"] = player.metals.get("iron", 0) + int(reward["metals_iron"])


def maybe_religion_event(player: "Player"):
    ensure_religion_state(player)
    if not player.religion: return
    chance = SETTINGS.get("religion_event_chance", 0.08) + max(0, religion_effect(player, "event_good_chance", 0))
    if random.random() >= min(0.35, chance): return
    title, quote, reward = random.choice(RELIGIOUS_EVENTS[player.religion])
    apply_religion_event_reward(player, reward)
    line = f"{title}: {quote}"
    player.religion_event_log.append(f"Ход {player.turn}: {line}")
    player.religion_event_log = player.religion_event_log[-20:]
    ui_panel("РЕЛИГИОЗНОЕ СОБЫТИЕ", RELIGION_CHOICES[player.religion]["icon"], C.PURPLE)
    print(clr(f"  {title}", C.BOLD + C.GOLD)); print(clr(f"  ❝ {quote} ❞", C.WHITE)); print(clr("Награда: " + format_reward(reward), C.GREEN))
    log_event(player, f"Религиозное событие: {title}")
    add_battlepass_xp(player, 4)


def maybe_spawn_sacred_general(player: "Player"):
    ensure_religion_state(player)
    if not player.religion: return
    available = [g for g in SACRED_GENERALS[player.religion] if g not in player.sacred_generals]
    if not available: return
    chance = SETTINGS.get("sacred_general_chance", 0.06) + max(0, religion_effect(player, "sacred_general_chance_bonus", 0))
    if random.random() >= min(0.25, chance): return
    name = random.choice(available); player.sacred_generals.append(name)
    ui_panel("СВЯЩЕННЫЙ ПОЛКОВОДЕЦ", RELIGION_CHOICES[player.religion]["icon"], C.GOLD)
    print(clr(f"  {name}", C.BOLD + C.GOLD))
    print(clr(f"  Эффект добавлен навсегда: {religion_effects_text(SACRED_GENERAL_EFFECTS[player.religion])}", C.GREEN))
    log_event(player, f"Священный полководец: {name}")
    add_battlepass_xp(player, 12)


