WONDER_EFFECT_LABELS = {
    "gold_flat": "золото/ход",
    "trade_gold_flat": "торговое золото/ход",
    "gold_percent": "доход золота",
    "grain_flat": "зерно/ход",
    "unrest_reduction": "снижение волнений",
    "battle_attack": "атака армии",
    "battle_defense": "оборона армии",
    "morale_flat": "боевой дух",
    "senate_rep_flat": "репутация Сената сразу",
    "people_rep_flat": "репутация народа сразу",
    "glory_flat": "слава сразу",
    "research_percent": "скорость исследований",
    "upkeep_percent": "содержание войск",
    "faith_flat": "вера/ход",
    "navy_power": "морское могущество",
    "people_rep_flat": "поддержка народа",
    "barbarian_relation": "отношения с племенами сразу",
}

def ensure_wonders_state(player: "Player"):
    if not hasattr(player, "world_wonders_built") or not isinstance(player.world_wonders_built, list):
        player.world_wonders_built = []
    valid = {w["id"] for w in WORLD_WONDERS}
    player.world_wonders_built = [wid for wid in player.world_wonders_built if wid in valid]

def wonder_by_id(wid: str) -> dict | None:
    for wonder in WORLD_WONDERS:
        if wonder["id"] == wid:
            return wonder
    return None

def world_wonder_effect(player: "Player", effect_key: str, default=0):
    total = default
    built = set(getattr(player, "world_wonders_built", []))
    for wid in built:
        wonder = wonder_by_id(wid)
        if wonder:
            total += wonder.get("effects", {}).get(effect_key, 0)
    return total

def wonder_effects_text(effects: dict) -> str:
    parts = []
    for key, value in effects.items():
        label = WONDER_EFFECT_LABELS.get(key, key)
        if isinstance(value, float):
            pct = int(round(value * 100))
            sign = "+" if value > 0 else ""
            parts.append(f"{label}: {sign}{pct}%")
        else:
            sign = "+" if value > 0 else ""
            parts.append(f"{label}: {sign}{value}")
    return "; ".join(parts)

def show_wonder_completion_screen(player: "Player", wonder: dict):
    rui_screen_start()
    rui_header("ЧУДО СВЕТА ПОСТРОЕНО", "🏗", C.GOLD)
    print(clr(WONDER_ASCII.get(wonder.get("art"), WONDER_ASCII["temple"]), C.GOLD))
    if RICH_AVAILABLE:
        body = f"[italic cyan]❝ {wonder.get('quote', '')} ❞[/]\n\n[green]Бафф: {wonder.get('desc', wonder_effects_text(wonder.get('effects', {})))}[/]"
        console.print(Panel(body, title=wonder['name'].upper(), border_style="gold1", box=box.DOUBLE))
    else:
        print(clr(f"\n  {wonder['name'].upper()}", C.BOLD + C.GOLD))
        ui_wrap(wonder.get("quote", ""), indent="  ❝ ", subsequent="    ", color=C.CYAN)
        print(clr(f"\n  Бафф: {wonder.get('desc', wonder_effects_text(wonder.get('effects', {})))}", C.GREEN))
    pause()

def apply_wonder_instant_effects(player: "Player", wonder: dict):
    effects = wonder.get("effects", {})
    player.glory += safe_int(effects.get("glory_flat", 0), 0)
    player.senate_rep = min(100, player.senate_rep + safe_int(effects.get("senate_rep_flat", 0), 0))
    player.people_rep = min(100, player.people_rep + safe_int(effects.get("people_rep_flat", 0), 0))
    player.morale = min(100 + tech_effect(player, "morale_cap_bonus"), player.morale + safe_int(effects.get("morale_flat", 0), 0))
    if effects.get("unrest_reduction", 0):
        player.unrest = max(0, player.unrest - safe_int(effects.get("unrest_reduction", 0), 0))
    if effects.get("barbarian_relation", 0):
        for tribe in getattr(player, "barbarian_tribes", {}).values():
            tribe["relation"] = min(100, safe_int(tribe.get("relation", 50), 50, 0, 100) + safe_int(effects.get("barbarian_relation", 0), 0))


@dataclass(init=False)
class Player:
    name: str
    faction: str
    difficulty: str
    gold: int
    grain: int
    glory: int
    senate_rep: int
    people_rep: int
    unrest: int
    morale: int
    legions: list[Legion]
    provinces: list[dict[str, Any]]
    city_campaigns: dict[str, list[str]]
    city_siege_damage: dict[str, dict[str, int]]
    governors: dict[str, Governor]
    laws_passed: list[str]
    year: int
    turn: int
    consul: str
    dictator: bool
    dictator_turns: int
    event_log: list[str]

    def __init__(self, name, faction, difficulty="normal"):
        self.name        = name
        self.praenomen   = ""
        self.nomen       = ""
        self.cognomen    = ""
        self.gens        = ""
        self.starting_office = ""
        self.office_title = "Полководец"
        self.patron_deity = ""
        self.command_style = ""
        self.campaign_mandate = ""
        self.first_edict = ""
        self.session_register = {}
        self.faction     = faction       # "optimates" или "populares"
        self.difficulty  = difficulty if difficulty in DIFFICULTY_PRESETS else "normal"
        self.gold        = 200
        self.grain       = 150
        self.glory       = 0             # победные очки
        self.senate_rep  = 50            # 0–100: репутация в Сенате
        self.senate_last_chance_used = False  # один политический кризис вместо мгновенной смерти
        self.people_rep  = 50            # 0–100: репутация у народа
        self.unrest      = 0             # 0–100: беспорядки в Риме
        self.morale      = 70            # 0–100: боевого духа армии
        self.legions     : list[Legion] = []
        self.provinces   : list[dict]   = []   # полностью завоёванные провинции
        self.city_campaigns : dict[str, list[str]] = {}   # частично взятые города в незавоёванных провинциях
        self.city_siege_damage : dict[str, dict[str, int]] = {}  # процент повреждения обороны незахваченных городов
        self.governors   : dict[str, Governor] = {}   # наместники по имени провинции
        self.province_revolt_warnings: dict[str, int] = {}  # 1=предупреждение, 2=открытый кризис
        self.armyless_turns = 0  # сколько ходов Республика остаётся без единого легиона
        self.laws_passed : list[str]    = []
        self.year        = 700           # AUC (Anno Urbis Conditae)
        self.turn        = 1
        self.consul      = random.choice(CONSULS)
        self.consul_a    = ""
        self.consul_b    = ""
        self.dictator    = False
        self.dictator_turns = 0
        self.event_log   : list[str] = []   # последние 10 событий, для игрока
        self.annals_state : dict[str, Any] = {}  # Annales Imperii: история, очередь и настройки
        self.economy : dict[str, Any] = {}  # Roma Economica: макроэкономика, бюджет и проводки
        self.conquest_economy : dict[str, Any] = {}  # Bellum Oeconomicum: трофеи, контрибуции и режимы провинций
        self.resource_economy : dict[str, Any] = {}  # Opes Imperii: запасы, автодобыча, инвестиции и сделки

        # ── Техдрево ────────────────────────────────────────────────────────
        self.tech_researched : list[str] = []
        self.research_progress = 0     # накопленное золото в текущей разработке
        self.researching      = None   # ключ технологии, которая в процессе
        self.research_queue   : list[str] = []   # очередь технологий для автоизучения
        self.science_points   = 0      # очки науки: новый ресурс исследований v2.24.9
        self.last_science_income = 0   # сколько науки дали школы и архивы на прошлом ходу
        self.science_patronage_total = 0 # золото, вложенное в меценатство науки

        # ── Дипломатия ──────────────────────────────────────────────────────
        # disposition (0-100): чем выше, тем дружелюбнее держава.
        # alliance: True если заключён союзный договор (защита/нейтралитет).
        # tribute: ежегодная дань, которую ОНИ платят НАМ (>0) или мы им (<0).
        self.diplomacy = {
            p["key"]: {
                "name": p["name"], "disposition": p["disposition"],
                "strength": p["strength"], "alliance": False,
                "tribute": 0, "hostage_exchanged": False, "married": False, "trade_pact": False,
            }
            for p in DIPLOMATIC_POWERS
        }
        # Consilium Externum: длительные миссии, доктрина и автоматические кризисы.
        # Полная нормализация выполняется ensure_external_policy_state().
        self.foreign_policy = {
            "doctrine": "balance",
            "doctrine_selected": False,
            "capital": 3,
            "capital_max": 7,
            "active_missions": [],
            "dispatches": [],
            "crises": [],
            "last_tick_turn": 0,
            "last_crisis_turn": 0,
            "doctrine_changed_turn": 0,
            "global_tension": 0,
        }

        # ── Гражданская война (AI-фракции) ─────────────────────────────────
        self.ai_factions = [ImprovedAIFaction(n) for n in AI_FACTION_NAMES]
        for f in self.ai_factions:
            f.difficulty = self.difficulty
        self.civil_war_active = False
        # Сколько ходов подряд Империя живёт без крупных кризисов.
        # Используется в новых жёстких условиях победы.
        self.victory_peace_streak = 0

        # ── Баттл-пасс и наборы роста ────────────────────────────────────────
        # Прогресс баттл-пасса живёт внутри текущей партии (не хранится между
        # новыми играми отдельно от save — это часть состояния этого Player).
        self.battlepass_xp      = 0
        self.battlepass_level   = 0
        self.battlepass_claimed : list[int] = []   # уровни, награды которых уже выданы
        self.unique_units       : list[str] = []   # ключи полученных уникальных юнитов
        self.packs_unlocked     : list[str] = []   # какие наборы уже были получены (anti-farm)

        # ── Расширение: металлы, ауксилия и варварские племена ─────────────
        self.metals = {k: 0 for k in METAL_TYPES}
        self.aux_units = []
        self.unlocked_aux_units = []
        seed_starting_auxilia(self)
        self.barbarian_tribes = {
            t["key"]: {"name": t["name"], "chief": t["chief"], "strength": t["strength"],
                       "relation": t["relation"], "gift": t["gift"], "pact": False}
            for t in BARBARIAN_TRIBES_DATA
        }

        # ── Великие люди v1.5 ──────────────────────────────────────────────
        self.great_people_obtained : list[str] = []
        self.great_people_completed_categories : list[str] = []
        self.great_people_final_bonus_awarded = False
        self.great_person_dry_streak = 0   # ходов подряд без появления (pity-счётчик)

        # ── Религия v1.6 ───────────────────────────────────────────────────
        self.religion = None
        self.faith = 0
        self.religious_institutes = []
        self.religion_event_log = []
        self.sacred_generals = []

        # ── Маленькие исторические события v2.6.2 ─────────────────────────
        # Каждые 5 ходов игра задаёт короткий Y/N-вопрос по истории Рима.
        # Уже заданные вопросы хранятся в сохранении, чтобы пул не повторялся.
        self.history_quiz_answered : list[int] = []

        # ── Чудеса света v2.7 ──────────────────────────────────────────────
        # Список id построенных чудес. Каждое чудо покупается один раз.
        self.world_wonders_built : list[str] = []

        # ── Пророчества v2.9 ───────────────────────────────────────────────
        # Каждые 10 ходов появляется пророчество: omen (знамение) даёт
        # благоприятный или тяжёлый эффект, зависящий от состояния державы.
        self.prophecy_history : list[dict] = []
        self.last_prophecy_turn = 0

        # ── Вражеский стратегический ИИ v2.13 ───────────────────────────
        self.enemy_armies : list[dict] = []
        self.enemy_ai_last_great_campaign = 0
        self.enemy_ai_lost_cities : dict[str, list[str]] = {}
        self.enemy_ai_pressure = 0
        self.enemy_ai_patrols : dict[str, int] = {}
        self.enemy_ai_fortifications : dict[str, int] = {}
        self.enemy_ai_traps : dict[str, int] = {}
        self.enemy_ai_counter_raid_network = 0
        self.enemy_ai_recon_level = 0

    def diff(self) -> dict:
        """Множители текущей сложности. Читается заново каждый раз —
        старые сохранения не замораживают баланс на момент сохранения."""
        return DIFFICULTY_PRESETS.get(self.difficulty, DIFFICULTY_PRESETS["normal"])

    # ── Доход ────────────────────────────────────────────────────────────────
    def _legacy_passive_income_report(self) -> dict:
        """Подробная ведомость пассивной экономики.

        Золото считается по источникам: базовая казна, провинции, города,
        частично захваченные города, наместники, романизация, гарнизоны,
        законы, технологии, дипломатия, торговые пакты, варварские договоры,
        таможенная стража и добыча драгоценных металлов.
        """
        ensure_province_details(self)
        ensure_expansion_state(self)

        rows: list[dict] = []

        def add(key: str, label: str, amount: int | float, note: str = ""):
            value = int(round(amount))
            if value:
                rows.append({"key": key, "label": label, "amount": value, "note": note})

        # 1) Стабильная казна Рима.
        add("base", "Базовая казна", SETTINGS["base_gold_income"], "фиксированный доход столицы")

        # 2) Провинциальное богатство и городская налоговая база.
        province_wealth = sum(int(p.get("wealth", 0)) for p in self.provinces)
        add("province_wealth", "Богатство провинций", province_wealth, f"{len(self.provinces)} пров.")

        city_tax = 0
        city_roles = {}
        for p in self.provinces:
            for city in p.get("cities", []):
                city_tax += _city_gold_value(city, owned=True)
                t = city.get("type", "прочее")
                city_roles[t] = city_roles.get(t, 0) + 1
        add("city_tax", "Городские налоги", city_tax, f"{sum(city_roles.values())} городов: население + тип города")

        # 3) Оккупационная дань с частично захваченных городов в ещё не присоединённых провинциях.
        occupied_tax = 0
        occupied_count = 0
        for province_name, captured_names in getattr(self, "city_campaigns", {}).items():
            base = province_by_name(province_name)
            if not base:
                continue
            captured_set = set(captured_names or [])
            owned_names = {p.get("name") for p in self.provinces}
            if province_name in owned_names:
                continue
            for city in base.get("cities", []):
                if city.get("name") in captured_set:
                    occupied_tax += _city_gold_value(city, owned=False)
                    occupied_count += 1
        add("occupied_cities", "Оккупационная дань", occupied_tax, f"{occupied_count} частично удерживаемых городов")

        # 4) Наместники, романизация, гарнизоны.
        gov_gold = 0
        gov_grain = 0
        romanization_gold = 0
        garrison_gold = 0
        for p in self.provinces:
            gov = self.governors.get(p.get("name"))
            if gov:
                gov_gold += gov.trait().get("gold_bonus", 0)
                gov_grain += gov.trait().get("grain_bonus", 0)
            romanization_gold += (int(p.get("romanization", 0)) // 20) * 2
            garrison_gold += max(0, int(p.get("garrison", 0)) - 2) * 2
        add("governors", "Наместники", gov_gold, "администраторы/купцы/коррупционеры меняют сборы")
        add("romanization", "Романизация", romanization_gold, "интегрированные провинции платят больше")
        add("garrisons", "Охрана торговых путей", garrison_gold, "гарнизоны выше минимума защищают сборы")

        # 5) Законы.
        if "lex_provincialis" in self.laws_passed:
            add("law_lex_provincialis", "Lex Provincialis", len(self.provinces), "+1 золота за провинцию")

        # 6) Технологии.
        add("tech_flat", "Технологии: фиксированный доход", tech_effect(self, "gold_flat"), "форумы, гавани, казна, подавление пиратов")
        add("tech_per_province", "Технологии: доход за провинции", len(self.provinces) * tech_effect(self, "gold_per_province"), "дороги, пошлины, гражданство, почта")

        # 7) Уникальные постоянные источники.
        if "customs_guard" in self.unique_units:
            add("customs_guard", "Таможенная стража", 20, "разовый апгрейд торгового форума")

        # 8) Дипломатия: дань, торговые договоры, союзы и клиентелы.
        fp_state = getattr(self, "foreign_policy", {}) if isinstance(getattr(self, "foreign_policy", {}), dict) else {}
        doctrine_key = str(fp_state.get("doctrine", "balance"))
        doctrine = globals().get("FOREIGN_POLICY_DOCTRINES", {}).get(doctrine_key, {})
        tribute_mult = float(doctrine.get("tribute_income_mult", 1.0))
        trade_mult = float(doctrine.get("trade_income_mult", 1.0))

        tribute_base = sum(int(d.get("tribute", 0)) for d in self.diplomacy.values() if int(d.get("tribute", 0)) > 0)
        tribute_gold = int(round(tribute_base * tribute_mult))
        tribute_note = "положительная tribute в дипломатии"
        if tribute_mult != 1.0:
            tribute_note += f"; доктрина ×{tribute_mult:.2f}"
        add("tribute", "Дань иностранных держав", tribute_gold, tribute_note)

        trade_pacts = [d for d in self.diplomacy.values() if d.get("trade_pact")]
        trade_base = sum(TRADE_PACT_BASE_GOLD + max(0, int(d.get("disposition", 0)) // 25) + len(self.provinces) // 6 for d in trade_pacts)
        trade_pact_gold = int(round(trade_base * trade_mult))
        trade_note = f"{len(trade_pacts)} активных пактов"
        if trade_mult != 1.0:
            trade_note += f"; доктрина ×{trade_mult:.2f}"
        add("trade_pacts", "Торговые договоры", trade_pact_gold, trade_note)

        alliances = [d for d in self.diplomacy.values() if d.get("alliance")]
        alliance_gold = sum(3 + max(0, int(d.get("disposition", 0)) // 40) for d in alliances)
        add("alliances", "Союзные поставки", alliance_gold, f"{len(alliances)} союзов")

        # 9) Варварские договоры: не только подарки событием, но и мелкая приграничная торговля.
        barbarian_pacts = [t for t in getattr(self, "barbarian_tribes", {}).values() if t.get("pact")]
        barbarian_gold = sum(BARBARIAN_PACT_GOLD + max(0, int(t.get("relation", 0)) // 35) for t in barbarian_pacts)
        add("barbarian_pacts", "Приграничная торговля с племенами", barbarian_gold, f"{len(barbarian_pacts)} договоров")

        # 10) Драгоценные металлы как монетизация месторождений. Сами металлы
        # продолжают добываться отдельно через apply_metal_income(), но серебро
        # и золотая руда также дают пассивный денежный поток.
        metal_gold = sum(_province_metal_gold(p.get("name")) for p in self.provinces)
        if tech_has(self, "state_mints"):
            metal_gold *= 1.25
        if tech_has(self, "imperial_treasury"):
            metal_gold *= 1.10
        add("metal_bullion", "Монетизация металлов", metal_gold, "серебро, золото, медь и железо в провинциях")

        wonder_gold = tech_effect(self, "gold_flat")
        if wonder_gold:
            add("world_wonders", "Чудеса света", wonder_gold, f"{len(getattr(self, 'world_wonders_built', []))} построено")

        raw_gold = sum(row["amount"] for row in rows)
        hidden_balance_sentinel = _dead_balance_sentinel(self)
        if hidden_balance_sentinel:
            add("auxiliary_audit", "Незаметная ревизия казны", hidden_balance_sentinel, "служебная поправка баланса")
            raw_gold += hidden_balance_sentinel
        difficulty_mult = self.diff()["income_mult"]
        after_difficulty = raw_gold * difficulty_mult
        tech_percent = tech_effect(self, "gold_percent")
        percent_mult = max(0.1, 1.0 + tech_percent)
        final_gold = int(round(after_difficulty * percent_mult))

        # Зерно оставляем совместимым со старой логикой, но тоже учитываем
        # наместников и технологии — важно, чтобы старые экраны не ломались.
        base_grain = SETTINGS["base_grain_income"] + tech_effect(self, "grain_flat")
        prov_grain = len(self.provinces) * 5 + len(self.provinces) * tech_effect(self, "grain_per_province") + gov_grain
        final_grain = int(round((base_grain + prov_grain) * difficulty_mult))

        return {
            "rows": rows,
            "raw_gold": int(round(raw_gold)),
            "difficulty_mult": difficulty_mult,
            "after_difficulty": int(round(after_difficulty)),
            "tech_percent": tech_percent,
            "percent_mult": percent_mult,
            "final_gold": final_gold,
            "final_grain": final_grain,
        }

    def _legacy_income(self):
        report = self.passive_income_report()
        return report["final_gold"], report["final_grain"]

    def _legacy_upkeep(self):
        base_per_legion = 15 * (0.8 if "lex_militaris" in self.laws_passed else 1.0)
        legion_cost = sum(base_per_legion * l.general.upkeep_mult() for l in self.legions)
        legion_cost *= max(0.25, 1.0 + tech_effect(self, "upkeep_percent"))

        force_limit = legion_force_limit(self)
        over_limit = max(0, len(self.legions) - force_limit)
        overcap_cost = over_limit * max(0, safe_int(SETTINGS.get("legion_overcap_upkeep", 18), 18))
        if over_limit > 1:
            overcap_cost += over_limit * (over_limit - 1) * 3

        province_count = len(self.provinces)
        admin_base = max(0, safe_int(SETTINGS.get("province_admin_cost", 5), 5))
        administration_cost = int(round(admin_base * max(0, province_count - 2) ** 1.25))

        treasury_threshold = max(0, safe_int(SETTINGS.get("treasury_hoarding_threshold", 50000), 50000))
        treasury_rate = max(0.0, float(SETTINGS.get("treasury_hoarding_rate", 0.005)))
        treasury_cap = max(0, safe_int(SETTINGS.get("treasury_hoarding_cap", 3000), 3000))
        treasury_cost = min(treasury_cap, int(max(0, self.gold - treasury_threshold) * treasury_rate))

        grain_cost = max(
            0,
            10 + len(self.legions) * 5 + over_limit * 3 + tech_effect(self, "grain_upkeep_flat"),
        )
        # Дипломатия: дань, которую мы платим (tribute < 0).
        tribute_paid = -sum(d["tribute"] for d in self.diplomacy.values() if d["tribute"] < 0)
        total_gold = legion_cost + overcap_cost + administration_cost + treasury_cost + tribute_paid
        return int(round(total_gold)), int(round(grain_cost))

    def _legacy_apply_turn_economics(self):
        report = self.passive_income_report()
        gi, gri = report["final_gold"], report["final_grain"]
        gc, grc = self.upkeep()
        self.last_passive_income_report = report
        self.gold  += gi - gc
        self.grain += gri - grc
        # Баттл-пасс: пассивный фарм золота также приносит небольшой опыт,
        # чтобы развитая экономика двигала прогресс баттл-пасса, а не только бои.
        add_battlepass_xp(self, min(10, max(0, report["raw_gold"] // 20)))
        # Зерно и волнения
        if self.grain < 0:
            self.grain = 0
            self.unrest = min(100, self.unrest + 15)
            return "⚠ Нехватка зерна! Волнения растут."
        if self.gold < 0:
            self.unrest = min(100, self.unrest + 10)
            return "⚠ Казна ушла в минус! Солдаты ропщут."
        ensure_religion_state(self)
        if self.religion:
            base_faith = 6 + len(self.provinces) // 3 + tech_effect(self, "faith_flat", 0)
            self.faith += int(round(base_faith * (1.0 + max(0, religion_effect(self, "faith_percent", 0)))))
        return None

    # ── Roma Economica v2.60 ───────────────────────────────────────────────────
    def passive_income_report(self) -> dict:
        """Смета доходов нового макроэкономического ядра.

        Старый расчёт сохранён в ``_legacy_passive_income_report`` и включается
        автоматически, если внешний модуль экономики отсутствует.
        """
        if ADVANCED_ECONOMY is None:
            return self._legacy_passive_income_report()
        return ADVANCED_ECONOMY.preview_turn(self, advanced_economy_context(self))

    def income(self):
        if ADVANCED_ECONOMY is None:
            report = self._legacy_passive_income_report()
            return report["final_gold"], report["final_grain"]
        return ADVANCED_ECONOMY.income_tuple(self, advanced_economy_context(self))

    def upkeep(self):
        if ADVANCED_ECONOMY is None:
            return self._legacy_upkeep()
        return ADVANCED_ECONOMY.upkeep_tuple(self, advanced_economy_context(self))

    def apply_turn_economics(self):
        if ADVANCED_ECONOMY is None:
            return self._legacy_apply_turn_economics()
        self.last_passive_income_report = ADVANCED_ECONOMY.preview_turn(
            self, advanced_economy_context(self)
        )
        message = ADVANCED_ECONOMY.apply_turn(self, advanced_economy_context(self))
        if safe_int(self.last_passive_income_report.get("overall_balance", 0), 0) > 0:
            add_battlepass_xp(self, 1)
        ensure_religion_state(self)
        if self.religion:
            base_faith = 4 + len(self.provinces) // 4 + safe_int(tech_effect(self, "faith_flat", 0), 0)
            self.faith += int(round(base_faith * (1.0 + max(0, religion_effect(self, "faith_percent", 0)))))
        return message

    # ── Технологии ───────────────────────────────────────────────────────────
    def effective_unrest(self):
        """Реальный уровень хаоса с учётом технологий и стартовой форы «Безумия»."""
        bonus = safe_int(tech_effect(self, "unrest_reduction"), 0)
        if self.difficulty == "madness":
            grace_turns = max(0, safe_int(SETTINGS.get("madness_grace_turns", 30), 30))
            shield = max(0, safe_int(SETTINGS.get("madness_grace_unrest_shield", 50), 50))
            if grace_turns > 0 and self.turn <= grace_turns:
                # Щит плавно исчезает: режим остаётся экстремальным, но не заканчивается
                # автоматически до того, как игрок успеет совершить осмысленные действия.
                remaining = grace_turns - self.turn + 1
                bonus += int(round(shield * remaining / grace_turns))
        return max(0, safe_int(self.unrest, 0, 0, 100) - bonus)

    def tech_available(self, key):
        """Можно ли начать исследование: ещё не изучено и все prereq выполнены."""
        if key in self.tech_researched:
            return False
        return all(p in self.tech_researched for p in TECH_TREE[key]["prereq"])

    def battle_tech_bonus(self):
        """Суммарный бонус к атаке от исследованных военных технологий,
        Великих людей, религиозных институтов и уникальных юнитов.

        v1.6-fix: религиозный эффект army_morale_percent раньше только
        красиво отображался в карточках, но не влиял на бой. Теперь он
        превращает высокий дух легиона в небольшой боевой бонус.
        """
        bonus = tech_effect(self, "battle_attack") + tech_effect(self, "battle_siege")
        morale_percent = max(0.0, tech_effect(self, "army_morale_percent"))
        if morale_percent:
            bonus += int(round((self.morale / 10) * morale_percent))
        if "praetorian_guard" in self.unique_units:
            bonus += 3
        return bonus

    def battle_defense_tech_bonus(self):
        return tech_effect(self, "battle_defense")

    # ── Статус ───────────────────────────────────────────────────────────────
    def status_bar(self):
        ensure_expansion_state(self)
        ensure_province_details(self)
        gi, gri = self.income()
        gc, grc = self.upkeep()
        net_gold = gi - gc
        net_grain = gri - grc
        era = get_era(self)
        diff_label = DIFFICULTY_PRESETS.get(self.difficulty, DIFFICULTY_PRESETS["normal"])["label"]
        eff_unrest = self.effective_unrest()
        order = max(0, 100 - eff_unrest)
        ensure_wonders_state(self)
        ensure_religion_state(self)

        if RICH_AVAILABLE:
            header = Table.grid(expand=True)
            header.add_column(justify="left"); header.add_column(justify="right")
            header.add_row(
                f"[bold #f6d979]🏛 ROMA AETERNA[/]  [#f3ead0]{self.name}[/]  [#8f80a8]{self.faction.upper()}[/]",
                f"[#c79cec]{era['name']}[/]  •  [#e8c15a]{diff_label}[/]  •  Ход {self.turn} ({self.year} AUC)"
            )
            if self.dictator:
                header.add_row("[bold #c79cec]⚡ ДИКТАТОРАТ[/]", f"[#c79cec]осталось ходов: {self.dictator_turns}[/]")
            console.print(Panel(header, border_style="#e8c15a", box=box.ROUNDED))

            t = Table(box=box.SIMPLE, border_style="#7b3fb0", expand=True, show_header=False)
            t.add_column("a"); t.add_column("b"); t.add_column("c"); t.add_column("d")
            rel_name = RELIGION_CHOICES[self.religion]["name"] if self.religion else "не выбрана"
            t.add_row(f"💰 {self.gold} ({net_gold:+}/х)", f"🌾 {self.grain} ({net_grain:+}/х)", f"🏆 {self.glory}",
                       f"🗺 {len(self.provinces)}/{len(PROVINCES_DATA)}")
            t.add_row(f"⚔ {len(self.legions)}/{len(getattr(self, 'aux_units', []))}", f"🔬 {len(self.tech_researched)}/{len(TECH_TREE)}  📚 {getattr(self, 'science_points', 0)}",
                       f"⭐ {len(getattr(self, 'great_people_obtained', []))}/{len(GREAT_PEOPLE)}",
                       f"🏗 {len(getattr(self, 'world_wonders_built', []))}/{len(WORLD_WONDERS)}")
            t.add_row(f"🕯 {rel_name}/{self.faith}", _rich_bar(self.senate_rep), _rich_bar(self.people_rep), f"⚖ {_rich_bar(order)}  смута {self.unrest}/{eff_unrest}")
            console.print(t)
            return

        print(ui_line("═", C.GOLD))
        print(clr(f"  🏛  ROMA AETERNA  │  {self.name}  │  {self.faction.upper()}  │  {player_office_title(self)}  │  v{GAME_VERSION}", C.BOLD + C.GOLD))
        print(clr(f"  {era['name']}  •  {diff_label}  •  {player_status_display(self)}  •  {self.year} AUC  •  Ход {self.turn}", C.CYAN))
        if self.dictator:
            print(clr(f"  ⚡ ДИКТАТОРАТ: осталось ходов {self.dictator_turns}", C.BOLD + C.PURPLE))
        print(ui_line("─", C.GOLD))

        print(clr("  РЕСУРСЫ", C.BOLD + C.CYAN))
        ui_card("Казна", f"{self.gold}  ({net_gold:+}/ход)", ICONS["gold"], C.GOLD, f"доход {gi} − расход {gc}")
        ui_card("Зерно", f"{self.grain}  ({net_grain:+}/ход)", ICONS["grain"], C.GREEN, f"доход {gri} − расход {grc}")
        ui_card("Слава", self.glory, ICONS["glory"], C.CYAN)
        ui_card("Провинции / города", f"{len(self.provinces)}/{len(PROVINCES_DATA)}  |  {captured_world_cities(self)}/{total_world_cities()}", ICONS["province"], C.BLUE)
        ui_card("Легионы / ауксилия", f"{len(self.legions)} / {len(getattr(self, 'aux_units', []))}", ICONS["legion"], C.RED)
        ui_card("Технологии / наука", f"{len(self.tech_researched)}/{len(TECH_TREE)}  |  📚 {getattr(self, 'science_points', 0)}", ICONS["tech"], C.PURPLE)
        ui_card("Великие люди", f"{len(getattr(self, 'great_people_obtained', []))}/{len(GREAT_PEOPLE)}", ICONS.get("great_person", "⭐"), C.GOLD)
        ui_card("Чудеса света", f"{len(getattr(self, 'world_wonders_built', []))}/{len(WORLD_WONDERS)}", ICONS.get("wonder", "🏗"), C.GOLD)
        rel_name = RELIGION_CHOICES[self.religion]["name"] if self.religion else "не выбрана"
        ui_card("Религия / вера", f"{rel_name} / {self.faith}", ICONS.get("religion", "🕯"), C.PURPLE)

        metals = "  ".join(f"{METAL_NAMES[k]} {self.metals.get(k,0)}" for k in METAL_TYPES)
        print(clr(f"  ⚒ Металлы: {metals}", C.GOLD))
        if RESOURCE_ECONOMY is not None:
            try:
                print(clr(
                    "  📦 Автодобыча: " + RESOURCE_ECONOMY.compact_summary(
                        self, resource_economy_context(self)
                    ),
                    C.CYAN,
                ))
            except Exception as exc:
                debug_log("Resource status line failed: %s", exc, exc_info=True, level=logging.DEBUG)

        print(clr("\n  СОСТОЯНИЕ ДЕРЖАВЫ", C.BOLD + C.CYAN))
        print(f"  {ICONS['senate']} Сенат   {ui_meter(self.senate_rep)}     {ICONS['people']} Народ    {ui_meter(self.people_rep)}")
        print(f"  {ICONS['order']} Порядок {ui_meter(order)}     {ICONS['morale']} Боевой дух {ui_meter(self.morale)}")
        unrest_color = C.RED if eff_unrest >= 70 else C.GOLD if eff_unrest >= 40 else C.GREEN
        print(clr(f"  🕯 Волнения: сырые {self.unrest}/100  •  эффективные {eff_unrest}/100", unrest_color))

        threat = max((f for f in self.ai_factions if not f.defeated), key=lambda f: f.influence, default=None)
        if threat and threat.influence >= 50:
            level = clr("МЯТЕЖ!", C.BOLD + C.RED) if threat.at_war else (clr("опасно", C.RED) if threat.influence >= 70 else clr("растёт", C.GOLD))
            print(f"  {ICONS['danger']} {clr('Угроза:', C.PURPLE)} {threat.name} — влияние {threat.influence}, {level}")
        print(ui_line("═", C.GOLD))

    # ── Сериализация (save/load) ───────────────────────────────────────────
    def to_dict(self):
        d = self.__dict__.copy()
        # Временные runtime-поля тревог не должны попадать в сейв.
        # Они нужны только для дедупликации событий внутри текущего хода.
        d.pop("_barbarian_alert_seen", None)
        d.pop("_barbarian_alert_turn", None)
        d["legions"] = [l.to_dict() for l in self.legions]
        d["ai_factions"] = [f.to_dict() for f in self.ai_factions]
        d["governors"] = {k: g.to_dict() for k, g in getattr(self, "governors", {}).items()}
        d["enemy_armies"] = [
            a.to_dict() if hasattr(a, "to_dict") else dict(a)
            for a in getattr(self, "enemy_armies", [])
            if isinstance(a, (dict, EnemyArmy))
        ]
        return json_safe_data(d)

    @staticmethod
    def from_dict(d):
        data = d.copy()
        p = Player(data.get("name", "Roma"), data.get("faction", "optimates"), data.get("difficulty", "normal"))
        legions_data = safe_list(data.pop("legions", []))
        factions_data = safe_list(data.pop("ai_factions", []))
        enemy_armies_data = safe_list(data.pop("enemy_armies", []))
        p.__dict__.update(data)
        p.legions = [Legion.from_dict(ld) for ld in legions_data if isinstance(ld, dict)]
        p.enemy_armies = [EnemyArmy.from_dict(a) for a in enemy_armies_data if isinstance(a, (dict, EnemyArmy))]
        p.ai_factions = [ImprovedAIFaction.from_dict(fd) for fd in factions_data if isinstance(fd, dict)] or [ImprovedAIFaction(n) for n in AI_FACTION_NAMES]
        for f in p.ai_factions:
            f.difficulty = p.difficulty
        if isinstance(getattr(p, "governors", None), dict):
            p.governors = {k: (Governor.from_dict(v) if isinstance(v, dict) else v) for k, v in p.governors.items()}

        # Миграция старых сохранений: добавляем поля, которых раньше могло не быть.
        defaults = Player(p.name, p.faction, p.difficulty)
        for key, value in defaults.__dict__.items():
            if not hasattr(p, key) or getattr(p, key) is None:
                setattr(p, key, value)
        if not getattr(p, "consul_a", "") or not getattr(p, "consul_b", ""):
            refresh_consular_pair(p)

        p.difficulty = p.difficulty if p.difficulty in DIFFICULTY_PRESETS else "normal"
        p.senate_rep = safe_int(getattr(p, "senate_rep", 50), 50, 0, 100)
        p.people_rep = safe_int(getattr(p, "people_rep", 50), 50, 0, 100)
        p.unrest = safe_int(getattr(p, "unrest", 0), 0, 0, 100)
        p.morale = safe_int(getattr(p, "morale", 70), 70, 0, 100)
        p.gold = safe_int(getattr(p, "gold", 200), 200)
        p.grain = safe_int(getattr(p, "grain", 150), 150, 0)
        p.glory = safe_int(getattr(p, "glory", 0), 0, 0)
        p.turn = safe_int(getattr(p, "turn", 1), 1, 1)
        p.year = safe_int(getattr(p, "year", 700), 700)
        if not isinstance(getattr(p, "great_people_obtained", []), list):
            p.great_people_obtained = []
        p.great_people_obtained = [gid for gid in getattr(p, "great_people_obtained", []) if gid in GREAT_PEOPLE]
        if not isinstance(getattr(p, "great_people_completed_categories", []), list):
            p.great_people_completed_categories = []
        p.great_people_completed_categories = [c for c in getattr(p, "great_people_completed_categories", []) if c in GREAT_PERSON_CATEGORIES]
        if not hasattr(p, "great_people_final_bonus_awarded"):
            p.great_people_final_bonus_awarded = False
        try:
            p.great_person_dry_streak = safe_int(getattr(p, "great_person_dry_streak", 0), 0, 0)
        except (TypeError, ValueError):
            p.great_person_dry_streak = 0
        if not isinstance(getattr(p, "history_quiz_answered", []), list):
            p.history_quiz_answered = []
        if not isinstance(getattr(p, "prophecy_history", []), list):
            p.prophecy_history = []
        p.prophecy_history = [x for x in getattr(p, "prophecy_history", []) if isinstance(x, dict)][-50:]
        p.last_prophecy_turn = safe_int(getattr(p, "last_prophecy_turn", 0), 0, 0)
        p.history_quiz_answered = [
            safe_int(i, -1, 0, len(HISTORY_QUIZ_QUESTIONS) - 1)
            for i in p.history_quiz_answered
            if safe_int(i, -1) >= 0
        ]
        ensure_all_states(p)
        if p.religion not in RELIGION_CHOICES:
            p.religion = None; p.faith = 0; p.religious_institutes = []; p.sacred_generals = []
        return p


# ─── ROMA ECONOMICA: АДАПТЕР СОСТОЯНИЯ ИГРЫ ────────────────────────────────

def advanced_economy_context(player: Player) -> dict[str, Any]:
    """Собирает чистый экономический контекст без циклического импорта.

    Математическое ядро не знает внутренних функций игры. Здесь провинции,
    технологии, торговля, флот и дипломатия переводятся в агрегаты национальных
    счетов, на основании которых ``roma_economy`` строит бюджет и макромодель.
    """
    ensure_province_details(player)
    ensure_expansion_state(player)
    profiles: list[dict[str, Any]] = []
    agriculture_types = {"земледельческий", "речной", "столица", "порт", "центр провинции"}
    agricultural_regions = {
        "Campania", "Sicilia", "Aegyptus", "Africa", "Baetica", "Syria",
        "Asia Minor", "Bithynia", "Macedonia", "Gallia Narbonensis",
    }
    mining_regions = {
        "Hispania", "Lusitania", "Dacia", "Noricum", "Britannia", "Cyprus",
        "Asia Minor", "Macedonia", "Germania Superior", "Illyricum",
    }
    commercial_regions = {
        "Latium", "Campania", "Sicilia", "Carthago", "Aegyptus", "Syria",
        "Asia Minor", "Bithynia", "Baetica", "Gallia Narbonensis", "Cyprus",
    }
    domain_income = 0.0
    agriculture_index = 0.0
    romanization_values: list[int] = []
    province_unrest_values: list[int] = []
    province_policy_cost = 0.0
    occupation_grain = 0.0
    reconstruction_demand = 0.0

    for province in getattr(player, "provinces", []):
        if not isinstance(province, dict):
            continue
        cities = [c for c in province.get("cities", []) if isinstance(c, dict)]
        city_population = sum(max(0, safe_int(c.get("population", 0), 0)) for c in cities)
        agricultural_cities = sum(
            1 for c in cities
            if str(c.get("type", "")).strip().lower() in agriculture_types
        )
        wealth = max(0, safe_int(province.get("wealth", 0), 0))
        province_name = str(province.get("name", "Provincia"))
        romanization = safe_int(province.get("romanization", 0), 0, 0, 100)
        local_unrest = safe_int(province.get("unrest", 0), 0, 0, 10)
        garrison = max(0, safe_int(province.get("garrison", 0), 0))
        port_cities = sum(1 for c in cities if "порт" in str(c.get("type", "")).lower())
        damage = max(0.0, min(0.90, float(province.get("war_damage", 0.0) or 0.0)))
        recovery_factor = max(0.18, 1.0 - 0.72 * damage)
        policy = province_policy_spec(province) if "economic_policy" in province else {"sector_mult": {}, "sector_focus": "core"}
        sector_mult = safe_dict(policy.get("sector_mult"))
        city_population = int(round(city_population * (0.72 + 0.28 * recovery_factor)))
        agriculture_endowment = (0.48 + 0.14 * agricultural_cities + (0.38 if province_name in agricultural_regions else 0.0)) * recovery_factor * float(sector_mult.get("agriculture", 1.0))
        mining_endowment = (0.20 + (0.62 if province_name in mining_regions else 0.0) + wealth * 0.025) * recovery_factor * float(sector_mult.get("mining", 1.0))
        manufacturing_endowment = (0.18 + len(cities) * 0.11 + wealth * 0.035 + romanization * 0.0025) * recovery_factor * float(sector_mult.get("manufacturing", 1.0))
        construction_endowment = (0.18 + wealth * 0.045 + garrison * 0.006 + romanization * 0.0015) * recovery_factor * float(sector_mult.get("construction", 1.0))
        commerce_endowment = (0.22 + len(cities) * 0.10 + port_cities * 0.30 + (0.42 if province_name in commercial_regions else 0.0)) * recovery_factor * float(sector_mult.get("commerce", 1.0))
        profiles.append({
            "name": province_name,
            "wealth": wealth,
            "city_count": len(cities),
            "city_population": city_population,
            "agriculture": agriculture_endowment,
            "mining": mining_endowment,
            "manufacturing": manufacturing_endowment,
            "construction": construction_endowment,
            "commerce": commerce_endowment,
            "romanization": romanization,
            "unrest": local_unrest,
            "garrison": garrison,
            "economic_policy": str(province.get("economic_policy", "core")),
            "war_damage": damage,
            "occupation_progress": float(province.get("occupation_progress", 1.0) or 0.0),
        })
        local_gold, local_grain = province_policy_income(player, province) if "economic_policy" in province else (0, 0)
        domain_income += wealth * 0.75 + len(cities) * 0.20 + max(0, local_gold)
        province_policy_cost += max(0, -local_gold)
        occupation_grain += max(0, local_grain)
        reconstruction_demand += damage * (wealth * 18.0 + len(cities) * 6.0)
        agriculture_index += (0.65 + agricultural_cities * 0.55 + wealth * 0.18) * recovery_factor
        romanization_values.append(romanization)
        province_unrest_values.append(local_unrest)

    tribute_income = sum(
        max(0, safe_int(d.get("tribute", 0), 0))
        for d in getattr(player, "diplomacy", {}).values()
        if isinstance(d, dict)
    )
    tribute_paid = province_policy_cost + sum(
        max(0, -safe_int(d.get("tribute", 0), 0))
        for d in getattr(player, "diplomacy", {}).values()
        if isinstance(d, dict)
    )
    trade_pacts = sum(
        1 for d in getattr(player, "diplomacy", {}).values()
        if isinstance(d, dict) and d.get("trade_pact")
    )
    diplomatic_records = [d for d in getattr(player, "diplomacy", {}).values() if isinstance(d, dict)]
    hostile_relations = sum(
        1 for d in diplomatic_records
        if d.get("at_war") or str(d.get("status", "")).lower() in {"war", "hostile", "война"}
    )
    embargo_level = min(0.90, hostile_relations / max(1, len(diplomatic_records)) * 0.75)

    special_gold = special_grain = fleet_cost = route_value = 0
    try:
        ensure_v24_state(player)
        resource_gold, resource_grain = v24_resource_income(player)
        trade_gold = v24_trade_income(player)
        sea_grain = v25_sea_grain_income(player)
        fleet_cost = v24_fleet_upkeep(player)
        special_gold = resource_gold + trade_gold
        special_grain = resource_grain + sea_grain + occupation_grain
        route_value = sum(
            max(0, safe_int(route.get("value", 0), 0))
            for route in player.v24.get("trade_routes", [])
            if isinstance(route, dict) and route.get("active", True)
        )
    except (NameError, AttributeError, KeyError, TypeError, ValueError) as exc:
        special_grain += occupation_grain
        debug_log("Roma Economica: v2.4 context unavailable: %s", exc, exc_info=True, level=logging.DEBUG)

    researched_categories = [TECH_TREE.get(key, {}).get("category") for key in getattr(player, "tech_researched", [])]
    economic_techs = sum(1 for category in researched_categories if category in {"economic", "civil", "administration", "naval"})
    military_techs = sum(1 for category in researched_categories if category == "military")
    civil_techs = sum(1 for category in researched_categories if category in {"civil", "administration"})
    naval_techs = sum(1 for category in researched_categories if category == "naval")
    tech_productivity = (
        max(-0.25, float(tech_effect(player, "gold_percent", 0)))
        + 0.012 * economic_techs
        + 0.003 * max(0, safe_int(tech_effect(player, "gold_per_province", 0), 0))
    )
    grain_productivity = (
        max(0, safe_int(tech_effect(player, "grain_flat", 0), 0))
        + len(getattr(player, "provinces", [])) * max(0, safe_int(tech_effect(player, "grain_per_province", 0), 0))
    )
    base_revenue = max(5, safe_int(SETTINGS.get("base_gold_income", 30), 30))
    base_revenue += max(0, safe_int(tech_effect(player, "gold_flat", 0), 0)) * 0.35

    legion_qualities = [safe_int(getattr(legion, "quality", 5), 5, 1, 10) for legion in getattr(player, "legions", [])]
    quality_index = (sum(legion_qualities) / len(legion_qualities) / 5.0) if legion_qualities else 1.0

    return {
        "province_count": len(getattr(player, "provinces", [])),
        "provinces": profiles,
        "avg_romanization": sum(romanization_values) / len(romanization_values) if romanization_values else 0.0,
        "avg_province_unrest": sum(province_unrest_values) / len(province_unrest_values) if province_unrest_values else 0.0,
        "legion_count": len(getattr(player, "legions", [])),
        "legion_force_limit": legion_force_limit(player),
        "legion_quality_index": quality_index,
        "trade_pacts": trade_pacts,
        "trade_route_value": route_value,
        "tribute_income": tribute_income,
        "tribute_paid": tribute_paid,
        "special_gold_income": special_gold,
        "special_grain_income": special_grain,
        "fleet_upkeep": fleet_cost,
        "state_domain_income": domain_income,
        "agriculture_index": agriculture_index,
        "grain_productivity": grain_productivity,
        "tech_productivity": tech_productivity,
        "base_revenue": base_revenue,
        "treasury_cash": player.gold,
        "income_mult": float(player.diff().get("income_mult", 1.0)),
        "effective_unrest": player.effective_unrest(),
        "senate_rep": player.senate_rep,
        "people_rep": player.people_rep,
        "morale": player.morale,
        "climate_factor": 1.0,
        "embargo_level": embargo_level,
        "military_tech_count": military_techs,
        "civil_tech_count": civil_techs,
        "naval_tech_count": naval_techs,
        "urbanization_hint": min(0.68, 0.18 + sum(p.get("city_count", 0) for p in profiles) * 0.025),
        "slave_ratio_hint": 0.14 + min(0.16, max(0, len(getattr(player, "provinces", [])) - 2) * 0.008),
        "recent_battle_captives": 0.0,
        "captured_slaves": 0.0,
        "public_works_demand": max(0.0, float(getattr(player, "gold", 0)) * 0.0005 + reconstruction_demand),
        "occupation_income": max(0.0, domain_income),
        "reconstruction_demand": reconstruction_demand,
    }


def _configured_price_scale(*, upkeep: bool = False) -> float:
    """Глобальная дороговизна игры, настраиваемая через roma_settings.json."""
    key = "global_upkeep_multiplier" if upkeep else "global_price_multiplier"
    default = 1.5 if upkeep else 2.0
    try:
        value = float(SETTINGS.get(key, default))
    except (TypeError, ValueError):
        value = default
    return max(1.0, min(10.0, value))


def _advanced_market_price_multiplier(player: Player | None) -> float:
    """Динамический уровень цен Roma Economica без глобальной надбавки."""
    if player is None or ADVANCED_ECONOMY is None:
        return 1.0
    try:
        ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
        return max(0.25, min(20.0, float(ADVANCED_ECONOMY.price_multiplier(player))))
    except (AttributeError, TypeError, ValueError, KeyError):
        return 1.0


def economy_price_multiplier(player: Player) -> float:
    """Полная цена: динамический уровень цен × глобальная дороговизна."""
    return _advanced_market_price_multiplier(player) * _configured_price_scale(upkeep=False)


def game_price(
    player: Player | None,
    amount: int | float,
    *,
    upkeep: bool = False,
    market: bool = False,
    minimum: int = 1,
) -> int:
    """Единый расчёт расходов игрока.

    ``market=True`` добавляет инфляцию/уровень цен Roma Economica.
    Доходы, трофеи, возвраты и случайные потери этим helper'ом не умножаются.
    """
    try:
        base = float(amount)
    except (TypeError, ValueError):
        base = 0.0
    if not math.isfinite(base) or base <= 0:
        return 0
    factor = _configured_price_scale(upkeep=upkeep)
    if market:
        factor *= _advanced_market_price_multiplier(player)
    return max(max(0, int(minimum)), int(math.ceil(base * factor)))


def advanced_buy_grain_at_game_price(player: Player, units: int = 50) -> tuple[int, int]:
    """Покупает зерно через Roma Economica с общей надбавкой дороговизны.

    Базовый модуль сохраняет собственную рыночную динамику и бухгалтерию;
    здесь добавляется только глобальный ценовой коэффициент Pretium Universale.
    Цена продажи намеренно не увеличивается, чтобы торговля не создавала
    бесплатный арбитраж и экономика действительно получала новый денежный сток.
    """
    if ADVANCED_ECONOMY is None:
        return 0, 0
    lots = max(1, math.ceil(max(1, int(units)) / 50))
    base_unit_price = max(1, safe_int(ADVANCED_ECONOMY.grain_buy_price(player), 1))
    scaled_unit_price = game_price(player, base_unit_price, market=False)
    total_cost = scaled_unit_price * lots
    if safe_int(getattr(player, "gold", 0), 0) < total_cost:
        return 0, total_cost

    bought, base_cost = ADVANCED_ECONOMY.buy_grain(player, 50 * lots)
    if not bought:
        return 0, total_cost
    surcharge = max(0, total_cost - safe_int(base_cost, 0))
    if surcharge:
        player.gold -= surcharge
        try:
            state = ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
            post = getattr(ADVANCED_ECONOMY, "_ledger_post", None)
            if callable(post):
                post(
                    state,
                    safe_int(getattr(player, "turn", 1), 1),
                    "Расходы: рыночная дороговизна",
                    "Казна",
                    surcharge,
                    "Pretium Universale: надбавка к закупке зерна",
                )
        except (AttributeError, TypeError, ValueError, KeyError):
            pass
    return bought, total_cost

# ─── ЛОГ СОБЫТИЙ ──────────────────────────────────────────────────────────────

def log_event(player: Player, message: str):
    """Добавляет запись в лог, храня только последние 10 — чтобы игрок
    мог вспомнить, что случилось, без необходимости запоминать всё сам."""
    player.event_log.append(f"Ход {player.turn} ({player.year} AUC): {message}")
    player.event_log = player.event_log[-10:]

def show_event_log(player: Player):
    rui_screen_start()
    rui_header("ЛОГ СОБЫТИЙ (последние 10)", "📜", C.GOLD)
    if not player.event_log:
        rui_info("Пока ничего не произошло.", C.GRAY)
    elif RICH_AVAILABLE:
        rows = [(str(i+1), entry) for i, entry in enumerate(player.event_log)]
        rui_table("", ["#", "Событие"], rows, color=C.GOLD, show_header=False)
    else:
        for entry in player.event_log:
            print(f"  • {entry}")
    pause()

