PROPHECY_EFFECT_LABELS = {
    "gold": "золото", "grain": "зерно", "glory": "слава", "faith": "вера",
    "morale": "мораль", "unrest": "волнения", "senate_rep": "Сенат", "people_rep": "народ",
    "research_progress": "исследования", "diplomacy": "дипломатия", "ai_influence": "влияние врагов",
    "governor_loyalty": "лояльность наместников", "legion_quality": "качество легионов",
    "legion_strength": "сила легионов", "legion_fatigue": "усталость легионов", "metals": "металлы",
}

def ensure_prophecy_state(player: Player):
    if not isinstance(getattr(player, "prophecy_history", []), list):
        player.prophecy_history = []
    player.prophecy_history = [x for x in player.prophecy_history if isinstance(x, dict)][-PROPHECY_HISTORY_LIMIT:]
    player.last_prophecy_turn = safe_int(getattr(player, "last_prophecy_turn", 0), 0, 0)


def _prophecy_context(player: Player) -> set[str]:
    ensure_religion_state(player)
    tags = set()
    eff_unrest = player.effective_unrest() if hasattr(player, "effective_unrest") else getattr(player, "unrest", 0)
    if eff_unrest >= 45 or getattr(player, "people_rep", 50) <= 35:
        tags.update(["crisis", "unrest"])
    if getattr(player, "grain", 0) < 120:
        tags.add("grain")
    if getattr(player, "gold", 0) < 120:
        tags.add("economy")
    if getattr(player, "morale", 70) < 55 or len(getattr(player, "legions", [])) >= 3:
        tags.add("war")
    if getattr(player, "senate_rep", 50) < 45:
        tags.add("senate")
    if getattr(player, "religion", None) or getattr(player, "faith", 0) >= 30:
        tags.add("religion")
    if len(getattr(player, "provinces", [])) >= 8 or getattr(player, "glory", 0) >= 500:
        tags.add("empire")
    if any(d.get("alliance") or d.get("trade_pact") for d in getattr(player, "diplomacy", {}).values() if isinstance(d, dict)):
        tags.add("diplomacy")
    if getattr(player, "researching", None) or getattr(player, "research_queue", []):
        tags.add("science")
    if not tags:
        tags.update(["order", "peace", "hero"])
    return tags


def _choose_prophecy(player: Player) -> dict:
    tags = _prophecy_context(player)
    recent = {p.get("id") for p in getattr(player, "prophecy_history", [])[-8:]}
    weighted = []
    for prophecy in PROPHECIES:
        weight = 10
        if prophecy.get("theme") in tags:
            weight += 30
        if prophecy.get("mood") == "buff" and (getattr(player, "gold", 0) < 90 or getattr(player, "grain", 0) < 90 or player.effective_unrest() >= 60):
            weight += 12
        if prophecy.get("mood") == "debuff" and getattr(player, "gold", 0) > 350 and getattr(player, "grain", 0) > 280 and player.effective_unrest() < 25:
            weight += 12
        if prophecy.get("id") in recent:
            weight = max(1, weight // 5)
        weighted.append((prophecy, weight))
    return random.choices([p for p, _ in weighted], weights=[w for _, w in weighted], k=1)[0]


def _apply_prophecy_effect(player: Player, prophecy: dict) -> list[str]:
    effects = prophecy.get("effects", {})
    notes = []

    def bounded_attr(attr: str, delta: int, lo: int = 0, hi: int = 100):
        before = safe_int(getattr(player, attr, 0), 0, lo, hi)
        after = max(lo, min(hi, before + int(delta)))
        setattr(player, attr, after)
        if after != before:
            notes.append(f"{PROPHECY_EFFECT_LABELS.get(attr, attr)} {after - before:+}")

    def open_attr(attr: str, delta: int, lo: int = 0):
        before = safe_int(getattr(player, attr, 0), 0, lo)
        after = max(lo, before + int(delta))
        setattr(player, attr, after)
        if after != before:
            notes.append(f"{PROPHECY_EFFECT_LABELS.get(attr, attr)} {after - before:+}")

    for key, value in effects.items():
        if key in ("gold", "grain", "glory", "faith", "research_progress"):
            open_attr(key, int(value), 0)
        elif key in ("morale", "senate_rep", "people_rep"):
            bounded_attr(key, int(value), 0, 100)
        elif key == "unrest":
            bounded_attr("unrest", int(value), 0, 100)
        elif key == "diplomacy":
            changed = 0
            for d in getattr(player, "diplomacy", {}).values():
                if not isinstance(d, dict):
                    continue
                before = safe_int(d.get("disposition", 50), 50, 0, 100)
                d["disposition"] = max(0, min(100, before + int(value)))
                changed += d["disposition"] - before
            if changed:
                notes.append(f"дипломатия {changed:+} суммарно")
        elif key == "ai_influence":
            changed = 0
            for f in getattr(player, "ai_factions", []):
                before = safe_int(getattr(f, "influence", 0), 0, 0, 100)
                f.influence = max(0, min(100, before + int(value)))
                changed += f.influence - before
            if changed:
                notes.append(f"влияние соперников {changed:+} суммарно")
        elif key == "governor_loyalty":
            changed = 0
            for gov in getattr(player, "governors", {}).values():
                if hasattr(gov, "loyalty"):
                    before = safe_int(getattr(gov, "loyalty", 70), 70, 0, 100)
                    gov.loyalty = max(0, min(100, before + int(value)))
                    changed += gov.loyalty - before
            if changed:
                notes.append(f"лояльность наместников {changed:+} суммарно")
        elif key == "legion_quality":
            changed = 0
            for legion in getattr(player, "legions", []):
                before = safe_int(getattr(legion, "quality", 1), 1, 1, 10)
                legion.quality = max(1, min(10, before + int(value)))
                changed += legion.quality - before
            if changed:
                notes.append(f"качество легионов {changed:+} суммарно")
        elif key == "legion_strength":
            changed = 0
            for legion in getattr(player, "legions", []):
                before = safe_int(getattr(legion, "strength", 100), 100, 0, 200)
                legion.strength = max(0, min(200, before + int(value)))
                changed += legion.strength - before
            if changed:
                notes.append(f"сила легионов {changed:+} суммарно")
        elif key == "legion_fatigue":
            changed = 0
            for legion in getattr(player, "legions", []):
                before = safe_int(getattr(legion, "fatigue", 0), 0, 0, 100)
                legion.fatigue = max(0, min(100, before + int(value)))
                changed += legion.fatigue - before
            if changed:
                notes.append(f"усталость легионов {changed:+} суммарно")
        elif key == "metals" and isinstance(value, dict):
            if not isinstance(getattr(player, "metals", None), dict):
                player.metals = {k: 0 for k in METAL_TYPES}
            metal_notes = []
            for metal, delta in value.items():
                if metal not in player.metals:
                    continue
                before = safe_int(player.metals.get(metal, 0), 0, 0)
                player.metals[metal] = max(0, before + int(delta))
                if player.metals[metal] != before:
                    metal_notes.append(f"{METAL_NAMES.get(metal, metal)} {player.metals[metal] - before:+}")
            if metal_notes:
                notes.append("; ".join(metal_notes))
    if not notes:
        notes.append("знамение истолковано без прямого эффекта")
    return notes


def _prophecy_effects_label(prophecy: dict) -> str:
    parts = []
    for key, value in prophecy.get("effects", {}).items():
        label = PROPHECY_EFFECT_LABELS.get(key, key)
        if isinstance(value, dict):
            metal_parts = [f"{METAL_NAMES.get(k, k)} {v:+}" for k, v in value.items()]
            parts.append(f"{label}: " + ", ".join(metal_parts))
        elif isinstance(value, int):
            parts.append(f"{label} {value:+}")
        else:
            parts.append(f"{label}: {value}")
    return "; ".join(parts) if parts else "без прямого эффекта"


def maybe_prophecy_event(player: Player):
    ensure_prophecy_state(player)
    if player.turn < PROPHECY_INTERVAL:
        return False
    if player.turn % PROPHECY_INTERVAL != 0:
        return False
    if getattr(player, "last_prophecy_turn", 0) == player.turn:
        return False

    prophecy = _choose_prophecy(player)
    notes = _apply_prophecy_effect(player, prophecy)
    player.last_prophecy_turn = player.turn
    entry = {
        "turn": player.turn,
        "year": player.year,
        "id": prophecy.get("id"),
        "tradition": prophecy.get("tradition"),
        "seer": prophecy.get("seer"),
        "title": prophecy.get("title"),
        "text": prophecy.get("text"),
        "source": prophecy.get("source"),
        "mood": prophecy.get("mood"),
        "theme": prophecy.get("theme"),
        "effects": notes,
    }
    player.prophecy_history.append(entry)
    player.prophecy_history = player.prophecy_history[-PROPHECY_HISTORY_LIMIT:]

    color = C.GREEN if prophecy.get("mood") == "buff" else C.RED
    print(clr("\n  🔮 ПРОРОЧЕСТВО ЯВЛЕНО", C.BOLD + color))
    print(clr(f"  {prophecy.get('tradition')} — {prophecy.get('seer')}: {prophecy.get('title')}", C.BOLD + C.GOLD))
    ui_wrap(prophecy.get("text", ""), indent="  ", color=C.WHITE)
    print(clr(f"  Источник/мотив: {prophecy.get('source')}", C.GRAY))
    print(clr("  Эффект: " + "; ".join(notes), color))
    log_event(player, f"Пророчество: {prophecy.get('title')} ({'; '.join(notes)})")
    return True


