def show_battlepass(player: Player):
    rui_screen_start()
    rui_header("БАТТЛПАСС", "🎖", C.GOLD)
    per_level = SETTINGS["battlepass_xp_per_level"]
    rui_info(f"Уровень: {player.battlepass_level}/100", C.GOLD)
    if player.battlepass_level < 100:
        xp_in_level = player.battlepass_xp - player.battlepass_level * per_level
        rui_info(f"Прогресс: {rui_meter_text(int(xp_in_level / per_level * 100))}  ({xp_in_level}/{per_level} XP)")
    else:
        rui_info("МАКСИМАЛЬНЫЙ УРОВЕНЬ ДОСТИГНУТ", C.GREEN)

    recent = player.battlepass_claimed[-5:]
    if RICH_AVAILABLE:
        rows = [(f"Ур.{lvl}", BATTLEPASS_REWARDS[lvl - 1]["name"]) for lvl in recent] if recent else [("—", "Пока нет.")]
        rui_table("Последние полученные награды", ["Уровень", "Награда"], rows, color=C.CYAN)
    else:
        print(f"\n{clr('  Последние полученные награды:', C.CYAN)}")
        if recent:
            for lvl in recent:
                r = BATTLEPASS_REWARDS[lvl - 1]
                print(f"    Ур.{lvl}: {r['name']}")
        else:
            print(clr("    Пока нет.", C.GRAY))

    if RICH_AVAILABLE:
        rows = []
        for lvl in (50, 75, 100):
            status = "[green]✓ получено[/]" if lvl in player.battlepass_claimed else "[bright_black]заблокировано[/]"
            r = BATTLEPASS_REWARDS[lvl - 1]
            rows.append((f"Ур.{lvl}", r["name"], status))
        rui_table("Ключевые награды", ["Уровень", "Награда", "Статус"], rows, color=C.GOLD)
    else:
        print(f"\n{clr('  Ключевые награды:', C.GOLD)}")
        for lvl in (50, 75, 100):
            status = clr("✓ получено", C.GREEN) if lvl in player.battlepass_claimed else clr("заблокировано", C.GRAY)
            r = BATTLEPASS_REWARDS[lvl - 1]
            print(f"    Ур.{lvl}: {r['name']} — {status}")
    pause()

def unlock_golden_pack(player: Player):
    if "golden" in player.packs_unlocked:
        print(clr("\n  Золотой набор уже был получен в этой партии.", C.GRAY))
        return
    pack = STARTER_PACKS["golden"]
    player.gold += pack["gold"]
    for tech in pack["techs"]:
        if tech not in player.tech_researched:
            player.tech_researched.append(tech)
    for gname, lname in pack["legion_generals"]:
        g = General(gname, "legendary", loyalty=100)
        l = Legion(lname, quality=10, general=g)
        l.veterans = True
        player.legions.append(l)
    player.packs_unlocked.append("golden")
    newly_unlocked = unlock_tech_aux_units(player)
    print(clr(f"\n  ✓ {pack['name']} получен!", C.BOLD + C.GREEN))
    print(f"    +{pack['gold']} золота, {len(pack['techs'])} технологий, "
          f"{len(pack['legion_generals'])} легиона макс. прокачки.")
    if newly_unlocked:
        print(clr(f"    Открыты войска: {', '.join(newly_unlocked)}", C.CYAN))
    log_event(player, "Получен Золотой набор (бесплатная разблокировка)")

def unlock_full_battlepass(player: Player):
    if player.battlepass_level >= 100:
        print(clr("\n  Баттл-пасс уже полностью пройден.", C.GRAY))
        return
    for level in range(1, 101):
        claim_battlepass_level(player, level, silent=True)
    player.battlepass_xp = max(player.battlepass_xp, 100 * SETTINGS["battlepass_xp_per_level"])
    player.battlepass_level = 100
    print(clr("\n  ✓ Баттл-пасс пройден полностью! Получены все 100 наград.", C.BOLD + C.GREEN))
    log_event(player, "Баттл-пасс полностью разблокирован бесплатно")

