# Полная прокачка как видимый раздел удалена; скрытое CHEAT-меню оставлено
# только для тестов и разблокировки бесплатного контента.

def read_choice_secret(prompt: str, valid_options, secret_word: str, secret_return: str) -> str:
    """read_choice с дополнительной скрытой командой."""
    if valid_options is None:
        raise ValueError("read_choice_secret: valid_options не задан")
    try:
        valid_upper = {str(v).strip().upper() for v in valid_options if str(v).strip()}
    except TypeError as exc:
        raise TypeError("read_choice_secret: valid_options должен быть итерируемым") from exc
    if not valid_upper:
        raise ValueError("read_choice_secret: список допустимых вариантов пуст")

    secret_upper = str(secret_word or "").strip().upper()
    if not secret_upper:
        raise ValueError("read_choice_secret: пустое секретное слово")
    shown = ", ".join(sorted(valid_upper, key=lambda x: (len(x), x)))

    while True:
        try:
            ch = input(prompt).strip().upper()
        except EOFError:
            if "Q" in valid_upper:
                return "Q"
            raise
        if ch == secret_upper:
            return secret_return
        if ch in valid_upper:
            return ch
        print(clr(f"  Не распознано «{ch}». Доступно: {shown}", C.RED))

