def max_legion_action_points() -> int:
    return safe_int(SETTINGS.get("legion_action_points_per_turn", 5), 2, 1, 20)

def ensure_legion_logistics(player):
    """Миграция старых сохранений: у всех легионов должны быть ОД и усталость."""
    for legion in getattr(player, "legions", []):
        if not hasattr(legion, "action_points"):
            legion.action_points = max_legion_action_points()
        if not hasattr(legion, "fatigue"):
            legion.fatigue = 0
        legion.action_points = safe_int(getattr(legion, "action_points", max_legion_action_points()), max_legion_action_points(), 0, 20)
        legion.fatigue = safe_int(getattr(legion, "fatigue", 0), 0, 0, 100)

def reset_legion_operations(player):
    """На новом ходу легионы восстанавливают очки действий и снимают усталость."""
    recover = safe_int(SETTINGS.get("legion_fatigue_recovery", 35), 35, 0, 100)
    for legion in getattr(player, "legions", []):
        old_fatigue = safe_int(getattr(legion, "fatigue", 0), 0, 0, 100)
        legion.action_points = max_legion_action_points()
        legion.fatigue = max(0, old_fatigue - recover)

def city_action_cost(city: dict | None) -> int:
    if not city:
        return safe_int(SETTINGS.get("normal_city_action_cost", 1), 1, 1, 20)
    city_type = str(city.get("type", "")).lower()
    is_capital = city_type in ("столица", "центр провинции") or str(city.get("name", "")).lower() in ("roma",)
    key = "capital_city_action_cost" if is_capital else "normal_city_action_cost"
    return safe_int(SETTINGS.get(key, 2 if is_capital else 1), 2 if is_capital else 1, 1, 20)

def legion_fatigue_penalty(legion: Legion) -> int:
    fatigue = safe_int(getattr(legion, "fatigue", 0), 0, 0, 100)
    threshold = safe_int(SETTINGS.get("legion_fatigue_penalty_threshold", 60), 60, 0, 100)
    if fatigue < threshold:
        return 0
    # Чем выше усталость, тем грубее падает боеспособность.
    return 4 + max(0, fatigue - threshold) // 10

def can_legion_attack_city(legion: Legion, city: dict | None) -> tuple[bool, str]:
    ensure = max_legion_action_points()
    if not hasattr(legion, "action_points"):
        legion.action_points = ensure
    if not hasattr(legion, "fatigue"):
        legion.fatigue = 0
    cost = city_action_cost(city)
    block = safe_int(SETTINGS.get("legion_fatigue_block_threshold", 90), 90, 0, 100)
    if safe_int(getattr(legion, "fatigue", 0), 0, 0, 100) >= block:
        return False, f"{legion.name} слишком измотан: усталость {legion.fatigue}/{block}. Нужен новый ход."
    if safe_int(getattr(legion, "action_points", 0), 0, 0, 20) < cost:
        return False, f"{legion.name} не хватает очков действий: нужно {cost}, доступно {legion.action_points}."
    return True, ""

def spend_legion_attack_action(legion: Legion, city: dict | None):
    cost = city_action_cost(city)
    legion.action_points = max(0, safe_int(getattr(legion, "action_points", max_legion_action_points()), max_legion_action_points(), 0, 20) - cost)
    fatigue_gain = safe_int(SETTINGS.get("legion_fatigue_per_attack", 15), 15, 0, 100)
    legion.fatigue = min(100, safe_int(getattr(legion, "fatigue", 0), 0, 0, 100) + fatigue_gain)

def capital_city_name(province_def: dict) -> str | None:
    cities = province_def.get("cities", [])
    for city in cities:
        city_type = str(city.get("type", "")).lower()
        if city_type in ("столица", "центр провинции"):
            return city.get("name")
    return cities[0].get("name") if cities else None

def province_ready_to_annex(player, province_def: dict) -> tuple[bool, str]:
    done, total = city_campaign_progress(player, province_def["name"])
    if total <= 0:
        return True, "нет городов"
    percent = safe_int(SETTINGS.get("province_annex_city_percent", 60), 60, 1, 100)
    need = max(1, math.ceil(total * percent / 100))
    if done < need:
        return False, f"нужно минимум {need}/{total} городов ({percent}%)"
    if SETTINGS.get("province_annex_requires_capital", True):
        cap = capital_city_name(province_def)
        if cap and cap not in captured_city_names(player, province_def["name"]):
            return False, f"нужно взять столицу провинции: {cap}"
    return True, f"условия выполнены: {done}/{total} городов"


