def ensure_conquest_economy_state(player) -> dict[str, Any]:
    state = getattr(player, "conquest_economy", None)
    if not isinstance(state, dict):
        state = {}
        player.conquest_economy = state
    defaults = {
        "version": 1,
        "claimed_cities": [],
        "claimed_provinces": [],
        "city_spoils_total": 0,
        "province_indemnities_total": 0,
        "grain_requisitions_total": 0,
        "captives_total": 0.0,
        "last_occupation_income": 0,
        "history": [],
    }
    for key, value in defaults.items():
        if key not in state or state[key] is None:
            state[key] = list(value) if isinstance(value, list) else value
    if not isinstance(state.get("claimed_cities"), list):
        state["claimed_cities"] = []
    if not isinstance(state.get("claimed_provinces"), list):
        state["claimed_provinces"] = []
    if not isinstance(state.get("history"), list):
        state["history"] = []
    state["claimed_cities"] = [str(x) for x in state["claimed_cities"]][-500:]
    state["claimed_provinces"] = [str(x) for x in state["claimed_provinces"]][-100:]
    state["history"] = [x for x in state["history"] if isinstance(x, dict)][-160:]
    return state


def conquest_price_factor(player) -> float:
    try:
        price = float(economy_price_multiplier(player))
    except Exception:
        price = 1.0
    cap = max(1.0, float(SETTINGS.get("conquest_price_factor_cap", 4.0)))
    return max(0.75, min(cap, math.sqrt(max(0.20, price))))


def province_policy_spec(province: dict | None) -> dict[str, Any]:
    province = province if isinstance(province, dict) else {}
    key = str(province.get("economic_policy", "integration"))
    return PROVINCE_ECONOMIC_POLICIES.get(key, PROVINCE_ECONOMIC_POLICIES["integration"])


def province_policy_income(player, province: dict) -> tuple[int, int]:
    """Возвращает автоматический чистый доход провинции (золото, зерно) за ход."""
    spec = province_policy_spec(province)
    cities = [c for c in province.get("cities", []) if isinstance(c, dict)]
    population = sum(max(0, safe_int(c.get("population", 0), 0)) for c in cities)
    wealth = max(0, safe_int(province.get("wealth", 0), 0))
    romanization = safe_int(province.get("romanization", 0), 0, 0, 100)
    unrest = safe_int(province.get("unrest", 0), 0, 0, 10)
    damage = max(0.0, min(0.90, float(province.get("war_damage", 0.0) or 0.0)))
    occupation = max(0.0, min(1.0, float(province.get("occupation_progress", 0.0) or 0.0)))
    garrison = max(0, safe_int(province.get("garrison", 0), 0))
    stability = max(0.18, 1.0 - 0.070 * unrest)
    recovery = max(0.12, 1.0 - 0.78 * damage)
    integration = 0.58 + 0.30 * romanization / 100.0 + 0.12 * occupation
    gross = (18.0 + wealth * 8.0 + len(cities) * 3.0 + population * 0.18)
    gross *= spec["income_mult"] * stability * recovery * integration
    administrative_cost = (5.0 + len(cities) * 0.75 + garrison * 4.0) * spec["cost_mult"]
    if str(province.get("economic_policy")) == "military":
        administrative_cost += 7.0 + garrison * 3.0
    gold = int(round(gross - administrative_cost))
    agricultural = sum(1 for c in cities if str(c.get("type", "")).lower() in {"земледельческий", "речной", "столица", "порт"})
    grain = int(round((agricultural * 5.0 + wealth * 1.7 + population * 0.025) * recovery * stability))
    if str(province.get("economic_policy")) == "tribute":
        grain = int(round(grain * 1.25))
    elif str(province.get("economic_policy")) == "autonomy":
        grain = int(round(grain * 0.75))
    return gold, max(0, grain)


def _conquest_history_add(player, kind: str, province: str, city: str = "", **values) -> None:
    state = ensure_conquest_economy_state(player)
    row = {"turn": safe_int(getattr(player, "turn", 1), 1), "kind": kind, "province": province, "city": city}
    row.update(values)
    state["history"].append(row)
    del state["history"][:-160]


def city_conquest_reward(player, province_def: dict, city: dict, *, source: str = "assault", announce: bool = True) -> dict[str, Any]:
    """Начисляет трофеи один раз за каждый реально захваченный город."""
    ensure_expansion_state(player)
    state = ensure_conquest_economy_state(player)
    province_name = str(province_def.get("name", "Provincia"))
    city_name = str(city.get("name", "Urbs"))
    claim_key = f"{province_name}::{city_name}"
    if claim_key in state["claimed_cities"]:
        return {"gold": 0, "grain": 0, "slaves": 0.0, "metals": {}, "duplicate": True}

    population = max(1, safe_int(city.get("population", 10), 10))
    difficulty = safe_int(city.get("difficulty", 3), 3, 1, 10)
    wealth = max(0, safe_int(province_def.get("wealth", 1), 1))
    city_type = str(city.get("type", "город")).strip().lower()
    type_mult = CITY_CONQUEST_TYPE_MULT.get(city_type, 1.0)
    source_mult = {"assault": 1.0, "breakthrough": 0.82, "amphibious": 0.90, "diplomatic": 0.35}.get(source, 1.0)
    scale = max(0.1, float(SETTINGS.get("city_conquest_spoils_scale", 1.0)))
    nominal = conquest_price_factor(player)
    gold = int(round((220 + population * 5.2 + difficulty * 78 + wealth * 48) * type_mult * source_mult * scale * nominal))

    grain_types = {"земледельческий", "речной", "порт", "столица", "центр провинции"}
    grain = int(round((18 + population * 0.55 + wealth * 4.0) * (1.45 if city_type in grain_types else 0.55) * source_mult))
    slave_rate = 0.012 + 0.0035 * difficulty
    if city_type in {"столица", "центр провинции", "племенной"}:
        slave_rate += 0.010
    slaves = round(max(0.4, population * slave_rate * source_mult), 2)
    capital_gain = round((2.0 + population * 0.018 + wealth * 0.35) * type_mult * source_mult, 2)
    sector = "commerce" if city_type in {"порт", "торговый", "административный"} else "mining" if city_type == "рудники" else "manufacturing" if city_type in {"ремесленный", "военный", "осадный"} else "agriculture"

    metals: dict[str, int] = {}
    if city_type == "рудники":
        metals = {"iron": max(1, difficulty // 2), "copper": max(1, wealth // 2)}
    elif city_type in {"военный", "осадный", "крепость"}:
        metals = {"iron": max(1, difficulty // 3)}
    for metal, amount in metals.items():
        if metal in player.metals:
            player.metals[metal] = max(0, safe_int(player.metals.get(metal, 0), 0) + amount)

    registered = False
    if ADVANCED_ECONOMY is not None and hasattr(ADVANCED_ECONOMY, "register_conquest_windfall"):
        ADVANCED_ECONOMY.register_conquest_windfall(
            player,
            gold=gold,
            grain=grain,
            slaves=slaves,
            province=province_name,
            city=city_name,
            capital_gain=capital_gain,
            sector=sector,
            source=source,
        )
        registered = True
    if not registered:
        player.gold += gold
        player.grain += grain

    state["claimed_cities"].append(claim_key)
    state["city_spoils_total"] = safe_int(state.get("city_spoils_total", 0), 0) + gold
    state["grain_requisitions_total"] = safe_int(state.get("grain_requisitions_total", 0), 0) + grain
    state["captives_total"] = round(float(state.get("captives_total", 0.0) or 0.0) + slaves, 2)
    _conquest_history_add(player, "city", province_name, city_name, gold=gold, grain=grain, slaves=slaves, source=source)

    result = {"gold": gold, "grain": grain, "slaves": slaves, "metals": metals, "capital_gain": capital_gain, "duplicate": False}
    if announce:
        metal_text = ", ".join(f"{METAL_NAMES.get(k, k)} +{v}" for k, v in metals.items())
        extras = [f"зерно +{grain}", f"пленные {slaves:.1f} тыс."]
        if metal_text:
            extras.append(metal_text)
        print(clr(f"  💰 Военные трофеи {city_name}: +{gold} золота; " + "; ".join(extras) + ".", C.BOLD + C.GOLD))
    return result


def recommend_province_economic_policy(province: dict) -> tuple[str, str]:
    cities = [c for c in province.get("cities", []) if isinstance(c, dict)]
    types = [str(c.get("type", "")).lower() for c in cities]
    wealth = max(0, safe_int(province.get("wealth", 0), 0))
    unrest = safe_int(province.get("unrest", 0), 0, 0, 10)
    frontier = any(t in {"крепость", "военный", "пограничный", "осадный"} for t in types)
    mining = types.count("рудники") + sum(1 for r in PROVINCE_RESOURCES.get(province.get("name"), []) if r in {"iron", "copper", "silver", "gold", "stone"})
    commercial = sum(1 for t in types if t in {"порт", "торговый", "административный"})
    agricultural = sum(1 for t in types if t in {"земледельческий", "речной"})
    if unrest >= 5 or frontier:
        return "military", "граница и сопротивление требуют гарнизона"
    if mining >= 2 or wealth >= 8:
        return "tribute", "богатство и месторождения дают высокую контрибуцию"
    if commercial >= 3:
        return "autonomy", "местные торговые элиты сохранят оборот и порты"
    if agricultural >= 3:
        return "colony", "ветеранская колония быстро освоит землю"
    return "integration", "сбалансированное восстановление выгоднее краткого грабежа"


def _apply_province_policy_choice(player, province: dict, policy_key: str, *, initial: bool = False) -> dict[str, Any]:
    if policy_key not in PROVINCE_ECONOMIC_POLICIES:
        policy_key = "integration"
    spec = PROVINCE_ECONOMIC_POLICIES[policy_key]
    old = str(province.get("economic_policy", ""))
    change_cost = 0 if initial or not old else game_price(player, max(0, safe_int(SETTINGS.get("conquest_policy_change_cost", 120), 120)), market=True)
    if change_cost and player.gold < change_cost:
        return {"ok": False, "message": f"нужно {change_cost} золота для смены режима"}
    if change_cost:
        player.gold -= change_cost
    province["economic_policy"] = policy_key
    province["economic_policy_turn"] = safe_int(getattr(player, "turn", 1), 1)
    province["occupation_progress"] = max(0.05, float(province.get("occupation_progress", 0.05) or 0.05))
    if initial:
        province["policy_lock_until"] = safe_int(getattr(player, "turn", 1), 1) + max(0, safe_int(SETTINGS.get("conquest_policy_lock_turns", 3), 3))
    if policy_key == "military":
        province["garrison"] = min(5, max(1, safe_int(province.get("garrison", 0), 0) + 1))
    elif policy_key == "colony":
        colony_cost = int(round((260 + max(0, safe_int(province.get("wealth", 0), 0)) * 28) * conquest_price_factor(player)))
        if initial and player.gold >= colony_cost:
            player.gold -= colony_cost
            province["romanization"] = min(100, safe_int(province.get("romanization", 10), 10) + 12)
            province["garrison"] = min(5, max(1, safe_int(province.get("garrison", 0), 0) + 1))
            province["war_damage"] = max(0.0, float(province.get("war_damage", 0.0) or 0.0) - 0.08)
            province["colony_investment"] = colony_cost
        elif initial:
            province["colony_investment"] = 0
    log_event(player, f"Экономический режим {province.get('name')}: {spec['name']}")
    return {"ok": True, "message": spec["name"], "cost": change_cost}


def configure_conquered_province_economy(player, province: dict, *, initial: bool = False) -> str:
    recommended, reason = recommend_province_economic_policy(province)
    rui_screen_start()
    rui_header(f"УСТРОЙСТВО ПРОВИНЦИИ: {province.get('name', 'Provincia')}", "🏛", C.GOLD)
    damage = float(province.get("war_damage", 0.0) or 0.0)
    rui_info(f"Военный ущерб: {damage:.0%} • волнения {province.get('unrest', 0)}/10 • романизация {province.get('romanization', 0)}/100", C.CYAN)
    rui_info(f"Рекомендация consilium: {PROVINCE_ECONOMIC_POLICIES[recommended]['name']} — {reason}.", C.GOLD)
    rows = []
    keys = list(PROVINCE_ECONOMIC_POLICIES)
    old_policy = province.get("economic_policy")
    for i, key in enumerate(keys, 1):
        spec = PROVINCE_ECONOMIC_POLICIES[key]
        temp = dict(province)
        temp["economic_policy"] = key
        gold, grain = province_policy_income(player, temp)
        mark = "★" if key == recommended else ""
        current = "текущий" if key == old_policy else ""
        rows.append((str(i), f"{mark} {spec['name']}", f"{gold:+} зол./ход", f"{grain:+} зерна/ход", f"ром. {spec['romanization']:+}; волн. {spec['unrest']:+}", current or spec["desc"]))
    rui_table("Пакеты управления", ["#", "Режим", "Казна", "Зерно", "Политика", "Последствия"], rows, color=C.GOLD)
    valid = [str(i) for i in range(1, len(keys) + 1)] + ["A", "Q"]
    print(clr(f"  A. Принять рекомендацию ({PROVINCE_ECONOMIC_POLICIES[recommended]['short']})", C.BOLD + C.GREEN))
    choice = read_choice(f"\n{clr('  Установить режим: ', C.CYAN)}", valid)
    if choice == "Q":
        chosen = old_policy if old_policy in PROVINCE_ECONOMIC_POLICIES else recommended
    elif choice == "A":
        chosen = recommended
    else:
        chosen = keys[int(choice) - 1]
    result = _apply_province_policy_choice(player, province, chosen, initial=initial)
    if not result.get("ok"):
        print(clr(f"  ✗ {result.get('message')}", C.RED))
        if initial:
            _apply_province_policy_choice(player, province, recommended, initial=True)
            chosen = recommended
    spec = PROVINCE_ECONOMIC_POLICIES[chosen]
    gold, grain = province_policy_income(player, province)
    print(clr(f"\n  ✓ {province.get('name')} получает режим «{spec['name']}». Прогноз: {gold:+} золота и {grain:+} зерна за ход.", C.BOLD + C.GREEN))
    if initial:
        pause()
    return chosen


def province_conquest_indemnity(player, province_def: dict, captured_ratio: float = 1.0) -> dict[str, Any]:
    cities = [c for c in province_def.get("cities", []) if isinstance(c, dict)]
    population = sum(max(0, safe_int(c.get("population", 0), 0)) for c in cities)
    wealth = max(0, safe_int(province_def.get("wealth", 0), 0))
    city_types = [str(c.get("type", "")).lower() for c in cities]
    ratio = max(0.35, min(1.0, float(captured_ratio)))
    scale = max(0.1, float(SETTINGS.get("province_conquest_indemnity_scale", 1.0)))
    nominal = conquest_price_factor(player)
    gold = int(round((1800 + wealth * 520 + population * 5.5 + len(cities) * 115) * (0.70 + 0.30 * ratio) * scale * nominal))
    grain = int(round((90 + population * 0.35 + city_types.count("земледельческий") * 55 + city_types.count("речной") * 35) * ratio))
    slaves = round(max(3.0, population * (0.018 + 0.012 * ratio)), 2)
    capital_transfer = round(10.0 + wealth * 1.8 + len(cities) * 0.75 + population * 0.015, 2)
    sector = "mining" if city_types.count("рудники") >= 1 else "commerce" if sum(t in {"порт", "торговый"} for t in city_types) >= 2 else "agriculture" if sum(t in {"земледельческий", "речной"} for t in city_types) >= 2 else "construction"
    return {"gold": gold, "grain": grain, "slaves": slaves, "capital_transfer": capital_transfer, "sector": sector, "population": population}


def register_province_conquest(player, province: dict, source_def: dict, captured_ratio: float) -> dict[str, Any]:
    state = ensure_conquest_economy_state(player)
    name = str(province.get("name", "Provincia"))
    if name in state["claimed_provinces"]:
        return {"gold": 0, "grain": 0, "slaves": 0.0, "duplicate": True}
    reward = province_conquest_indemnity(player, source_def, captured_ratio)
    registered = False
    if ADVANCED_ECONOMY is not None and hasattr(ADVANCED_ECONOMY, "register_province_annexation"):
        ADVANCED_ECONOMY.register_province_annexation(
            player,
            advanced_economy_context(player),
            province=name,
            gold=reward["gold"],
            grain=reward["grain"],
            slaves=reward["slaves"],
            local_population=reward["population"],
            capital_transfer=reward["capital_transfer"],
            sector=reward["sector"],
            policy=str(province.get("economic_policy", "integration")),
        )
        registered = True
    if not registered:
        player.gold += reward["gold"]
        player.grain += reward["grain"]
    state["claimed_provinces"].append(name)
    state["province_indemnities_total"] = safe_int(state.get("province_indemnities_total", 0), 0) + reward["gold"]
    state["grain_requisitions_total"] = safe_int(state.get("grain_requisitions_total", 0), 0) + reward["grain"]
    state["captives_total"] = round(float(state.get("captives_total", 0.0) or 0.0) + reward["slaves"], 2)
    _conquest_history_add(player, "province", name, gold=reward["gold"], grain=reward["grain"], slaves=reward["slaves"], ratio=round(captured_ratio, 3))
    print(clr(f"\n  🏺 ПРОВИНЦИАЛЬНАЯ КОНТРИБУЦИЯ: +{reward['gold']} золота, +{reward['grain']} зерна, {reward['slaves']:.1f} тыс. пленных.", C.BOLD + C.GOLD))
    return reward


def conquered_province_economy_tick(player) -> tuple[int, int]:
    """Восстанавливает завоёванные земли; денежный поток входит в следующий бюджет."""
    ensure_conquest_economy_state(player)
    total_gold = 0
    total_grain = 0
    for province in getattr(player, "provinces", []):
        if not isinstance(province, dict) or "economic_policy" not in province:
            continue
        spec = province_policy_spec(province)
        damage = max(0.0, min(0.90, float(province.get("war_damage", 0.0) or 0.0)))
        recovery = max(0.005, float(spec.get("recovery", SETTINGS.get("conquest_reconstruction_base", 0.035))))
        admin_bonus = 0.004 * safe_int(province.get("garrison", 0), 0) + 0.0006 * safe_int(province.get("romanization", 0), 0)
        province["war_damage"] = max(0.0, damage - recovery - admin_bonus)
        province["occupation_progress"] = min(1.0, float(province.get("occupation_progress", 0.05) or 0.05) + 0.035 + 0.0007 * safe_int(province.get("romanization", 0), 0))
        province["romanization"] = min(100, safe_int(province.get("romanization", 0), 0) + safe_int(spec.get("romanization", 0), 0))
        if spec.get("unrest", 0) < 0:
            if random.random() < min(0.95, 0.55 + province["occupation_progress"] * 0.30):
                province["unrest"] = max(0, safe_int(province.get("unrest", 0), 0) + safe_int(spec.get("unrest", 0), 0))
        elif spec.get("unrest", 0) > 0 and random.random() < 0.46:
            province["unrest"] = min(10, safe_int(province.get("unrest", 0), 0) + safe_int(spec.get("unrest", 0), 0))
        if spec.get("garrison", 0) and safe_int(province.get("garrison", 0), 0) < 2 and random.random() < 0.30:
            province["garrison"] = min(5, safe_int(province.get("garrison", 0), 0) + 1)
        gold, grain = province_policy_income(player, province)
        province["last_policy_income"] = gold
        province["last_policy_grain"] = grain
        total_gold += gold
        total_grain += grain
    state = ensure_conquest_economy_state(player)
    state["last_occupation_income"] = total_gold
    if total_gold or total_grain:
        turn_summary_add(player, f"Завоёванные провинции включены в бюджет: {total_gold:+} золота, {total_grain:+} зерна")
    return total_gold, total_grain


def annex_province_after_campaign(player, target: dict):
    ensure_conquest_economy_state(player)
    already_owned = next((p for p in player.provinces if isinstance(p, dict) and p.get("name") == target.get("name")), None)
    if already_owned:
        return already_owned, []
    done, total = city_campaign_progress(player, target["name"])
    captured_ratio = done / max(1, total)
    target_copy = captured_province_copy(target["name"])
    target_copy["romanization"] = 10
    target_copy["garrison"] = 0
    target_copy["conquest_turn"] = safe_int(getattr(player, "turn", 1), 1)
    target_copy["war_damage"] = max(0.14, min(0.52, 0.44 - 0.18 * captured_ratio + 0.015 * max(0, safe_int(target.get("unrest", 2), 2))))
    target_copy["occupation_progress"] = 0.05
    recommended, _reason = recommend_province_economic_policy(target_copy)
    target_copy["economic_policy"] = recommended
    target_copy["economic_policy_turn"] = safe_int(getattr(player, "turn", 1), 1)
    player.provinces.append(target_copy)
    player.governors[target_copy["name"]] = Governor()
    ensure_expansion_state(player)
    unlocked_now = []
    for unit in UNIQUE_AUXILIARY_UNITS.get(target_copy["name"], []):
        if unit["key"] not in player.unlocked_aux_units:
            player.unlocked_aux_units.append(unit["key"])
            unlocked_now.append(unit["name"])
    register_province_conquest(player, target_copy, target, captured_ratio)
    player.city_campaigns.pop(target["name"], None)
    clear_city_siege_damage(player, target["name"])
    configure_conquered_province_economy(player, target_copy, initial=True)
    return target_copy, unlocked_now

# ─── БОЕВАЯ СИСТЕМА ──────────────────────────────────────────────────────────

def decide_enemy_tactic(enemy: dict, legion: Legion, player_tactic: str, player = None) -> tuple:
    """
    Совместимый фасад для старых вызовов. Если player не передан, работает
    упрощённая логика; основной бой вызывает enemy_ai_decide_tactic напрямую.
    Возвращает (бонус_к_def_bonus, фраза для боевого лога).
    """
    if player is not None:
        _atk_bonus, def_bonus, desc, _chosen = enemy_ai_decide_tactic(player, legion, enemy, BATTLE_HISTORY, player_tactic)
        return def_bonus, desc

    power_ratio = enemy.get("strength", 10) / max(1, legion.strength)
    tactic_key = _PLAYER_TACTIC_MAP.get(str(player_tactic), str(player_tactic))
    if power_ratio < 0.5:
        return 2, "стягивает ряды в глухую оборону — отступать некуда"
    if power_ratio >= 1.1 and tactic_key in ("frontal", "flanking"):
        return 6, "ловит момент и контратакует в открывшийся фланг"
    if tactic_key == "defensive":
        return 1, "не ввязывается в бой с укрывшимся легионом, бережёт людей"
    return random.randint(2, 4), "перестраивается по ходу боя"

def battle_battle_roll_3d6() -> tuple[int, tuple[int, int, int]]:
    """Бросок 3d6: более колоколообразный и менее хаотичный, чем d20."""
    d1 = random.randint(1, 6)
    d2 = random.randint(1, 6)
    d3 = random.randint(1, 6)
    return d1 + d2 + d3, (d1, d2, d3)


def battle_roll_3d6() -> int:
    """Совместимость для артиллерийских проверок: возвращает только сумму 3d6."""
    roll, _dice = battle_battle_roll_3d6()
    return roll


def _battle_result_label(won: bool, margin: int) -> str:
    """Человеческое название масштаба победы/поражения."""
    if won:
        if margin >= 32:
            return "разгромная победа"
        if margin >= 18:
            return "уверенная победа"
        if margin >= 8:
            return "трудная победа"
        return "пиррова победа"
    if margin >= 32:
        return "катастрофическое поражение"
    if margin >= 18:
        return "тяжёлое поражение"
    if margin >= 8:
        return "неудачное отступление"
    return "срыв атаки"


# Все возможные суммы 3d6 и число способов их получить.
# Сумма 10-11 выпадает чаще, 3 и 18 — редко. Это и даёт устойчивую «военную» случайность.
D6_3_DISTRIBUTION = (
    (3, 1), (4, 3), (5, 6), (6, 10), (7, 15), (8, 21),
    (9, 25), (10, 27), (11, 27), (12, 25), (13, 21),
    (14, 15), (15, 10), (16, 6), (17, 3), (18, 1),
)
D6_3_TOTAL_OUTCOMES = 216
D6_3_PAIR_OUTCOMES = D6_3_TOTAL_OUTCOMES * D6_3_TOTAL_OUTCOMES


def _attrition_from_margin(margin: int) -> int:
    """Оценка износа победителя/проигравшего по разнице итогов."""
    if margin >= 0:
        return max(0, min(9, 7 - margin // 5))
    return 15 + min(18, (-margin) // 3)


def advanced_table_3d6_forecast(roman_power: int, enemy_power: int) -> dict:
    """
    Точный прогноз боя без Numba и без случайного Monte Carlo.

    Вместо 800 случайных симуляций перебираются все 216 вариантов 3d6 Рима
    и все 216 вариантов 3d6 врага: всего 46 656 исходов с весами вероятности.
    Поэтому прогноз стабильный, быстрый и одинаковый на любом Python/Termux.
    """
    roman_power = safe_int(roman_power, 0)
    enemy_power = safe_int(enemy_power, 0)

    wins_weight = 0
    margin_weighted_sum = 0
    attrition_weighted_sum = 0
    catastrophe_weight = 0

    for roman_roll, roman_count in D6_3_DISTRIBUTION:
        roman_total = roman_power + roman_roll * 3
        for enemy_roll, enemy_count in D6_3_DISTRIBUTION:
            weight = roman_count * enemy_count
            margin = roman_total - (enemy_power + enemy_roll * 3)
            margin_weighted_sum += margin * weight
            attrition_weighted_sum += _attrition_from_margin(margin) * weight

            if margin >= 0:
                wins_weight += weight
            elif margin <= -28:
                catastrophe_weight += weight

    total = D6_3_PAIR_OUTCOMES
    return {
        "sims": total,
        "win_rate": wins_weight / total,
        "avg_margin": margin_weighted_sum / total,
        "avg_attrition": attrition_weighted_sum / total,
        "catastrophe": catastrophe_weight / total,
        "engine": "таблица 3d6",
        "method": "полный перебор 3d6",
    }


def advanced_monte_carlo_forecast(roman_power: int, enemy_power: int, sims: int = 800) -> dict:
    """
    Совместимое имя для старых вызовов.
    Фактически это уже не Monte Carlo, а точный табличный прогноз 3d6.
    Параметр sims оставлен только ради совместимости со старыми настройками.
    """
    return advanced_table_3d6_forecast(roman_power, enemy_power)


def table_3d6_duel_totals(roman_power: int, enemy_power: int) -> tuple[int, tuple[int, int, int], int, tuple[int, int, int], int]:
    """
    Единый бросок для всех боевых подсистем: легионы, ауксилия, флот.
    Возвращает итог Рима, кости Рима, итог врага, кости врага и разницу.
    """
    rr, rd = battle_battle_roll_3d6()
    er, ed = battle_battle_roll_3d6()
    roman_total = safe_int(roman_power, 0) + rr * 3
    enemy_total = safe_int(enemy_power, 0) + er * 3
    return roman_total, rd, enemy_total, ed, roman_total - enemy_total


def print_table_3d6_forecast(title: str, roman_power: int, enemy_power: int, indent: str = "  ") -> dict:
    """Печатает точный прогноз 3d6 для любой подсистемы боя."""
    forecast = advanced_table_3d6_forecast(roman_power, enemy_power)
    print(clr(f"\n{indent}{title}:", C.CYAN))
    print(f"{indent}  Метод: {forecast.get('method', 'полный перебор 3d6')}")
    print(f"{indent}  Исходов: {forecast['sims']}")
    print(f"{indent}  Шанс победы: {forecast['win_rate'] * 100:.0f}%")
    print(f"{indent}  Средняя разница: {forecast['avg_margin']:+.1f}")
    print(f"{indent}  Средний износ: {forecast['avg_attrition']:.1f}")
    print(f"{indent}  Риск катастрофы: {forecast['catastrophe'] * 100:.0f}%")
    return forecast


def format_3d6(dice: tuple[int, int, int]) -> str:
    """Красивый вывод кости 3d6."""
    return f"3d6({dice[0]}, {dice[1]}, {dice[2]})"

def _legacy_resolve_battle_core_v222(player: Player, legion: Legion, enemy: dict, is_civil_war: bool = False) -> bool:
    """
    Боевая система v2.22: 3d6 + боеспособность + табличный прогноз.

    Отличие от старого d20: один случайный бросок больше не решает всё.
    Итог строится вокруг качества легиона, силы, морали, усталости, командира,
    технологий, ауксилии, тактики, доктрины врага и оперативных обстоятельств.
    """
    print(f"\n{hr('═')}")
    label = "ГРАЖДАНСКАЯ ВОЙНА" if is_civil_war else "БИТВА"
    print(clr(f"  ⚔  {label}: {legion.name}  vs  {enemy['name']}", C.BOLD + C.RED))
    print(hr('═'))
    print_art("battle", C.RED)

    # Тактика игрока
    print("\nВыберите тактику:")
    print(f"  {clr('1', C.GOLD)} Фронтальный удар   (+8 натиск, -3 строй)")
    print(f"  {clr('2', C.GOLD)} Манипулярный строй (+4 натиск, +5 строй)")
    print(f"  {clr('3', C.GOLD)} Засада             (+10 натиск, рискованный манёвр)")
    print(f"  {clr('4', C.GOLD)} Оборонительная     (-3 натиск, +10 строй)")
    has_testudo = "testudo" in player.tech_researched
    tactics = {"1": (8, -3, "Фронтальный удар"), "2": (4, 5, "Манипулярный строй"), "3": (10, -1, "Засада"), "4": (-3, 10, "Оборонительная")}
    if has_testudo:
        testudo_def = 8 + player.battle_defense_tech_bonus()
        print(f"  {clr('5', C.GOLD)} Testudo            (+1 натиск, +{testudo_def} строй)")
        tactics["5"] = (1, testudo_def, "Testudo")
    choice = read_choice(f"\n{clr('Ваш выбор: ', C.CYAN)}", tactics.keys())
    t_atk, t_def, tactic_label = tactics[choice]

    # Вражеская тактика и оперативная обстановка
    enemy_t_atk, enemy_t_def, tactic_desc, enemy_tactic_key = enemy_ai_decide_tactic(player, legion, enemy, BATTLE_HISTORY, choice)
    enemy_grand_mod = safe_int(enemy.get("battle_mod", 0), 0)
    enemy_strength = safe_int(enemy.get("strength", 10), 10, 1, 200)
    raw_strength_component = enemy_strength
    strength_component = min(raw_strength_component, 116 if enemy.get("joint_attack") else 104)
    tactical_component = max(-14, min(28, enemy_t_atk + enemy_t_def))
    operational_component = max(-10, min(18, enemy_grand_mod))

    fatigue_penalty = legion_fatigue_penalty(legion)
    aux_bonus = auxiliary_battle_bonus(player)
    general_bonus = legion.general.atk_bonus() + legion.general.def_bonus()
    tech_bonus = player.battle_tech_bonus() + player.battle_defense_tech_bonus()
    veteran_bonus = 8 if legion.veterans else 0
    elite_bonus = 8 if legion.elite else 0

    # v2.22.2: компактная шкала боеспособности.
    # Раньше качество/сила/мораль складывались слишком крупными числами
    # (+70...+140 до броска), и 3d6 математически уже не мог изменить исход.
    # Теперь обычные легионы и гарнизоны живут в диапазоне примерно 15–45,
    # а элитные/полностью прокачанные войска могут выходить выше — как и должны.
    roman_quality = safe_int(legion.quality, 5, 1, 10)
    roman_strength = safe_int(legion.strength, 50, 1, 100)
    roman_morale = safe_int(legion.morale, 80, 0, 100)
    roman_components = {
        "качество": roman_quality * 2,
        "сила": roman_strength // 5,
        "мораль": roman_morale // 10,
        "командир": min(8, general_bonus),
        "технологии": min(12, tech_bonus),
        "ауксилия": min(10, aux_bonus),
        "ветераны/элита": (3 if legion.veterans else 0) + (4 if legion.elite else 0),
        "тактика": max(-4, min(10, t_atk + t_def)),
        "усталость": -(fatigue_penalty // 2),
    }
    roman_power = sum(roman_components.values())

    # Вражеская сила тоже сжимается. Грубое поле strength остаётся важным,
    # но больше не превращает бой в арифметически предрешённый приговор.
    enemy_components = {
        "база": 14,
        "сила": strength_component // 3,
        "тактика": max(-6, min(12, tactical_component)),
        "оперативный бонус": max(-5, min(10, operational_component)),
        "доктрина/инициатива": 4,
    }
    enemy_power = sum(enemy_components.values())

    tactic_name = ENEMY_TACTICS.get(enemy_tactic_key, {}).get("name", "Манёвр")
    sign = "+" if tactical_component >= 0 else ""
    print(clr(f"  Тактика Рима: {tactic_label} ({t_atk + t_def:+} к боеспособности)", C.CYAN))
    print(clr(f"  {enemy['name']} выбирает: {tactic_name} — {tactic_desc} ({sign}{tactical_component} тактический итог)", C.GRAY))
    if aux_bonus:
        print(clr(f"  Поддержка ауксилии: +{aux_bonus} к боеспособности", C.CYAN))
    if fatigue_penalty:
        print(clr(f"  Усталость легиона: -{fatigue_penalty} к боеспособности", C.GOLD))
    if raw_strength_component != strength_component:
        print(clr(f"  Баланс: грубая сила врага ограничена {raw_strength_component} → {strength_component}.", C.GRAY))

    if SETTINGS.get("advanced_battle_show_forecast", True):
        forecast = advanced_monte_carlo_forecast(
            roman_power,
            enemy_power,
            SETTINGS.get("advanced_battle_monte_carlo_sims", 800),
        )
        print(clr("\n  Прогноз штаба 3d6:", C.BOLD + C.CYAN))
        print(f"    Метод: {forecast.get('method', forecast['engine'])}")
        print(f"    Исходов: {forecast['sims']} ({forecast['engine']})")
        print(f"    Шанс победы: {int(round(forecast['win_rate'] * 100))}%")
        print(f"    Средняя разница: {forecast['avg_margin']:+.1f}")
        print(f"    Средний износ: {forecast['avg_attrition']:.1f}")
        print(f"    Риск катастрофы: {int(round(forecast['catastrophe'] * 100))}%")

    roman_roll, roman_dice = battle_battle_roll_3d6()
    enemy_roll, enemy_dice = battle_battle_roll_3d6()
    roman_total = roman_power + roman_roll * 3
    enemy_total = enemy_power + enemy_roll * 3

    time.sleep(0.5)
    print(clr("\n  Боеспособность Рима:", C.BOLD + C.GREEN))
    print("    " + ", ".join(f"{k} {v:+}" for k, v in roman_components.items() if v))
    print(clr("  Боеспособность врага:", C.BOLD + C.RED))
    print("    " + ", ".join(f"{k} {v:+}" for k, v in enemy_components.items() if v))
    print(f"\n  Бросок Рима:  3d6{roman_dice} ×3 + {roman_power} = {clr(str(roman_total), C.GREEN)}")
    print(f"  Бросок врага: 3d6{enemy_dice} ×3 + {enemy_power} = {clr(str(enemy_total), C.RED)}")
    time.sleep(0.8)

    if roman_total >= enemy_total:
        margin = roman_total - enemy_total
        result_label = _battle_result_label(True, margin)
        win_attrition = max(
            SETTINGS.get("advanced_battle_min_win_attrition", 1),
            min(SETTINGS.get("advanced_battle_max_win_attrition", 9), 6 - margin // 8 + random.randint(0, 2)),
        )
        if legion.veterans:
            win_attrition = max(0, win_attrition - 1)
        if legion.elite:
            win_attrition = max(0, win_attrition - 1)
        if win_attrition and legion in player.legions:
            legion.strength = max(10, legion.strength - win_attrition)

        legion.after_battle_xp(True)
        if is_civil_war:
            player.glory += 15 + margin
            player.senate_rep = min(100, player.senate_rep + 10)
            print_art("victory", C.GOLD)
            print(clr(f"\n  ✓ VICTORIA! {result_label.capitalize()}: мятеж {enemy['name']} подавлен!", C.BOLD + C.GREEN))
            print(f"  Слава: +{15 + margin}  Репутация в Сенате: +10")
            add_battlepass_xp(player, 20)
        else:
            glory_gained = enemy_strength * 2 + margin * 2
            gold_looted = enemy_strength * 5 + random.randint(0, 30)
            player.glory += glory_gained
            player.gold += gold_looted
            print_art("victory", C.GOLD)
            print(clr(f"\n  ✓ VICTORIA! {result_label.capitalize()}: {enemy['name']} разбит!", C.BOLD + C.GREEN))
            print(f"  Слава: +{glory_gained}  Золото добычи: +{gold_looted}")
            add_battlepass_xp(player, 15)
        if win_attrition:
            print(clr(f"  Боевой износ победителей: -{win_attrition} силы легиона.", C.GOLD))
        tick_aux_after_battle(player, True)
        maybe_destroy_legion_after_battle(player, legion, True, margin)
        if legion.veterans:
            print(clr("  ★ Легион заслужил статус ВЕТЕРАНОВ!", C.GOLD))
        if legion in player.legions:
            print(f"  Лояльность {legion.general.name}: {legion.general.loyalty}")
        BATTLE_HISTORY.append({
            "player_tactic": choice,
            "enemy_tactic": enemy_tactic_key,
            "won": True,
            "turn": player.turn,
            "enemy": enemy.get("name", "Hostes"),
            "margin": margin,
            "system": "3d6_monte_carlo",
        })
        if len(BATTLE_HISTORY) > 30:
            del BATTLE_HISTORY[:-30]
        remember_ai_battle(player, choice, enemy_tactic_key, True, margin)
        return True

    margin = enemy_total - roman_total
    result_label = _battle_result_label(False, margin)
    player.morale = max(10, player.morale - margin * 2)
    legion.after_battle_xp(False)
    if is_civil_war:
        player.senate_rep = max(0, player.senate_rep - 10)
        print_art("defeat", C.RED)
        print(clr(f"\n  ✗ CLADES! {result_label.capitalize()}: {enemy['name']} теснит наши легионы!", C.BOLD + C.RED))
        print(f"  Репутация в Сенате: -10  Моральный дух армии: -{margin*2}")
    else:
        print_art("defeat", C.RED)
        print(clr(f"\n  ✗ CLADES! {result_label.capitalize()}: отступление перед {enemy['name']}!", C.BOLD + C.RED))
        print(f"  Потери силы легиона: -15  Моральный дух армии: -{margin*2}")
    tick_aux_after_battle(player, False)
    maybe_destroy_legion_after_battle(player, legion, False, margin)
    if legion in player.legions:
        print(f"  Лояльность {legion.general.name}: {legion.general.loyalty}")
    BATTLE_HISTORY.append({
        "player_tactic": choice,
        "enemy_tactic": enemy_tactic_key,
        "won": False,
        "turn": player.turn,
        "enemy": enemy.get("name", "Hostes"),
        "margin": margin,
        "system": "3d6_monte_carlo",
    })
    if len(BATTLE_HISTORY) > 30:
        del BATTLE_HISTORY[:-30]
    remember_ai_battle(player, choice, enemy_tactic_key, False, margin)
    if safe_int(enemy.get("counter_mod", 0), 0) and not enemy.get("joint_attack"):
        enemy_ai_pursuit_counterattack(player, legion, enemy)
    return False

# ─── СОБЫТИЯ С ВЫБОРОМ ────────────────────────────────────────────────────────
# В отличие от RANDOM_EVENTS (чисто случайный эффект), эти события дают
# игроку реальное решение с разными последствиями — например, голод в
# провинции можно залить зерном, подавить силой или проигнорировать.

def _famine_send_grain(player, prov):
    player.grain -= 40
    prov["unrest"] = max(0, prov["unrest"] - 3)
    player.people_rep = min(100, player.people_rep + 5)

def _famine_suppress(player, prov):
    player.people_rep = max(0, player.people_rep - 15)
    prov["unrest"] = max(0, prov["unrest"] - 5)
    player.glory += 10

def _famine_ignore(player, prov):
    prov["unrest"] = min(10, prov["unrest"] + 4)

def _revolt_threat_buyoff(player, prov):
    player.gold -= game_price(player, 35, market=True)
    prov["unrest"] = max(0, prov["unrest"] - 4)

def _revolt_threat_crush(player, prov):
    player.people_rep = max(0, player.people_rep - 10)
    prov["unrest"] = 0
    player.glory += 8

def _revolt_threat_ignore(player, prov):
    prov["unrest"] = min(10, prov["unrest"] + 3)
    player.unrest = min(100, player.unrest + 5)

def _ally_request_help(player, ally_key):
    d = player.diplomacy[ally_key]
    player.gold -= game_price(player, 50, market=True)
    d["disposition"] = min(100, d["disposition"] + 20)
    player.senate_rep = min(100, player.senate_rep + 5)

def _ally_request_decline(player, ally_key):
    d = player.diplomacy[ally_key]
    d["disposition"] = max(0, d["disposition"] - 20)

def _treasure_keep(player, ctx):
    player.gold += 60

def _treasure_temple(player, ctx):
    player.senate_rep = min(100, player.senate_rep + 8)
    player.people_rep = min(100, player.people_rep + 8)

def _omen_sacrifice(player, ctx):
    player.gold -= game_price(player, 25, market=True)
    player.senate_rep = min(100, player.senate_rep + 6)
    player.people_rep = min(100, player.people_rep + 6)

def _omen_refuse(player, ctx):
    player.people_rep = max(0, player.people_rep - 10)

# ── Новые события патча 1.1: используют наместников, варваров и легионы ──────

def _governor_investigate(player, ctx):
    prov, gov = ctx
    player.gold -= game_price(player, 30, market=True)
    if gov.trait_key == "corrupt":
        gov.adjust_loyalty(-20)
        prov["unrest"] = max(0, prov["unrest"] - 2)
        player.senate_rep = min(100, player.senate_rep + 6)
    else:
        gov.adjust_loyalty(10)
        player.senate_rep = min(100, player.senate_rep + 3)

def _governor_trust(player, ctx):
    prov, gov = ctx
    gov.adjust_loyalty(8)
    if gov.trait_key == "corrupt":
        prov["unrest"] = min(10, prov["unrest"] + 2)
        player.people_rep = max(0, player.people_rep - 5)

def _governor_replace(player, ctx):
    prov, gov = ctx
    player.gold -= game_price(player, 30, market=True)
    player.governors[prov["name"]] = Governor()
    prov["unrest"] = max(0, prov["unrest"] - 1)

def _barbarian_envoys_welcome(player, ctx):
    key, tribe = ctx
    tribe["relation"] = min(100, tribe["relation"] + 15)
    player.gold -= game_price(player, 20, market=True)

def _barbarian_envoys_demand(player, ctx):
    key, tribe = ctx
    if random.random() < 0.5 + (tribe["relation"] - 50) / 200:
        player.gold += 40 + tribe["strength"] * 3
        tribe["relation"] = max(0, tribe["relation"] - 10)
    else:
        tribe["relation"] = max(0, tribe["relation"] - 25)
        player.morale = max(10, player.morale - 8)

def _barbarian_envoys_dismiss(player, ctx):
    key, tribe = ctx
    tribe["relation"] = max(0, tribe["relation"] - 15)
    player.senate_rep = min(100, player.senate_rep + 4)

def _legion_pay_settle(player, legion):
    cost = game_price(player, 25 + legion.quality * 4, market=True)
    player.gold -= cost
    legion.morale = min(100, legion.morale + 15)
    legion.general.adjust_loyalty(8)

def _legion_pay_delay(player, legion):
    legion.morale = max(10, legion.morale - 10)
    legion.general.adjust_loyalty(-12)

def _legion_pay_punish(player, legion):
    player.people_rep = max(0, player.people_rep - 8)
    legion.morale = min(100, legion.morale + 5)
    legion.general.adjust_loyalty(-5)
    player.glory += 4

