def legion_menu(player: Player):
    rui_screen_start()
    rui_header("УПРАВЛЕНИЕ ЛЕГИОНАМИ", "⚔", C.RED)

    if player.legions:
        if RICH_AVAILABLE:
            rows = []
            for l in player.legions:
                tags = []
                if l.veterans:
                    tags.append("[gold1]ВЕТЕРАНЫ[/]")
                if l.elite:
                    tags.append("[magenta]ЭЛИТНЫЙ[/]")
                name_cell = f"[red]{l.name}[/]" + (" " + " ".join(tags) if tags else "")
                t = l.general.talent()
                loy = l.general.loyalty
                loy_style = "green" if loy >= 60 else "gold1" if loy >= 30 else "red"
                warn = " ⚠" if loy <= SETTINGS.get("general_mutiny_loyalty_threshold", 15) else ""
                gen_cell = f"{l.general.name} [{t['name']}] [{loy_style}]{loy}{warn}[/]"
                rows.append((name_cell, str(l.strength), str(l.morale), str(getattr(l, "action_points", max_legion_action_points())), str(getattr(l, "fatigue", 0)), f"[cyan]{l.location}[/]", str(l.battles), gen_cell))
            rui_table("Легионы", ["Легион", "Сила", "Мораль", "ОД", "Устал.", "Позиция", "Сражений", "Командир"], rows, color=C.RED)
        else:
            for l in player.legions:
                print(l.description())
                print()
    else:
        rui_info("Нет легионов.", C.GRAY)

    cost = legion_recruitment_cost(player)
    train_cost = game_price(player, SETTINGS["legion_train_cost"], market=True)
    refund = SETTINGS["legion_disband_refund"]
    rui_menu([
        ("N", "Нанять легион", f"{cost} золота", "🛡"),
        ("T", "Тренировать легион", f"{train_cost} золота/ур.", "🎯"),
        ("M", "Массовая тренировка", "+1 ур. каждому, пока хватает золота", "⚡"),
        ("D", "Распустить легион", f"+{refund} золота", "🏴"),
        ("Q", "Назад", "", "🚪"),
    ], title="Действия")

    valid = ["N", "T", "M", "D", "Q"] if player.legions else ["N", "Q"]
    ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", valid)

    if ch == "Q":
        return

    if ch == "N":
        if player.gold >= cost:
            player.gold -= cost
            num = len(player.legions) + 1
            roman_nums = ['I','II','III','IV','V','VI','VII','VIII','IX','X','XI','XII']
            name = f"Legio {roman_nums[min(num-1, len(roman_nums)-1)]} Romana"
            new_legion = Legion(name)
            player.legions.append(new_legion)
            print(clr(f"\n  {name} сформирован! Командир: {new_legion.general.name} "
                       f"({new_legion.general.talent()['name']})", C.GREEN))
            log_event(player, f"Сформирован {name} под командованием {new_legion.general.name}")
        else:
            print(clr(f"\n  Недостаточно золота! (нужно {cost})", C.RED))

    elif ch == "T":
        for i, l in enumerate(player.legions):
            max_levels = max(0, 10 - l.quality)
            print(f"  {i+1}. {l.name} — качество {l.quality}/10, можно поднять на {max_levels}")
        li_valid = [str(i + 1) for i in range(len(player.legions))] + ["Q"]
        li = read_choice(f"{clr('  Какой легион тренировать (или Q — отменить): ', C.CYAN)}", li_valid)
        if li != "Q":
            legion = player.legions[int(li) - 1]
            max_levels = max(0, 10 - legion.quality)
            if max_levels <= 0:
                print(clr("\n  Этот легион уже максимального качества.", C.GRAY))
            else:
                affordable = player.gold // train_cost if train_cost > 0 else max_levels
                print(f"  Доступно золота: {player.gold}. Цена полного улучшения: {max_levels * train_cost}.")
                levels = read_int(f"{clr('  Сколько уровней тренировать? 0 = максимум, Q = отмена: ', C.CYAN)}", 0, max_levels)
                if levels is not None:
                    if levels == 0:
                        levels = max_levels
                    done = train_legion_multiple_levels(player, legion, levels)
                    if done:
                        print(clr(f"\n  {legion.name} улучшен на {done} уровн. Качество: {legion.quality}/10", C.GREEN))
                        if done < levels:
                            print(clr("  Хватило золота не на все выбранные уровни.", C.GOLD))
                        log_event(player, f"{legion.name} натренирован на {done} уровн.")
                    else:
                        need = min(levels, max_levels) * train_cost
                        print(clr(f"\n  Недостаточно золота. Нужно до {need}, есть {player.gold}.", C.RED))

    elif ch == "M":
        upgraded = train_all_legions_once(player)
        if upgraded:
            print(clr(f"\n  Массовые учения завершены: улучшено легионов — {upgraded}.", C.GREEN))
            log_event(player, f"Массовые учения: улучшено легионов {upgraded}")
        else:
            print(clr("\n  Некого улучшать или не хватает золота.", C.RED))

    elif ch == "D":
        for i, l in enumerate(player.legions):
            print(f"  {i+1}. {l.name}")
        li_valid = [str(i + 1) for i in range(len(player.legions))] + ["Q"]
        li = read_choice(f"{clr('  Распустить какой легион (или Q — отменить): ', C.CYAN)}", li_valid)
        if li != "Q":
            removed = player.legions.pop(int(li) - 1)
            player.gold += refund
            print(clr(f"\n  {removed.name} распущен. +{refund} золота.", C.GOLD))
            log_event(player, f"{removed.name} распущен")

    pause()

