def _foreign_default_trust(disposition: int) -> int:
    return max(0, min(100, disposition - 8))


def ensure_external_policy_state(player: "Player"):
    """Миграция старой дипломатии в систему Consilium Externum.

    Сохраняет совместимость со старыми сейвами и прежними полями alliance,
    trade_pact, tribute, client и casus_belli, которые уже используются
    экономикой и условиями победы.
    """
    if not hasattr(player, "diplomacy") or not isinstance(player.diplomacy, dict):
        player.diplomacy = {}

    base_by_key = {p["key"]: p for p in DIPLOMATIC_POWERS}
    for key, base in base_by_key.items():
        row = player.diplomacy.get(key) if isinstance(player.diplomacy.get(key), dict) else {}
        profile = DIPLOMATIC_POWER_PROFILES.get(key, {})
        disposition = safe_int(row.get("disposition", base["disposition"]), base["disposition"], 0, 100)
        hostility = safe_int(row.get("hostility", profile.get("hostility", 50)), profile.get("hostility", 50), 0, 100)
        row.update({
            "name": str(row.get("name") or base["name"]),
            "disposition": disposition,
            "strength": safe_int(row.get("strength", base["strength"]), base["strength"], 1, 20),
            "wealth": safe_int(row.get("wealth", profile.get("wealth", 50)), profile.get("wealth", 50), 0, 100),
            "trade_interest": safe_int(row.get("trade_interest", profile.get("trade_interest", 50)), profile.get("trade_interest", 50), 0, 100),
            "hostility": hostility,
            "fear": safe_int(row.get("fear", 10), 10, 0, 100),
            "trust": safe_int(row.get("trust", _foreign_default_trust(disposition)), _foreign_default_trust(disposition), 0, 100),
            "tension": safe_int(row.get("tension", max(0, hostility - disposition // 2)), max(0, hostility - disposition // 2), 0, 100),
            "intel": safe_int(row.get("intel", 20), 20, 0, 100),
            "leverage": safe_int(row.get("leverage", 0), 0, 0, 100),
            "status": str(row.get("status") or profile.get("status", "нейтральная держава")),
            "alliance": bool(row.get("alliance", False)),
            "trade_pact": bool(row.get("trade_pact", False)),
            "non_aggression": bool(row.get("non_aggression", False)),
            "client": bool(row.get("client", False)),
            "casus_belli": bool(row.get("casus_belli", False)),
            "war_approved": bool(row.get("war_approved", False)),
            "hostage_exchanged": bool(row.get("hostage_exchanged", False)),
            "married": bool(row.get("married", False)),
            "tribute": safe_int(row.get("tribute", 0), 0, -999, 999),
            "mission_cooldown": safe_int(row.get("mission_cooldown", 0), 0, 0, 99),
            "last_policy_event_turn": safe_int(row.get("last_policy_event_turn", 0), 0, 0),
            "last_contact_turn": safe_int(row.get("last_contact_turn", 0), 0, 0),
            "casus_belli_turn": safe_int(row.get("casus_belli_turn", 0), 0, 0),
            "war_approved_turn": safe_int(row.get("war_approved_turn", 0), 0, 0),
            "trade_pact_turn": safe_int(row.get("trade_pact_turn", 0), 0, 0),
            "non_aggression_turn": safe_int(row.get("non_aggression_turn", 0), 0, 0),
            "alliance_turn": safe_int(row.get("alliance_turn", 0), 0, 0),
            "client_turn": safe_int(row.get("client_turn", 0), 0, 0),
            "tribute_turn": safe_int(row.get("tribute_turn", 0), 0, 0),
        })
        player.diplomacy[key] = row

    for key, row in list(player.diplomacy.items()):
        if not isinstance(row, dict):
            player.diplomacy.pop(key, None)
            continue
        row.setdefault("name", key)
        row.setdefault("disposition", 45)
        row.setdefault("strength", 5)
        row.setdefault("wealth", 50)
        row.setdefault("trade_interest", 50)
        row.setdefault("hostility", 50)
        row.setdefault("fear", 10)
        row.setdefault("trust", _foreign_default_trust(safe_int(row.get("disposition", 45), 45, 0, 100)))
        row.setdefault("tension", 25)
        row.setdefault("intel", 20)
        row.setdefault("leverage", 0)
        row.setdefault("status", "держава")
        row.setdefault("alliance", False)
        row.setdefault("trade_pact", False)
        row.setdefault("non_aggression", False)
        row.setdefault("client", False)
        row.setdefault("casus_belli", False)
        row.setdefault("war_approved", False)
        row.setdefault("tribute", 0)
        row.setdefault("mission_cooldown", 0)
        row.setdefault("last_policy_event_turn", 0)
        row.setdefault("last_contact_turn", 0)
        row.setdefault("casus_belli_turn", 0)
        row.setdefault("war_approved_turn", 0)
        row.setdefault("trade_pact_turn", 0)
        row.setdefault("non_aggression_turn", 0)
        row.setdefault("alliance_turn", 0)
        row.setdefault("client_turn", 0)
        row.setdefault("tribute_turn", 0)

    state = getattr(player, "foreign_policy", None)
    if not isinstance(state, dict):
        state = {}
    doctrine = str(state.get("doctrine", "balance"))
    if doctrine not in FOREIGN_POLICY_DOCTRINES:
        doctrine = "balance"
    state["doctrine"] = doctrine
    state["doctrine_selected"] = bool(state.get("doctrine_selected", state.get("doctrine_changed_turn", 0) > 0))
    doctrine_cap = safe_int(FOREIGN_POLICY_DOCTRINES[doctrine].get("capital_max", 6), 6, 3, 12)
    state["capital_max"] = doctrine_cap
    state["capital"] = safe_int(state.get("capital", 3), 3, 0, doctrine_cap)
    clean_missions = []
    for mission in safe_list(state.get("active_missions", [])):
        if not isinstance(mission, dict) or mission.get("type") not in FOREIGN_MISSIONS or mission.get("target") not in player.diplomacy:
            continue
        mdef = FOREIGN_MISSIONS[mission["type"]]
        mission["remaining"] = safe_int(mission.get("remaining", mdef["duration"]), mdef["duration"], 1, 99)
        mission["started_turn"] = safe_int(mission.get("started_turn", getattr(player, "turn", 1)), getattr(player, "turn", 1), 0)
        mission["chance"] = safe_int(mission.get("chance", mdef["base_chance"]), mdef["base_chance"], 5, 95)
        clean_missions.append(mission)
    state["active_missions"] = clean_missions
    state["dispatches"] = [x for x in safe_list(state.get("dispatches", [])) if isinstance(x, dict)][-30:]
    state["crises"] = [x for x in safe_list(state.get("crises", [])) if isinstance(x, dict)][-8:]
    state["last_tick_turn"] = safe_int(state.get("last_tick_turn", 0), 0, 0)
    state["last_crisis_turn"] = safe_int(state.get("last_crisis_turn", 0), 0, 0)
    state["doctrine_changed_turn"] = safe_int(state.get("doctrine_changed_turn", 0), 0, 0)
    state["global_tension"] = safe_int(state.get("global_tension", 0), 0, 0, 100)
    player.foreign_policy = state
    return player.diplomacy


def _foreign_dispatch(player: "Player", title: str, text: str, target: str | None = None, tone: str = "info") -> None:
    ensure_external_policy_state(player)
    record = {
        "turn": safe_int(getattr(player, "turn", 1), 1, 1),
        "title": str(title),
        "text": str(text),
        "target": target,
        "tone": tone,
    }
    player.foreign_policy["dispatches"].append(record)
    player.foreign_policy["dispatches"] = player.foreign_policy["dispatches"][-30:]
    log_event(player, f"Внешняя политика: {title}")
    if hasattr(player, "turn_summary") and isinstance(player.turn_summary, list):
        player.turn_summary.append(f"{title}: {text}")


def _rome_pressure(player: "Player") -> int:
    legion_power = sum(
        safe_int(getattr(l, "strength", 0), 0) + safe_int(getattr(l, "quality", 0), 0) * 5
        for l in getattr(player, "legions", [])
    )
    province_power = len(getattr(player, "provinces", [])) * 3
    glory_pressure = safe_int(getattr(player, "glory", 0), 0) // 70
    morale_pressure = max(0, safe_int(getattr(player, "morale", 70), 70) - 50) // 3
    fp_state = getattr(player, "foreign_policy", {}) if isinstance(getattr(player, "foreign_policy", {}), dict) else {}
    doctrine = FOREIGN_POLICY_DOCTRINES.get(str(fp_state.get("doctrine", "balance")), {})
    doctrine_pressure = safe_int(doctrine.get("pressure_bonus", 0), 0)
    return min(100, legion_power // 7 + province_power + glory_pressure + morale_pressure + doctrine_pressure)


def _foreign_posture(row: dict) -> str:
    if row.get("client"):
        return "клиент"
    if row.get("alliance"):
        return "союзник"
    if row.get("war_approved"):
        return "война разрешена"
    if row.get("casus_belli") and safe_int(row.get("tension", 0), 0) >= 60:
        return "на грани войны"
    if safe_int(row.get("tension", 0), 0) >= 75:
        return "кризис"
    if safe_int(row.get("disposition", 0), 0) >= 70 and safe_int(row.get("trust", 0), 0) >= 60:
        return "дружественная"
    if row.get("trade_pact"):
        return "торговый партнёр"
    if row.get("non_aggression"):
        return "сдержанный мир"
    if safe_int(row.get("disposition", 0), 0) <= 25:
        return "враждебная"
    return row.get("status", "нейтральная")


def _foreign_status(row: dict) -> str:
    tags = [_foreign_posture(row)]
    if row.get("trade_pact") and "торгов" not in tags[0]:
        tags.append("торговый договор")
    if row.get("non_aggression"):
        tags.append("пакт о ненападении")
    if row.get("casus_belli"):
        tags.append("casus belli")
    tribute = safe_int(row.get("tribute", 0), 0)
    if tribute > 0:
        tags.append(f"дань +{tribute}")
    elif tribute < 0:
        tags.append(f"Рим платит {-tribute}")
    return ", ".join(tags)


def _foreign_intel_value(row: dict, key: str) -> str:
    intel = safe_int(row.get("intel", 0), 0, 0, 100)
    value = safe_int(row.get(key, 0), 0)
    if intel >= 70:
        return str(value)
    if intel >= 40:
        low = max(0, value - 1 if key == "strength" else value - 10)
        high = value + 1 if key == "strength" else min(100, value + 10)
        return f"{low}–{high}"
    if key == "strength":
        return "высокая" if value >= 7 else "средняя" if value >= 4 else "малая"
    return "высокое" if value >= 70 else "среднее" if value >= 40 else "низкое"


def _selected_power(player: "Player") -> tuple[str | None, dict | None]:
    ensure_external_policy_state(player)
    keys = list(player.diplomacy.keys())
    rui_screen_start()
    rui_header("ДИПЛОМАТИЧЕСКИЕ ДОСЬЕ", "🗺", C.CYAN)
    rows = []
    for i, key in enumerate(keys, 1):
        d = player.diplomacy[key]
        rows.append((
            str(i), d["name"], str(d["disposition"]),
            str(d["tension"]), _foreign_posture(d),
        ))
    rui_table("Иностранные державы", ["#", "Держава", "Отн.", "Напр.", "Позиция"], rows, color=C.CYAN)
    valid = [str(i) for i in range(1, len(keys) + 1)] + ["Q"]
    ch = read_choice(f"\n{clr('  Выберите державу (или Q): ', C.CYAN)}", valid)
    if ch == "Q":
        return None, None
    key = keys[int(ch) - 1]
    return key, player.diplomacy[key]


def _senate_vote_for_external_policy(player: "Player", d: dict, policy: str) -> tuple[bool, list[tuple[str, str]]]:
    ensure_republic_overhaul_state(player)
    parties = player.v24["senate_parties"]
    votes = []
    for key, party in parties.items():
        influence = safe_int(party.get("influence", 25), 25)
        score = influence // 10 + random.randint(1, 12)
        if policy == "war":
            if key == "militares": score += 6
            if key == "mercatores" and d.get("trade_pact"): score -= 5
            if key == "optimates" and player.senate_rep >= 60: score += 3
            score += safe_int(d.get("tension", 0), 0) // 20
            if d.get("casus_belli"): score += 3
        elif policy == "client":
            if key in ("optimates", "mercatores"): score += 4
            score += safe_int(d.get("leverage", 0), 0) // 25
        elif policy == "trade":
            if key == "mercatores": score += 7
            if key == "militares": score -= 2
            score += safe_int(d.get("trade_interest", 0), 0) // 30
        elif policy == "alliance":
            if key == "optimates": score += 4
            if key == "militares" and d.get("strength", 0) >= 6: score += 3
            score += safe_int(d.get("trust", 0), 0) // 25
        vote = "за" if score >= 10 else "против"
        votes.append((party.get("name", key), vote))
    yes = sum(1 for _, vote in votes if vote == "за")
    return yes >= max(1, (len(votes) + 1) // 2), votes


def _print_external_vote(votes: list[tuple[str, str]], passed: bool) -> None:
    print(clr("\n  Голоса сенатских фракций:", C.GOLD))
    for name, vote in votes:
        color = C.GREEN if vote == "за" else C.RED
        print(f"    {name}: {clr(vote, color)}")
    print(clr("  Решение принято." if passed else "  Решение отклонено.", C.GREEN if passed else C.RED))


def _foreign_doctrine(player: "Player") -> dict:
    ensure_external_policy_state(player)
    return FOREIGN_POLICY_DOCTRINES[player.foreign_policy["doctrine"]]


def _mission_active_for_target(player: "Player", key: str) -> bool:
    return any(m.get("target") == key for m in player.foreign_policy.get("active_missions", []))


def _mission_success_chance(player: "Player", mission_type: str, d: dict) -> int:
    mission = FOREIGN_MISSIONS[mission_type]
    doctrine = _foreign_doctrine(player)
    chance = mission["base_chance"]
    chance += safe_int(doctrine.get("mission_bonus", {}).get(mission_type, 0), 0)
    chance += safe_int(tech_effect(player, "diplomacy_bonus", 0), 0) // 2
    chance += max(-12, min(12, (safe_int(d.get("trust", 50), 50) - 50) // 4))
    chance += safe_int(d.get("intel", 0), 0) // 12
    chance -= safe_int(d.get("tension", 0), 0) // 10
    if mission_type in ("intimidation", "provocation"):
        chance += (_rome_pressure(player) - safe_int(d.get("strength", 5), 5) * 7) // 4
        chance += safe_int(d.get("fear", 0), 0) // 10
        chance -= safe_int(d.get("trust", 0), 0) // 12
    if mission_type == "commercial":
        chance += safe_int(d.get("trade_interest", 0), 0) // 10
    if mission_type == "court":
        chance += safe_int(d.get("leverage", 0), 0) // 10
    return max(15, min(95, chance))


def _commit_foreign_mission(player: "Player", key: str, mission_type: str) -> tuple[bool, str]:
    """Ядро запуска миссии без интерфейса; удобно для сейвов и self-test."""
    ensure_external_policy_state(player)
    if key not in player.diplomacy:
        return False, "Неизвестная держава"
    if mission_type not in FOREIGN_MISSIONS:
        return False, "Неизвестный тип миссии"
    d = player.diplomacy[key]
    doctrine = _foreign_doctrine(player)
    if _mission_active_for_target(player, key):
        return False, "В этой державе уже действует римская миссия"
    if len(player.foreign_policy["active_missions"]) >= safe_int(doctrine.get("max_missions", 2), 2):
        return False, "Канцелярия уже ведёт предельное число миссий"
    if safe_int(d.get("mission_cooldown", 0), 0) > 0:
        return False, f"Нужно выждать ещё {d['mission_cooldown']} ход."

    mission = FOREIGN_MISSIONS[mission_type]
    mission_gold = game_price(player, mission["gold"], market=True)
    if player.gold < mission_gold:
        return False, f"Нужно {mission_gold} золота"
    if player.foreign_policy["capital"] < mission["capital"]:
        return False, f"Нужно {mission['capital']} дипломатический капитал"

    # Шанс вычисляется до добавления записи: helper нормализует state.
    chance = _mission_success_chance(player, mission_type, d)
    player.gold -= mission_gold
    player.foreign_policy["capital"] -= mission["capital"]
    player.foreign_policy["active_missions"].append({
        "type": mission_type,
        "target": key,
        "remaining": mission["duration"],
        "started_turn": player.turn,
        "chance": chance,
    })
    d["last_contact_turn"] = player.turn
    _foreign_dispatch(player, "Миссия отправлена", f"{mission['name']} направлена в державу {d['name']}.", key)
    return True, f"Миссия начата. Срок: {mission['duration']} ход. Шанс: {chance}%."


def launch_foreign_mission(player: "Player", key: str, d: dict) -> None:
    ensure_external_policy_state(player)
    rui_screen_start()
    rui_header(f"ДИПЛОМАТИЧЕСКАЯ МИССИЯ: {d['name']}", "📜", C.CYAN)
    rows = []
    keys = list(FOREIGN_MISSIONS.keys())
    for i, mission_type in enumerate(keys, 1):
        mission = FOREIGN_MISSIONS[mission_type]
        chance = _mission_success_chance(player, mission_type, d)
        mission_gold = game_price(player, mission["gold"], market=True)
        rows.append((str(i), mission["name"], f"{mission['duration']} х.", f"{mission_gold}💰/{mission['capital']} ДК", f"{chance}%", mission["desc"]))
    rui_table("Доступные операции", ["#", "Миссия", "Срок", "Цена", "Шанс", "Результат"], rows, color=C.CYAN)
    valid = [str(i) for i in range(1, len(keys) + 1)] + ["Q"]
    ch = read_choice(f"\n{clr('  Выбор (или Q): ', C.CYAN)}", valid)
    if ch == "Q":
        return
    mission_type = keys[int(ch) - 1]
    ok, message = _commit_foreign_mission(player, key, mission_type)
    print(clr(f"  {message}", C.GREEN if ok else C.RED))
    pause()


def _apply_foreign_mission_result(player: "Player", mission_data: dict) -> None:
    mission_type = mission_data.get("type")
    key = mission_data.get("target")
    if mission_type not in FOREIGN_MISSIONS or key not in player.diplomacy:
        return
    d = player.diplomacy[key]
    mission = FOREIGN_MISSIONS[mission_type]
    stored_chance = mission_data.get("chance")
    if stored_chance is None:
        stored_chance = _mission_success_chance(player, mission_type, d)
    chance = safe_int(stored_chance, 50, 0, 100)
    success = random.randint(1, 100) <= chance
    d["mission_cooldown"] = 1

    if success:
        if mission_type == "embassy":
            d["disposition"] = min(100, d["disposition"] + 12)
            d["trust"] = min(100, d["trust"] + 9)
            d["intel"] = min(100, d["intel"] + 12)
            text = "+12 отношения, +9 доверия, +12 разведки"
        elif mission_type == "commercial":
            d["trade_interest"] = min(100, d["trade_interest"] + 18)
            d["disposition"] = min(100, d["disposition"] + 6)
            d["trust"] = min(100, d["trust"] + 5)
            if d["trade_interest"] >= 80 and d["trust"] >= 50 and not d.get("trade_pact"):
                d["leverage"] = min(100, d["leverage"] + 8)
                text = "+18 торгового интереса; договор подготовлен к ратификации"
            else:
                text = "+18 торгового интереса, +6 отношения"
        elif mission_type == "intelligence":
            gain = random.randint(24, 36)
            d["intel"] = min(100, d["intel"] + gain)
            d["leverage"] = min(100, d["leverage"] + 6)
            text = f"+{gain} разведки, +6 рычагов влияния"
        elif mission_type == "court":
            gain = random.randint(16, 24)
            d["leverage"] = min(100, d["leverage"] + gain)
            d["trust"] = min(100, d["trust"] + 7)
            d["disposition"] = min(100, d["disposition"] + 5)
            text = f"+{gain} рычагов влияния, +7 доверия"
        elif mission_type == "mediation":
            d["tension"] = max(0, d["tension"] - 20)
            d["disposition"] = min(100, d["disposition"] + 7)
            d["trust"] = min(100, d["trust"] + 5)
            text = "−20 напряжённости, +7 отношения"
        elif mission_type == "intimidation":
            d["fear"] = min(100, d["fear"] + 17)
            d["leverage"] = min(100, d["leverage"] + 10)
            d["tension"] = min(100, d["tension"] + 9)
            d["trust"] = max(0, d["trust"] - 5)
            text = "+17 страха, +10 рычагов, +9 напряжённости"
        else:  # provocation
            d["casus_belli"] = True
            d["tension"] = min(100, d["tension"] + 16)
            d["hostility"] = min(100, d["hostility"] + 10)
            player.senate_rep = max(0, player.senate_rep - 2)
            text = "получен casus belli; Сенат −2"
        _foreign_dispatch(player, f"Миссия завершена: {mission['name']}", f"{d['name']}: успех — {text}.", key, "good")
        print(clr(f"\n  🕊 {mission['name']} в державе {d['name']}: успех ({text}).", C.GREEN))
    else:
        if mission_type in ("intimidation", "provocation"):
            d["disposition"] = max(0, d["disposition"] - 12)
            d["trust"] = max(0, d["trust"] - 10)
            d["tension"] = min(100, d["tension"] + 15)
            player.senate_rep = max(0, player.senate_rep - 3)
            text = "агенты раскрыты; отношение −12, напряжённость +15"
        else:
            d["disposition"] = max(0, d["disposition"] - 4)
            d["trust"] = max(0, d["trust"] - 5)
            d["intel"] = min(100, d["intel"] + 4)
            text = "переговоры сорваны; доверие −5"
        _foreign_dispatch(player, f"Провал миссии: {mission['name']}", f"{d['name']}: {text}.", key, "bad")
        print(clr(f"\n  ⚠ {mission['name']} в державе {d['name']}: провал ({text}).", C.RED))


def choose_foreign_doctrine(player: "Player") -> None:
    ensure_external_policy_state(player)
    state = player.foreign_policy
    current = state["doctrine"]
    initial_adoption = not bool(state.get("doctrine_selected", False))
    cooldown = 0 if initial_adoption else max(0, 5 - (player.turn - state["doctrine_changed_turn"]))
    rui_screen_start()
    rui_header("ВНЕШНЕПОЛИТИЧЕСКАЯ ДОКТРИНА", "🏛", C.GOLD)
    rows = []
    keys = list(FOREIGN_POLICY_DOCTRINES.keys())
    for i, key in enumerate(keys, 1):
        doctrine = FOREIGN_POLICY_DOCTRINES[key]
        marker = "временный курс" if key == current and initial_adoption else "текущая" if key == current else ""
        rows.append((
            str(i), doctrine["name"], f"+{doctrine['capital_regen']}/{doctrine['capital_max']} ДК",
            str(doctrine["max_missions"]), marker,
        ))
    rui_table("Курс Рима", ["#", "Доктрина", "ДК: ход/лимит", "Миссии", "Статус"], rows, color=C.GOLD)
    for i, key in enumerate(keys, 1):
        ui_wrap(f"{i}. {FOREIGN_POLICY_DOCTRINES[key]['passive']}", color=C.GRAY)
    ui_wrap(FOREIGN_POLICY_DOCTRINES[current]["desc"], color=C.CYAN)
    if initial_adoption:
        rui_info("Первое утверждение доктрины бесплатно. До решения действует временный курс равновесия.", C.GREEN)
    elif cooldown:
        rui_info(f"Смена курса будет доступна через {cooldown} ход.", C.RED)
    ch = read_choice(f"\n{clr('  Выбор (или Q): ', C.CYAN)}", [str(i) for i in range(1, len(keys) + 1)] + ["Q"])
    if ch == "Q":
        return
    new_key = keys[int(ch) - 1]
    if not initial_adoption and new_key == current:
        print(clr("  Эта доктрина уже действует.", C.GOLD)); pause(); return
    if cooldown:
        print(clr("  Канцелярия ещё не завершила перестройку прежнего курса.", C.RED)); pause(); return

    gold_cost = 0 if initial_adoption else game_price(player, 80, market=True)
    capital_cost = 0 if initial_adoption else 1
    if player.gold < gold_cost or state["capital"] < capital_cost:
        print(clr(f"  Смена курса требует {gold_cost} золота и {capital_cost} дипломатический капитал.", C.RED)); pause(); return
    player.gold -= gold_cost
    state["capital"] -= capital_cost
    state["doctrine"] = new_key
    state["doctrine_selected"] = True
    state["doctrine_changed_turn"] = player.turn
    state["capital_max"] = safe_int(FOREIGN_POLICY_DOCTRINES[new_key].get("capital_max", 6), 6, 3, 12)
    state["capital"] = min(state["capital"], state["capital_max"])
    _foreign_dispatch(player, "Новая внешнеполитическая доктрина", FOREIGN_POLICY_DOCTRINES[new_key]["name"], tone="info")
    print(clr(f"  Принят курс: {FOREIGN_POLICY_DOCTRINES[new_key]['name']}.", C.GREEN))
    pause()


def _set_casus_belli(player: "Player", d: dict, enabled: bool = True) -> None:
    d["casus_belli"] = bool(enabled)
    d["casus_belli_turn"] = safe_int(getattr(player, "turn", 1), 1, 0) if enabled else 0
    if not enabled:
        d["war_approved"] = False
        d["war_approved_turn"] = 0


def _set_war_approved(player: "Player", d: dict, enabled: bool = True) -> None:
    d["war_approved"] = bool(enabled)
    d["war_approved_turn"] = safe_int(getattr(player, "turn", 1), 1, 0) if enabled else 0
    if enabled:
        _set_casus_belli(player, d, True)


def _spend_diplomatic_capital(player: "Player", amount: int) -> bool:
    ensure_external_policy_state(player)
    if player.foreign_policy["capital"] < amount:
        print(clr(f"  Требуется дипломатический капитал: {amount}.", C.RED))
        return False
    player.foreign_policy["capital"] -= amount
    return True


def negotiate_trade_pact(player: "Player", key: str, d: dict) -> None:
    if d.get("trade_pact"):
        print(clr("  Торговый договор уже действует.", C.GOLD)); pause(); return
    if d["disposition"] < 40 or d["trust"] < 30 or d["trade_interest"] < 45:
        print(clr("  Пока нет основы для договора: нужны отношения 40, доверие 30 и торговый интерес 45.", C.RED)); pause(); return
    if not _spend_diplomatic_capital(player, 1): pause(); return
    passed, votes = _senate_vote_for_external_policy(player, d, "trade")
    _print_external_vote(votes, passed)
    acceptance = d["disposition"] + d["trust"] + d["trade_interest"] + d["leverage"] // 2 - d["tension"]
    if passed and acceptance >= 125:
        d["trade_pact"] = True
        d["trade_pact_turn"] = player.turn
        d["trust"] = min(100, d["trust"] + 8)
        d["tension"] = max(0, d["tension"] - 5)
        _foreign_dispatch(player, "Торговый договор", f"С {d['name']} открыт постоянный рынок.", key, "good")
        print(clr("  Договор ратифицирован обеими сторонами.", C.GREEN))
    else:
        d["trust"] = max(0, d["trust"] - 3)
        print(clr("  Договор не прошёл ратификацию или был отвергнут иностранным двором.", C.RED))
    pause()


def negotiate_non_aggression(player: "Player", key: str, d: dict) -> None:
    if d.get("non_aggression") or d.get("alliance"):
        print(clr("  Мирные обязательства уже действуют.", C.GOLD)); pause(); return
    if d["disposition"] < 42 or d["trust"] < 35 or d["tension"] > 60:
        print(clr("  Требуются отношения 42, доверие 35 и напряжённость не выше 60.", C.RED)); pause(); return
    if not _spend_diplomatic_capital(player, 1): pause(); return
    score = d["disposition"] + d["trust"] + d["fear"] // 2 - d["tension"]
    if score >= 85 or random.randint(1, 100) <= max(20, min(90, score)):
        d["non_aggression"] = True
        d["non_aggression_turn"] = player.turn
        d["trust"] = min(100, d["trust"] + 10)
        d["tension"] = max(0, d["tension"] - 12)
        _foreign_dispatch(player, "Пакт о ненападении", f"Рим и {d['name']} обязались не прибегать к войне.", key, "good")
        print(clr("  Пакт заключён.", C.GREEN))
    else:
        d["tension"] = min(100, d["tension"] + 4)
        print(clr("  Иностранный двор отказался связывать себе руки.", C.RED))
    pause()


def propose_alliance(player: "Player", key: str, d: dict) -> None:
    if d.get("alliance"):
        print(clr("  Союз уже заключён.", C.GOLD)); pause(); return
    if d["disposition"] < 68 or d["trust"] < 60 or d["tension"] > 35:
        print(clr("  Для союза нужны отношения 68, доверие 60 и напряжённость не выше 35.", C.RED)); pause(); return
    if not _spend_diplomatic_capital(player, 2): pause(); return
    passed, votes = _senate_vote_for_external_policy(player, d, "alliance")
    _print_external_vote(votes, passed)
    if passed:
        d["alliance"] = True
        d["alliance_turn"] = player.turn
        d["non_aggression"] = True
        d["non_aggression_turn"] = player.turn
        d["trust"] = min(100, d["trust"] + 12)
        d["tension"] = max(0, d["tension"] - 15)
        _set_casus_belli(player, d, False)
        player.glory += 25
        _foreign_dispatch(player, "Союзный договор", f"{d['name']} вступает в союз с Римом.", key, "good")
        print(clr("  Союз скреплён клятвами. Слава +25.", C.GREEN))
    else:
        print(clr("  Сенат не поддержал союз.", C.RED))
    pause()


def make_client_kingdom(player: "Player", key: str, d: dict) -> None:
    if d.get("client"):
        print(clr("  Эта держава уже является клиентом Рима.", C.GOLD)); pause(); return
    if d["disposition"] < 45 or d["fear"] < 45 or d["leverage"] < 35:
        print(clr("  Для клиентелы нужны отношения 45, страх 45 и рычаги влияния 35.", C.RED)); pause(); return
    if not _spend_diplomatic_capital(player, 2): pause(); return
    passed, votes = _senate_vote_for_external_policy(player, d, "client")
    _print_external_vote(votes, passed)
    pressure = _rome_pressure(player) + d["fear"] + d["leverage"] - d["strength"] * 7
    if passed and pressure >= 75:
        d["client"] = True
        d["client_turn"] = player.turn
        d["alliance"] = True
        d["alliance_turn"] = player.turn
        d["non_aggression"] = True
        d["non_aggression_turn"] = player.turn
        _set_casus_belli(player, d, False)
        d["tribute"] = max(10, d["wealth"] // 5)
        d["tribute_turn"] = player.turn
        d["trust"] = min(100, d["trust"] + 5)
        d["tension"] = max(0, d["tension"] - 10)
        player.glory += 45
        _foreign_dispatch(player, "Клиентское царство", f"{d['name']} признаёт верховенство Рима и платит {d['tribute']} золота за ход.", key, "good")
        print(clr(f"  Держава стала клиентом. Дань: {d['tribute']} золота за ход.", C.GREEN))
    else:
        d["tension"] = min(100, d["tension"] + 8)
        d["trust"] = max(0, d["trust"] - 7)
        print(clr("  Попытка навязать клиентелу вызвала сопротивление.", C.RED))
    pause()


def demand_tribute(player: "Player", key: str, d: dict) -> None:
    if d.get("alliance") and not d.get("client"):
        print(clr("  Требование дани разрушит союз; сперва разорвите договоры.", C.RED)); pause(); return
    if not _spend_diplomatic_capital(player, 1): pause(); return
    score = _rome_pressure(player) + d["fear"] + d["leverage"] - d["strength"] * 8 - d["trust"] // 2
    if score >= 65:
        amount = max(5, d["wealth"] // 7)
        d["tribute"] = max(d.get("tribute", 0), amount)
        d["tribute_turn"] = player.turn
        d["fear"] = min(100, d["fear"] + 8)
        d["trust"] = max(0, d["trust"] - 12)
        d["tension"] = min(100, d["tension"] + 12)
        _foreign_dispatch(player, "Дань навязана", f"{d['name']} обязалась платить {amount} золота за ход.", key, "good")
        print(clr(f"  Ультиматум принят. Дань: {amount} золота за ход.", C.GREEN))
    else:
        d["disposition"] = max(0, d["disposition"] - 12)
        d["tension"] = min(100, d["tension"] + 18)
        _set_casus_belli(player, d, True)
        _foreign_dispatch(player, "Ультиматум отвергнут", f"{d['name']} отказалась платить дань; возник casus belli.", key, "bad")
        print(clr("  Требование отвергнуто. Напряжённость резко выросла; получен casus belli.", C.RED))
    pause()


def ask_senate_for_war(player: "Player", key: str, d: dict) -> None:
    if d.get("alliance"):
        print(clr("  Нельзя просить войну против действующего союзника.", C.RED)); pause(); return
    if not (d.get("casus_belli") or d["tension"] >= 70):
        print(clr("  Сенат требует casus belli либо напряжённость не ниже 70.", C.RED)); pause(); return
    passed, votes = _senate_vote_for_external_policy(player, d, "war")
    _print_external_vote(votes, passed)
    if passed:
        _set_war_approved(player, d, True)
        player.morale = min(100, player.morale + 3)
        player.senate_rep = min(100, player.senate_rep + 2)
        _foreign_dispatch(player, "Сенат разрешил войну", f"Против державы {d['name']} разрешено силовое решение.", key, "bad")
        print(clr("  Сенат разрешает войну. Мораль +3.", C.GREEN))
    else:
        player.senate_rep = max(0, player.senate_rep - 3)
        print(clr("  Сенат отказал в объявлении войны.", C.RED))
    pause()


def request_foreign_aid(player: "Player", key: str, d: dict) -> None:
    if not (d.get("alliance") or d.get("client")):
        print(clr("  Помощь можно просить только у союзника или клиента.", C.RED)); pause(); return
    if d["trust"] < 45:
        print(clr("  Союзник не доверяет Риму достаточно для новой просьбы.", C.RED)); pause(); return
    if not _spend_diplomatic_capital(player, 1): pause(); return
    gift_type = DIPLOMATIC_POWER_PROFILES.get(key, {}).get("gift", "gold")
    if gift_type == "grain":
        amount = random.randint(55, 95); player.grain += amount; aid = f"+{amount} зерна"
    elif gift_type == "science":
        amount = random.randint(20, 35); player.science_points += amount; aid = f"+{amount} науки"
    elif gift_type == "aux":
        amount = random.randint(45, 75); player.gold += amount; aid = f"+{amount} золота на ауксилии"
    elif gift_type == "metals":
        metal = random.choice(list(METAL_TYPES)); player.metals[metal] = player.metals.get(metal, 0) + 1; aid = f"+1 {METAL_NAMES[metal]}"
    else:
        amount = random.randint(45, 85); player.gold += amount; aid = f"+{amount} золота"
    d["trust"] = max(0, d["trust"] - 10)
    d["leverage"] = max(0, d["leverage"] - 5)
    _foreign_dispatch(player, "Союзная помощь", f"{d['name']} передаёт Риму {aid}.", key, "good")
    print(clr(f"  Союзник помогает: {aid}. Доверие −10.", C.GREEN))
    pause()


def break_foreign_treaties(player: "Player", key: str, d: dict) -> None:
    if not any((d.get("alliance"), d.get("trade_pact"), d.get("non_aggression"), d.get("client"), d.get("tribute", 0))):
        print(clr("  Между сторонами нет действующих обязательств.", C.GOLD)); pause(); return
    print(clr("  Разрыв договоров ухудшит доверие и повысит напряжённость.", C.RED))
    if read_choice(f"  {clr('Разорвать все обязательства? (Y/N): ', C.CYAN)}", ["Y", "N"]) != "Y":
        return
    d["alliance"] = False
    d["trade_pact"] = False
    d["non_aggression"] = False
    d["client"] = False
    d["tribute"] = 0
    d["alliance_turn"] = 0
    d["trade_pact_turn"] = 0
    d["non_aggression_turn"] = 0
    d["client_turn"] = 0
    d["tribute_turn"] = 0
    d["trust"] = max(0, d["trust"] - 25)
    d["disposition"] = max(0, d["disposition"] - 15)
    d["tension"] = min(100, d["tension"] + 20)
    player.senate_rep = max(0, player.senate_rep - 3)
    _foreign_dispatch(player, "Договоры разорваны", f"Рим отказался от обязательств перед державой {d['name']}.", key, "bad")
    pause()


def foreign_treaty_menu(player: "Player", key: str, d: dict) -> None:
    while True:
        rui_screen_start()
        rui_header(f"ДОГОВОРЫ: {d['name']}", "🤝", C.GOLD)
        rui_info(f"Статус: {_foreign_status(d)}", C.CYAN)
        rui_info(f"Отношение {d['disposition']} • Доверие {d['trust']} • Страх {d['fear']} • Напряжение {d['tension']} • Рычаги {d['leverage']}", C.WHITE)
        rui_menu([
            ("1", "Торговый договор", "рынки и пассивный доход", "⚱"),
            ("2", "Пакт о ненападении", "снижает напряжение и риск кризиса", "🕊"),
            ("3", "Союзный договор", "требует высокого доверия", "🤝"),
            ("4", "Установить клиентелу", "страх + влияние + одобрение Сената", "👑"),
            ("5", "Потребовать дань", "ультиматум, риск войны", "⚔"),
            ("6", "Просить союзную помощь", "только союзник или клиент", "🎁"),
            ("7", "Просить Сенат о войне", "casus belli или высокий кризис", "🏛"),
            ("8", "Разорвать договоры", "обнулить обязательства", "✂"),
            ("Q", "Назад", "", "↩"),
        ], title="Договорная канцелярия")
        ch = read_choice(f"\n{clr('  Решение: ', C.CYAN)}", ["1","2","3","4","5","6","7","8","Q"])
        if ch == "Q": return
        if ch == "1": negotiate_trade_pact(player, key, d)
        elif ch == "2": negotiate_non_aggression(player, key, d)
        elif ch == "3": propose_alliance(player, key, d)
        elif ch == "4": make_client_kingdom(player, key, d)
        elif ch == "5": demand_tribute(player, key, d)
        elif ch == "6": request_foreign_aid(player, key, d)
        elif ch == "7": ask_senate_for_war(player, key, d)
        elif ch == "8": break_foreign_treaties(player, key, d)


def show_foreign_dispatches(player: "Player", target: str | None = None) -> None:
    ensure_external_policy_state(player)
    dispatches = player.foreign_policy["dispatches"]
    if target:
        dispatches = [x for x in dispatches if x.get("target") == target]
    rui_screen_start()
    rui_header("ДИПЛОМАТИЧЕСКИЕ ДЕПЕШИ", "📨", C.CYAN)
    if not dispatches:
        rui_info("Канцелярия пока не получила донесений.", C.GRAY)
    else:
        rows = []
        for item in dispatches[-15:]:
            rows.append((str(item.get("turn", "?")), str(item.get("title", "")), str(item.get("text", ""))))
        rui_table("Последние сообщения", ["Ход", "Заголовок", "Содержание"], rows, color=C.CYAN)
    pause()


def show_foreign_dossier(player: "Player", key: str, d: dict) -> None:
    active = next((m for m in player.foreign_policy["active_missions"] if m.get("target") == key), None)
    rui_screen_start()
    rui_header(f"ДОСЬЕ: {d['name']}", "🗺", C.CYAN)
    rows = [
        ("Политическая позиция", _foreign_posture(d)),
        ("Отношение к Риму", f"{d['disposition']}/100"),
        ("Доверие", f"{d['trust']}/100"),
        ("Страх перед Римом", f"{d['fear']}/100"),
        ("Напряжённость", f"{d['tension']}/100"),
        ("Римские рычаги", f"{d['leverage']}/100"),
        ("Разведывательное покрытие", f"{d['intel']}/100"),
        ("Оценка силы", _foreign_intel_value(d, "strength")),
        ("Оценка богатства", _foreign_intel_value(d, "wealth")),
        ("Торговый интерес", _foreign_intel_value(d, "trade_interest")),
        ("Договоры", _foreign_status(d)),
        ("Активная миссия", f"{FOREIGN_MISSIONS[active['type']]['name']} — {active['remaining']} ход." if active else "нет"),
    ]
    rui_table("Сведения канцелярии", ["Показатель", "Значение"], rows, color=C.CYAN)
    pause()


def external_power_actions(player: "Player", key: str, d: dict) -> None:
    while True:
        ensure_external_policy_state(player)
        rui_screen_start()
        rui_header(f"CONSILIUM EXTERNUM: {d['name']}", "🌍", C.CYAN)
        rui_info(f"Курс державы: {_foreign_posture(d)}", C.GOLD)
        rui_info(f"Отношение {d['disposition']} • Доверие {d['trust']} • Страх {d['fear']} • Напряжение {d['tension']} • Разведка {d['intel']} • Рычаги {d['leverage']}", C.CYAN)
        rui_menu([
            ("1", "Открыть разведывательное досье", "силы, богатство, договоры, текущая миссия", "🗺"),
            ("2", "Отправить дипломатическую миссию", "операция займёт несколько ходов", "📜"),
            ("3", "Договоры и ультиматумы", "торговля, союз, клиентела, война", "🤝"),
            ("4", "Депеши по этой державе", "история отношений и операций", "📨"),
            ("Q", "Назад", "", "↩"),
        ], title="Римская канцелярия")
        ch = read_choice(f"\n{clr('  Приказ: ', C.CYAN)}", ["1", "2", "3", "4", "Q"])
        if ch == "Q": return
        if ch == "1": show_foreign_dossier(player, key, d)
        elif ch == "2": launch_foreign_mission(player, key, d)
        elif ch == "3": foreign_treaty_menu(player, key, d)
        elif ch == "4": show_foreign_dispatches(player, key)


def external_policy_overview(player: "Player") -> None:
    ensure_external_policy_state(player)
    doctrine = _foreign_doctrine(player)
    state = player.foreign_policy
    adopted = "утверждена" if state.get("doctrine_selected") else "временная"
    rui_info(
        f"Доктрина: {doctrine['name']} ({adopted}) • ДК: {state['capital']}/{state['capital_max']} • "
        f"Миссии: {len(state['active_missions'])}/{doctrine['max_missions']} • Напряжённость мира: {state['global_tension']}/100",
        C.CYAN,
    )
    rui_info(f"Пассивный эффект: {doctrine['passive']}", C.GOLD)
    if state.get("crises"):
        rui_info(f"Нерешённых международных кризисов: {len(state['crises'])}.", C.RED)
    rows = []
    for d in player.diplomacy.values():
        rows.append((
            d["name"], str(d["disposition"]), str(d["trust"]),
            str(d["tension"]), _foreign_posture(d),
        ))
    rui_table("Державы и союзы", ["Держава", "Отн.", "Дов.", "Напр.", "Позиция"], rows, color=C.CYAN)


def show_active_foreign_missions(player: "Player") -> None:
    ensure_external_policy_state(player)
    rui_screen_start()
    rui_header("АКТИВНЫЕ ДИПЛОМАТИЧЕСКИЕ МИССИИ", "📜", C.GOLD)
    missions = player.foreign_policy["active_missions"]
    if not missions:
        rui_info("Посольские канцелярии не ведут длительных операций.", C.GRAY)
    else:
        rows = []
        for mission in missions:
            target = player.diplomacy.get(mission.get("target"), {})
            mdef = FOREIGN_MISSIONS.get(mission.get("type"), {})
            rows.append((mdef.get("name", mission.get("type")), target.get("name", mission.get("target")), str(mission.get("remaining", 0)), f"{mission.get('chance', 0)}%"))
        rui_table("Текущие поручения", ["Миссия", "Держава", "Осталось", "Шанс"], rows, color=C.GOLD)
    pause()


def _foreign_recommended_mission(player: "Player", d: dict) -> str:
    doctrine_key = player.foreign_policy.get("doctrine", "balance")
    if d.get("intel", 0) < 40:
        return "Создать агентурную сеть"
    if d.get("tension", 0) >= 65:
        return "Демонстрация силы" if doctrine_key == "coercion" else "Посредническая конференция"
    if d.get("disposition", 0) < 45 or d.get("trust", 0) < 35:
        return "Торжественное посольство"
    if d.get("trade_interest", 0) >= 60 and not d.get("trade_pact"):
        return "Коммерческая миссия"
    if d.get("fear", 0) >= 40 and d.get("leverage", 0) < 35 and not d.get("client"):
        return "Влияние при дворе"
    return "Посредническая конференция"


def show_foreign_assessment(player: "Player") -> None:
    ensure_external_policy_state(player)
    rui_screen_start()
    rui_header("СТРАТЕГИЧЕСКАЯ ОЦЕНКА СРЕДИЗЕМНОМОРЬЯ", "🦉", C.GOLD)
    powers = list(player.diplomacy.items())
    if not powers:
        rui_info("Канцелярия не располагает сведениями об иностранных державах.", C.GRAY)
        pause(); return

    risk_key, risk = max(powers, key=lambda kv: kv[1]["tension"] + kv[1]["hostility"] + kv[1]["strength"] * 4 - kv[1]["fear"] // 2)
    trade_candidates = [(k, d) for k, d in powers if not d.get("trade_pact")]
    trade_key, trade = max(trade_candidates or powers, key=lambda kv: kv[1]["trade_interest"] + kv[1]["disposition"] + kv[1]["trust"] - kv[1]["tension"])
    client_candidates = [(k, d) for k, d in powers if not d.get("client")]
    client_key, client = max(client_candidates or powers, key=lambda kv: kv[1]["fear"] + kv[1]["leverage"] + kv[1]["disposition"] - kv[1]["strength"] * 5)
    intel_key, intel = min(powers, key=lambda kv: kv[1]["intel"])
    friend_key, friend = max(powers, key=lambda kv: kv[1]["disposition"] + kv[1]["trust"] - kv[1]["tension"])

    rows = [
        ("Главная угроза", risk["name"], f"напряжение {risk['tension']}, враждебность {risk['hostility']}, сила {_foreign_intel_value(risk, 'strength')}"),
        ("Лучший торговый рынок", trade["name"], f"интерес {trade['trade_interest']}, доверие {trade['trust']}, отношение {trade['disposition']}"),
        ("Кандидат в клиентелу", client["name"], f"страх {client['fear']}, рычаги {client['leverage']}, сила {_foreign_intel_value(client, 'strength')}"),
        ("Разведывательный пробел", intel["name"], f"покрытие {intel['intel']}/100"),
        ("Надёжнейший партнёр", friend["name"], f"отношение {friend['disposition']}, доверие {friend['trust']}"),
    ]
    rui_table("Записка советника", ["Категория", "Держава", "Основание"], rows, color=C.GOLD)

    mission_rows = []
    for _, d in sorted(powers, key=lambda kv: kv[1]["tension"], reverse=True)[:4]:
        mission_rows.append((d["name"], _foreign_recommended_mission(player, d), _foreign_posture(d)))
    rui_table("Рекомендуемые поручения", ["Держава", "Миссия", "Положение"], mission_rows, color=C.CYAN)
    pause()


def show_pending_foreign_crises(player: "Player") -> None:
    ensure_external_policy_state(player)
    state = player.foreign_policy
    rui_screen_start()
    rui_header("НЕРАЗРЕШЁННЫЕ МЕЖДУНАРОДНЫЕ КРИЗИСЫ", "⚠", C.RED)
    if not state["crises"]:
        rui_info("Срочных нот и ультиматумов нет.", C.GREEN)
        pause(); return
    rows = []
    for i, crisis in enumerate(state["crises"], 1):
        target = player.diplomacy.get(crisis.get("target"), {})
        rows.append((str(i), str(crisis.get("title", "Кризис")), target.get("name", str(crisis.get("target", "?"))), str(crisis.get("created_turn", "?"))))
    rui_table("Очередь канцелярии", ["#", "Кризис", "Держава", "Ход"], rows, color=C.RED)
    valid = [str(i) for i in range(1, len(state["crises"]) + 1)] + ["Q"]
    ch = read_choice(f"\n{clr('  Рассмотреть кризис (или Q): ', C.CYAN)}", valid)
    if ch == "Q":
        return
    crisis = state["crises"].pop(int(ch) - 1)
    _resolve_foreign_crisis(player, crisis)


def show_foreign_policy_help(player: "Player") -> None:
    ensure_external_policy_state(player)
    rui_screen_start()
    rui_header("КАК РАБОТАЕТ CONSILIUM EXTERNUM", "📚", C.CYAN)
    ui_wrap("Дипломатический капитал восстанавливается после каждого хода и расходуется на миссии, договоры и ответы на кризисы.", color=C.WHITE)
    ui_wrap("Миссии длятся несколько ходов. Их шанс зависит от доктрины, доверия, разведки, напряжённости и силы Рима.", color=C.WHITE)
    ui_wrap("Торговля, союзы, клиентела и разрешение войны требуют политических предпосылок; важные договоры проходят голосование Сената.", color=C.WHITE)
    ui_wrap("Международные события возникают автоматически в конце хода. Частота и содержание зависят от общей напряжённости и поведения конкретной державы.", color=C.WHITE)
    ui_wrap("Разведка определяет точность сведений о силе и богатстве. Рычаги влияния нужны для клиентелы и давления.", color=C.WHITE)
    pause()


def _foreign_target_weight(player: "Player", d: dict) -> int:
    recency = max(0, 6 - max(0, player.turn - safe_int(d.get("last_policy_event_turn", 0), 0)))
    score = 8 + d["tension"] // 8 + d["hostility"] // 15 + abs(50 - d["disposition"]) // 12
    score += d["strength"] // 2
    score -= recency * 2
    if d.get("alliance") or d.get("client"):
        score += 2
    return max(1, score)


def _foreign_event_weight(player: "Player", d: dict, event: dict) -> int:
    kind = event["kind"]
    if kind == "trade":
        score = d["trade_interest"] + d["disposition"] + d["trust"] - d["tension"]
    elif kind == "border":
        score = d["tension"] + d["hostility"] + d["strength"] * 4 - d["trust"]
    elif kind == "aid":
        score = d["trust"] + d["disposition"] + d["wealth"] // 2 - d["tension"]
    elif kind == "client":
        score = d["fear"] + d["leverage"] + d["disposition"] - d["strength"] * 5
    elif kind == "insult":
        score = d["hostility"] + d["tension"] - d["fear"] - d["trust"] // 2
    elif kind == "ultimatum":
        score = d["strength"] * 8 + d["hostility"] + d["tension"] - d["fear"] * 2
    else:  # gift
        score = d["disposition"] + d["trust"] + d["wealth"] - d["tension"]
    return max(1, score // 8 + 1)


def _queue_foreign_crisis(player: "Player", event: dict, key: str) -> None:
    ensure_external_policy_state(player)
    if key not in player.diplomacy:
        return
    if any(x.get("target") == key for x in player.foreign_policy["crises"]):
        return
    player.foreign_policy["crises"].append({
        "kind": event["kind"],
        "title": event["title"],
        "text": event["text"],
        "target": key,
        "created_turn": player.turn,
    })
    player.foreign_policy["crises"] = player.foreign_policy["crises"][-8:]


def maybe_external_policy_event(player: "Player") -> None:
    """Формирует международное событие автоматически в конце хода."""
    ensure_external_policy_state(player)
    state = player.foreign_policy
    doctrine = _foreign_doctrine(player)
    cooldown = safe_int(doctrine.get("crisis_cooldown", 2), 2, 1, 6)
    if player.turn - state["last_crisis_turn"] < cooldown:
        return
    if state["crises"]:
        return

    crisis_chance = 0.12 + state["global_tension"] / 450
    if doctrine.get("name") == "Дипломатия фасций":
        crisis_chance += 0.06
    if random.random() > min(0.46, crisis_chance):
        return

    candidates = list(player.diplomacy.items())
    if not candidates:
        return
    target_weights = [_foreign_target_weight(player, d) for _, d in candidates]
    key, d = random.choices(candidates, weights=target_weights, k=1)[0]

    possible = []
    weights = []
    for event in FOREIGN_CRISIS_EVENTS:
        kind = event["kind"]
        if kind == "trade" and d.get("trade_pact"):
            continue
        if kind == "client" and d.get("client"):
            continue
        if kind == "ultimatum" and (d.get("client") or d.get("alliance") or d["tension"] < 45):
            continue
        if kind == "insult" and d.get("alliance"):
            continue
        if kind == "border" and d.get("alliance") and d["tension"] < 55:
            continue
        possible.append(event)
        weights.append(_foreign_event_weight(player, d, event))
    if not possible:
        return

    event = random.choices(possible, weights=weights, k=1)[0]
    _queue_foreign_crisis(player, event, key)
    state["last_crisis_turn"] = player.turn
    d["last_policy_event_turn"] = player.turn


def _resolve_foreign_crisis(player: "Player", crisis: dict) -> None:
    key = crisis.get("target")
    if key not in player.diplomacy:
        return
    d = player.diplomacy[key]
    kind = crisis.get("kind")
    rui_screen_start()
    rui_header(str(crisis.get("title", "Международный кризис")), "🌍", C.RED if kind in ("border", "insult", "ultimatum") else C.CYAN)
    ui_wrap(f"{d['name']}: {crisis.get('text', '')}", color=C.WHITE)
    rui_info(f"Отношение {d['disposition']} • Доверие {d['trust']} • Страх {d['fear']} • Напряжение {d['tension']}", C.CYAN)

    trade_cost = game_price(player, 30, market=True)
    border_cost = game_price(player, 35, market=True)
    full_aid_cost = game_price(player, 60, market=True)
    symbolic_aid_cost = game_price(player, 25, market=True)
    client_cost = game_price(player, 80, market=True)
    guarantee_cost = game_price(player, 35, market=True)
    ultimatum_cost = game_price(player, 50, market=True)
    senate_compromise_cost = game_price(player, 25, market=True)

    if kind == "trade":
        options = [
            ("1", "Принять предложение", f"{trade_cost} золота; торговый договор и доверие", "⚱"),
            ("2", "Поручить купцам торг", "1 ДК; шанс улучшить условия", "📜"),
            ("3", "Отказать", "не тратить ресурсы", "✋"),
        ]
        requirements = {"1": (trade_cost, 0), "2": (0, 1)}
    elif kind == "border":
        options = [
            ("1", "Компенсировать ущерб", f"{border_cost} золота; снизить напряжение", "💰"),
            ("2", "Выслать легионных трибунов", "страх и напряжение растут", "⚔"),
            ("3", "Передать спор Сенату", "голосование и непредсказуемый итог", "🏛"),
        ]
        requirements = {"1": (border_cost, 0)}
    elif kind == "aid":
        options = [
            ("1", "Выделить полную помощь", f"{full_aid_cost} золота; большой рост доверия", "🎁"),
            ("2", "Отправить символические дары", f"{symbolic_aid_cost} золота; малый рост отношений", "📦"),
            ("3", "Отказать", "доверие падает", "✋"),
        ]
        requirements = {"1": (full_aid_cost, 0), "2": (symbolic_aid_cost, 0)}
    elif kind == "client":
        options = [
            ("1", "Принять под покровительство", f"{client_cost} золота и 1 ДК; рычаги влияния", "👑"),
            ("2", "Ограничиться гарантией", f"{guarantee_cost} золота; доверие и страх", "🛡"),
            ("3", "Не вмешиваться", "двор ищет другого покровителя", "…"),
        ]
        requirements = {"1": (client_cost, 1), "2": (guarantee_cost, 0)}
    elif kind == "gift":
        options = [
            ("1", "Принять дары и обещать услугу", "немедленная выгода, чужие рычаги", "🎁"),
            ("2", "Принять без обязательств", "меньшая выгода, риск обиды", "⚖"),
            ("3", "Вернуть дары", "престиж, но отношения падают", "↩"),
        ]
        requirements = {}
    elif kind == "insult":
        options = [
            ("1", "Потребовать публичных извинений", "проверка страха и силы Рима", "📜"),
            ("2", "Использовать как casus belli", "напряжение и мораль растут", "⚔"),
            ("3", "Стерпеть ради мира", "доверие и престиж падают", "🕊"),
        ]
        requirements = {}
    else:
        options = [
            ("1", f"Заплатить {ultimatum_cost} золота", "избежать кризиса ценой престижа", "💰"),
            ("2", "Ответить встречным ультиматумом", "сравнение сил и страха", "⚔"),
            ("3", "Созвать Сенат", "решение фракций", "🏛"),
        ]
        requirements = {"1": (ultimatum_cost, 0)}

    while True:
        rui_menu(options, title="Ответ Рима")
        ch = read_choice(f"\n{clr('  Решение: ', C.CYAN)}", ["1", "2", "3"])
        gold_need, capital_need = requirements.get(ch, (0, 0))
        if player.gold < gold_need:
            print(clr(f"  Для этого решения требуется {gold_need} золота; в казне {player.gold}.", C.RED))
            continue
        if player.foreign_policy["capital"] < capital_need:
            print(clr(f"  Для этого решения требуется {capital_need} дипломатический капитал.", C.RED))
            continue
        break

    outcome = ""
    tone = "info"
    if kind == "trade":
        if ch == "1":
            player.gold -= trade_cost
            d["trade_pact"] = True; d["trade_pact_turn"] = player.turn
            d["trust"] = min(100, d["trust"] + 8); d["disposition"] = min(100, d["disposition"] + 6)
            outcome = "торговое предложение принято"; tone = "good"
        elif ch == "2":
            _spend_diplomatic_capital(player, 1)
            success = random.randint(1, 100) <= 55 + d["trade_interest"] // 4
            if success:
                d["trade_pact"] = True; d["trade_pact_turn"] = player.turn
                d["trust"] = min(100, d["trust"] + 10); outcome = "купцы добились выгодного договора"; tone = "good"
            else:
                d["trust"] = max(0, d["trust"] - 4); outcome = "переговоры купцов сорвались"; tone = "bad"
        else:
            d["disposition"] = max(0, d["disposition"] - 4); outcome = "Рим отказал в торговле"; tone = "bad"
    elif kind == "border":
        if ch == "1":
            player.gold -= border_cost; d["tension"] = max(0, d["tension"] - 15); d["trust"] = min(100, d["trust"] + 6); outcome = "спор урегулирован компенсацией"; tone = "good"
        elif ch == "2":
            d["fear"] = min(100, d["fear"] + 10); d["tension"] = min(100, d["tension"] + 12); player.morale = min(100, player.morale + 2); outcome = "Рим ответил демонстрацией силы"; tone = "bad"
        else:
            passed, votes = _senate_vote_for_external_policy(player, d, "war"); _print_external_vote(votes, passed)
            if passed:
                _set_casus_belli(player, d, True); d["tension"] = min(100, d["tension"] + 8); outcome = "Сенат признал вину чужой стороны"; tone = "bad"
            else:
                d["tension"] = max(0, d["tension"] - 5); outcome = "Сенат предпочёл компромисс"; tone = "good"
    elif kind == "aid":
        if ch == "1":
            player.gold -= full_aid_cost; d["trust"] = min(100, d["trust"] + 16); d["disposition"] = min(100, d["disposition"] + 10); d["leverage"] = min(100, d["leverage"] + 8); outcome = "оказана полная помощь"; tone = "good"
        elif ch == "2":
            player.gold -= symbolic_aid_cost; d["trust"] = min(100, d["trust"] + 6); d["disposition"] = min(100, d["disposition"] + 4); outcome = "отправлены символические дары"; tone = "good"
        else:
            d["trust"] = max(0, d["trust"] - 9); d["disposition"] = max(0, d["disposition"] - 5); outcome = "в помощи отказано"; tone = "bad"
    elif kind == "client":
        if ch == "1":
            player.gold -= client_cost; _spend_diplomatic_capital(player, 1)
            d["leverage"] = min(100, d["leverage"] + 22); d["fear"] = min(100, d["fear"] + 10); d["trust"] = min(100, d["trust"] + 8); outcome = "Рим принял двор под покровительство; путь к клиентеле открыт"; tone = "good"
        elif ch == "2":
            player.gold -= guarantee_cost; d["trust"] = min(100, d["trust"] + 9); d["fear"] = min(100, d["fear"] + 5); d["non_aggression"] = True; d["non_aggression_turn"] = player.turn; outcome = "дана ограниченная гарантия"; tone = "good"
        else:
            d["disposition"] = max(0, d["disposition"] - 7); d["leverage"] = max(0, d["leverage"] - 5); outcome = "Рим отказался от покровительства"; tone = "bad"
    elif kind == "gift":
        gift = max(20, d["wealth"] // 2)
        if ch == "1":
            player.gold += gift; d["disposition"] = min(100, d["disposition"] + 6); d["leverage"] = max(0, d["leverage"] - 8); outcome = f"приняты дары на {gift} золота с обещанием услуги"; tone = "good"
        elif ch == "2":
            player.gold += gift // 2; d["trust"] = max(0, d["trust"] - 3); outcome = f"принята лишь половина дара: +{gift // 2} золота"
        else:
            player.glory += 12; d["disposition"] = max(0, d["disposition"] - 5); outcome = "дары возвращены; слава +12"; tone = "bad"
    elif kind == "insult":
        if ch == "1":
            success = _rome_pressure(player) + d["fear"] >= d["strength"] * 10 + 55
            if success:
                d["disposition"] = min(100, d["disposition"] + 3); d["fear"] = min(100, d["fear"] + 8); player.glory += 15; outcome = "двор принёс извинения; слава +15"; tone = "good"
            else:
                d["tension"] = min(100, d["tension"] + 12); d["trust"] = max(0, d["trust"] - 8); outcome = "требование извинений отвергнуто"; tone = "bad"
        elif ch == "2":
            _set_casus_belli(player, d, True); d["tension"] = min(100, d["tension"] + 15); player.morale = min(100, player.morale + 3); outcome = "оскорбление объявлено casus belli"; tone = "bad"
        else:
            player.glory = max(0, player.glory - 10); d["fear"] = max(0, d["fear"] - 6); d["tension"] = max(0, d["tension"] - 5); outcome = "Рим стерпел оскорбление; слава −10"
    else:
        if ch == "1":
            player.gold -= ultimatum_cost; player.senate_rep = max(0, player.senate_rep - 4); d["tension"] = max(0, d["tension"] - 10); d["fear"] = max(0, d["fear"] - 5); outcome = "Рим уступил ультиматуму"; tone = "bad"
        elif ch == "2":
            if _rome_pressure(player) + d["fear"] >= d["strength"] * 9 + 45:
                d["fear"] = min(100, d["fear"] + 14); d["leverage"] = min(100, d["leverage"] + 8); player.glory += 20; outcome = "встречный ультиматум заставил противника отступить"; tone = "good"
            else:
                _set_casus_belli(player, d, True); d["tension"] = min(100, d["tension"] + 20); outcome = "обе стороны готовятся к войне"; tone = "bad"
        else:
            passed, votes = _senate_vote_for_external_policy(player, d, "war"); _print_external_vote(votes, passed)
            if passed:
                _set_war_approved(player, d, True); outcome = "Сенат отверг ультиматум и разрешил войну"; tone = "bad"
            else:
                player.gold = max(0, player.gold - senate_compromise_cost); d["tension"] = max(0, d["tension"] - 6); outcome = f"Сенат купил компромисс за {senate_compromise_cost} золота"

    d["last_contact_turn"] = player.turn
    _foreign_dispatch(player, str(crisis.get("title", "Международный кризис")), f"{d['name']}: {outcome}.", key, tone)
    print(clr(f"  Итог: {outcome}.", C.GREEN if tone == "good" else C.RED if tone == "bad" else C.GOLD))
    pause()


def foreign_policy_end_turn(player: "Player") -> None:
    """Полный цикл дипломатии после хода: миссии, дрейф, договоры и кризис."""
    ensure_external_policy_state(player)
    state = player.foreign_policy
    if state["last_tick_turn"] >= player.turn:
        return
    state["last_tick_turn"] = player.turn
    doctrine = _foreign_doctrine(player)
    state["capital_max"] = safe_int(doctrine.get("capital_max", 6), 6, 3, 12)

    regen = safe_int(doctrine.get("capital_regen", 1), 1)
    regen += min(1, sum(1 for d in player.diplomacy.values() if d.get("alliance")))
    state["capital"] = min(state["capital_max"], state["capital"] + regen)

    remaining_missions = []
    for mission in list(state["active_missions"]):
        mission["remaining"] = safe_int(mission.get("remaining", 1), 1) - 1
        if mission["remaining"] <= 0:
            _apply_foreign_mission_result(player, mission)
        else:
            remaining_missions.append(mission)
    state["active_missions"] = remaining_missions

    pressure = _rome_pressure(player)
    tension_total = 0
    doctrine_key = state.get("doctrine", "balance")
    for key, d in player.diplomacy.items():
        d["mission_cooldown"] = max(0, safe_int(d.get("mission_cooldown", 0), 0) - 1)
        target_fear = max(0, min(100, pressure - d["strength"] * 5 + d["hostility"] // 3))
        if d["fear"] < target_fear:
            d["fear"] = min(100, d["fear"] + min(4, target_fear - d["fear"]))
        elif d["fear"] > target_fear:
            d["fear"] = max(0, d["fear"] - 2)

        tension_drift = safe_int(doctrine.get("tension_drift", 0), 0)
        tension_drift += 1 if d["hostility"] >= 70 else 0
        tension_drift -= 2 if d.get("non_aggression") else 0
        tension_drift -= 2 if d.get("alliance") else 0
        tension_drift += 1 if d.get("tribute", 0) > 0 and not d.get("client") else 0
        tension_drift += random.choice([-1, 0, 0, 1])
        d["tension"] = max(0, min(100, d["tension"] + tension_drift))

        relation_drift = safe_int(doctrine.get("relation_drift", 0), 0)
        if d.get("alliance"): relation_drift += 1
        if d.get("trade_pact"): relation_drift += 1
        if d.get("non_aggression"): relation_drift += 1
        if d["tension"] >= 70: relation_drift -= 2
        if d["trust"] <= 20: relation_drift -= 1
        if d.get("tribute", 0) > 0 and not d.get("client"): relation_drift -= 1
        d["disposition"] = max(0, min(100, d["disposition"] + relation_drift + random.choice([-1, 0, 0, 1])))

        trust_drift = 0
        if d.get("alliance") or d.get("non_aggression"): trust_drift += 1
        if d["tension"] >= 65: trust_drift -= 1
        if player.turn - d.get("last_contact_turn", 0) >= 8 and not d.get("alliance"): trust_drift -= 1
        if doctrine_key == "coercion": trust_drift -= 1
        d["trust"] = max(0, min(100, d["trust"] + trust_drift))

        if doctrine_key == "commerce" and d.get("trade_pact"):
            d["trade_interest"] = min(100, d["trade_interest"] + 1)
        if doctrine_key == "clients" and d.get("client"):
            d["leverage"] = min(100, d["leverage"] + 1)
        else:
            d["leverage"] = max(0, d["leverage"] - (0 if d.get("client") else 1))

        # Договоры перестают быть вечными, если отношения фактически разрушены.
        if d.get("alliance") and (d["trust"] <= 15 or d["tension"] >= 90):
            d["alliance"] = False; d["alliance_turn"] = 0
            d["non_aggression"] = False; d["non_aggression_turn"] = 0
            _foreign_dispatch(player, "Союз распался", f"{d['name']} отказалась от союзных обязательств.", key, "bad")
        if d.get("trade_pact") and d["tension"] >= 92:
            d["trade_pact"] = False; d["trade_pact_turn"] = 0
            _foreign_dispatch(player, "Торговля прервана", f"{d['name']} закрыла рынки для римских купцов.", key, "bad")
        if d.get("non_aggression") and not d.get("alliance") and d["tension"] >= 84:
            d["non_aggression"] = False; d["non_aggression_turn"] = 0
            _foreign_dispatch(player, "Пакт денонсирован", f"{d['name']} более не считает себя связанной пактом о ненападении.", key, "bad")
        if d.get("client") and d["trust"] <= 8 and d["fear"] <= 25 and random.random() < 0.18:
            d["client"] = False; d["client_turn"] = 0
            d["alliance"] = False; d["alliance_turn"] = 0
            d["tribute"] = 0; d["tribute_turn"] = 0
            d["tension"] = min(100, d["tension"] + 20)
            _foreign_dispatch(player, "Мятеж клиента", f"{d['name']} отвергла римское покровительство.", key, "bad")

        # Casus belli и разрешение Сената не действуют бесконечно.
        if d.get("war_approved") and d.get("war_approved_turn", 0) and player.turn - d["war_approved_turn"] >= 8 and d["tension"] < 65:
            d["war_approved"] = False; d["war_approved_turn"] = 0
            _foreign_dispatch(player, "Военный мандат истёк", f"Сенат более не считает войну с {d['name']} срочной.", key)
        if d.get("casus_belli") and d.get("casus_belli_turn", 0) and player.turn - d["casus_belli_turn"] >= 10 and d["tension"] < 55:
            _set_casus_belli(player, d, False)
            _foreign_dispatch(player, "Casus belli исчерпан", f"Повод к войне с {d['name']} утратил силу.", key)

        tension_total += d["tension"]

    state["global_tension"] = int(round(tension_total / max(1, len(player.diplomacy))))

    # Международный кризис формируется после годовых расчётов, но больше не
    # вклинивается внутрь гражданской войны или другого незавершённого экрана.
    # Рассмотрение переносится в единый Совет после хода, когда все бои и
    # внутренние мятежи уже завершены.
    if not state["crises"]:
        maybe_external_policy_event(player)
    if state["crises"]:
        crisis = state["crises"][0]
        crisis.setdefault("created_turn", player.turn)
        crisis.setdefault("expires_turn", player.turn + 4)
        if crisis.get("notified_turn") != player.turn:
            target = player.diplomacy.get(crisis.get("target"), {})
            turn_summary_add(
                player,
                f"Международный кризис: {crisis.get('title', 'неотложная нота')} — "
                f"{target.get('name', crisis.get('target', 'неизвестная держава'))}."
            )
            crisis["notified_turn"] = player.turn


def ai_diplomacy_tick(player: "Player"):
    return foreign_policy_end_turn(player)


def external_policy_menu(player: Player):
    ensure_external_policy_state(player)
    while True:
        rui_screen_start()
        rui_header("CONSILIUM EXTERNUM", "🌍", C.CYAN)
        external_policy_overview(player)
        rui_menu([
            ("1", "Досье иностранной державы", "миссии, договоры и история отношений", "🗺"),
            ("2", "Стратегическая оценка", "главные угрозы, рынки и рекомендации", "🦉"),
            ("3", "Утвердить или изменить доктрину", "равновесие, торговля, клиентела или принуждение", "🏛"),
            ("4", "Активные дипломатические миссии", "операции, сроки и шансы", "📜"),
            ("5", "Дипломатические депеши", "последние донесения и исходы кризисов", "📨"),
            ("6", "Нерешённые кризисы", "срочные ноты и ультиматумы", "⚠"),
            ("7", "Справка о системе", "капитал, разведка, договоры и события", "📚"),
            ("Q", "Назад", "", "↩"),
        ], title="Канцелярия внешних дел")
        ch = read_choice(f"\n{clr('  Ваш приказ: ', C.CYAN)}", ["1", "2", "3", "4", "5", "6", "7", "Q"])
        if ch == "Q": return
        if ch == "1":
            key, d = _selected_power(player)
            if key and d:
                external_power_actions(player, key, d)
        elif ch == "2":
            show_foreign_assessment(player)
        elif ch == "3":
            choose_foreign_doctrine(player)
        elif ch == "4":
            show_active_foreign_missions(player)
        elif ch == "5":
            show_foreign_dispatches(player)
        elif ch == "6":
            show_pending_foreign_crises(player)
        elif ch == "7":
            show_foreign_policy_help(player)


def diplomacy_menu(player: Player):
    """Совместимость: прежняя кнопка дипломатии ведёт в Consilium Externum."""
    return external_policy_menu(player)



def available_tech_keys(player: Player) -> list[str]:
    return [k for k in TECH_TREE if player.tech_available(k) and k not in getattr(player, "research_queue", [])]

def complete_research(player: Player, key: str):
    if key not in player.tech_researched:
        player.tech_researched.append(key)
    player.researching = None
    player.research_progress = 0
    show_tech_completion_card(player, key)
    log_event(player, f"Технология изучена: {TECH_TREE[key]['name']}")
    newly_unlocked = unlock_tech_aux_units(player)
    if newly_unlocked:
        print(clr(f"  Открыты новые войска: {', '.join(newly_unlocked)}", C.CYAN))
        log_event(player, f"Открыты войска: {', '.join(newly_unlocked)}")
    add_battlepass_xp(player, 15)


