def handle_civil_war(player: Player):
    """
    Проверяет, не пора ли одной из AI-фракций поднять мятеж, и если да —
    даёт игроку бой за стабильность Республики.
    """
    rebel = next((
        f for f in player.ai_factions
        if (f.should_revolt(player.senate_rep, player.people_rep, player.morale, player.turn) if isinstance(f, ImprovedAIFaction) else f.should_revolt(player.senate_rep))
    ), None)
    if not rebel:
        return

    clear()
    print(clr("\n  ⚔⚔⚔  ГРАЖДАНСКАЯ ВОЙНА!  ⚔⚔⚔", C.BOLD + C.RED))
    print(hr('═'))
    print(f"\n  {clr(rebel.name, C.PURPLE)} поднимает мятеж против Республики!")
    print(f"  Их сила: {rebel.strength}   Влияние: {rebel.influence}")
    rebel.at_war = True
    player.civil_war_active = True

    if not player.legions:
        print(clr("\n  У вас нет легионов для защиты! Мятежники захватывают власть.", C.RED))
        player.senate_rep = max(0, player.senate_rep - 30)
        rebel.influence = 100
        pause()
        return

    print(f"\n{clr('  Выберите легион для подавления мятежа:', C.GOLD)}")
    for i, l in enumerate(player.legions):
        print(f"  {i+1}. {l.name} (сила {l.strength})")
    li_valid = [str(i + 1) for i in range(len(player.legions))]
    li = read_choice(f"{clr('  Легион: ', C.CYAN)}", li_valid)
    legion = player.legions[int(li) - 1]
    enemy = {"name": rebel.name, "strength": rebel.strength, "region": "Roma"}
    won = resolve_battle(player, legion, enemy, is_civil_war=True)
    if won:
        rebel.defeated = True
        rebel.influence = 0
        print(clr(f"\n  {rebel.name} разгромлена и распущена.", C.BOLD + C.GREEN))
    else:
        rebel.influence = min(100, rebel.influence + 10)
        print(clr(f"\n  Мятеж продолжается. Сенат в панике.", C.RED))
    player.civil_war_active = False
    rebel.at_war = False
    pause()


