def _v24_clamp(value, default=0, lo=0, hi=100):
    return safe_int(value, default, lo, hi)

def default_dynasty_state(player):
    gens = random.choice(list(ROMAN_GENTES.keys()))
    return {
        "ruler": {
            "name": f"{player.name} Augustus", "age": 32, "gens": gens,
            "martial": random.randint(4, 9), "stewardship": random.randint(4, 9),
            "charisma": random.randint(4, 9), "piety": random.randint(3, 8),
            "health": 80, "legitimacy": 60,
        },
        "heirs": [{"name": random.choice(["Lucius", "Gaius", "Marcus", "Titus"]) + " Caesar",
                   "age": random.randint(8, 18), "gens": gens, "talent": random.randint(3, 9)}],
        "dynasty_prestige": 20,
        "succession_crisis": False,
    }

def default_v24_state(player):
    return {
        "dynasty": default_dynasty_state(player),
        "senate_parties": {k: v.copy() for k, v in SENATE_PARTIES.items()},
        "gentes": {k: v.copy() for k, v in ROMAN_GENTES.items()},
        "resources": {},
        "trade_routes": [],
        "fleet": {"flagships": [], "ships": [], "admiral": "Гай Дуилий", "naval_tradition": 0, "pirate_threat": 20, "sea_control": 10, "captured_islands": [], "sea_zone_control": {}},
    }

def _normalize_v24_dynasty(player, state):
    base = default_dynasty_state(player)
    dyn = state.get("dynasty") if isinstance(state.get("dynasty"), dict) else base
    ruler = dyn.get("ruler") if isinstance(dyn.get("ruler"), dict) else base["ruler"]
    gens = ruler.get("gens") if ruler.get("gens") in ROMAN_GENTES else random.choice(list(ROMAN_GENTES.keys()))
    ruler.update({
        "name": str(ruler.get("name") or base["ruler"]["name"]),
        "age": _v24_clamp(ruler.get("age"), 32, 0, 120),
        "gens": gens,
        "martial": _v24_clamp(ruler.get("martial"), 5, 1, 10),
        "stewardship": _v24_clamp(ruler.get("stewardship"), 5, 1, 10),
        "charisma": _v24_clamp(ruler.get("charisma"), 5, 1, 10),
        "piety": _v24_clamp(ruler.get("piety"), 5, 1, 10),
        "health": _v24_clamp(ruler.get("health"), 80, 0, 100),
        "legitimacy": _v24_clamp(ruler.get("legitimacy"), 60, 0, 100),
    })
    heirs = []
    for h in safe_list(dyn.get("heirs")):
        if not isinstance(h, dict):
            continue
        heirs.append({
            "name": str(h.get("name") or "Lucius Caesar"),
            "age": _v24_clamp(h.get("age"), 12, 0, 80),
            "gens": h.get("gens") if h.get("gens") in ROMAN_GENTES else gens,
            "talent": _v24_clamp(h.get("talent"), 5, 1, 10),
        })
    dyn["ruler"] = ruler
    dyn["heirs"] = heirs or base["heirs"]
    dyn["dynasty_prestige"] = safe_int(dyn.get("dynasty_prestige", 20), 20, 0)
    dyn["succession_crisis"] = bool(dyn.get("succession_crisis", False))
    return dyn


def calculate_resources(player):
    if RESOURCE_ECONOMY is not None:
        try:
            state = RESOURCE_ECONOMY.ensure_state(player, resource_economy_context(player))
            stock = state.get("stockpiles", {}) if isinstance(state, dict) else {}
            return {key: max(0, int(value)) for key, value in stock.items() if float(value) >= 1.0}
        except Exception as exc:
            debug_log("Resource stock bridge failed: %s", exc, exc_info=True, level=logging.DEBUG)
    result = {}
    for prov in getattr(player, "provinces", []):
        if not isinstance(prov, dict):
            continue
        for res in PROVINCE_RESOURCES.get(prov.get("name"), []):
            result[res] = result.get(res, 0) + 1
    return result

def v24_resource_income(player):
    if RESOURCE_ECONOMY is not None:
        try:
            RESOURCE_ECONOMY.ensure_state(player, resource_economy_context(player))
        except Exception as exc:
            debug_log("Legacy resource income bridge failed: %s", exc, exc_info=True, level=logging.DEBUG)
        return 0, 0
    ensure_v24_state(player)
    order_bonus = max(0, 100 - player.effective_unrest()) / 1000
    senate_bonus = max(0, player.senate_rep - 50) / 1000
    steward_bonus = 1.0 + order_bonus + senate_bonus
    gold = grain = 0
    for res, amount in player.v24["resources"].items():
        info = RESOURCE_INFO.get(res)
        if not info:
            continue
        gold += int(round(info[1] * amount * steward_bonus))
        grain += info[2] * amount
    return gold, grain


def has_v24_system(player) -> bool:
    """Проверяет готовность подсистемы v2.4 по состоянию игрока, а не по globals()."""
    return isinstance(getattr(player, "v24", None), dict) and callable(globals().get("v24_fleet_upkeep"))


