def v24_naval_era_multiplier(player) -> float:
    """Пираты и местные флоты усиливаются по мере роста Рима, а не душат новичка сразу."""
    provs = len(getattr(player, "provinces", []))
    if provs >= 24:
        return 1.45
    if provs >= 14:
        return 1.30
    if provs >= 7:
        return 1.15
    return 1.00

def v24_zone_stage_bonus(fleet, zone_id: str) -> int:
    """Чем выше контроль моря, тем сильнее ответ врага — создаёт эскалацию после побед."""
    control = fleet.get("sea_zone_control", {}).get(zone_id, 0)
    return control // 6


def v24_tick_senate(player):
    ensure_v24_state(player)
    parties = player.v24["senate_parties"]
    parties["optimates"]["influence"] += random.randint(-2, 3) + (2 if player.senate_rep > 65 else 0)
    parties["populares"]["influence"] += random.randint(-2, 3) + (2 if player.people_rep > 65 else 0)
    parties["militares"]["influence"] += random.randint(-1, 4) + len(player.legions) // 5
    parties["mercatores"]["influence"] += random.randint(-1, 4) + len(player.v24["trade_routes"])
    total = sum(max(1, p["influence"]) for p in parties.values()) or 1
    # Сохраняем сумму около 100%, но не даём одной партии монополизировать Сенат.
    normalized = {k: max(5, min(70, int(round(max(1, p["influence"]) * 100 / total)))) for k, p in parties.items()}
    drift = 100 - sum(normalized.values())
    leader = max(normalized, key=normalized.get)
    normalized[leader] = max(5, min(70, normalized[leader] + drift))
    for k, value in normalized.items():
        parties[k]["influence"] = value
    senate_rep = safe_int(getattr(player, "senate_rep", 50), 50, 0, 100)
    if senate_rep < 40:
        recovery_chance, recovery = 0.45, 2
    elif senate_rep < 75:
        recovery_chance, recovery = 0.25, 1
    else:
        recovery_chance, recovery = 0.10, 1
    if senate_rep < 100 and random.random() < recovery_chance:
        player.senate_rep = min(100, senate_rep + recovery)


def v24_end_turn_tick(player):
    ensure_v24_state(player)
    res_gold, res_grain = v24_resource_income(player)
    trade_gold = v24_trade_income(player)
    fleet_cost = v24_fleet_upkeep(player)
    player.gold += res_gold + trade_gold - fleet_cost
    player.grain += res_grain
    # Императорский двор удалён из республиканской кампании: династический тик отключён.
    v24_tick_senate(player)
    v24_tick_trade_and_fleet(player)
    if res_gold or res_grain or trade_gold or fleet_cost:
        log_event(player, f"v2.4 экономика: +{res_gold + trade_gold - fleet_cost} золота, +{res_grain} зерна")


def handle_preemptive_strike(player: Player):
    """
    Превентивный удар по соперничающей AI-фракции (Партия Красса/Катона/Клодия),
    не дожидаясь, пока та сама поднимет мятеж через should_revolt().
    Без этого игрок может только обороняться, и при высоком senate_rep
    (>=60) фракция спокойно растёт до 100 и побеждает без единого боя.
    Поражение в превентивном ударе наказывается мягче, чем оборона в
    реальном мятеже (нет паники в Сенате — это игрок начал драку),
    но фракция всё равно немного озлобляется и наращивает влияние.
    """
    candidates = [f for f in player.ai_factions if not f.defeated and not f.at_war]
    if not candidates:
        print(clr("\n  Все соперничающие партии уже разбиты или воюют.", C.GRAY)); pause(); return
    if not player.legions:
        print(clr("\n  Нет легионов для удара. Сперва наберите хотя бы один.", C.RED)); pause(); return

    print(clr("\n  Выберите партию для удара:", C.GOLD))
    for i, f in enumerate(candidates, 1):
        risk = clr("ОПАСНО", C.RED) if f.influence >= 70 else (clr("терпимо", C.GOLD) if f.influence >= 40 else clr("слабая", C.GREEN))
        print(f"  {i}. {f.name} — влияние {f.influence}, сила {f.strength} [{risk}]")
    fi_valid = [str(i + 1) for i in range(len(candidates))]
    fi = read_choice(f"{clr('  Партия: ', C.CYAN)}", fi_valid)
    target = candidates[int(fi) - 1]

    print(clr(f"\n  Покушение на видных людей {target.name} раскроется лишь в случае неудачи.", C.GRAY))
    print(f"\n{clr('  Выберите легион для удара:', C.GOLD)}")
    for i, l in enumerate(player.legions):
        print(f"  {i+1}. {l.name} (сила {l.strength})")
    li_valid = [str(i + 1) for i in range(len(player.legions))]
    li = read_choice(f"{clr('  Легион: ', C.CYAN)}", li_valid)
    legion = player.legions[int(li) - 1]

    enemy = {"name": target.name, "strength": target.strength, "region": "Roma"}
    won = resolve_battle(player, legion, enemy, is_civil_war=True)
    if won:
        target.defeated = True
        target.influence = 0
        print(clr(f"\n  {target.name} разгромлена превентивно и распущена.", C.BOLD + C.GREEN))
        log_event(player, f"Превентивный удар: {target.name} уничтожена")
    else:
        target.influence = min(100, target.influence + 6)
        print(clr(f"\n  Удар сорван. {target.name} лишь утвердилась во вражде к вам.", C.RED))
        log_event(player, f"Провал превентивного удара по {target.name}")
    pause()


# ─── РЕСПУБЛИКАНСКАЯ ПОЛИТИКА И ТОРГОВЛЯ v2.24.18 ──────────────────────────
# Политический экран больше не является витриной цифр: роды шлют дары и
