def update_trade_market(player):
    state = ensure_republic_overhaul_state(player)
    for res in RESOURCE_INFO:
        drift = random.randint(-8, 8)
        if state["trade_market"].get(res, 100) > 120:
            drift -= 2
        if state["trade_market"].get(res, 100) < 80:
            drift += 2
        state["trade_market"][res] = max(55, min(170, state["trade_market"].get(res, 100) + drift))


def process_republic_caravans(player):
    state = ensure_republic_overhaul_state(player)
    if not state["caravans"]:
        update_trade_market(player); return
    arrived = []
    lost = []
    for c in list(state["caravans"]):
        c["turns"] = max(0, safe_int(c.get("turns", 1), 1) - 1)
        if c["turns"] > 0:
            continue
        risk = safe_int(c.get("risk", 20), 20, 0, 95)
        if random.randint(1, 100) <= risk:
            lost.append(c)
        else:
            player.gold += safe_int(c.get("value", 0), 0)
            arrived.append(c)
        state["caravans"].remove(c)
    if arrived:
        total = sum(c["value"] for c in arrived)
        print(clr(f"\n  🐎 Караваны прибыли: +{total} золота.", C.GREEN))
        log_event(player, f"Караваны прибыли: +{total} золота")
    if lost:
        print(clr(f"\n  ☠ Потеряны караваны: {len(lost)}. Разбойники и пираты богатеют.", C.RED))
        player.v24["fleet"]["pirate_threat"] = min(100, player.v24["fleet"].get("pirate_threat", 20) + 3 * len(lost))
        log_event(player, f"Караваны потеряны: {len(lost)}")
    update_trade_market(player)


def _available_trade_goods(player) -> list[tuple[str, str, int]]:
    ensure_republic_overhaul_state(player)
    goods = []
    if player.grain >= 30:
        goods.append(("grain", "🌾 Зерно", min(200, player.grain)))
    for metal in METAL_TYPES:
        amount = safe_int(player.metals.get(metal, 0), 0)
        if amount > 0:
            label = METAL_NAMES.get(metal, metal)
            goods.append((metal, label, amount))
    for res, amount in player.v24.get("resources", {}).items():
        if amount > 0 and res not in {g[0] for g in goods}:
            goods.append((res, RESOURCE_INFO.get(res, (res,0,0))[0], amount))
    return goods


def send_trade_caravan(player):
    state = ensure_republic_overhaul_state(player)
    state["resources"] = calculate_resources(player)
    goods = _available_trade_goods(player)
    if not goods:
        print(clr("  Нет товаров для каравана.", C.RED)); pause(); return
    rows = [(str(i), label, str(amount), f"цена {state['trade_market'].get(key, 100)}%") for i, (key, label, amount) in enumerate(goods, 1)]
    rui_table("Товары", ["#", "Товар", "Доступно", "Рынок"], rows, color=C.CYAN)
    pick = read_choice(f"\n{clr('  Товар: ', C.CYAN)}", [str(i) for i in range(1, len(goods)+1)] + ["Q"])
    if pick == "Q": return
    key, label, available = goods[int(pick)-1]
    amount = min(available, 50 if key == "grain" else 5)
    base_value = RESOURCE_INFO.get(key, (label, 10, 0))[1]
    if key in METAL_TYPES:
        base_value = {"iron": 12, "copper": 10, "silver": 24, "gold": 34}.get(key, 12)
    market = state["trade_market"].get(key, 100)
    destinations = [p["name"] for p in player.provinces if p.get("name") != "Latium"] or ["Campania"]
    for i, d in enumerate(destinations, 1): print(f"  {i}. Roma → {d}")
    dpick = read_choice(f"\n{clr('  Маршрут: ', C.CYAN)}", [str(i) for i in range(1, len(destinations)+1)] + ["Q"])
    if dpick == "Q": return
    dest = destinations[int(dpick)-1]
    escorts = [("none", "без охраны", 30), ("aux", "ауксилия", 16), ("legion", "легион", 7)]
    valid = ["1"]
    print(clr("\n  Охрана:", C.GOLD))
    for i, (_, name, risk) in enumerate(escorts, 1):
        ok = i == 1 or (i == 2 and player.aux_units) or (i == 3 and player.legions)
        print((f"  {i}. {name} — риск {risk}%" if ok else clr(f"  {i}. {name} [нет войск]", C.GRAY)))
        if ok: valid.append(str(i))
    epick = read_choice(f"\n{clr('  Охрана: ', C.CYAN)}", sorted(set(valid)) + ["Q"])
    if epick == "Q": return
    escort, _, risk = escorts[int(epick)-1]
    # Списываем товар.
    if key == "grain":
        player.grain -= amount
    elif key in METAL_TYPES:
        player.metals[key] = max(0, player.metals.get(key, 0) - amount)
    elif RESOURCE_ECONOMY is not None:
        resource_state = RESOURCE_ECONOMY.ensure_state(player, resource_economy_context(player))
        if key in resource_state.get("stockpiles", {}):
            resource_state["stockpiles"][key] = max(
                0.0, float(resource_state["stockpiles"].get(key, 0.0)) - amount
            )
    # Риск ниже при морском контроле и активном флоте.
    risk = max(3, risk - player.v24["fleet"].get("sea_control", 10)//12)
    value = max(10, int(amount * base_value * market / 100))
    turns = random.randint(2, 4)
    state["caravans"].append({"origin":"Roma", "dest":dest, "goods":key, "amount":amount, "value":value, "turns":turns, "risk":risk, "escort":escort})
    print(clr(f"  Караван отправлен: {label} ×{amount}, прибыль при прибытии {value}, срок {turns} хода, риск {risk}%.", C.GREEN))
    log_event(player, f"Караван Roma → {dest}: {label} ×{amount}")
    pause()


def found_trade_route(player):
    ensure_republic_overhaul_state(player)
    route_cost = game_price(player, 100, market=True)
    if player.gold < route_cost:
        print(clr(f"  Недостаточно золота: нужно {route_cost}.", C.RED)); pause(); return
    candidates = [p["name"] for p in player.provinces if isinstance(p, dict) and p.get("name") != "Latium"]
    existing = {r["name"].split("↔")[-1].strip() for r in player.v24["trade_routes"]}
    candidates = [c for c in candidates if c not in existing]
    if not candidates:
        print(clr("  Нужна новая провинция за пределами Лация без действующего маршрута.", C.RED)); pause(); return
    for i, c in enumerate(candidates, 1):
        value = 18 + len(PROVINCE_RESOURCES.get(c, [])) * 8
        print(f"  {i}. Roma ↔ {c} — +{value} золота/ход")
    pick = read_choice(f"\n{clr('  Маршрут: ', C.CYAN)}", [str(i) for i in range(1, len(candidates)+1)] + ["Q"])
    if pick == "Q": return
    dest = candidates[int(pick)-1]
    value = 18 + len(PROVINCE_RESOURCES.get(dest, [])) * 8
    player.gold -= route_cost
    player.v24["trade_routes"].append({"name": f"Roma ↔ {dest}", "value": value, "active": True})
    log_event(player, f"Основан торговый путь Roma ↔ {dest}")
    print(clr(f"  Основан торговый путь Roma ↔ {dest}: +{value} золота/ход.", C.GREEN))
    pause()


def guard_trade_routes(player):
    ensure_republic_overhaul_state(player)
    guard_cost = game_price(player, 50, market=True)
    if player.gold < guard_cost:
        print(clr(f"  Недостаточно золота: нужно {guard_cost}.", C.RED)); pause(); return
    player.gold -= guard_cost
    fleet = player.v24["fleet"]
    fleet["pirate_threat"] = max(0, fleet.get("pirate_threat", 20) - 15)
    for route in player.v24["trade_routes"]: route["active"] = True
    for c in player.v24["caravans"]: c["risk"] = max(2, c.get("risk", 20) - 8)
    log_event(player, "Торговые пути взяты под усиленную охрану")
    print(clr("  Маршруты очищены: пираты отступают, риски караванов снижены.", C.GREEN))
    pause()


def try_legion_breakthrough(player, legion: Legion, target: dict, mult: float) -> tuple[bool, str]:
    """После победы легион может повредить следующий город и взять его лишь при 100% урона."""
    next_city = next_city_to_attack(player, target)
    if not next_city:
        return False, ""
    can_attack, reason = can_legion_attack_city(legion, next_city)
    if not can_attack:
        return False, reason

    chance = 14 + max(0, safe_int(getattr(player, "morale", 70), 70) - 60) // 2 + max(0, legion.quality - 5) * 3
    if getattr(legion, "veterans", False):
        chance += 7
    chance = max(5, min(45, chance))
    if random.randint(1, 100) > chance:
        return False, f"прорыв не удался ({chance}%)"

    spend_legion_attack_action(legion, next_city)
    legion.location = next_city["name"]
    raw_damage = calculate_legion_city_damage(player, legion, next_city, True)
    breakthrough_damage = max(4, int(round(raw_damage * 0.75)))
    actual, total_damage, remaining = apply_city_siege_damage(
        player, target["name"], next_city["name"], breakthrough_damage
    )

    if total_damage < CITY_SIEGE_MAX_DAMAGE:
        log_event(
            player,
            f"Прорыв: {legion.name} повредил оборону {next_city['name']} "
            f"на {actual}% (всего {total_damage}%)",
        )
        return False, (
            f"⚡ Прорыв! {legion.name} атаковал следующий город {next_city['name']}: "
            f"+{actual}% урона, оборона {remaining}%."
        )

    taken = player.city_campaigns.setdefault(target["name"], [])
    if next_city["name"] not in taken:
        taken.append(next_city["name"])
    clear_city_siege_damage(player, target["name"], next_city["name"])
    reward = city_conquest_reward(player, target, next_city, source="breakthrough", announce=False)
    player.glory += 8 + safe_int(next_city.get("difficulty", 3), 3)
    log_event(player, f"Прорыв: {legion.name} взял второй город {next_city['name']} в {target['name']}")
    return True, (
        f"⚡ Прорыв! {legion.name} добил оборону и взял второй город: {next_city['name']} "
        f"(шанс {chance}%). Трофеи: +{reward['gold']} золота, +{reward['grain']} зерна."
    )


