def v24_end_turn_tick(player):
    ensure_v24_state(player)
    res_gold, res_grain = v24_resource_income(player)
    trade_gold = v24_trade_income(player)
    sea_grain = v25_sea_grain_income(player)
    fleet_cost = v24_fleet_upkeep(player)
    v24_tick_senate(player)
    v24_tick_trade_and_fleet(player)
    if res_gold or res_grain or trade_gold or sea_grain or fleet_cost:
        log_event(
            player,
            f"Mare Nostrum учтено в бюджете: доход {res_gold + trade_gold}, "
            f"флот -{fleet_cost}, зерно +{res_grain + sea_grain}",
        )


# ─── КОНЕЦ ХОДА ──────────────────────────────────────────────────────────────

def _check_general_mutiny(player: Player):
    """
    Каждый ход генерал с лояльностью ≤ порога может поднять мятеж.
    Механика отличается от AIFaction: здесь легион буквально уходит к мятежному генералу.
    """
    threshold = SETTINGS.get("general_mutiny_loyalty_threshold", 15)
    chance    = SETTINGS["general_mutiny_chance"] * player.diff()["ai_faction_growth_mult"]
    for legion in player.legions[:]:   # копия списка — возможно удаление
        g = legion.general
        if g.loyalty <= threshold and random.random() < chance:
            player.legions.remove(legion)
            player.senate_rep = max(0, player.senate_rep - 15)
            player.unrest = min(100, player.unrest + 20)
            print(clr(f"\n  ⚔ МЯТЕЖ ГЕНЕРАЛА! {g.name} уводит {legion.name} из-под вашей власти!", C.BOLD + C.RED))
            print(f"  Сенат в ужасе. Репутация -15, беспорядки +20")
            log_event(player, f"Генерал {g.name} поднял мятеж — {legion.name} потерян")
            break   # один мятеж за ход достаточно


