def ensure_victory_state(player: Player):
    if not hasattr(player, "victory_peace_streak"):
        player.victory_peace_streak = 0

def total_world_cities() -> int:
    """Сколько городов существует на текущей карте после нормализации данных."""
    return sum(len(p.get("cities", [])) for p in PROVINCES_DATA)

def _city_cache_signature(player: Player) -> tuple:
    """Дешёвая сигнатура состояния городов для автоматической инвалидизации кэша."""
    provinces = tuple(
        (p.get("name"), len(safe_list(p.get("cities"))), p.get("map_data_version"))
        for p in safe_list(getattr(player, "provinces", [])) if isinstance(p, dict)
    )
    campaigns = tuple(
        sorted((str(k), tuple(sorted(set(safe_list(v))))) for k, v in safe_dict(getattr(player, "city_campaigns", {})).items())
    )
    return (MAP_DATA_VERSION, provinces, campaigns)

def _build_city_cache(player: Player) -> dict:
    ensure_province_details(player)
    ensure_city_campaigns(player)
    signature = _city_cache_signature(player)
    cached = getattr(player, "_cached_cities", None)
    if isinstance(cached, dict) and cached.get("signature") == signature:
        return cached

    owned = {p.get("name") for p in player.provinces}
    captured_total = sum(len(safe_list(p.get("cities"))) for p in player.provinces if isinstance(p, dict))
    for prov_name, city_names in player.city_campaigns.items():
        if prov_name not in owned:
            captured_total += len(set(safe_list(city_names)))

    all_owned = len(owned) >= len(PROVINCES_DATA)
    if all_owned:
        owned_by_name = {p.get("name"): p for p in player.provinces if isinstance(p, dict)}
        for prov_def in PROVINCES_DATA:
            owned_prov = owned_by_name.get(prov_def["name"])
            if not owned_prov:
                all_owned = False
                break
            captured = {c.get("name") for c in safe_list(owned_prov.get("cities")) if isinstance(c, dict) and c.get("captured", True)}
            needed = {c.get("name") for c in safe_list(prov_def.get("cities")) if isinstance(c, dict)}
            if not needed.issubset(captured):
                all_owned = False
                break

    cached = {"signature": signature, "captured": captured_total, "all_owned": all_owned}
    player._cached_cities = cached
    return cached

def captured_world_cities(player: Player) -> int:
    """Сколько городов уже реально взято: полные провинции + частичные походы."""
    return safe_int(_build_city_cache(player).get("captured", 0), 0, 0)

def all_owned_cities_captured(player: Player) -> bool:
    return bool(_build_city_cache(player).get("all_owned", False))

def minimum_romanization(player: Player) -> int:
    return min((p.get("romanization", 0) for p in player.provinces), default=0)

def maximum_province_unrest(player: Player) -> int:
    return max((p.get("unrest", 0) for p in player.provinces), default=0)

def minimum_general_loyalty(player: Player) -> int:
    return min((l.general.loyalty for l in player.legions), default=0)

def minimum_governor_loyalty(player: Player) -> int:
    ensure_province_details(player)
    return min((g.loyalty for g in player.governors.values()), default=0)

def update_victory_peace_streak(player: Player):
    """Один стабильный ход засчитывается только без войн, бунтов и опасных волнений."""
    ensure_victory_state(player)
    stable = (
        not player.civil_war_active
        and player.effective_unrest() < 50
        and maximum_province_unrest(player) <= 4
        and not any(getattr(f, "at_war", False) for f in player.ai_factions)
    )
    player.victory_peace_streak = player.victory_peace_streak + 1 if stable else 0

def victory_progress_lines(player: Player) -> list[str]:
    ensure_victory_state(player)
    rules = VICTORY_RULES.get(player.difficulty, VICTORY_RULES["normal"])
    lines = []
    total_cities = total_world_cities()
    captured_cities = captured_world_cities(player)

    def mark(ok):
        return clr("✓", C.GREEN) if ok else clr("✗", C.RED)

    if "min_turn" in rules:
        lines.append(f"{mark(player.turn >= rules['min_turn'])} Ход: {player.turn}/{rules['min_turn']}")

    province_goal = len(PROVINCES_DATA) if rules.get("all_provinces") else rules.get("provinces")
    if province_goal:
        lines.append(f"{mark(len(player.provinces) >= province_goal)} Провинции: {len(player.provinces)}/{province_goal} из {len(PROVINCES_DATA)}")

    city_goal = total_cities if rules.get("all_cities") else rules.get("cities")
    if city_goal:
        lines.append(f"{mark(captured_cities >= city_goal)} Города: {captured_cities}/{city_goal} из {total_cities}")

    if rules.get("all_techs"):
        lines.append(f"{mark(len(player.tech_researched) >= len(TECH_TREE))} Технологии: {len(player.tech_researched)}/{len(TECH_TREE)}")
    elif "techs" in rules:
        lines.append(f"{mark(len(player.tech_researched) >= rules['techs'])} Технологии: {len(player.tech_researched)}/{rules['techs']} из {len(TECH_TREE)}")

    if "romanization" in rules:
        mr = minimum_romanization(player)
        lines.append(f"{mark(mr >= rules['romanization'])} Мин. романизация: {mr}/{rules['romanization']}")
    if "max_province_unrest" in rules:
        mu = maximum_province_unrest(player)
        lines.append(f"{mark(mu <= rules['max_province_unrest'])} Макс. волнения провинций: {mu}/{rules['max_province_unrest']}")

    for key, label, value in [("glory", "Слава", player.glory), ("gold", "Казна", player.gold), ("grain", "Зерно", player.grain), ("senate", "Сенат", player.senate_rep), ("people", "Народ", player.people_rep), ("legions", "Легионы", len(player.legions))]:
        if key in rules:
            lines.append(f"{mark(value >= rules[key])} {label}: {value}/{rules[key]}")

    if "general_loyalty" in rules:
        ml = minimum_general_loyalty(player)
        lines.append(f"{mark(ml >= rules['general_loyalty'])} Мин. лояльность генералов: {ml}/{rules['general_loyalty']}")
    if "governor_loyalty" in rules:
        ml = minimum_governor_loyalty(player)
        lines.append(f"{mark(ml >= rules['governor_loyalty'])} Мин. лояльность наместников: {ml}/{rules['governor_loyalty']}")
    if "peace_streak" in rules:
        lines.append(f"{mark(player.victory_peace_streak >= rules['peace_streak'])} Стабильные ходы: {player.victory_peace_streak}/{rules['peace_streak']}")
    return lines

def has_victory(player: Player) -> bool:
    ensure_victory_state(player)
    rules = VICTORY_RULES.get(player.difficulty, VICTORY_RULES["normal"])
    if player.turn < rules.get("min_turn", 0):
        return False
    if rules.get("all_provinces") and len(player.provinces) < len(PROVINCES_DATA):
        return False
    if "provinces" in rules and len(player.provinces) < rules["provinces"]:
        return False
    if rules.get("all_cities") and not all_owned_cities_captured(player):
        return False
    if "cities" in rules and captured_world_cities(player) < rules["cities"]:
        return False
    if rules.get("all_techs") and len(player.tech_researched) < len(TECH_TREE):
        return False
    if "techs" in rules and len(player.tech_researched) < rules["techs"]:
        return False
    if "romanization" in rules and minimum_romanization(player) < rules["romanization"]:
        return False
    if "max_province_unrest" in rules and maximum_province_unrest(player) > rules["max_province_unrest"]:
        return False
    checks = {
        "glory": player.glory, "gold": player.gold, "grain": player.grain,
        "senate": player.senate_rep, "people": player.people_rep,
        "legions": len(player.legions), "peace_streak": player.victory_peace_streak,
        "general_loyalty": minimum_general_loyalty(player),
        "governor_loyalty": minimum_governor_loyalty(player),
    }
    return all(checks[k] >= v for k, v in rules.items() if k in checks)

def show_victory_requirements(player: Player):
    rui_screen_start()
    rules = VICTORY_RULES.get(player.difficulty, VICTORY_RULES["normal"])
    rui_header("УСЛОВИЯ ПОБЕДЫ", "🏆", C.GOLD)
    rui_info(rules['title'], C.CYAN)
    rui_info(f"Сложность: {DIFFICULTY_PRESETS[player.difficulty]['label']}")
    if RICH_AVAILABLE:
        rows = [(line,) for line in victory_progress_lines(player)]
        rui_table("", ["Прогресс"], rows, color=C.GOLD, show_header=False)
    else:
        for line in victory_progress_lines(player):
            print("  " + line)
    rui_info("Победа засчитывается только при выполнении всех условий выбранной сложности.", C.GRAY)
    pause()

