    if player.senate_rep <= 0:
        if not bool(getattr(player, "senate_last_chance_used", False)):
            player.senate_last_chance_used = True
            restored = max(1, safe_int(SETTINGS.get("senate_last_chance_rep", 12), 12, 1, 30))
