        rui_screen_start()
        text = f"Сенат объявил {player.name} врагом народа.\nВас убивают в курии Помпея."
        if RICH_AVAILABLE:
            console.print(Panel(text, title="⚔ IDES OF MARCH!", border_style="red", box=box.DOUBLE))
