    upkeep_gold, upkeep_grain = player.upkeep()
    net_gold = report["final_gold"] - upkeep_gold
    net_grain = report["final_grain"] - upkeep_grain

    rui_section("📜 Источники золота за ход", C.CYAN)
    sorted_rows = sorted(report["rows"], key=lambda r: r["amount"], reverse=True)
