# ─── MINI-ANTICHEAT: целостность кода, диапазоны ресурсов, подпись сейвов ────
# Это не «невзламываемая» защита: локальный Python-код всегда можно изменить.
# Но такой блок ловит случайные правки .py, ручное редактирование сейвов и
# невозможные значения вроде 999999999 золота.

def integrity_file_for_script(script_path: str | None = None) -> str:
    """Отдельный baseline SHA-256 для каждого .py-файла игры.

    Это позволяет держать рядом оригинал, patched/dev-сборку и launcher без
    конфликта из-за общего roma_integrity.sha256.
    """
    script_path = script_path or __file__
    base = os.path.splitext(os.path.basename(script_path))[0]
    safe_base = re.sub(r"[^A-Za-z0-9_.\-]+", "_", base).strip("._-") or "roma_game"
    return os.path.join(SCRIPT_DIR, f"{safe_base}.sha256")


INTEGRITY_FILE = integrity_file_for_script()
SAVE_SIGNATURE_FIELD = "_roma_save_signature"
SAVE_GARBAGE_FIELD = "_roma_auxiliary_records"
SAVE_ENCRYPTED_FIELD = "_roma_encrypted_save"
SAVE_SIGNATURE_VERSION = 2

# Версии, ключи которых принимаются при чтении старых encrypted-save.
# Новые сохранения всегда используют текущую GAME_VERSION.
SAVE_KEY_COMPAT_VERSIONS = (
    GAME_VERSION,
    "2.29.6-imperial-onefile",
    "2.29.5-imperial-ui",
    "2.29.4-runtime-guard",
    "2.29.3-no-roma-menu",
    "2.26.0-lua",
)

# Ключ подписи не лежит в коде одной очевидной строкой. Это не абсолютная защита
# от человека, который умеет читать Python, но против правки JSON «на коленке»
# и поиска строки ключа в файле работает заметно лучше.
_SAVE_KEY_PARTS = (
    "524f4d41", "2d414554", "45524e41", "2d736176",
    "652d7365", "616c2d76", "322e3231", "2d53505152",
)
SAVE_SIGNATURE_KEY = bytes.fromhex("".join(_SAVE_KEY_PARTS)).decode("utf-8")

ANTICHEAT_LIMITS = {
    "gold": 5000000,
    "grain": 250000,
    "glory": 250000,
    "faith": 250000,
    "research_progress": 100000,
    "turn": 10000,
    "year": 20000,
    "legions": 120,
    "aux_units": 220,
    "fleet_ships": 500,
    "metal": 100000,
}

def json_safe_data(value, _seen: set[int] | None = None, _depth: int = 0):
    """Возвращает JSON-совместимую структуру с защитой от циклов и чрезмерной глубины."""
    if _seen is None:
        _seen = set()
    if _depth > 80:
        return "<max-depth>"

    if value is None or isinstance(value, (str, int, bool)):
        return value
    if isinstance(value, float):
        return value if math.isfinite(value) else 0.0

    trackable = isinstance(value, (set, tuple, list, dict)) or hasattr(value, "to_dict")
    obj_id = id(value)
    if trackable:
        if obj_id in _seen:
            return "<cycle>"
        _seen.add(obj_id)

    try:
        if isinstance(value, set):
            converted = [json_safe_data(v, _seen, _depth + 1) for v in value]
            return sorted(converted, key=lambda item: repr(item))
        if isinstance(value, tuple):
            return [json_safe_data(v, _seen, _depth + 1) for v in value]
        if isinstance(value, list):
            return [json_safe_data(v, _seen, _depth + 1) for v in value]
        if isinstance(value, dict):
            return {
                str(k): json_safe_data(v, _seen, _depth + 1)
                for k, v in value.items()
            }
        if hasattr(value, "to_dict"):
            try:
                return json_safe_data(value.to_dict(), _seen, _depth + 1)
            except Exception:
                return str(value)
        return str(value)
    finally:
        if trackable:
            _seen.discard(obj_id)


def _canonical_json(data) -> str:
    return json.dumps(json_safe_data(data), ensure_ascii=False, sort_keys=True, separators=(",", ":"))


def _local_hardware_id() -> str:
    """Локальный отпечаток машины для XOR-шифрования сейва.
    Важно: при смене устройства/окружения такой сейв может не открыться.
    """
    try:
        node = uuid.getnode()
    except (OSError, ValueError) as e:
        debug_log("uuid.getnode failed: %s", e, exc_info=True, level=logging.DEBUG)
        node = 0
    home = os.path.expanduser("~")
    parts = [platform.system(), platform.machine(), str(node), home[-24:]]
    return "|".join(str(x) for x in parts)

def _portable_save_fallback_id() -> str:
    """Более стабильный fallback для Termux/Pydroid, где uuid.getnode()/home могут плавать."""
    parts = [
        "portable",
        platform.system() or "unknown-os",
        platform.machine() or "unknown-machine",
        os.environ.get("ANDROID_ROOT", ""),
        os.environ.get("PREFIX", ""),
    ]
    return "|".join(str(x) for x in parts)

def _derive_save_key(
    purpose: str = "sign",
    hardware_id: str | None = None,
    game_version: str | None = None,
) -> bytes:
    version = str(game_version or GAME_VERSION)
    material = f"{SAVE_SIGNATURE_KEY}|{version}|{purpose}|{hardware_id or _local_hardware_id()}"
    return hashlib.sha256(material.encode("utf-8")).digest()

def _derive_save_key_candidates(purpose: str = "sign") -> list[bytes]:
    ids = [_local_hardware_id(), _portable_save_fallback_id()]
    unique_ids = []
    for item in ids:
        if item not in unique_ids:
            unique_ids.append(item)

    versions = []
    for version in SAVE_KEY_COMPAT_VERSIONS:
        if version and version not in versions:
            versions.append(version)

    candidates = []
    for version in versions:
        for hardware_id in unique_ids:
            key = _derive_save_key(purpose, hardware_id, game_version=version)
            if key not in candidates:
                candidates.append(key)
    return candidates

def _xor_bytes(data: bytes, key: bytes) -> bytes:
    if not key:
        return data
    return bytes(b ^ key[i % len(key)] for i, b in enumerate(data))

def encrypt_save_payload(data: dict) -> dict:
    """XOR-шифрование JSON-сейва в переносимом JSON-конверте."""
    if not isinstance(data, dict):
        raise TypeError("encrypt_save_payload ожидает dict")
    raw = _canonical_json(data).encode("utf-8")
    nonce = secrets.token_hex(16)
    portable_base_key = _derive_save_key("xor-save", _portable_save_fallback_id())
    key = hashlib.sha256(portable_base_key + nonce.encode("ascii")).digest()
    encrypted = _xor_bytes(raw, key)
    return {
        SAVE_ENCRYPTED_FIELD: {
            "version": 2,
            "algorithm": "XOR-SHA256-v2-portable-primary",
            "nonce": nonce,
            "payload": base64.b64encode(encrypted).decode("ascii"),
        }
    }


def _try_known_plaintext_save_recovery(encrypted: bytes) -> dict | None:
    """Аварийное восстановление старого XOR-сейва, если аппаратный ключ изменился.

    Старые версии могли шифровать сейв ключом, завязанным на uuid.getnode().
    Если Android/Termux меняет этот отпечаток, обычная расшифровка невозможна.
    Формат JSON при этом предсказуем: canonical JSON начинается с
    {"_roma_auxiliary_records":[{"checksum":"...
    Этого хватает, чтобы восстановить 32-байтный XOR-ключ и прочитать сейв.
    """
    known_prefix = b'{"_roma_auxiliary_records":[{"checksum":"'
    if len(encrypted) < 32:
        return None
    key = bytes(c ^ p for c, p in zip(encrypted[:32], known_prefix[:32]))
    try:
        raw = _xor_bytes(encrypted, key)
        decoded = json.loads(raw.decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError, ValueError, TypeError):
        return None
    if isinstance(decoded, dict) and SAVE_SIGNATURE_FIELD in decoded:
        debug_log("Legacy encrypted save recovered via known-plaintext XOR fallback", level=logging.WARNING)
        return decoded
    return None


def decrypt_save_payload(data: dict) -> dict:
    """Возвращает расшифрованный сейв или открытый legacy-JSON."""
    if not isinstance(data, dict) or SAVE_ENCRYPTED_FIELD not in data:
        return data

    block = data.get(SAVE_ENCRYPTED_FIELD)
    if not isinstance(block, dict):
        raise ValueError("битый encrypted-save блок: ожидался объект")

    version = safe_int(block.get("version", 0), 0, 0, 100)
    if version not in (1, 2):
        raise ValueError(f"неподдерживаемая версия encrypted-save: {version}")

    nonce = block.get("nonce")
    payload = block.get("payload")
    if not isinstance(nonce, str) or not re.fullmatch(r"[0-9a-fA-F]{8,128}", nonce):
        raise ValueError("битый encrypted-save блок: неверный nonce")
    if not isinstance(payload, str) or not payload:
        raise ValueError("битый encrypted-save блок: нет payload")
    if len(payload) > 32 * 1024 * 1024:
        raise ValueError("encrypted-save payload слишком велик")

    try:
        encrypted = base64.b64decode(payload.encode("ascii"), validate=True)
    except (binascii.Error, ValueError, TypeError, UnicodeEncodeError) as exc:
        raise ValueError(f"битый encrypted-save payload: {exc}") from exc
    if not encrypted:
        raise ValueError("encrypted-save payload пуст")

    errors = []
    for base_key in _derive_save_key_candidates("xor-save"):
        try:
            key = hashlib.sha256(base_key + nonce.encode("ascii")).digest()
            raw = _xor_bytes(encrypted, key)
            decoded = json.loads(raw.decode("utf-8"))
            if not isinstance(decoded, dict):
                raise ValueError("encrypted-save не содержит объект")
            return decoded
        except (UnicodeDecodeError, json.JSONDecodeError, ValueError) as exc:
            errors.append(str(exc))

    recovered = _try_known_plaintext_save_recovery(encrypted)
    if recovered is not None:
        print(clr(
            "  ⚠ Старое encrypted-save восстановлено. Пересохраните игру новым portable-ключом.",
            C.GOLD,
        ))
        return recovered

    debug_log("Save decrypt failed: %s", "; ".join(errors[-3:]), level=logging.WARNING)
    raise ValueError("encrypted-save не удалось расшифровать; блок повреждён или ключ изменился")

IMPORTANT_SAVE_FIELDS = ("gold", "grain", "glory", "faith", "turn", "year", "provinces", "legions", "aux_units", "metals")

def _field_checksum(field: str, value) -> str:
    """Portable checksum for important save fields.

    Раньше контрольные поля зависели от _local_hardware_id(), а на Android/Termux
    этот отпечаток может меняться между запусками. Из-за этого свежий сейв
    проходил HMAC-подпись, но падал на проверке «мусорных» контрольных полей.
    Новые сейвы используют portable-id, как и новое шифрование.
    """
    msg = f"{field}:".encode("utf-8") + _canonical_json(value).encode("utf-8")
    return hmac.new(_derive_save_key("garbage-checks", _portable_save_fallback_id()), msg, hashlib.sha256).hexdigest()

def add_garbage_checksums(data: dict) -> dict:
    """Добавляет «мусорные» поля, которые на деле являются контрольными суммами важных данных."""
    payload = dict(data) if isinstance(data, dict) else {}
    records = []
    for i, field in enumerate(IMPORTANT_SAVE_FIELDS):
        if field in payload:
            digest = _field_checksum(field, payload.get(field))
            records.append({
                "slot": f"aux_{i:02d}_{digest[:6]}",
                "noise": hashlib.sha256((digest + field).encode("utf-8")).hexdigest()[8:40],
                "checksum": digest,
            })
    # Пара настоящих пустышек, чтобы структура не выглядела как честная таблица хешей.
    records.append({"slot": "aux_rome_weather", "noise": hashlib.sha256(str(time.time_ns()).encode()).hexdigest()[:32], "checksum": ""})
    payload[SAVE_GARBAGE_FIELD] = records
    return payload

def verify_garbage_checksums(data: dict) -> bool:
    """Проверяет скрытые контрольные суммы важных полей сейва."""
    if not isinstance(data, dict):
        return False
    records = data.get(SAVE_GARBAGE_FIELD)
    if records is None:
        print(clr("  ⚠ Сейв без контрольных полей: будет обновлён при сохранении.", C.GOLD))
        return True
    if not isinstance(records, list):
        return False

    valid_records = [record for record in records if isinstance(record, dict)]
    for index, field in enumerate(IMPORTANT_SAVE_FIELDS):
        if field not in data:
            continue
        prefix = f"aux_{index:02d}_"
        record = next(
            (
                item for item in valid_records
                if str(item.get("slot", "")).startswith(prefix)
            ),
            None,
        )
        if record is None:
            return False
        expected = _field_checksum(field, data.get(field))
        actual = str(record.get("checksum", ""))
        if not hmac.compare_digest(actual, expected):
            return False
    return True

def _dead_balance_sentinel(player) -> int:
    """Выглядит как бесполезная проверка, но участвует в экономике как микробалласт.
    Если её вырезать и заменить нулём/единицей наугад, доход начнёт слегка плыть.
    """
    try:
        seed = f"{len(getattr(player, 'provinces', []))}:{getattr(player, 'turn', 1)}:{GAME_VERSION}"
        nibble = hashlib.sha256(seed.encode("utf-8")).digest()[0]
        return -1 if nibble % 29 == 0 else 0
    except (TypeError, ValueError, AttributeError) as e:
        debug_log("Dead balance sentinel fallback: %s", e, exc_info=True, level=logging.DEBUG)
        return 0

def _current_code_hash() -> str:
    """SHA-256 текущего .py-файла. Baseline хранится в отдельном .sha256 для этого скрипта."""
    try:
        with open(__file__, "rb") as f:
            return hashlib.sha256(f.read()).hexdigest()
    except OSError:
        return ""

def _known_repo_dirs() -> list[str]:
    """Кандидаты на рабочий Git-репозиторий ROMA AETERNA.

    Главный путь можно переопределить переменной окружения ROMA_REPO_DIR.
    Для Termux по умолчанию используется ~/Roma-Aeterna.
    """
    candidates = []
    env_repo = os.environ.get("ROMA_REPO_DIR", "").strip()
    if env_repo:
        candidates.append(os.path.expanduser(env_repo))
    candidates.append(SCRIPT_DIR)
    candidates.append(os.path.expanduser("~/Roma-Aeterna"))

    result = []
    for path in candidates:
        if not path:
            continue
        path = os.path.abspath(path)
        if path not in result and os.path.isdir(path):
            result.append(path)
    return result


def _mirror_integrity_to_repo(current_hash: str, show_message: bool = False) -> list[str]:
    """Копирует актуальную игру и baseline в Git-репозиторий, если он найден.

    Это удобство для разработчика: можно запускать игру из ~/downloads,
    выполнить --update-integrity, а файл игры + SHA сами попадут в ~/Roma-Aeterna.
    """
    mirrored = []
    script_name = os.path.basename(__file__)
    specific_sha_name = os.path.basename(INTEGRITY_FILE)

    for repo_dir in _known_repo_dirs():
        if not os.path.isdir(os.path.join(repo_dir, ".git")):
            continue
        try:
            # 1. Кладём актуальный .py в репозиторий, если запуск был не из него.
            dst_script = os.path.join(repo_dir, script_name)
            if os.path.abspath(dst_script) != os.path.abspath(__file__):
                shutil.copy2(__file__, dst_script)
                mirrored.append(dst_script)

            # 2. Кладём новый per-script baseline.
            dst_specific_sha = os.path.join(repo_dir, specific_sha_name)
            with open(dst_specific_sha, "w", encoding="utf-8") as f:
                f.write(current_hash + "\n")
            mirrored.append(dst_specific_sha)

            # 3. Для совместимости со старым лаунчером/репозиторием обновляем roma_integrity.sha256.
            dst_legacy_sha = os.path.join(repo_dir, "roma_integrity.sha256")
            with open(dst_legacy_sha, "w", encoding="utf-8") as f:
                f.write(current_hash + "\n")
            mirrored.append(dst_legacy_sha)

            break
        except OSError as e:
            if show_message:
                print(clr(f"  ⚠ Не удалось скопировать baseline в {repo_dir}: {e}", C.RED))
    return mirrored


def write_code_integrity_baseline(show_message: bool = False) -> bool:
    """Пересоздаёт baseline SHA-256 для текущего .py-файла.

    Режим разработчика для легального обновления игры. После правки кода
    выполните: python <игра>.py --update-integrity.

    В Termux функция также пытается автоматически скопировать актуальный .py
    и SHA-файлы в Git-репозиторий ~/Roma-Aeterna, если он существует.
    """
    current = _current_code_hash()
    if not current:
        if show_message:
            print(clr("  ⚠ Не удалось вычислить SHA-256 текущего файла.", C.RED))
        return False
    try:
        with open(INTEGRITY_FILE, "w", encoding="utf-8") as f:
            f.write(current + "\n")
        # Старое имя оставлено для совместимости с репозиторием и лаунчером.
        with open(os.path.join(SCRIPT_DIR, "roma_integrity.sha256"), "w", encoding="utf-8") as f:
            f.write(current + "\n")
    except OSError as e:
        if show_message:
            print(clr(f"  ⚠ Не удалось записать baseline SHA-256: {e}", C.RED))
        return False

    mirrored = _mirror_integrity_to_repo(current, show_message=show_message)

    if show_message:
        print(clr("\n  ✅ MINI-ANTICHEAT: baseline SHA-256 обновлён.", C.GREEN))
        print(clr(f"  Файл: {INTEGRITY_FILE}", C.GRAY))
        print(clr(f"  Совместимость: {os.path.join(SCRIPT_DIR, 'roma_integrity.sha256')}", C.GRAY))
        print(clr(f"  SHA-256: {current}", C.GRAY))
        if mirrored:
            print(clr("  Git-репозиторий обновлён автоматически:", C.GREEN))
            for path in mirrored:
                print(clr(f"    • {path}", C.GRAY))
        else:
            print(clr("  Git-репозиторий не найден. При необходимости скопируйте файлы вручную.", C.GOLD))
    return True


def handle_integrity_cli() -> bool:
    """Обрабатывает служебные команды античита и сообщает, надо ли выходить.

    Использование:
      python roma_strategy_....py --update-integrity   # обновить baseline и выйти
      python roma_strategy_....py --check-integrity    # проверить baseline и выйти
    Старый способ ROMA_RESET_INTEGRITY=1 сохранён для совместимости.
    """
    args = {str(a).strip().lower() for a in sys.argv[1:]}
    if "--update-integrity" in args or "--reset-integrity" in args or os.environ.get("ROMA_RESET_INTEGRITY") == "1":
        ok = write_code_integrity_baseline(show_message=True)
        sys.exit(0 if ok else 1)
    if "--check-integrity" in args:
        ok = verify_code_integrity(strict=False)
        if ok:
            print(clr("\n  ✅ MINI-ANTICHEAT: baseline совпадает с текущим файлом.", C.GREEN))
        else:
            print(clr("\n  ❌ MINI-ANTICHEAT: baseline не совпадает с текущим файлом.", C.RED))
        sys.exit(0 if ok else 1)
    return False


def verify_code_integrity(strict: bool = True) -> bool:
    """
    Первый запуск после установки создаёт baseline-хеш.
    Последующие запуски сравнивают SHA-256 текущего кода с baseline.

    Для легального обновления после патча используйте:
      python <имя_текущего_файла>.py --update-integrity
    или старый совместимый вариант:
      ROMA_RESET_INTEGRITY=1 python <имя_текущего_файла>.py

    В обоих режимах baseline обновляется и программа сразу завершается,
    не запуская игру.
    """
    current = _current_code_hash()
    if not current:
        return True

    if not os.path.exists(INTEGRITY_FILE):
        return write_code_integrity_baseline(show_message=False)

    try:
        with open(INTEGRITY_FILE, "r", encoding="utf-8") as f:
            expected = f.read().strip()
    except OSError:
        return True

    if not hmac.compare_digest(current, expected):
        print(clr("\n  ⚠ MINI-ANTICHEAT: файл игры изменён после создания SHA-256 baseline.", C.RED))
        print(clr(f"  Ожидалось: {expected}", C.GRAY))
        print(clr(f"  Сейчас:    {current}", C.GRAY))
        if strict:
            print(clr("  Запуск остановлен. После легального обновления выполните:", C.RED))
            print(clr(f"  python {os.path.basename(__file__)} --update-integrity", C.GOLD))
        return False
    return True

def _save_payload_for_signature(data: dict) -> dict:
    payload = dict(data) if isinstance(data, dict) else {}
    payload.pop(SAVE_SIGNATURE_FIELD, None)
    return payload

def sign_save_data(data: dict) -> dict:
    """Добавляет HMAC-SHA256 подпись к savegame JSON и скрытые контрольные поля."""
    payload = add_garbage_checksums(_save_payload_for_signature(data))
    signature = hmac.new(
        SAVE_SIGNATURE_KEY.encode("utf-8"),
        _canonical_json(payload).encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()
    signed = dict(payload)
    signed[SAVE_SIGNATURE_FIELD] = {
        "version": SAVE_SIGNATURE_VERSION,
        "algorithm": "HMAC-SHA256",
        "value": signature,
    }
    return signed

def verify_save_data_signature(data: dict) -> bool:
    """
    True — подпись верна.
    False — подпись есть, но не совпала.
    None — старый сейв без подписи: разрешаем миграцию, но следующий save подпишет файл.
    """
    if not isinstance(data, dict):
        return False
    signature_block = data.get(SAVE_SIGNATURE_FIELD)
    if signature_block is None:
        print(clr("  ⚠ Старое сохранение без подписи. После следующего сохранения оно будет подписано.", C.GOLD))
        return None
    if not isinstance(signature_block, dict):
        print(clr("  Сохранение повреждено: блок подписи имеет неверный формат.", C.RED))
        return False
    expected = signature_block.get("value")
    if not isinstance(expected, str) or not expected:
        print(clr("  Сохранение повреждено: подпись отсутствует внутри блока.", C.RED))
        return False
    payload = _save_payload_for_signature(data)
    actual = hmac.new(
        SAVE_SIGNATURE_KEY.encode("utf-8"),
        _canonical_json(payload).encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()
    if not hmac.compare_digest(str(expected), actual):
        return False
    if not verify_garbage_checksums(payload):
        # Подпись HMAC уже совпала, значит сам payload не менялся после сохранения.
        # Контрольные «мусорные» поля в старых сборках могли зависеть от нестабильного
        # Android/Termux hardware-id, поэтому не блокируем загрузку, а позволяем игроку
        # войти и пересохраниться. Следующий save перепишет проверки portable-ключом.
        print(clr("  ⚠ Контрольные поля старого формата не совпали; загрузка разрешена, пересохраните игру.", C.GOLD))
        debug_log("Save garbage checks mismatch, but HMAC signature is valid; allowing migration", level=logging.WARNING)
    return True

def anticheat_validate_player(player: Player, context: str = "runtime") -> bool:
    """
    Проверяет невозможные значения и мягко чинит их.
    Возвращает True, если всё чисто; False, если были исправления/подозрения.
    """
    if player is None:
        return True

    suspicious = []

    def clamp_attr(attr: str, low: int, high: int):
        raw = getattr(player, attr, low)
        fixed = safe_int(raw, low, low, high)
        if raw != fixed:
            suspicious.append(f"{attr}: {raw} → {fixed}")
            setattr(player, attr, fixed)

    clamp_attr("gold", 0, ANTICHEAT_LIMITS["gold"])
    clamp_attr("grain", 0, ANTICHEAT_LIMITS["grain"])
    clamp_attr("glory", 0, ANTICHEAT_LIMITS["glory"])
    clamp_attr("faith", 0, ANTICHEAT_LIMITS["faith"])
    clamp_attr("research_progress", 0, ANTICHEAT_LIMITS["research_progress"])
    clamp_attr("senate_rep", 0, 100)
    clamp_attr("people_rep", 0, 100)
    clamp_attr("unrest", 0, 100)
    clamp_attr("morale", 0, 100)
    clamp_attr("turn", 1, ANTICHEAT_LIMITS["turn"])
    clamp_attr("year", 1, ANTICHEAT_LIMITS["year"])

    if len(getattr(player, "legions", [])) > ANTICHEAT_LIMITS["legions"]:
        suspicious.append(f"legions: {len(player.legions)} → {ANTICHEAT_LIMITS['legions']}")
        player.legions = player.legions[:ANTICHEAT_LIMITS["legions"]]
    if len(getattr(player, "aux_units", [])) > ANTICHEAT_LIMITS["aux_units"]:
        suspicious.append(f"aux_units: {len(player.aux_units)} → {ANTICHEAT_LIMITS['aux_units']}")
        player.aux_units = player.aux_units[:ANTICHEAT_LIMITS["aux_units"]]

    if isinstance(getattr(player, "metals", None), dict):
        for key, value in list(player.metals.items()):
            fixed = safe_int(value, 0, 0, ANTICHEAT_LIMITS["metal"])
            if value != fixed:
                suspicious.append(f"metal.{key}: {value} → {fixed}")
                player.metals[key] = fixed

    valid_province_names = {p["name"] for p in PROVINCES_DATA}
    if len(getattr(player, "provinces", [])) > len(PROVINCES_DATA):
        suspicious.append(f"provinces: {len(player.provinces)} → {len(PROVINCES_DATA)}")
    if isinstance(getattr(player, "provinces", None), list):
        owned_names = set()
        cleaned = []
        for prov in player.provinces:
            if not isinstance(prov, dict):
                suspicious.append("province: несловарная запись удалена")
                continue
            name = prov.get("name")
            if name not in valid_province_names or name in owned_names:
                suspicious.append(f"province.{name}: удалена неверная/дублирующая запись")
                continue
            owned_names.add(name)
            for attr, low, high in (("unrest", 0, 10), ("romanization", 0, 100), ("garrison", 0, 5), ("wealth", 0, 99)):
                raw = prov.get(attr, low)
                fixed = safe_int(raw, low, low, high)
                if raw != fixed:
                    suspicious.append(f"province.{name}.{attr}: {raw} → {fixed}")
                    prov[attr] = fixed
            for city in safe_list(prov.get("cities")):
                if not isinstance(city, dict):
                    continue
                raw_pop = city.get("population", 0)
                fixed_pop = safe_int(raw_pop, 0, 0, 1000000)
                if raw_pop != fixed_pop:
                    suspicious.append(f"city.{city.get('name','?')}.population: {raw_pop} → {fixed_pop}")
                    city["population"] = fixed_pop
            cleaned.append(prov)
        player.provinces = cleaned[:len(PROVINCES_DATA)]

    invalidate_city_cache(player)

    if suspicious:
        print(clr(f"\n  ⚠ MINI-ANTICHEAT ({context}): исправлены подозрительные значения:", C.RED))
        for item in suspicious[:8]:
            print(clr(f"    • {item}", C.GRAY))
        if len(suspicious) > 8:
            print(clr(f"    • …ещё {len(suspicious) - 8}", C.GRAY))
        try:
            log_event(player, "Mini-anticheat исправил невозможные значения")
        except (AttributeError, TypeError, ValueError) as e:
            debug_log("Could not write anticheat event log: %s", e, exc_info=True, level=logging.DEBUG)
        return False
    return True


def validate_save_payload_structure(data: dict) -> tuple[bool, str]:
    """Проверяет типы и разумные пределы legacy/нового payload до Player.from_dict."""
    if not isinstance(data, dict):
        return False, "корень сохранения должен быть объектом"

    scalar_rules = {
        "gold": (0, ANTICHEAT_LIMITS["gold"]),
        "grain": (0, ANTICHEAT_LIMITS["grain"]),
        "glory": (0, ANTICHEAT_LIMITS["glory"]),
        "faith": (0, ANTICHEAT_LIMITS["faith"]),
        "turn": (0, ANTICHEAT_LIMITS["turn"]),
        "year": (0, ANTICHEAT_LIMITS["year"]),
    }
    for field, (low, high) in scalar_rules.items():
        if field not in data:
            continue
        value = data.get(field)
        try:
            number = int(value)
        except (TypeError, ValueError, OverflowError):
            return False, f"поле {field!r} не является числом"
        if number < low or number > high * 4:
            return False, f"поле {field!r} выходит за допустимые пределы"

    for field, limit in (
        ("provinces", max(1, len(PROVINCES_DATA)) * 2),
        ("legions", ANTICHEAT_LIMITS["legions"] * 2),
        ("aux_units", ANTICHEAT_LIMITS["aux_units"] * 2),
    ):
        if field in data:
            value = data.get(field)
            if not isinstance(value, list):
                return False, f"поле {field!r} должно быть списком"
            if len(value) > limit:
                return False, f"поле {field!r} содержит слишком много записей"

    if "metals" in data and not isinstance(data.get("metals"), dict):
        return False, "поле 'metals' должно быть объектом"
    return True, "ok"


def save_game(player: Player, filename: str = SAVE_FILE, *, autosave: bool = False):
    """Атомарное сохранение.

    Ручное сохранение выполняет полный fsync и резервное копирование. Автосейв
    сохраняет тот же полный state, но использует компактный JSON и делает тяжёлый
    backup/fsync только через заданный интервал.
    """
    filename = safe_save_path(filename, default=SAVE_FILE)
    temp_filename = filename + ".tmp"
    backup_filename = filename + ".bak"
    try:
        ensure_all_states(player)
        anticheat_validate_player(player, "autosave" if autosave else "save")
        data = encrypt_save_payload(sign_save_data(player.to_dict()))

        backup_interval = max(1, safe_int(SETTINGS.get("autosave_backup_interval", 20), 20))
        full_integrity = not autosave or player.turn % backup_interval == 0
        with open(temp_filename, "w", encoding="utf-8") as handle:
            if autosave:
                json.dump(data, handle, ensure_ascii=False, separators=(",", ":"))
            else:
                json.dump(data, handle, ensure_ascii=False, indent=2)
            handle.flush()
            if full_integrity:
                try:
                    os.fsync(handle.fileno())
                except OSError as exc:
                    debug_log("Save fsync failed: %s", exc, exc_info=True, level=logging.WARNING)

        if full_integrity and os.path.exists(filename):
            try:
                shutil.copy2(filename, backup_filename)
            except OSError as exc:
                debug_log("Save backup failed: %s", exc, exc_info=True, level=logging.WARNING)
        os.replace(temp_filename, filename)
        debug_log(
            "Game %s saved atomically to %s",
            "auto" if autosave else "manual",
            filename,
            level=logging.INFO,
        )
        return True
    except (OSError, TypeError, ValueError, OverflowError) as exc:
        try:
            if os.path.exists(temp_filename):
                os.remove(temp_filename)
        except OSError as cleanup_exc:
            debug_log("Save temp cleanup failed: %s", cleanup_exc, exc_info=True, level=logging.WARNING)
        debug_log("Save failed: %s", exc, exc_info=True, level=logging.ERROR)
        print(clr(f"  Ошибка сохранения: {exc}", C.RED))
        return False

def load_game(filename: str = SAVE_FILE):
    filename = safe_save_path(filename, default=SAVE_FILE)
    try:
        with open(filename, "r", encoding="utf-8") as handle:
            data = json.load(handle)

        data = decrypt_save_payload(data)
        signature_ok = verify_save_data_signature(data)
        if signature_ok is False:
            print(clr("  Сохранение изменено вручную или повреждено: подпись не совпала.", C.RED))
            return None

        data = _save_payload_for_signature(data)
        data.pop(SAVE_GARBAGE_FIELD, None)

        valid, reason = validate_save_payload_structure(data)
        if not valid:
            print(clr(f"  Сохранение отклонено: {reason}.", C.RED))
            debug_log("Save structure rejected: %s", reason, level=logging.ERROR)
            return None

        player = Player.from_dict(data)
        ensure_all_states(player)
        anticheat_validate_player(player, "load")
        return player
    except FileNotFoundError:
        print(clr(f"  Файл сохранения не найден: {filename}", C.GOLD))
        return None
    except (json.JSONDecodeError, KeyError, TypeError, ValueError, OSError) as exc:
        debug_log("Load failed from %s: %s", filename, exc, exc_info=True, level=logging.ERROR)
        print(clr(f"  Сохранение повреждено: {exc}", C.RED))
        return None

def save_game_menu(player: Player):
    rui_screen_start()
    rui_header("СОХРАНЕНИЕ", "💾", C.GOLD)
