def setup_madness_start(player: "Player"):
    """Старт режима «Безумие»: 5 фулл-легионов против ИИ с шансами ×20."""
    player.gold = max(player.gold, 1800)
    player.grain = max(player.grain, 1400)
    player.glory += 300
    player.morale = 100
    player.senate_rep = max(player.senate_rep, 65)
    player.people_rep = max(player.people_rep, 65)
    player.metals["iron"] = max(player.metals.get("iron", 0), 20)
    player.metals["copper"] = max(player.metals.get("copper", 0), 12)
    player.metals["silver"] = max(player.metals.get("silver", 0), 6)
    player.metals["gold"] = max(player.metals.get("gold", 0), 3)
    player.legions.clear()
    names = [
        ("Луций Корнелий Сулла", "Legio I Furor"),
        ("Гай Юлий Цезарь", "Legio II Ultima"),
        ("Марк Випсаний Агриппа", "Legio III Fulminata"),
        ("Сципион Африканский", "Legio IV Invicta"),
        ("Марк Антоний", "Legio V Ferrata"),
    ]
    for gname, lname in names:
        g = General(gname, "legendary", loyalty=100)
        l = Legion(lname, quality=10, general=g)
        l.strength = 100
        l.morale = 100
        l.veterans = True
        l.elite = True
        if hasattr(l, "fatigue"):
            l.fatigue = 0
        player.legions.append(l)
    ensure_enemy_grand_ai_state(player)
    # Сразу создаём плотную вражескую карту, чтобы режим с первого хода был бойней.
    for _ in range(min(18, _enemy_armies_cap(player))):
        spawn_enemy_army(player, reason="madness_start")
    grace_turns = max(0, safe_int(SETTINGS.get("madness_grace_turns", 30), 30))
    log_event(player, f"Режим Безумие: 5 фулл-легионов, ИИ ×20; фора от хаоса до {grace_turns}-го хода")
    print(clr(f"  ☠ БЕЗУМИЕ: первые {grace_turns} ходов действует убывающий чрезвычайный контроль волнений.", C.BOLD + C.PURPLE))

