MOBILE_TITLE_SUBLINE = "SENATUS • LEGIONES • CLASSIS • PROVINCIAE"


def mobile_title_width() -> int:
    """Безопасная ширина стартового экрана для телефонов."""
    try:
        cols = os.get_terminal_size().columns
    except OSError:
        cols =UI_WIDTH
    # 58 — верхний предел: шире на телефоне уже начинает выглядеть как простыня.
    return max(42, min(58, cols - 2))


def mobile_plain(text: str) -> str:
    """Убирает ANSI-коды для расчёта ширины."""
    return re.sub(r"\033\[[0-9;]*m", "", str(text))


def mobile_wcswidth(text: str) -> int:
    """Приблизительная визуальная ширина без внешней зависимости wcwidth.

    Termux часто считает эмодзи и CJK-символы двойной шириной. Для рамок это
    важно: обычный len() делает красивые панели кривыми. Алгоритм не идеален,
    но на Android ведёт себя ощутимо лучше старого подсчёта.
    """
    import unicodedata
    text = mobile_plain(text)
    total = 0
    for ch in text:
        if unicodedata.combining(ch):
            continue
        code = ord(ch)
        if code == 0:
            continue
        if 0x1F000 <= code <= 0x1FAFF or 0x2600 <= code <= 0x27BF:
            total += 2
        elif unicodedata.east_asian_width(ch) in ("F", "W"):
            total += 2
        else:
            total += 1
    return total


def mobile_fit(text: str, width: int, align: str = "left") -> str:
    """Обрезает/добивает строку пробелами по визуальной ширине."""
    clean = mobile_plain(text)
    if mobile_wcswidth(clean) > width:
        out = ""
        for ch in clean:
            if mobile_wcswidth(out + ch + "…") > width:
                break
            out += ch
        clean = out + "…"
    pad = max(0, width - mobile_wcswidth(clean))
    if align == "center":
        left = pad // 2
        right = pad - left
        return " " * left + clean + " " * right
    if align == "right":
        return " " * pad + clean
    return clean + " " * pad


def mobile_center(text: str, width: int) -> str:
    return mobile_fit(text, width, align="center")


def mobile_shorten_path(path: str, width: int) -> str:
    """Показывает путь к сейву так, чтобы он не ломал мобильную рамку."""
    path = str(path or "")
    if mobile_wcswidth(path) <= width:
        return path
    base = os.path.basename(path)
    tail = f"…/{base}"
    if mobile_wcswidth(tail) <= width:
        return tail
    return mobile_fit(base, width)


def mobile_rule(label: str = "", color=C.GOLD, left: str = "╠", right: str = "╣", char: str = "═") -> None:
    width = mobile_title_width()
    inner = width - 2
    if not label:
        print(clr(left + char * inner + right, color))
        return
    label = f" {label} "
    label_width = mobile_wcswidth(label)
    remain = max(0, inner - label_width)
    a = remain // 2
    b = remain - a
    print(clr(left + char * a + label + char * b + right, color))


def mobile_box(title: str, lines: list[str], color=C.GOLD, icon: str = "🏛") -> None:
    """Красивая мобильная рамка без разъезда Unicode-ширины."""
    width = mobile_title_width()
    inner = width - 2
    content = inner - 2
    print(clr("╔" + "═" * inner + "╗", color))
    head = f" {icon} {title} "
    print(clr("║" + mobile_center(head, inner) + "║", color))
    print(clr("╠" + "═" * inner + "╣", color))
    for raw in lines:
        raw = str(raw)
        clean = mobile_plain(raw)
        wrapped = textwrap.wrap(
            clean,
            width=max(24, content),
            break_long_words=False,
            break_on_hyphens=False,
        ) or [""]
        for line in wrapped:
            print(clr("║ ", color) + mobile_fit(line, content) + clr(" ║", color))
    print(clr("╚" + "═" * inner + "╝", color))


def mobile_badges(items: list[str], color=C.CYAN) -> None:
    """Ряд маленьких «чипов» под логотипом."""
    width = mobile_title_width()
    line = "  ".join(f"[{item}]" for item in items)
    print(clr(mobile_center(line, width), color))


