def _choose_roman_register_item(title: str, intro: list[str], table_title: str, data: dict[str, dict], prompt: str, icon: str, color=C.GOLD) -> str:
    """Общий экран выбора для новых пунктов регистрации сессии."""
    mobile_box(title, intro, color=color, icon=icon)
    if RICH_AVAILABLE:
        rows = []
        for num, item in data.items():
            rows.append((f"[gold1]{num}[/]", item["name"], item["ru"], item["hint"]))
        rui_table(table_title, ["#", "Formula", "Смысл", "Первый эффект"], rows, color=color, show_header=False)
    else:
        lines = [f"{num} — {item['name']}: {item['ru']}; {item['hint']}" for num, item in data.items()]
        mobile_box(table_title, lines, color=color, icon="📜")
    choice = read_choice(f"\n{clr('  ' + prompt, C.CYAN)}", list(data.keys()))
    item = data[choice]
    mobile_box("Tabella Signata", [
        f"{item['name']} — {item['ru']}",
        item["desc"],
    ], color=C.GREEN, icon="✓")
    return item["key"]


