def _register_label(data: dict[str, dict], key: str) -> str:
    for item in data.values():
        if item["key"] == key:
            return f"{item['name']} — {item['ru']}"
    return key or "не выбрано"


def apply_session_register(player: "Player") -> None:
    """Применяет новые стартовые выборы к ресурсам и состоянию партии."""
    patron = getattr(player, "patron_deity", "")
    style = getattr(player, "command_style", "")
    mandate = getattr(player, "campaign_mandate", "")
    edict = getattr(player, "first_edict", "")

    # Deus tutelaris
    if patron == "iuppiter":
        player.senate_rep = min(100, player.senate_rep + 10); player.glory += 25
    elif patron == "mars":
        player.morale = min(100, player.morale + 6); player.metals["iron"] = player.metals.get("iron", 0) + 1
        if player.legions:
            player.legions[0].quality = min(10, player.legions[0].quality + 1)
    elif patron == "minerva":
        player.science_points = getattr(player, "science_points", 0) + 30; player.research_progress = getattr(player, "research_progress", 0) + 10
        player.senate_rep = min(100, player.senate_rep + 5)
    elif patron == "neptunus":
        player.gold += 40; player.glory += 15
        try:
            ensure_v24_state(player)
            player.v24["fleet"]["naval_tradition"] = player.v24["fleet"].get("naval_tradition", 0) + 12
        except Exception as exc:
            debug_log("Patron fleet bonus failed: %s", exc, exc_info=True, level=logging.WARNING)
    elif patron == "vesta":
        player.grain += 100; player.people_rep = min(100, player.people_rep + 5); player.unrest = max(0, player.unrest - 5)

    # Mos imperii
    if style == "disciplina":
        player.unrest = max(0, player.unrest - 5); player.senate_rep = min(100, player.senate_rep + 5); player.morale = min(100, player.morale + 3)
    elif style == "celeritas":
        player.glory += 20; player.morale = min(100, player.morale + 5); player.gold = max(50, player.gold - game_price(player, 20, market=True))
    elif style == "clementia":
        player.people_rep = min(100, player.people_rep + 10); player.unrest = max(0, player.unrest - 4)
        for tribe in getattr(player, "barbarian_tribes", {}).values():
            tribe["relation"] = min(100, safe_int(tribe.get("relation", 50), 50, 0, 100) + 4)
    elif style == "severitas":
        player.unrest = max(0, player.unrest - 8); player.senate_rep = min(100, player.senate_rep + 8); player.people_rep = max(0, player.people_rep - 5)
    elif style == "prudentia":
        player.gold += 35; player.science_points = getattr(player, "science_points", 0) + 15

    # Mandatum senatus
    if mandate == "italia_prima":
        player.grain += 70; player.unrest = max(0, player.unrest - 5); player.senate_rep = min(100, player.senate_rep + 4)
    elif mandate == "mare_nostrum":
        player.gold += 55; player.glory += 12
        try:
            ensure_v24_state(player)
            player.v24["fleet"]["naval_tradition"] = player.v24["fleet"].get("naval_tradition", 0) + 10
        except Exception as exc:
            debug_log("Mandate fleet bonus failed: %s", exc, exc_info=True, level=logging.WARNING)
    elif mandate == "leges_et_viae":
        player.gold += 40; player.science_points = getattr(player, "science_points", 0) + 20; player.unrest = max(0, player.unrest - 3)
    elif mandate == "pax_romana":
        player.people_rep = min(100, player.people_rep + 8); player.unrest = max(0, player.unrest - 8)
        for power in getattr(player, "diplomacy", {}).values():
            if isinstance(power, dict):
                power["disposition"] = min(100, safe_int(power.get("disposition", 50), 50, 0, 100) + 3)
    elif mandate == "gloria_sine_fine":
        player.glory += 40; player.morale = min(100, player.morale + 4); player.unrest = min(100, player.unrest + 4)

    # Edictum primum
    if edict == "edictum_frumentarium":
        player.grain += 120; player.people_rep = min(100, player.people_rep + 8)
    elif edict == "census_argentarius":
        player.gold += 90; player.senate_rep = min(100, player.senate_rep + 6); player.people_rep = max(0, player.people_rep - 4)
    elif edict == "ludi_publici":
        player.gold = max(0, player.gold - game_price(player, 45, market=True)); player.people_rep = min(100, player.people_rep + 12); player.morale = min(100, player.morale + 4)
    elif edict == "castra_nova":
        player.grain = max(0, player.grain - 35); player.metals["iron"] = player.metals.get("iron", 0) + 1
        if player.legions:
            player.legions[0].quality = min(10, player.legions[0].quality + 1)
    elif edict == "sacra_publica":
        player.faith = getattr(player, "faith", 0) + 50; player.unrest = max(0, player.unrest - 4); player.senate_rep = min(100, player.senate_rep + 4)

    player.session_register = {
        "patron_deity": patron,
        "command_style": style,
        "campaign_mandate": mandate,
        "first_edict": edict,
    }
    log_event(player, f"Цензовая регистрация: {_register_label(ROMAN_PATRON_DEITIES, patron)}; {_register_label(ROMAN_COMMAND_STYLES, style)}; {_register_label(ROMAN_CAMPAIGN_MANDATES, mandate)}; {_register_label(ROMAN_FIRST_EDICTS, edict)}")


def show_session_register_summary(player: "Player") -> None:
    """Финальная карточка регистрации перед входом в основное меню."""
    diff_label = DIFFICULTY_PRESETS.get(player.difficulty, DIFFICULTY_PRESETS["normal"])["label"]
    lines = [
        f"Имя: {player.name}",
        f"Род: {getattr(player, 'gens', 'gens incerta')}",
        f"Должность: {player_office_title(player)}",
        f"Партия: {'Populares — партия Форума' if player.faction == 'populares' else 'Optimates — партия Сената'}",
        f"Покровительство: {_register_label(ROMAN_PATRON_DEITIES, getattr(player, 'patron_deity', ''))}",
        f"Нрав власти: {_register_label(ROMAN_COMMAND_STYLES, getattr(player, 'command_style', ''))}",
        f"Наказ: {_register_label(ROMAN_CAMPAIGN_MANDATES, getattr(player, 'campaign_mandate', ''))}",
        f"Первый эдикт: {_register_label(ROMAN_FIRST_EDICTS, getattr(player, 'first_edict', ''))}",
        f"Сложность: {diff_label}",
        f"Итог старта: {player.gold} золота, {player.grain} зерна, {player.glory} славы, {player.faith} веры",
    ]
    mobile_box("Tabula Sessionis", lines, color=C.GREEN, icon="📜")


def title_screen():
    rui_screen_start()
    mobile_title_banner()
    mobile_roman_prologue()

    if os.path.exists(SAVE_FILE):
        mobile_save_box()
        ch = read_choice(f"\n{clr('  Edictum tuum (Y/N): ', C.CYAN)}", ["Y", "N"])
        if ch == "Y":
            loaded = load_game()
            if loaded:
                diff_label = DIFFICULTY_PRESETS.get(loaded.difficulty, {}).get("label", "?")
                mobile_box("Кампания загружена", [
                    f"Имя: {loaded.name}",
                    f"Сложность: {diff_label}",
                    f"Год: {loaded.year} AUC   Ход: {loaded.turn}",
                    f"Слава: {loaded.glory}",
                ], color=C.GREEN, icon="✓")
                pause()
                return loaded
            print(clr("  Не удалось загрузить, начинаем новую игру.", C.RED))

    mobile_new_campaign_box()
    pause("Нажмите Enter, чтобы явиться к цензору и Сенату…")

    name_parts = read_roman_player_name()
    name = name_parts["full"]
    starting_office = choose_starting_office()

    fc = choose_roman_faction()
    patron_deity = choose_patron_deity()
    command_style = choose_command_style()
    campaign_mandate = choose_campaign_mandate()
    first_edict = choose_first_edict()

    diff_ch = choose_roman_difficulty()
    difficulty = {"E": "easy", "N": "normal", "H": "hardcore", "M": "madness"}[diff_ch]
    bonus = DIFFICULTY_PRESETS[difficulty]["starting_gold_bonus"]

    if fc == "2":
        p = Player(name, "populares", difficulty)
        p.people_rep = 70; p.senate_rep = 40
    else:
        p = Player(name, "optimates", difficulty)
        p.senate_rep = 70; p.people_rep = 40

    p.praenomen = name_parts["praenomen"]
    p.nomen = name_parts["nomen"]
    p.cognomen = name_parts["cognomen"]
    p.gens = name_parts["gens"]
    p.starting_office = starting_office
    p.office_title = player_office_title(p)
    p.patron_deity = patron_deity
    p.command_style = command_style
    p.campaign_mandate = campaign_mandate
    p.first_edict = first_edict

    p.gold = max(50, p.gold + bonus)

    # Стартовые провинции
    p.provinces.append(captured_province_copy("Latium"))
    p.provinces.append(captured_province_copy("Campania"))
    ensure_province_details(p)
    ensure_expansion_state(p)
    p.metals["iron"] = 3
    p.metals["copper"] = 2
    if difficulty == "madness":
        setup_madness_start(p)
    else:
        p.legions.append(Legion("Legio I Romana", quality=4))
    apply_starting_office(p)
    apply_session_register(p)
    refresh_consular_pair(p)
    ensure_all_states(p)
    show_session_register_summary(p)
    pause("Нажмите Enter, чтобы открыть главное меню Республики…")
    log_event(p, f"Начало игры — {p.name}, {player_office_title(p)} [{DIFFICULTY_PRESETS[difficulty]['label']}]")
    return p

