# ─── ВНЕШНИЕ JSON-ЦИТАТЫ v2.25.6 ────────────────────────────────────────────
def _quote_json_dir() -> str:
    return os.path.join(SCRIPT_DIR, "data", "quotes")


def _load_quote_json(filename: str) -> list[dict[str, Any]]:
    path = os.path.join(_quote_json_dir(), filename)
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except FileNotFoundError:
        debug_log("Quote JSON not found: %s", path, level=logging.WARNING)
        return []
    except (json.JSONDecodeError, OSError) as e:
        debug_log("Quote JSON load error %s: %s", path, e, level=logging.WARNING)
        return []
    if isinstance(data, dict):
        data = list(data.values())
    return [x for x in data if isinstance(x, dict)]


def _select_external_quote_text(row: dict[str, Any]) -> str:
    mode = str(SETTINGS.get("quote_text_mode", "quote")).strip().lower()
    fields = {
        "quote": "quote",
        "ru": "quote",
        "base": "quote",
        "original": "original",
        "literal": "literal_translation",
        "literal_translation": "literal_translation",
        "semantic": "semantic_translation",
        "semantic_translation": "semantic_translation",
        "sense": "semantic_translation",
    }
    primary = fields.get(mode, "quote")
    for field in (primary, "quote", "semantic_translation", "literal_translation", "original"):
        value = str(row.get(field, "")).strip()
        if value:
            return value
    return ""


def _quote_rows_by_id(filename: str) -> dict[str, dict[str, Any]]:
    rows = {}
    for row in _load_quote_json(filename):
        key = str(row.get("id", "")).strip()
        if key:
            rows[key] = row
    return rows


def load_external_quote_files(strict: bool = False) -> None:
    """Подгружает цитаты из data/quotes/*.json и накладывает их на игровые данные.

    JSON не обязан заполнять поля original/literal/semantic сразу: если выбранное
    поле пустое, игра безопасно берёт обычное quote. При отсутствии файлов игра
    продолжает работать на встроенных цитатах.
    """
    global TECH_QUOTES

    tech_rows = _quote_rows_by_id("tech_quotes.json")
    if tech_rows:
        missing = sorted(set(TECH_TREE) - set(tech_rows))
        extra = sorted(set(tech_rows) - set(TECH_TREE))
        if strict and (missing or extra):
            raise RuntimeError(f"tech_quotes.json mismatch. Missing: {missing}; Extra: {extra}")
        for key, row in tech_rows.items():
            if key in TECH_TREE:
                text = _select_external_quote_text(row)
                source = str(row.get("source", row.get("author", "Римская сентенция"))).strip()
                TECH_QUOTES[key] = {"quote": text or "Sapientia vincit.", "author": source or "Римская сентенция"}

    people_rows = _quote_rows_by_id("great_people_quotes.json")
    if people_rows:
        missing = sorted(set(GREAT_PEOPLE) - set(people_rows))
        extra = sorted(set(people_rows) - set(GREAT_PEOPLE))
        if strict and (missing or extra):
            raise RuntimeError(f"great_people_quotes.json mismatch. Missing: {missing}; Extra: {extra}")
        for key, row in people_rows.items():
            person = GREAT_PEOPLE.get(key)
            if isinstance(person, dict):
                text = _select_external_quote_text(row)
                if text:
                    person["quote"] = text
                source = str(row.get("source", row.get("author", ""))).strip()
                if source:
                    person["source"] = source

    wonder_rows = _quote_rows_by_id("world_wonder_quotes.json")
    if wonder_rows:
        current_ids = {str(w.get("id", "")) for w in WORLD_WONDERS if isinstance(w, dict)}
        missing = sorted(current_ids - set(wonder_rows))
        extra = sorted(set(wonder_rows) - current_ids)
        if strict and (missing or extra):
            raise RuntimeError(f"world_wonder_quotes.json mismatch. Missing: {missing}; Extra: {extra}")
        for wonder in WORLD_WONDERS:
            if not isinstance(wonder, dict):
                continue
            key = str(wonder.get("id", ""))
            row = wonder_rows.get(key)
            if row:
                text = _select_external_quote_text(row)
                source = str(row.get("source", "")).strip()
                if text and source and source not in text:
                    wonder["quote"] = f"{text} — {source}"
                elif text:
                    wonder["quote"] = text



# ─── ПАТЧ v2.25.7: SAVE MIGRATOR / STATE VERSION / TURN BATCHING ───────────
# Этот слой намеренно расположен поздно: он видит все уже объявленные модули
# и безопасно переопределяет финальные точки входа без разрушения старых сейвов.

STATE_SCHEMA_VERSION = "2.60.0"
SAVE_COMPAT_MIN_VERSION = "2.0"
SAVE_COMPAT_MAX_VERSION = "2.60.0"
MIGRATION_LOG_LIMIT = 80


def _version_tuple(value: str) -> tuple[int, ...]:
    nums = re.findall(r"\d+", str(value or ""))
    return tuple(int(x) for x in nums[:4]) if nums else (0,)


def _ensure_migration_log(player: "Player") -> list[dict[str, Any]]:
    if not isinstance(getattr(player, "migration_log", None), list):
        player.migration_log = []
    player.migration_log = [x for x in player.migration_log if isinstance(x, dict)][-MIGRATION_LOG_LIMIT:]
    return player.migration_log


def migration_log_add(player: "Player", code: str, text: str, *, from_version: str = "", to_version: str = STATE_SCHEMA_VERSION) -> None:
    """Пишет идемпотентную запись миграции в сам сейв."""
    log = _ensure_migration_log(player)
    turn = safe_int(getattr(player, "turn", 1), 1, 1)
    if any(x.get("code") == code and x.get("turn") == turn for x in log):
        return
    log.append({
        "turn": turn,
        "year": safe_int(getattr(player, "year", 700), 700, 1),
        "from": str(from_version or getattr(player, "version", "legacy")),
        "to": str(to_version),
        "code": str(code),
        "text": str(text),
    })
    player.migration_log = log[-MIGRATION_LOG_LIMIT:]


def migration_changelog(player: "Player", limit: int = 8) -> list[str]:
    """Короткий changelog последних автоправок при загрузке."""
    log = _ensure_migration_log(player)
    return [f"{x.get('from','?')} → {x.get('to','?')}: {x.get('text','')}" for x in log[-limit:]]


def ensure_player_version_state(player: "Player") -> None:
    old_version = str(getattr(player, "version", "") or "legacy")
    _ensure_migration_log(player)
    if not hasattr(player, "migration_changelog") or not isinstance(player.migration_changelog, list):
        player.migration_changelog = []
    if old_version != STATE_SCHEMA_VERSION:
        migration_log_add(
            player,
            f"schema:{old_version}->{STATE_SCHEMA_VERSION}",
            "обновлена схема состояния Player; добавлены version и migration_log",
            from_version=old_version,
            to_version=STATE_SCHEMA_VERSION,
        )
    player.version = STATE_SCHEMA_VERSION
    player.save_compat = {"min": SAVE_COMPAT_MIN_VERSION, "max": SAVE_COMPAT_MAX_VERSION, "game": GAME_VERSION}
    player.migration_changelog = migration_changelog(player)


# Обновляем конструктор: новые партии сразу получают версию состояния.
_Player_init_before_state_version = Player.__init__
def _player_init_with_state_version(self, *args, **kwargs):
    _Player_init_before_state_version(self, *args, **kwargs)
    self.version = STATE_SCHEMA_VERSION
    self.migration_log = []
    self.migration_changelog = []
    self.save_compat = {"min": SAVE_COMPAT_MIN_VERSION, "max": SAVE_COMPAT_MAX_VERSION, "game": GAME_VERSION}
Player.__init__ = _player_init_with_state_version


# Финальная единая точка ensure_*: сюда складываются все подсистемы, включая
# поздние патчи науки, флота, артиллерии, падения Рима и сводки хода.
_ensure_all_states_before_v2257 = ensure_all_states
def ensure_all_states(player):
    if player is None:
        return None
    try:
        _ensure_all_states_before_v2257(player)
    except Exception as e:
        debug_log("Base ensure_all_states failed: %s", e, exc_info=True, level=logging.WARNING)

    for fn_name in (
        "ensure_city_campaigns",
        "ensure_city_siege_damage",
        "ensure_province_details",
        "ensure_expansion_state",
        "ensure_wonders_state",
        "ensure_religion_state",
        "ensure_legion_logistics",
        "ensure_victory_state",
        "ensure_prophecy_state",
        "ensure_v24_state",
        "ensure_republic_overhaul_state",
        "ensure_external_policy_state",
        "ensure_enemy_grand_ai_state",
        "ensure_ai_memory_state",
        "ensure_enemy_final_stage_state",
        "ensure_rome_fall_state",
        "ensure_ai_director_state",
        "ensure_turn_summary_state",
        "ensure_lost_city_state",
        "ensure_siege_arsenal",
        "ensure_artillery_state",
        "ensure_science_state",
        "ensure_conquest_economy_state",
    ):
        fn = globals().get(fn_name)
        if callable(fn):
            try:
                fn(player)
            except Exception as e:
                migration_log_add(player, f"ensure_warning:{fn_name}", f"модуль {fn_name} восстановлен частично: {type(e).__name__}")
                debug_log("State initializer %s failed: %s", fn_name, e, exc_info=True, level=logging.WARNING)

    ensure_player_version_state(player)
    return player


# Усиливаем from_dict: старые сейвы v2.0–2.25 получают явный журнал миграции.
_Player_from_dict_before_v2257 = Player.from_dict
def _player_from_dict_with_migration(data):
    raw = safe_dict(data)
    source_version = str(raw.get("version") or raw.get("state_version") or raw.get("game_version") or "legacy")
    player = _Player_from_dict_before_v2257(raw)
    ensure_all_states(player)
    if source_version in ("legacy", "") or _version_tuple(source_version) < _version_tuple(STATE_SCHEMA_VERSION):
        migration_log_add(
            player,
            f"load_compat:{source_version}->{STATE_SCHEMA_VERSION}",
            "старое сохранение нормализовано под текущую схему",
            from_version=source_version,
            to_version=STATE_SCHEMA_VERSION,
        )
    ensure_player_version_state(player)
    return player
Player.from_dict = staticmethod(_player_from_dict_with_migration)


# to_dict теперь всегда пишет версию и лог миграции в сам JSON-сейв.
_Player_to_dict_before_v2257 = Player.to_dict
def _player_to_dict_with_migration(self):
    ensure_all_states(self)
    data = _Player_to_dict_before_v2257(self)
    data["version"] = STATE_SCHEMA_VERSION
    data["state_version"] = STATE_SCHEMA_VERSION
    data["game_version"] = GAME_VERSION
    data["save_compat"] = {"min": SAVE_COMPAT_MIN_VERSION, "max": SAVE_COMPAT_MAX_VERSION, "game": GAME_VERSION}
    data["migration_log"] = safe_list(getattr(self, "migration_log", []))[-MIGRATION_LOG_LIMIT:]
    data["migration_changelog"] = migration_changelog(self)
    return json_safe_data(data)
Player.to_dict = _player_to_dict_with_migration


# Автоматический changelog при загрузке: игрок видит, что именно починил мигратор.
_load_game_before_v2257 = load_game
def load_game(filename: str = SAVE_FILE):
    player = _load_game_before_v2257(filename)
    if player is None:
        return None
    ensure_all_states(player)
    changes = migration_changelog(player, limit=5)
    if changes:
        print(clr("\n  🧱 Мигратор сейва: совместимость проверена.", C.CYAN))
        for line in changes:
            print(clr(f"    • {line}", C.GRAY))
    return player


# ── Батчинг конца хода ─────────────────────────────────────────────────────
@dataclass
class TurnBatchContext:
    player: "Player"
    events: list[str] = field(default_factory=list)
    counters: dict[str, int] = field(default_factory=dict)

    def add(self, key: str, amount: int = 1) -> None:
        self.counters[key] = self.counters.get(key, 0) + amount

    def event(self, text: str) -> None:
        if text:
            self.events.append(text)

    def flush(self) -> None:
        if self.counters:
            parts = ", ".join(f"{k}: {v}" for k, v in sorted(self.counters.items()) if v)
            if parts:
                try:
                    turn_summary_add(self.player, f"Батч конца хода: {parts}")
                except Exception:
                    log_event(self.player, f"Батч конца хода: {parts}")
        for text in self.events[-6:]:
            try:
                turn_summary_add(self.player, text)
            except Exception:
                log_event(self.player, text)


def _decrement_turn_map(value) -> tuple[dict, int]:
    if not isinstance(value, dict):
        return {}, 0
    updated = {}
    expired = 0
    for key, raw in value.items():
        turns = safe_int(raw, 0)
        if turns > 1:
            updated[key] = turns - 1
        elif turns > 0:
            expired += 1
    return updated, expired


_enemy_ai_grand_strategy_tick_before_v2257 = enemy_ai_grand_strategy_tick
def enemy_ai_grand_strategy_tick(player: "Player"):
    """Оптимизированный тик ИИ: одно ensure, пакетное истечение таймеров, затем старая логика."""
    ensure_enemy_grand_ai_state(player)
    batch = TurnBatchContext(player)
    for attr, label in (
        ("enemy_ai_patrols", "патрули"),
        ("enemy_ai_fortifications", "укрепления"),
        ("enemy_ai_traps", "ловушки"),
    ):
        updated, expired = _decrement_turn_map(getattr(player, attr, {}))
        setattr(player, attr, updated)
        batch.add(f"истекли {label}", expired)
    old_network = safe_int(getattr(player, "enemy_ai_counter_raid_network", 0), 0)
    player.enemy_ai_counter_raid_network = max(0, old_network - 1)
    if old_network and not player.enemy_ai_counter_raid_network:
        batch.add("истекла сеть против рейдов")

    # Старая функция тоже умеет уменьшать таймеры, поэтому временно ставим уже
    # обработанные значения; оставшаяся тяжёлая логика ИИ работает как прежде.
    _enemy_ai_grand_strategy_tick_before_v2257(player)
    batch.add("армии ИИ", len(getattr(player, "enemy_armies", [])))
    batch.flush()


_v24_end_turn_tick_before_v2257 = v24_end_turn_tick
def v24_end_turn_tick(player):
    """Флот и торговля считаются одним пакетом, без лишних повторных обходов меню."""
    ensure_v24_state(player)
    before_gold = safe_int(getattr(player, "gold", 0), 0)
    before_grain = safe_int(getattr(player, "grain", 0), 0)
    _v24_end_turn_tick_before_v2257(player)
    fleet = safe_dict(getattr(player, "v24", {}).get("fleet", {}))
    squadrons = safe_list(fleet.get("squadrons", []))
    routes = safe_dict(getattr(player, "v24", {}).get("trade", {})).get("routes", [])
    if len(squadrons) + len(safe_list(routes)) >= 12:
        dg = safe_int(getattr(player, "gold", 0), 0) - before_gold
        dr = safe_int(getattr(player, "grain", 0), 0) - before_grain
        try:
            turn_summary_add(player, f"Флот и торговля обработаны пакетом: {len(squadrons)} эскадр, итог {dg:+} золота, {dr:+} зерна")
        except Exception as exc:
            debug_log("Turn batch trade summary failed: %s", exc, exc_info=True, level=logging.WARNING)


_end_turn_before_v2257 = end_turn
def end_turn(player: Player):
    ensure_all_states(player)
    player._turn_batch = TurnBatchContext(player)
    try:
        return _end_turn_before_v2257(player)
    finally:
        try:
            player._turn_batch.flush()
        except Exception as exc:
            debug_log("Turn batch flush failed: %s", exc, exc_info=True, level=logging.WARNING)
        if hasattr(player, "_turn_batch"):
            delattr(player, "_turn_batch")
        ensure_all_states(player)


# ─── HOTFIX v2.26.1: Rich-меню после Lua-выноса контента ────────────────────
# В TRUE_ROLLBACK v2.25.7 поздний слой повторно определял main_menu() и тем самым
# отключал Rich-меню. Этот финальный слой возвращает порядок: Textual → Rich →
# классическое ANSI, а список разрешённых клавиш берёт из того же набора пунктов,
# который отображается игроку.

MAIN_MENU_KEYS_V2261 = [
    "1", "2", "4", "5", "6", "7", "8", "9",
    "A", "B", "V", "C", "L", "W", "Y", "Z", "T",
    "D", "P", "F", "N", "S", "Q",
]


def _classic_main_menu_v2261(player: "Player"):
    ensure_all_states(player)
    sections = _main_menu_sections_v2257()
    clear()
    player.status_bar()
    ui_panel("ГЛАВНОЕ МЕНЮ", "☰", C.GOLD)
    render_classic_menu_sections(sections)
    return read_choice_secret(
        f"\n{clr('  ➤ Ваш приказ: ', C.CYAN)}",
        menu_valid_keys(sections),
        SECRET_UNLOCK_CODE,
        "CHEAT",
    )


def rich_main_menu_v2261(player=None):
    """Rich-обёртка с исправленным набором кнопок без мёртвой клавиши 3."""
    if player is None:
        raise RuntimeError("rich_main_menu требует объект player")
    ensure_all_states(player)

    # Если оригинальный Rich-экран доступен, используем его оформление, но
    # страхуемся от устаревших/лишних пунктов через повторный ввод ниже.
    choice = rich_main_menu(player)
    if choice in MAIN_MENU_KEYS_V2261 or choice == "CHEAT":
        return choice
    print(clr(f"  Неактивная клавиша «{choice}». Выберите пункт из меню.", C.RED))
    time.sleep(1)
    return _classic_main_menu_v2261(player)


# ─── ПАТЧ v2.22.5: АУКСИЛИЯ КАК ПЕРВАЯ ЛИНИЯ ОБОРОНЫ ────────────────────────
# Стартовые силы: две средние ауксилии. Рейды, осады, вражеские кампании и
# совместные удары сначала встречает ауксилия. Легионы остаются для походов
# игрока, гражданских войн и ручных решений в штабах.

STARTING_AUXILIA = [
    {
        "key": "starting_aux_socii_pedites",
        "name": "Союзнические педиты",
        "type": "пехота",
        "province": "Latium",
        "category": "стартовая ауксилия",
        "strength": 32,
        "attack": 10,
        "defense": 11,
        "upkeep": 3,
        "morale": 72,
        "ability": "средняя линия обороны",
        "description": "Италийская пехота союзников, готовая принимать первые удары врага.",
    },
    {
        "key": "starting_aux_equites_italici",
        "name": "Италийские всадники",
        "type": "конница",
        "province": "Latium",
        "category": "стартовая ауксилия",
        "strength": 30,
        "attack": 12,
        "defense": 8,
        "upkeep": 3,
        "morale": 74,
        "ability": "быстрое реагирование",
        "description": "Средний конный отряд для перехвата рейдов, осадных обозов и разведки.",
    },
]


def seed_starting_auxilia(player) -> None:
    """Добавляет новой партии две средние ауксилии; сохранения не дублируются."""
    if not hasattr(player, "aux_units") or not isinstance(player.aux_units, list):
        player.aux_units = []
    existing = {u.get("key") for u in player.aux_units if isinstance(u, dict)}
    for unit_def in STARTING_AUXILIA:
        if unit_def["key"] not in existing:
            add_aux_unit(player, unit_def, free=True)


def _best_available_auxilia(player) -> dict | None:
    normalize_aux_army(player)
    units = [
        u for u in getattr(player, "aux_units", [])
        if isinstance(u, dict) and safe_int(u.get("strength", 0), 0) > 3
    ]
    if not units:
        return None
    return max(units, key=lambda u: (aux_unit_power(u), safe_int(u.get("morale", 70), 70)))


def _enemy_power_for_aux_defense(enemy: dict | None, army: dict | None = None, fallback: int = 35) -> int:
    src = army or enemy or {}
    if army is not None:
        base = enemy_army_battle_power(army)
    elif isinstance(enemy, dict) and enemy.get("army_ids"):
        base = safe_int(enemy.get("strength", fallback), fallback)
    elif isinstance(enemy, dict):
        base = safe_int(enemy.get("strength", fallback), fallback)
    else:
        base = fallback
    mod = safe_int((enemy or {}).get("battle_mod", 0), 0)
    return max(10, base // 4 + 10 + mod // 3)


def _legacy_auxiliary_defense_battle_auto_v225(
    player,
    enemy: dict,
    context: str,
    province_name: str | None = None,
    army: dict | None = None,
    reward_glory: int = 10,
) -> bool | None:
    """Автоматический бой ауксилии против вражеского рейда/осады/кампании.

    True  — ауксилия отбила угрозу.
    False — ауксилия проиграла, угроза продолжается.
    None  — ауксилии нет; вызывающий код может применить старую логику.
    """
    unit = _best_available_auxilia(player)
    enemy = enemy or {}
    if unit is None:
        print(clr("  Свободной ауксилии нет: обороняться придётся гарнизонами и легионами.", C.RED))
        return None

    enemy_name = enemy.get("name") or enemy.get("unit_name") or (army or {}).get("unit_name") or "вражеская армия"
    aux_raw_power = aux_unit_power(unit)
    type_bonus = 0
    if "конница" in unit.get("type", "") and context in ("рейд", "кампания"):
        type_bonus += 3
    if "пехота" in unit.get("type", "") and context in ("осада", "штурм"):
        type_bonus += 2

    aux_power = max(
        8,
        aux_raw_power // 4
        + safe_int(unit.get("morale", 70), 70) // 12
        + type_bonus
        + player.battle_tech_bonus() // 4,
    )
    enemy_power = _enemy_power_for_aux_defense(enemy, army=army)

    print(clr(f"\n  🏹 АУКСИЛИЯ ВСТРЕЧАЕТ УГРОЗУ: {unit.get('name', 'отряд')} против {enemy_name}.", C.BOLD + C.CYAN))
    if province_name:
        print(clr(f"  Театр действий: {province_name}. Тип угрозы: {context}.", C.GRAY))
    print_table_3d6_forecast("Прогноз боя ауксилии 3d6", aux_power, enemy_power)
    aux_total, aux_dice, enemy_total, enemy_dice, margin = table_3d6_duel_totals(aux_power, enemy_power)
    print(f"  Бросок ауксилии: {format_3d6(aux_dice)} ×3 + {aux_power} = {clr(str(aux_total), C.GREEN)}")
    print(f"  Бросок врага:    {format_3d6(enemy_dice)} ×3 + {enemy_power} = {clr(str(enemy_total), C.RED)}")

    won = aux_total >= enemy_total
    battle_margin = aux_total - enemy_total
    auxiliary_unit_after_battle(player, unit, won, battle_margin)

    if won:
        enemy_loss = random.randint(8, 18) + max(0, battle_margin) // 4
        if army:
            army["strength"] = max(0, safe_int(army.get("strength", 25), 25) - enemy_loss)
            army["morale"] = max(0, safe_int(army.get("morale", 70), 70) - random.randint(8, 18))
            army["cooldown"] = 2
            if safe_int(army.get("strength", 0), 0) <= 6 or safe_int(army.get("morale", 0), 0) <= 5:
                try:
                    player.enemy_armies.remove(army)
                except (ValueError, AttributeError):
                    pass
        elif isinstance(enemy, dict) and enemy.get("army_ids"):
            enemy_ai_apply_army_losses(player, enemy, victory=True)

        player.glory += reward_glory + max(0, battle_margin // 2)
        add_battlepass_xp(player, 6)
        print(clr(f"  ✓ Ауксилия отбила {context}. Слава +{reward_glory + max(0, battle_margin // 2)}.", C.GREEN))
        log_event(player, f"Ауксилия отбила {context}: {unit.get('name', 'отряд')} против {enemy_name}")
        if province_name:
            try:
                _remember_failed_ai_target(player, province_name)
            except NameError:
                pass
        return True

    player.morale = max(10, safe_int(getattr(player, "morale", 70), 70) - random.randint(2, 6))
    if army:
        army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + 4)
        army["morale"] = min(100, safe_int(army.get("morale", 70), 70) + random.randint(2, 6))
    elif isinstance(enemy, dict) and enemy.get("army_ids"):
        enemy_ai_apply_army_losses(player, enemy, victory=False)
    print(clr(f"  ✗ Ауксилия не удержала {context}: угроза продолжается.", C.RED))
    log_event(player, f"Ауксилия проиграла {context}: {unit.get('name', 'отряд')} против {enemy_name}")
    return False


# Сохраняем легионный бой и включаем перехват только для вражеских кампаний,
# которые помечены force_auxiliary_defense.
_resolve_battle_legion_original_v225 = _legacy_resolve_battle_core_v222

def _legacy_resolve_battle_aux_gate_v225(player: Player, legion: Legion, enemy: dict, is_civil_war: bool = False) -> bool:
    if (
        not is_civil_war
        and isinstance(enemy, dict)
        and enemy.get("force_auxiliary_defense")
        and getattr(player, "aux_units", None)
    ):
        result = auxiliary_defense_battle(
            player,
            enemy,
            enemy.get("aux_context", "кампания"),
            province_name=getattr(legion, "location", None),
            reward_glory=14,
        )
        return bool(result)
    return _resolve_battle_legion_original_v225(player, legion, enemy, is_civil_war=is_civil_war)


def enemy_ai_raid_event(player: "Player"):
    ensure_enemy_final_stage_state(player)
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_raid_chance", 0.16))
    raiders = [
        a for a in getattr(player, "enemy_armies", [])
        if a.get("order") == "raid" and safe_int(a.get("cooldown", 0), 0) <= 0
    ]
    if not raiders or random.random() >= chance:
        return

    army = max(raiders, key=enemy_army_battle_power)
    target_name = army.get("target")
    target = next((p for p in getattr(player, "provinces", []) if p.get("name") == target_name), None)
    if not target:
        return

    print(clr(f"\n  🐺 ВРАЖЕСКИЙ РЕЙД: {army.get('unit_name', 'рейдеры')} грабят окрестности {target_name}.", C.BOLD + C.RED))
    enemy = {
        "name": army.get("unit_name", "рейдеры"),
        "strength": enemy_army_battle_power(army) * 2,
        "battle_mod": safe_int(army.get("battle_mod", 0), 0),
    }
    result = auxiliary_defense_battle(player, enemy, "рейд", province_name=target_name, army=army, reward_glory=8)
    army["cooldown"] = 2
    if result is True:
        return

    gold_loss = random.randint(15, 55)
    grain_loss = random.randint(15, 75)
    if result is None:
        gold_loss += 15
        grain_loss += 15
    player.gold = max(0, safe_int(getattr(player, "gold", 0), 0) - gold_loss)
    player.grain = max(0, safe_int(getattr(player, "grain", 0), 0) - grain_loss)
    target["unrest"] = min(10, safe_int(target.get("unrest", 0), 0) + random.randint(1, 2))
    print(clr(f"  ✗ Рейд прошёл по тылам: золото -{gold_loss}, зерно -{grain_loss}, волнения растут.", C.RED))
    log_event(player, f"Вражеский рейд в {target_name}: ауксилия не остановила налёт")



# ─── v2.23.2: реальная оккупация городов врагом ─────────────────────────────
def _enemy_ai_total_cities(province_name: str) -> int:
    roster = CITY_ROSTERS.get(province_name, [])
    if roster:
        return len(roster)
    prov = province_by_name(province_name)
    return len(prov.get("cities", [])) if prov else 1


def _legacy_enemy_ai_register_city_capture_v225(player: "Player", province_name: str, city_name: str | None, *, source: str = "осада") -> bool:
    """
    Фикс v2.23.2: успешная осада/реванш теперь меняет карту.
    Возвращает True, если после потери городов отпала вся провинция.
    """
    if not province_name or province_name == "Latium":
        return False
    target = next((p for p in getattr(player, "provinces", []) if p.get("name") == province_name), None)
    if not target:
        return False

    _enemy_ai_forget_roman_city(player, province_name, city_name)
    lost = safe_list(player.enemy_ai_lost_cities.get(province_name, []))
    if city_name and city_name not in lost:
        lost.append(city_name)
    player.enemy_ai_lost_cities[province_name] = lost[-15:]

    total = max(1, _enemy_ai_total_cities(province_name))
    held = len(safe_list(player.city_campaigns.get(province_name, [])))
    lost_count = len(player.enemy_ai_lost_cities.get(province_name, []))
    unrest = safe_int(target.get("unrest", 0), 0)
    garrison = safe_int(target.get("garrison", 0), 0)

    # Провинция отпадает не по редкому 8–10% броску, а когда враг реально откусил
    # существенную часть городов или когда местная смута уже разрушила управление.
    collapse_score = lost_count * 16 + unrest * 6 - garrison * 12
    should_collapse = held <= max(1, total // 2) or lost_count >= max(4, total // 3) or collapse_score >= 110
    if should_collapse:
        try:
            player.provinces.remove(target)
        except ValueError:
            pass
        player.governors.pop(province_name, None)
        player.city_campaigns.pop(province_name, None)
        player.enemy_ai_lost_cities.pop(province_name, None)
        player.unrest = min(100, safe_int(getattr(player, "unrest", 0), 0) + 8)
        print(clr(f"  ☠ {province_name} отпала: враг закрепился в городах и выбил римскую администрацию.", C.BOLD + C.RED))
        log_event(player, f"Провинция {province_name} потеряна после {source}")
        return True

    print(clr(f"  ⚠ Карта изменилась: {city_name} больше не считается удержанным Римом ({held}/{total} городов под контролем).", C.GOLD))
    log_event(player, f"Враг удерживает {city_name} в {province_name}; римский контроль ослаб")
    return False


def enemy_ai_execute_operational_orders(player: "Player"):
    """Исполнительный слой: приказы штаба теперь чаще превращаются в осады/давление на карте."""
    ensure_enemy_grand_ai_state(player)
    active = {s.get("province") for s in getattr(player, "enemy_ai_sieges", []) if isinstance(s, dict)}
    siege_armies = [a for a in player.enemy_armies
                    if a.get("order") == "siege" and a.get("target")
                    and a.get("target") not in active
                    and safe_int(a.get("cooldown", 0), 0) <= 0
                    and safe_int(a.get("strength", 0), 0) >= 18]
    # Не все сразу: иначе будет каша сообщений. Но хотя бы 1–2 реальные осады за ход при наличии приказов.
    limit = 2 if is_madness_mode(player) or len(getattr(player, "provinces", [])) >= 5 else 1
    for army in sorted(siege_armies, key=enemy_army_battle_power, reverse=True)[:limit]:
        enemy_ai_start_siege(player, army.get("target"), army)
        army["cooldown"] = max(safe_int(army.get("cooldown", 0), 0), 1)

def enemy_ai_start_siege(player: "Player", province_name: str | None = None, army: dict | None = None):
    ensure_enemy_grand_ai_state(player)
    owned = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
    if not owned:
        return
    if province_name is None:
        target = max(owned, key=lambda p: safe_int(p.get("unrest", 0), 0) * 2 + safe_int(p.get("wealth", 0), 0) + random.randint(0, 5))
        province_name = target.get("name")
    owned_names = {p.get("name") for p in owned}
    if province_name not in owned_names:
        return
    if any(s.get("province") == province_name for s in player.enemy_ai_sieges):
        return
    if army is None:
        candidates = [a for a in player.enemy_armies if a.get("order") == "siege" and a.get("target") == province_name]
        army = max(candidates, key=enemy_army_battle_power, default=None)
    if army is None:
        army = spawn_enemy_army(player, province_name, reason="recapture")
    if not army:
        return

    ensure_city_campaigns(player)
    held_cities = safe_list(player.city_campaigns.get(province_name, []))
    city_defs = CITY_ROSTERS.get(province_name, [])
    if held_cities:
        city = random.choice(held_cities)
    else:
        city = random.choice(city_defs)[0] if city_defs else province_name
    siege = {
        "province": province_name,
        "city": city,
        "army_id": army.get("id"),
        "progress": 0,
        "turns": 0,
        "power": enemy_army_battle_power(army),
    }
    print(clr(f"\n  🏗 Враг начинает осаду: {army.get('unit_name', 'армия')} окружает {city} ({province_name}).", C.BOLD + C.RED))
    enemy = {
        "name": army.get("unit_name", "осадная армия"),
        "strength": enemy_army_battle_power(army) * 2,
        "battle_mod": 2,
    }
    result = auxiliary_defense_battle(player, enemy, "осада", province_name=province_name, army=army, reward_glory=12)
    if result is True:
        print(clr(f"  ✓ Осада {city} сорвана до развёртывания лагеря.", C.GREEN))
        return

    if result is None:
        loss = random.randint(18, 48)
        player.gold = max(0, safe_int(getattr(player, "gold", 0), 0) - loss)
        print(clr(f"  💰 Свободной ауксилии нет: город оплачивает срочную оборону, казна -{loss}.", C.RED))

    player.enemy_ai_sieges.append(siege)
    print(clr("  Осада продолжается: у Рима есть время усилить гарнизон или снять осаду.", C.GRAY))
    log_event(player, f"Враг начал осаду {city} в провинции {province_name}")


def enemy_ai_joint_attack(player: "Player"):
    ensure_enemy_final_stage_state(player)
    if len(player.enemy_armies) < 2:
        return
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_joint_attack_chance", 0.18))
    chance += min(0.12, len(player.enemy_armies) * 0.010)
    if player.morale < 45:
        chance += 0.07
    coalition = getattr(player, "enemy_ai_coalition", {})
    if isinstance(coalition, dict) and coalition.get("active"):
        chance += 0.04
    if random.random() >= chance:
        return

    available = [
        a for a in player.enemy_armies
        if a.get("order") in {"strike", "ambush", "recon"}
        and safe_int(a.get("cooldown", 0), 0) <= 0
        and safe_int(a.get("strength", 0), 0) >= 18
    ]
    if len(available) < 2:
        return

    max_count = min(4, len(available))
    armies = sorted(available, key=enemy_army_battle_power, reverse=True)[:random.randint(2, max_count)]
    enemy = _build_joint_enemy(armies)
    target_name = armies[0].get("target") or "фронтир"
    print(clr(f"\n  ⚔ ВРАЖЕСКАЯ КООРДИНАЦИЯ: {len(armies)} армии идут общим ударом.", C.BOLD + C.RED))
    print(clr(f"  Состав: {enemy.get('unit_summary', 'союзная армия')}", C.GRAY))
    if enemy.get("commanders"):
        print(clr(f"  Полководцы: {', '.join(enemy['commanders'])}", C.PURPLE))

    result = auxiliary_defense_battle(player, enemy, "штурм", province_name=target_name, reward_glory=14)
    for a in armies:
        a["cooldown"] = max(1, safe_int(a.get("cooldown", 0), 0) + 1)
    if result is True:
        return

    player.morale = max(10, safe_int(player.morale, 70) - random.randint(4, 9))
    player.unrest = min(100, safe_int(player.unrest, 0) + random.randint(1, 3))
    print(clr("  ✗ Совместный удар врага прорвал первую линию: мораль падает, в Риме растёт тревога.", C.RED))
    log_event(player, "Совместный удар врага прорвал ауксилию")


# ─── ПАТЧ v2.22.6: ИНТЕРАКТИВНАЯ ПЕРВАЯ ЛИНИЯ АУКСИЛИИ ──────────────────────
# Теперь ауксилия не бросается в авто-бой молча. При каждом рейде, осаде,
# кампании или совместном штурме игрок выбирает отряд и тактику.

AUX_DEFENSE_TACTICS = {
    "1": {
        "name": "Перехват",
        "desc": "+3 к бою; рискованный быстрый удар",
        "aux_mod": 3,
        "enemy_mod": 0,
        "loss_mod": 2,
    },
    "2": {
        "name": "Щитовая стена",
        "desc": "+1 к бою; меньше потерь при поражении",
        "aux_mod": 1,
        "enemy_mod": -1,
        "loss_mod": -3,
    },
    "3": {
        "name": "Засада",
        "desc": "+5 к бою; при провале враг давит сильнее",
        "aux_mod": 5,
        "enemy_mod": 0,
        "loss_mod": 4,
    },
    "4": {
        "name": "Изматывание",
        "desc": "+2 к бою; враг получает больше урона при победе Рима",
        "aux_mod": 2,
        "enemy_mod": -2,
        "loss_mod": 0,
    },
}


def _choose_auxilia_for_defense(player, context: str, enemy_name: str, province_name: str | None = None) -> dict | None | str:
    normalize_aux_army(player)
    units = [
        u for u in getattr(player, "aux_units", [])
        if isinstance(u, dict) and safe_int(u.get("strength", 0), 0) > 3
    ]
    if not units:
        print(clr("  Свободной ауксилии нет: обороняться придётся гарнизонами и легионами.", C.RED))
        return None

    print(clr(f"\n  🏹 ТРЕВОГА: {context.upper()} — {enemy_name}", C.BOLD + C.CYAN))
    if province_name:
        print(clr(f"  Провинция: {province_name}", C.GRAY))
    print(clr("  Выберите отряд ауксилии для боя:", C.CYAN))
    for i, unit in enumerate(units, 1):
        vet = clr(" [ВЕТ]", C.GOLD) if unit.get("veterans") else ""
        print(
            f"  {clr(str(i), C.GOLD)} {unit.get('name','отряд')}{vet} — "
            f"{unit.get('type','ауксилия')}, сила {safe_int(unit.get('strength',0),0)}, "
            f"мор. {safe_int(unit.get('morale',70),70)}, мощь {aux_unit_power(unit)}"
        )
    print(f"  {clr('A', C.GOLD)} Автовыбор лучшего отряда")
    print(f"  {clr('N', C.GOLD)} Не принимать бой / терпеть последствия")
    choice = read_choice(
        f"\n{clr('  Ваш приказ: ', C.CYAN)}",
        [str(i) for i in range(1, len(units) + 1)] + ["A", "N"],
    )
    if choice == "N":
        return "decline"
    if choice == "A":
        return max(units, key=lambda u: (aux_unit_power(u), safe_int(u.get("morale", 70), 70)))
    return units[int(choice) - 1]


def _choose_auxilia_tactic(context: str) -> tuple[str, dict]:
    print(clr("\n  Тактика ауксилии:", C.CYAN))
    for key, tactic in AUX_DEFENSE_TACTICS.items():
        print(f"  {clr(key, C.GOLD)} {tactic['name']:<14} — {tactic['desc']}")
    choice = read_choice(f"\n{clr('  Выберите тактику: ', C.CYAN)}", list(AUX_DEFENSE_TACTICS.keys()))
    return choice, AUX_DEFENSE_TACTICS[choice]


def _legacy_auxiliary_defense_battle_interactive_v226(
    player,
    enemy: dict,
    context: str,
    province_name: str | None = None,
    army: dict | None = None,
    reward_glory: int = 10,
) -> bool | None:
    """Интерактивный бой ауксилии против рейда/осады/кампании/штурма.

    True  — ауксилия отбила угрозу.
    False — ауксилия проиграла или игрок отказался, угроза продолжается.
    None  — ауксилии нет; вызывающий код применит последствия.
    """
    enemy = enemy or {}
    enemy_name = enemy.get("name") or enemy.get("unit_name") or (army or {}).get("unit_name") or "вражеская армия"

    unit = _choose_auxilia_for_defense(player, context, enemy_name, province_name)
    if unit is None:
        return None
    if unit == "decline":
        print(clr(f"  Рим не выводит ауксилию против угрозы: {context}.", C.GRAY))
        return False

    tactic_key, tactic = _choose_auxilia_tactic(context)

    aux_raw_power = aux_unit_power(unit)
    type_bonus = 0
    if "конница" in unit.get("type", "") and context in ("рейд", "кампания"):
        type_bonus += 3
    if "пехота" in unit.get("type", "") and context in ("осада", "штурм"):
        type_bonus += 2

    aux_power = max(
        8,
        aux_raw_power // 4
        + safe_int(unit.get("morale", 70), 70) // 12
        + type_bonus
        + safe_int(tactic.get("aux_mod", 0), 0)
        + player.battle_tech_bonus() // 4,
    )
    enemy_power = max(8, _enemy_power_for_aux_defense(enemy, army=army) + safe_int(tactic.get("enemy_mod", 0), 0))

    print(clr(f"\n  ⚔ АУКСИЛИЯ ВСТРЕЧАЕТ УГРОЗУ: {unit.get('name', 'отряд')} против {enemy_name}.", C.BOLD + C.CYAN))
    print(clr(f"  Приказ: {tactic['name']}. Тип угрозы: {context}.", C.GRAY))
    print_table_3d6_forecast("Прогноз боя ауксилии 3d6", aux_power, enemy_power)

    aux_total, aux_dice, enemy_total, enemy_dice, margin = table_3d6_duel_totals(aux_power, enemy_power)

    # Засада может обернуться плохо при очень низком броске.
    if tactic_key == "3" and sum(aux_dice) <= 8:
        enemy_total += 6
        margin = aux_total - enemy_total
        print(clr("  ⚠ Засада раскрыта: враг получает +6 к итогу.", C.RED))

    print(f"  Бросок ауксилии: {format_3d6(aux_dice)} ×3 + {aux_power} = {clr(str(aux_total), C.GREEN)}")
    print(f"  Бросок врага:    {format_3d6(enemy_dice)} ×3 + {enemy_power} = {clr(str(enemy_total), C.RED)}")

    won = aux_total >= enemy_total
    battle_margin = aux_total - enemy_total

    # Небольшая правка потерь от выбранной тактики.
    if not won and safe_int(tactic.get("loss_mod", 0), 0) != 0:
        unit["_aux_loss_mod_once"] = safe_int(tactic.get("loss_mod", 0), 0)

    before_strength = safe_int(unit.get("strength", 0), 0)
    auxiliary_unit_after_battle(player, unit, won, battle_margin)
    if "_aux_loss_mod_once" in unit:
        mod = safe_int(unit.pop("_aux_loss_mod_once", 0), 0)
        unit["strength"] = max(0, min(before_strength, safe_int(unit.get("strength", 0), 0) - mod))

    if won:
        enemy_loss = random.randint(8, 18) + max(0, battle_margin) // 4
        if tactic_key == "4":
            enemy_loss += 5
        if army:
            army["strength"] = max(0, safe_int(army.get("strength", 25), 25) - enemy_loss)
            army["morale"] = max(0, safe_int(army.get("morale", 70), 70) - random.randint(8, 18))
            army["cooldown"] = 2
            if safe_int(army.get("strength", 0), 0) <= 6 or safe_int(army.get("morale", 0), 0) <= 5:
                try:
                    player.enemy_armies.remove(army)
                except (ValueError, AttributeError):
                    pass
        elif isinstance(enemy, dict) and enemy.get("army_ids"):
            enemy_ai_apply_army_losses(player, enemy, victory=True)

        glory_gain = reward_glory + max(0, battle_margin // 2)
        player.glory += glory_gain
        add_battlepass_xp(player, 6)
        print(clr(f"  ✓ Ауксилия отбила {context}. Слава +{glory_gain}.", C.GREEN))
        log_event(player, f"Ауксилия отбила {context}: {unit.get('name', 'отряд')} против {enemy_name}")
        if province_name:
            try:
                _remember_failed_ai_target(player, province_name)
            except NameError:
                pass
        return True

    player.morale = max(10, safe_int(getattr(player, "morale", 70), 70) - random.randint(2, 6))
    if army:
        army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + 4)
        army["morale"] = min(100, safe_int(army.get("morale", 70), 70) + random.randint(2, 6))
    elif isinstance(enemy, dict) and enemy.get("army_ids"):
        enemy_ai_apply_army_losses(player, enemy, victory=False)
    print(clr(f"  ✗ Ауксилия не удержала {context}: угроза продолжается.", C.RED))
    log_event(player, f"Ауксилия проиграла {context}: {unit.get('name', 'отряд')} против {enemy_name}")
    return False


def barbarian_ai_tick(player: "Player"):
    """Варварские набеги теперь тоже сначала вызывают интерактивный бой ауксилии."""
    ensure_expansion_state(player)
    for key, tribe in getattr(player, "barbarian_tribes", {}).items():
        if not isinstance(tribe, dict):
            continue
        drift = random.randint(-2, 2)
        if tribe.get("pact"):
            drift += 1
        if safe_int(tribe.get("strength", 0), 0) > 6:
            drift -= 1
        tribe["relation"] = max(0, min(100, safe_int(tribe.get("relation", 50), 50) + drift))

        roll = random.random()
        if roll < 0.04 and tribe["relation"] < 30 and safe_int(tribe.get("strength", 0), 0) > 5:
            candidates = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
            if candidates:
                target = random.choice(candidates)
                enemy = {
                    "name": tribe.get("name", "варвары"),
                    "strength": 28 + safe_int(tribe.get("strength", 6), 6) * 7,
                    "battle_mod": max(0, safe_int(tribe.get("strength", 6), 6) // 2),
                }
                print(clr(f"\n  🐺 {tribe['name']} идут в набег на {target['name']}!", C.RED))
                result = barbarian_event_counterattack(
                    player,
                    enemy,
                    "варварский набег",
                    province_name=target.get("name"),
                    tribe_key=key,
                    reward_glory=8,
                )
                if result is True:
                    tribe["strength"] = max(1, safe_int(tribe.get("strength", 6), 6) - random.randint(1, 3))
                    tribe["relation"] = max(0, safe_int(tribe.get("relation", 50), 50) - 2)
                    log_event(player, f"Ауксилия отбила набег {tribe['name']} на {target['name']}")
                    continue

                damage = random.randint(1, 4)
                if result is None:
                    damage += 1
                target["unrest"] = min(10, target.get("unrest", 0) + damage)
                gold_loss = random.randint(5, 20) + (8 if result is None else 0)
                player.gold = max(0, player.gold - gold_loss)
                print(clr(f"  ✗ {tribe['name']} прорвались к {target['name']}: казна -{gold_loss}, волнения +{damage}.", C.RED))
                log_event(player, f"Набег {tribe['name']} на {target['name']}")
        elif roll < 0.07 and tribe["relation"] > 60 and not tribe.get("pact"):
            print(clr(f"\n  🪓 {tribe['name']} предлагают военный союз против общих врагов.", C.CYAN))
            if read_choice(f"  {clr('Принять союз? (Y/N): ', C.CYAN)}", ["Y", "N"]) == "Y":
                tribe["pact"] = True
                player.morale = min(100, player.morale + 5)
                log_event(player, f"Военный союз с {tribe['name']}")



# ─── v2.23.3: оперативная цель ИИ — осада Рима и состояние поражения ───────
# Предыдущий патч научил врага реально отнимать города. Этот слой доводит
# цепочку до финала: при достаточном давлении враг переходит от провинциальных
# рейдов к походу на Latium, осаждает Roma и при падении столицы завершает игру.

_enemy_ai_register_city_capture_v2232 = _legacy_enemy_ai_register_city_capture_v225
_enemy_ai_start_siege_v2232 = enemy_ai_start_siege
_enemy_ai_siege_tick_v2232 = enemy_ai_siege_tick
_enemy_ai_grand_strategy_tick_v2232 = enemy_ai_grand_strategy_tick
_check_endgame_v2232 = check_endgame


def ensure_rome_fall_state(player: "Player") -> None:
    if not hasattr(player, "rome_fallen"):
        player.rome_fallen = False
    if not hasattr(player, "rome_siege_alarm_turn"):
        player.rome_siege_alarm_turn = 0
    if not hasattr(player, "enemy_ai_rome_pressure"):
        player.enemy_ai_rome_pressure = 0
    if not hasattr(player, "enemy_ai_capital_siege"):
        player.enemy_ai_capital_siege = None


def _rome_is_owned(player: "Player") -> bool:
    return any(p.get("name") == "Latium" for p in getattr(player, "provinces", []))


def _enemy_ai_active_rome_siege(player: "Player") -> dict | None:
    ensure_rome_fall_state(player)
    capital = getattr(player, "enemy_ai_capital_siege", None)
    if isinstance(capital, dict) and capital.get("province") == "Latium":
        # Список обычных осад иногда перезаписывается старым кодом; отдельная
        # ссылка не даёт осаде Рима исчезнуть между стадиями хода.
        if not any(isinstance(s, dict) and s.get("province") == "Latium" for s in safe_list(getattr(player, "enemy_ai_sieges", []))):
            player.enemy_ai_sieges = safe_list(getattr(player, "enemy_ai_sieges", [])) + [capital]
        return capital
    for siege in safe_list(getattr(player, "enemy_ai_sieges", [])):
        if isinstance(siege, dict) and siege.get("province") == "Latium":
            player.enemy_ai_capital_siege = siege
            return siege
    return None


def _enemy_ai_rome_siege_threshold(player: "Player") -> int:
    # Roma должна быть крепче обычного города, но не бессмертной.
    latium = next((p for p in getattr(player, "provinces", []) if p.get("name") == "Latium"), None)
    garrison = safe_int((latium or {}).get("garrison", 0), 0)
    morale = safe_int(getattr(player, "morale", 70), 70)
    unrest = safe_int(getattr(player, "unrest", 0), 0)
    return max(75, 118 + garrison * 12 + morale // 3 - unrest // 2)


def _enemy_ai_best_rome_army(player: "Player") -> dict | None:
    armies = [a for a in getattr(player, "enemy_armies", []) if safe_int(a.get("strength", 0), 0) >= 12]
    if not armies:
        return None
    army = max(armies, key=lambda a: (enemy_army_battle_power(a), safe_int(a.get("morale", 70), 70), safe_int(a.get("supply", 80), 80)))
    army["order"] = "siege"
    army["target"] = "Latium"
    army["ai_focus"] = "capture_rome"
    army["cooldown"] = 0
    return army


def _legacy_enemy_ai_register_city_capture_rome_v2233(player: "Player", province_name: str, city_name: str | None, *, source: str = "осада") -> bool:
    ensure_rome_fall_state(player)
    if province_name == "Latium":
        city_name = city_name or "Roma"
        if str(city_name).lower() in {"roma", "rome", "рим"}:
            player.rome_fallen = True
            player.enemy_ai_rome_pressure = 100
            player.unrest = 100
            player.morale = max(0, safe_int(getattr(player, "morale", 70), 70) - 45)
            player.senate_rep = 0
            player.people_rep = max(0, safe_int(getattr(player, "people_rep", 50), 50) - 35)
            # Latium удаляем из владений, чтобы карта и условия победы больше
            # не считали столицу римской.
            player.provinces = [p for p in getattr(player, "provinces", []) if p.get("name") != "Latium"]
            player.governors.pop("Latium", None)
            player.city_campaigns.pop("Latium", None)
            player.enemy_ai_capital_siege = None
            player.enemy_ai_sieges = [s for s in safe_list(getattr(player, "enemy_ai_sieges", [])) if not (isinstance(s, dict) and s.get("province") == "Latium")]
            player.enemy_ai_lost_cities.setdefault("Latium", [])
            if "Roma" not in player.enemy_ai_lost_cities["Latium"]:
                player.enemy_ai_lost_cities["Latium"].append("Roma")
            print(clr("\n  ☠ ROMA CAPTA EST: враг ворвался в столицу. Сенат разбегается, республика гибнет.", C.BOLD + C.RED))
            log_event(player, f"Roma пала после {source}: игра проиграна")
            return True
        return False
    return _enemy_ai_register_city_capture_v2232(player, province_name, city_name, source=source)


def enemy_ai_start_siege(player: "Player", province_name: str | None = None, army: dict | None = None):
    ensure_rome_fall_state(player)
    if province_name == "Latium":
        if player.rome_fallen or not _rome_is_owned(player):
            return
        if _enemy_ai_active_rome_siege(player):
            return
        if army is None:
            army = _enemy_ai_best_rome_army(player)
        if not army:
            army = spawn_enemy_army(player, "Latium", reason="march_on_rome")
        if not army:
            return
        siege = {
            "province": "Latium",
            "city": "Roma",
            "army_id": army.get("id"),
            "progress": max(20, enemy_army_battle_power(army) // 2),
            "turns": 0,
            "power": enemy_army_battle_power(army),
            "capital_siege": True,
        }
        print(clr(f"\n  ☠ ПОХОД НА РИМ: {army.get('unit_name', 'вражеская армия')} выходит к стенам Roma.", C.BOLD + C.RED))
        print(clr("  Это не обычная осада: падение столицы немедленно завершит партию поражением.", C.RED))
        enemy = {"name": army.get("unit_name", "армия у стен Рима"), "strength": enemy_army_battle_power(army) * 2 + 20, "battle_mod": 4}
        result = auxiliary_defense_battle(player, enemy, "оборона Рима", province_name="Latium", army=army, reward_glory=25)
        if result is True:
            print(clr("  ✓ Стены Рима удержаны: поход на столицу сорван до развёртывания лагеря.", C.GREEN))
            player.enemy_ai_rome_pressure = max(0, safe_int(getattr(player, "enemy_ai_rome_pressure", 0), 0) - 25)
            return
        if result is None:
            player.gold = max(0, safe_int(getattr(player, "gold", 0), 0) - random.randint(35, 80))
            print(clr("  Рим срочно нанимает городскую стражу: казна проседает, но осада начинается.", C.RED))
        player.enemy_ai_capital_siege = siege
        player.enemy_ai_sieges.append(siege)
        player.rome_siege_alarm_turn = safe_int(getattr(player, "turn", 0), 0)
        log_event(player, "Враг начал осаду Рима")
        return
    return _enemy_ai_start_siege_v2232(player, province_name, army)


def enemy_ai_rome_assault_tick(player: "Player") -> None:
    ensure_rome_fall_state(player)
    if player.rome_fallen or not _rome_is_owned(player):
        return
    active = _enemy_ai_active_rome_siege(player)
    if active is None and _enemy_ai_should_march_on_rome(player):
        army = _enemy_ai_best_rome_army(player)
        if army:
            enemy_ai_start_siege(player, "Latium", army)
        return
    if active is None:
        return

    army = next((a for a in getattr(player, "enemy_armies", []) if a.get("id") == active.get("army_id")), None)
    power = enemy_army_battle_power(army) if army else safe_int(active.get("power", 35), 35)
    support = sum(enemy_army_battle_power(a) for a in getattr(player, "enemy_armies", []) if a.get("target") == "Latium" and a.get("id") != active.get("army_id")) // 5
    threshold = _enemy_ai_rome_siege_threshold(player)
    gain = max(18, power // 3 + support + safe_int(getattr(player, "enemy_ai_pressure", 0), 0) // 6 + safe_int(getattr(player, "unrest", 0), 0) // 6)
    active["turns"] = safe_int(active.get("turns", 0), 0) + 1
    active["progress"] = safe_int(active.get("progress", 0), 0) + gain
    player.enemy_ai_rome_pressure = min(100, safe_int(getattr(player, "enemy_ai_rome_pressure", 0), 0) + gain // 4)
    print(clr(f"\n  ☠ ОСАДА РИМА: давление {active['progress']} / {threshold}. Поддержка врага: +{support}.", C.BOLD + C.RED))
    if active["turns"] >= 2 and active["progress"] >= threshold:
        enemy_ai_register_city_capture(player, "Latium", "Roma", source="осады столицы")


def enemy_ai_siege_tick(player: "Player"):
    # Обычная логика осад не знает о финальной осаде столицы и может удалить
    # Latium из списка осад как "нестандартную" цель. Поэтому на время её
    # работы прячем capital_siege, а затем обрабатываем Roma отдельным блоком.
    ensure_rome_fall_state(player)
    sieges = safe_list(getattr(player, "enemy_ai_sieges", []))
    capital_sieges = [s for s in sieges if isinstance(s, dict) and s.get("province") == "Latium"]
    ordinary_sieges = [s for s in sieges if not (isinstance(s, dict) and s.get("province") == "Latium")]
    player.enemy_ai_sieges = ordinary_sieges
    # Старый осадный тик может увидеть армии с target=Latium и снова вызвать
    # enemy_ai_start_siege("Latium"), а затем сам же стереть эту нестандартную
    # осаду. На время обычной логики прячем цель Latium у таких армий.
    hidden_rome_orders = []
    for a in getattr(player, "enemy_armies", []):
        if isinstance(a, MutableMapping) and a.get("target") == "Latium":
            hidden_rome_orders.append((a, a.get("order"), a.get("target"), a.get("cooldown")))
            a["target"] = None
            a["cooldown"] = max(1, safe_int(a.get("cooldown", 0), 0))
    _enemy_ai_siege_tick_v2232(player)
    for a, order, target, cooldown in hidden_rome_orders:
        try:
            a["order"] = order
            a["target"] = target
            a["cooldown"] = cooldown
        except Exception as exc:
            debug_log("Enemy siege cooldown normalization failed: %s", exc, exc_info=True, level=logging.WARNING)
    # Если Рим ещё не пал, возвращаем осаду столицы; старые обычные осады уже
    # обновлены. Если во время обычной логики что-то уничтожило столицу, не мешаем.
    if not getattr(player, "rome_fallen", False):
        existing = safe_list(getattr(player, "enemy_ai_sieges", []))
        if capital_sieges and not any(isinstance(s, dict) and s.get("province") == "Latium" for s in existing):
            player.enemy_ai_sieges = existing + capital_sieges[:1]
    enemy_ai_rome_assault_tick(player)


def enemy_ai_grand_strategy_tick(player: "Player"):
    ensure_rome_fall_state(player)
    _enemy_ai_grand_strategy_tick_v2232(player)
    # После всех обычных действий штаб ещё раз проверяет, пора ли идти на Рим:
    # это закрывает случай, когда давление выросло уже в этом же ходу.
    enemy_ai_rome_assault_tick(player)


def check_endgame(player: "Player"):
    ensure_rome_fall_state(player)
    if getattr(player, "rome_fallen", False):
        rui_screen_start()
        text = (
            "Roma capta est. Стены столицы прорваны, Сенат рассеян, знамёна врага стоят на Форуме.\n"
            "Римская держава лишилась сердца: партия завершена поражением."
        )
        if RICH_AVAILABLE:
            console.print(Panel(text, title="☠ ROMA CAPTA EST", border_style="red", box=box.DOUBLE))
        else:
            print(clr("\n  ☠ ROMA CAPTA EST", C.BOLD + C.RED))
            print("  Roma capta est. Столица захвачена врагом.")
            print("  Римская держава лишилась сердца: партия завершена поражением.")
        return True
    if not _rome_is_owned(player):
        player.rome_fallen = True
        return check_endgame(player)
    return _check_endgame_v2232(player)



# ─── v2.24.0: FRONTLINE AI / ВРАГ УЧИТСЯ ВОЕВАТЬ ПО КАРТЕ ──────────────────
# Предыдущая версия слишком рано превращала стратегию в «все идут на Рим».
# Этот слой делает ИИ более похожим на противника глобальной стратегии:
#   • армии выбирают фронтир, а не телепортируются к столице;
#   • идут по графу соседних провинций;
#   • сначала откусывают приграничные области и закрепляются;
#   • Рим становится финальной целью после потери кольца вокруг Latium.

ROME_RING_PROVINCES = {"Campania", "Etruria", "Umbria", "Gallia"}


def _v224_province_graph() -> dict[str, set[str]]:
    graph: dict[str, set[str]] = {}
    for p in PROVINCES_DATA:
        name = p.get("name")
        if not name:
            continue
        graph.setdefault(name, set())
        for n in safe_list(p.get("neighbors", [])):
            graph.setdefault(n, set()).add(name)
            graph[name].add(n)
    return graph


def _v224_all_province_names() -> set[str]:
    return {p.get("name") for p in PROVINCES_DATA if p.get("name")}


def _v224_roman_owned_names(player: "Player") -> set[str]:
    return {p.get("name") for p in getattr(player, "provinces", []) if isinstance(p, dict) and p.get("name")}


def _v224_province_data(name: str) -> dict | None:
    return province_by_name(name) or next((p for p in PROVINCES_DATA if p.get("name") == name), None)


def _v224_shortest_path(start: str | None, goal: str | None) -> list[str]:
    if not isinstance(start, str) or not isinstance(goal, str):
        return []
    start = start.strip()
    goal = goal.strip()
    if not start or not goal:
        return []
    if start == goal:
        return [start]

    graph = _v224_province_graph()
    if start not in graph or goal not in graph:
        return []

    queue = deque([(start, [start])])
    seen = {start}
    while queue:
        node, path = queue.popleft()
        for neighbor in graph.get(node, set()):
            if neighbor in seen:
                continue
            next_path = path + [neighbor]
            if neighbor == goal:
                return next_path
            seen.add(neighbor)
            queue.append((neighbor, next_path))
    return []


def _v224_distance(start: str | None, goal: str | None) -> int:
    path = _v224_shortest_path(start, goal)
    if not path:
        return 99
    return max(0, len(path) - 1)


def _v224_rome_ring_lost(player: "Player") -> int:
    owned = _v224_roman_owned_names(player)
    return sum(1 for p in ROME_RING_PROVINCES if p not in owned)


def _v224_rome_vulnerable(player: "Player") -> bool:
    ensure_rome_fall_state(player)
    owned = _v224_roman_owned_names(player)
    if "Latium" not in owned:
        return True
    roman_count = len(owned)
    ring_lost = _v224_rome_ring_lost(player)
    pressure = safe_int(getattr(player, "enemy_ai_pressure", 0), 0)
    turn = safe_int(getattr(player, "turn", 0), 0)
    # Рим — финал кампании. Его нельзя осаждать, пока вокруг него ещё есть
    # живой пояс римских провинций, кроме совсем катастрофического кризиса.
    return (
        roman_count <= 2
        or ring_lost >= 3
        or (ring_lost >= 2 and pressure >= 75 and turn >= 16)
        or (pressure >= 92 and turn >= 24)
    )


def _enemy_ai_should_march_on_rome(player: "Player") -> bool:
    """v2.24: Рим не первая цель, а последний приз кампании."""
    return _v224_rome_vulnerable(player)


def _v224_frontier_targets(player: "Player", include_rome: bool = False) -> list[dict]:
    owned = _v224_roman_owned_names(player)
    graph = _v224_province_graph()
    targets: list[dict] = []
    for prov in getattr(player, "provinces", []):
        if not isinstance(prov, dict):
            continue
        name = prov.get("name")
        if not name:
            continue
        if name == "Latium" and not include_rome:
            continue
        if any(nb not in owned for nb in graph.get(name, set())):
            targets.append(prov)
    if not targets and include_rome:
        latium = next((p for p in getattr(player, "provinces", []) if p.get("name") == "Latium"), None)
        if latium:
            targets.append(latium)
    return targets


def _v224_target_score(player: "Player", army: dict, prov: dict, load: dict[str, int]) -> int:
    name = prov.get("name")
    if not name:
        return -999
    base = _strategic_province_value(player, prov) if "_strategic_province_value" in globals() else 20
    unrest = safe_int(prov.get("unrest", 0), 0)
    wealth = safe_int(prov.get("wealth", 0), 0)
    garrison = safe_int(prov.get("garrison", 0), 0)
    distance = _v224_distance(army.get("province"), name)
    lost_here = len(safe_list(getattr(player, "enemy_ai_lost_cities", {}).get(name, [])))
    score = base + unrest * 7 + wealth * 5 + lost_here * 18 - garrison * 10
    score -= min(40, distance * 8)
    score -= load.get(name, 0) * 30
    # Latium ценится только в финале. До этого штраф огромный.
    if name == "Latium" and not _v224_rome_vulnerable(player):
        score -= 500
    if name == "Latium" and _v224_rome_vulnerable(player):
        score += 80
    # Армии любят добивать уже надкушенные провинции.
    held = len(safe_list(getattr(player, "city_campaigns", {}).get(name, [])))
    total = max(1, _enemy_ai_total_cities(name) if "_enemy_ai_total_cities" in globals() else 1)
    if held < total:
        score += (total - held) * 12
    return score


def _v224_pick_front_target(player: "Player", army: dict, load: dict[str, int]) -> str | None:
    include_rome = _v224_rome_vulnerable(player)
    candidates = _v224_frontier_targets(player, include_rome=include_rome)
    if not candidates:
        return None
    ranked = sorted(candidates, key=lambda p: _v224_target_score(player, army, p, load), reverse=True)
    # Небольшая непредсказуемость: не всегда берёт математически первый вариант.
    top = ranked[:3]
    weights = [max(1, _v224_target_score(player, army, p, load)) for p in top]
    total = sum(weights)
    roll = random.randint(1, total)
    acc = 0
    for p, w in zip(top, weights):
        acc += w
        if roll <= acc:
            return p.get("name")
    return top[0].get("name")


def _v224_army_can_siege_now(player: "Player", army: dict, target: str | None) -> bool:
    if not target:
        return False
    dist = _v224_distance(army.get("province"), target)
    # Если армия стоит в соседней вражеской области или уже у цели — осада возможна.
    return dist <= 1


def _v224_move_army_towards(player: "Player", army: dict, target: str | None) -> None:
    """Марширует к фронту, не телепортируясь внутрь римской территории."""
    if not isinstance(army, dict) or not target:
        return

    start = army.get("province")
    path = _v224_shortest_path(start, target)
    if len(path) < 2:
        army["target"] = target
        army["order"] = "recon"
        army["ai_focus"] = "seeking_front"
        return

    next_step = path[1]
    owned = _v224_roman_owned_names(player)

    # Первый римский узел на пути становится целью атаки; армия остаётся снаружи.
    if next_step in owned:
        army["target"] = next_step
        army["order"] = "siege" if _v224_army_can_siege_now(player, army, next_step) else "recon"
        army["ai_focus"] = "front_contact"
        return

    if next_step != target:
        army["province"] = next_step
        army["order"] = "recon"
        army["target"] = target
        army["ai_focus"] = "front_march"
        army["supply"] = max(
            0,
            safe_int(army.get("supply", 80), 80) - random.randint(2, 6),
        )
        if random.random() < 0.22:
            print(clr(
                f"\n  🧭 МАРШ ВРАГА: {army.get('unit_name','отряд')} движется через {next_step} к {target}.",
                C.RED,
            ))
        return

    army["target"] = target
    army["order"] = "recon"
    army["ai_focus"] = "seeking_front"


def enemy_ai_recon_and_orders(player: "Player"):
    """v2.24: приказы завязаны на фронт, расстояние и постепенное наступление."""
    ensure_enemy_grand_ai_state(player)
    ensure_ai_memory_state(player)
    ensure_city_campaigns(player)
    load: dict[str, int] = {}
    armies = sorted(getattr(player, "enemy_armies", []), key=enemy_army_battle_power, reverse=True)
    for army in armies:
        if safe_int(army.get("cooldown", 0), 0) > 0:
            army["cooldown"] = max(0, safe_int(army.get("cooldown", 0), 0) - 1)
            continue
        if army.get("campaign_id"):
            continue
        strength = safe_int(army.get("strength", 25), 25)
        morale = safe_int(army.get("morale", 70), 70)
        supply = safe_int(army.get("supply", 80), 80)
        if strength < 16 or morale < 34 or supply < 25:
            army["order"] = "regroup"
            army["target"] = None
            army["ai_focus"] = "recover"
            army["strength"] = min(125, strength + random.randint(4, 10))
            army["morale"] = min(120, morale + random.randint(7, 14))
            army["supply"] = min(120, supply + random.randint(12, 24))
            continue
        target = _v224_pick_front_target(player, army, load)
        if not target:
            army["order"] = "recon"
            army["target"] = None
            army["ai_focus"] = "probing"
            continue
        load[target] = load.get(target, 0) + 1
        if not _v224_army_can_siege_now(player, army, target):
            _v224_move_army_towards(player, army, target)
            continue
        # У самой цели: выбираем не только осаду, но и рейд/засаду по роли.
        prov = next((p for p in getattr(player, "provinces", []) if p.get("name") == target), None) or {}
        power = enemy_army_battle_power(army)
        unrest = safe_int(prov.get("unrest", 0), 0)
        wealth = safe_int(prov.get("wealth", 0), 0)
        if target == "Latium" and _v224_rome_vulnerable(player):
            order = "siege"
        elif power >= 42 and (unrest >= 3 or safe_int(prov.get("garrison", 0), 0) <= 1):
            order = "siege"
        elif wealth >= 4 and random.random() < 0.45:
            order = "raid"
        elif random.random() < 0.25:
            order = "ambush"
        else:
            order = "siege"
        army["order"] = order
        army["target"] = target
        army["ai_focus"] = "front_breakthrough"
        army["supply"] = max(0, supply - random.randint(3, 8))
        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {
            "order": order,
            "target": target,
            "turn": getattr(player, "turn", 0),
            "focus": army.get("ai_focus"),
        }


def enemy_ai_execute_operational_orders(player: "Player"):
    """v2.24: исполнительный слой не шлёт все армии на одну цель."""
    ensure_enemy_grand_ai_state(player)
    ensure_city_campaigns(player)
    active = {s.get("province") for s in getattr(player, "enemy_ai_sieges", []) if isinstance(s, dict)}
    candidates = []
    for a in getattr(player, "enemy_armies", []):
        target = a.get("target")
        if a.get("order") != "siege" or not target:
            continue
        if target in active:
            continue
        if safe_int(a.get("cooldown", 0), 0) > 0 or safe_int(a.get("strength", 0), 0) < 18:
            continue
        if target == "Latium" and not _v224_rome_vulnerable(player):
            continue
        if _v224_army_can_siege_now(player, a, target):
            candidates.append(a)
    limit = 2 if is_madness_mode(player) else 1
    # Если фронтов много и империя большая — можно начать две обычные осады.
    if len(_v224_frontier_targets(player, include_rome=False)) >= 4 and len(getattr(player, "provinces", [])) >= 8:
        limit = max(limit, 2)
    for army in sorted(candidates, key=enemy_army_battle_power, reverse=True)[:limit]:
        enemy_ai_start_siege(player, army.get("target"), army)
        army["cooldown"] = max(safe_int(army.get("cooldown", 0), 0), 1)


def enemy_ai_start_siege(player: "Player", province_name: str | None = None, army: dict | None = None):
    """v2.24: осады начинаются на фронтире; Рим — только при открытой дороге."""
    ensure_rome_fall_state(player)
    ensure_enemy_grand_ai_state(player)
    ensure_city_campaigns(player)
    if province_name == "Latium":
        if not _v224_rome_vulnerable(player):
            return
        return _enemy_ai_start_siege_v2232(player, province_name, army)
    if province_name is None:
        if army is not None:
            province_name = _v224_pick_front_target(player, army, {})
        else:
            fronts = _v224_frontier_targets(player, include_rome=False)
            province_name = random.choice(fronts).get("name") if fronts else None
    if not province_name or province_name == "Latium":
        return
    owned = _v224_roman_owned_names(player)
    if province_name not in owned:
        return
    # Запрет на абсурдную глубокую осаду: цель должна быть на фронте.
    graph = _v224_province_graph()
    if not any(nb not in owned for nb in graph.get(province_name, set())):
        return
    return _enemy_ai_start_siege_v2232(player, province_name, army)


def enemy_ai_raid_event(player: "Player"):
    """v2.24: рейды бьют по фронтовым целям, а не по случайной глубине."""
    ensure_enemy_grand_ai_state(player)
    fronts = {p.get("name") for p in _v224_frontier_targets(player, include_rome=False)}
    for a in getattr(player, "enemy_armies", []):
        if a.get("order") == "raid" and a.get("target") not in fronts:
            a["target"] = _v224_pick_front_target(player, a, {})
    return _enemy_ai_raid_event_v217(player)


def enemy_ai_campaign_start(player: "Player"):
    """v2.24: большие кампании выбирают фронт, а не столицу по умолчанию."""
    ensure_enemy_grand_ai_state(player)
    idle = [a for a in getattr(player, "enemy_armies", [])
            if not a.get("campaign_id") and safe_int(a.get("cooldown", 0), 0) <= 0 and safe_int(a.get("strength", 0), 0) >= 18]
    if len(idle) < 3 or len(getattr(player, "enemy_ai_campaigns", [])) >= (4 if is_madness_mode(player) else 2):
        return
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_campaign_start_chance", 0.16))
    if random.random() >= chance:
        return
    seed = max(idle, key=enemy_army_battle_power)
    target = _v224_pick_front_target(player, seed, {})
    if not target:
        return
    chosen = sorted(idle, key=lambda a: (_v224_distance(a.get("province"), target), -enemy_army_battle_power(a)))[:min(4, len(idle))]
    cid = f"CAMP-v224-{getattr(player,'turn',0)}-{random.randint(100,999)}"
    for a in chosen:
        a["campaign_id"] = cid
        a["target"] = target
        a["order"] = "siege" if _v224_army_can_siege_now(player, a, target) else "recon"
        a["ai_focus"] = "front_campaign"
    player.enemy_ai_campaigns.append({
        "id": cid,
        "target": target,
        "army_ids": [a.get("id") for a in chosen],
        "phase": "advance",
        "turns_in_phase": 0,
        "threat": sum(enemy_army_battle_power(a) for a in chosen),
        "start_strength": sum(safe_int(a.get("strength", 0), 0) for a in chosen),
    })
    print(clr(f"\n  🗺 ВРАЖЕСКАЯ КАМПАНИЯ: {len(chosen)} армии открывают фронт против {target}.", C.BOLD + C.RED))
    log_event(player, f"Враг начал фронтовую кампанию против {target}")


def enemy_ai_campaign_tick(player: "Player"):
    """v2.24: кампании продвигаются по маршруту и не залипают в сборе."""
    ensure_enemy_grand_ai_state(player)
    if not getattr(player, "enemy_ai_campaigns", []):
        return
    live = {a.get("id"): a for a in getattr(player, "enemy_armies", [])}
    remaining = []
    for camp in safe_list(getattr(player, "enemy_ai_campaigns", [])):
        target = camp.get("target")
        armies = [live[i] for i in safe_list(camp.get("army_ids", [])) if i in live]
        if not armies or not target or target not in _v224_roman_owned_names(player):
            for a in armies:
                a["campaign_id"] = None
            continue
        camp["turns_in_phase"] = safe_int(camp.get("turns_in_phase", 0), 0) + 1
        near = 0
        for a in armies:
            if _v224_army_can_siege_now(player, a, target):
                a["order"] = "siege"
                a["target"] = target
                near += 1
            else:
                _v224_move_army_towards(player, a, target)
        if near >= max(1, len(armies)//2):
            best = max(armies, key=enemy_army_battle_power)
            enemy_ai_start_siege(player, target, best)
            for a in armies:
                a["cooldown"] = max(1, safe_int(a.get("cooldown", 0), 0))
            if random.random() < 0.45:
                print(clr(f"  ⚔ Кампания врага разворачивает осадные лагеря у {target}.", C.RED))
        if camp["turns_in_phase"] <= 8:
            remaining.append(camp)
        else:
            for a in armies:
                a["campaign_id"] = None
    player.enemy_ai_campaigns = remaining[-6:]


def enemy_ai_grand_strategy_tick(player: "Player"):
    """v2.24: полный ход ИИ через фронтовую модель."""
    ensure_rome_fall_state(player)
    ensure_enemy_grand_ai_state(player)
    ensure_ai_memory_state(player)
    if not getattr(player, "enemy_armies", []):
        initial_armies = 4 if is_madness_mode(player) else 2
        for _ in range(min(initial_armies, _enemy_armies_cap(player))):
            spawn_enemy_army(player, reason="frontier_start")
    # Старые системы оставлены, но порядок другой: сначала фронт и движение,
    # затем события, затем — финальная проверка Рима.
    _decay_ai_memory(player)
    enemy_ai_coalition_tick(player)
    enemy_ai_recon_and_orders(player)
    enemy_ai_execute_operational_orders(player)
    enemy_ai_pray_and_buff(player)
    enemy_ai_spawn_reinforcements(player)
    enemy_ai_mobilization(player)
    enemy_ai_campaign_start(player)
    enemy_ai_campaign_tick(player)
    enemy_ai_raid_event(player)
    enemy_ai_siege_tick(player)
    enemy_ai_recapture_city_event(player)
    enemy_ai_joint_attack(player)
    total_power = sum(enemy_army_battle_power(a) for a in getattr(player, "enemy_armies", []))
    fronts = len(_v224_frontier_targets(player, include_rome=False))
    player.enemy_ai_pressure = min(100, fronts * 4 + len(getattr(player, "enemy_armies", [])) * 2 + total_power // 34 + _v224_rome_ring_lost(player) * 8)
    # ВАЖНО v2.24.3: штурм Рима тикает только внутри enemy_ai_siege_tick().
    # Повторный вызов здесь удваивал прогресс осады столицы за один ход.


def show_enemy_ai_report(player: "Player"):
    # Поверх старого доклада добавляем понятную картину фронта.
    try:
        _show_enemy_ai_report_v217(player)
    except Exception as exc:
        debug_log("Enemy AI report legacy renderer failed: %s", exc, exc_info=True, level=logging.WARNING)
    fronts = [p.get("name") for p in _v224_frontier_targets(player, include_rome=False)]
    if fronts:
        rui_info("Фронты врага: " + ", ".join(fronts[:8]), C.RED)
    rui_info(f"Кольцо вокруг Рима потеряно: {_v224_rome_ring_lost(player)}/4. Осада столицы {'возможна' if _v224_rome_vulnerable(player) else 'пока преждевременна'}.", C.GOLD)


# ─── v2.24.19-p1: AI DIRECTOR STATE / ПАМЯТЬ И ГОРИЗОНТ ───────────────────
# Первый безопасный слой AI Director: только состояние, память эффективности
# и горизонт планирования. Этот патч ничего не меняет в принятии решений ИИ.

def ensure_ai_director_state(player: "Player") -> dict:
    """Создаёт память AI Director внутри существующего player.ai_memory.

    Новых обязательных полей Player не добавляем: старые сейвы получают
    director лениво при первом обращении, а текущая сериализация уже сохраняет
    ai_memory как часть __dict__.
    """
    mem = ensure_ai_memory_state(player)
    director = safe_dict(mem.get("director"))
    director.setdefault("goal_history", [])
    director.setdefault("recent_attack_results", [])
    director.setdefault("foreign_actions", {})
    director.setdefault("last_goal", None)
    director.setdefault("last_goal_turn", 0)
    mem["director"] = director
    return director


def _ai_director_horizon(player: "Player") -> int:
    """Возвращает быстрый горизонт планирования без перебора дерева ходов."""
    diff = getattr(player, "difficulty", "normal")
    base = {
        "easy": 5,
        "normal": 7,
        "hard": 9,
        "hardcore": 10,
        "madness": 10,
    }.get(diff, 7)
    pressure = safe_int(getattr(player, "enemy_ai_pressure", 0), 0, 0, 100)
    pressure_bonus = 2 if pressure >= 65 else 0
    return min(10, base + pressure_bonus)


def _ai_record_attack_result(player: "Player", target: str | None, success: bool, kind: str = "battle") -> None:
    """Запоминает результат действия ИИ для будущей адаптации.

    Сейчас это только запись памяти. Последующие патчи будут читать эту историю,
    чтобы прекращать повторные неудачные атаки и переходить к восстановлению.
    """
    if not target:
        return
    director = ensure_ai_director_state(player)
    results = safe_list(director.get("recent_attack_results"))
    results.append({
        "turn": safe_int(getattr(player, "turn", 0), 0),
        "target": str(target),
        "success": bool(success),
        "kind": str(kind or "battle"),
    })
    director["recent_attack_results"] = results[-20:]


def _ai_recent_failure_rate(player: "Player", target: str | None = None) -> float:
    """Доля провалов в последних пяти действиях ИИ, опционально по цели."""
    director = ensure_ai_director_state(player)
    results = [r for r in safe_list(director.get("recent_attack_results")) if isinstance(r, dict)]
    if target:
        results = [r for r in results if r.get("target") == target]
    results = results[-5:]
    if not results:
        return 0.0
    failures = sum(1 for r in results if not r.get("success"))
    return failures / max(1, len(results))


def _ai_goal_utilities(player: "Player") -> dict[str, int]:
    """Utility-оценка стратегических целей AI Director.

    Функция ничего не исполняет и не меняет в поведении ИИ: она только
    оценивает текущую ситуацию через существующую разведсводку, память
    провалов и горизонт планирования.
    """
    ensure_ai_director_state(player)
    profile = _ai_player_weakness_profile(player)
    horizon = _ai_director_horizon(player)
    failure_rate = _ai_recent_failure_rate(player)
    pressure = safe_int(getattr(player, "enemy_ai_pressure", 0), 0, 0, 100)
    provinces = safe_list(getattr(player, "provinces", []))
    armies = [a for a in safe_list(getattr(player, "enemy_armies", [])) if isinstance(a, (dict, EnemyArmy))]
    weak_armies = [
        a for a in armies
        if safe_int(a.get("strength", 25), 25) < 22
        or safe_int(a.get("morale", 70), 70) < 38
        or safe_int(a.get("supply", 80), 80) < 30
    ]
    coalition = getattr(player, "enemy_ai_coalition", {})
    coalition_active = bool(isinstance(coalition, dict) and coalition.get("active"))
    frontier_open = bool(_v224_frontier_targets(player, include_rome=False))

    utilities = {
        "recover": 18 + len(weak_armies) * 16 + int(failure_rate * 45),
        "weaken_economy": 22 + (20 if profile.get("rich_rome") else 0) + (14 if profile.get("low_gold") or profile.get("low_grain") else 0),
        "raise_revolt": 20 + safe_int(profile.get("unrest", 0), 0) // 2 + (18 if profile.get("thin_garrisons") else 0),
        "break_frontier": 28 + (18 if profile.get("overextended") else 0) + pressure // 4 + (10 if frontier_open else 0),
        "hunt_legions": 18 + safe_int(profile.get("weak_legion_count", 0), 0) * 18,
        "coalition": 14 + len(provinces) // 2 + (16 if pressure >= 50 else 0) + (20 if coalition_active else 0),
    }

    if failure_rate >= 0.60:
        utilities["recover"] += 28
        utilities["break_frontier"] -= 24
        utilities["hunt_legions"] -= 18

    weights = {
        "recover": 1.15,
        "weaken_economy": 1.05,
        "raise_revolt": 1.10,
        "break_frontier": 1.20,
        "hunt_legions": 1.08,
        "coalition": 1.14,
    }
    return {goal: max(0, int(score * weights.get(goal, 1.0) + horizon)) for goal, score in utilities.items()}


def _ai_select_goal(player: "Player") -> str:
    """Выбирает стратегическую цель без подключения её к приказам ИИ.

    Это state-machine часть AI Director: если прежняя цель всё ещё достаточно
    полезна, она удерживается несколько ходов. Функция только обновляет память
    director; приказы армий и дипломатия пока не читают этот выбор.
    """
    director = ensure_ai_director_state(player)
    utilities = _ai_goal_utilities(player)
    turn = safe_int(getattr(player, "turn", 0), 0)
    last_goal = director.get("last_goal")
    if last_goal and turn - safe_int(director.get("last_goal_turn", 0), 0) < 3:
        if utilities.get(last_goal, 0) >= max(utilities.values() or [0]) * 0.72:
            return str(last_goal)

    ranked = sorted(utilities.items(), key=lambda kv: kv[1], reverse=True)[:3]
    total = sum(max(1, score) for _, score in ranked)
    roll = random.randint(1, max(1, total))
    acc = 0
    selected = ranked[0][0] if ranked else "break_frontier"
    for goal, score in ranked:
        acc += max(1, score)
        if roll <= acc:
            selected = goal
            break

    director["last_goal"] = selected
    director["last_goal_turn"] = turn
    history = safe_list(director.get("goal_history"))
    history.append({"turn": turn, "goal": selected, "utilities": utilities})
    director["goal_history"] = history[-12:]
    return selected


# ─── v2.24.19-p3: AI DIRECTOR WAR COUNCIL / НАБЛЮДАТЕЛЬНЫЙ СЛОЙ ────────────
# Подключает AI Director к данным военного совета и отчёту штаба, но не меняет
# приказы армий, дипломатию, потери и боевое поведение.

_ai_update_war_council_memory_v22419_p3 = _ai_update_war_council_memory

def _ai_update_war_council_memory(player: "Player") -> dict:
    """Добавляет цель, горизонт и utility AI Director в существующий war council."""
    council = _ai_update_war_council_memory_v22419_p3(player)
    council["goal"] = _ai_select_goal(player)
    council["horizon"] = _ai_director_horizon(player)
    council["utility"] = _ai_goal_utilities(player)
    ensure_ai_memory_state(player)["war_council"] = council
    return council


_show_enemy_ai_report_v22419_p3 = show_enemy_ai_report

def show_enemy_ai_report(player: "Player"):
    """Показывает состояние AI Director в экране Вражеского штаба."""
    _show_enemy_ai_report_v22419_p3(player)
    council = safe_dict(ensure_ai_memory_state(player).get("war_council"))
    if not council:
        council = _ai_update_war_council_memory(player)

    goal = str(council.get("goal") or ensure_ai_director_state(player).get("last_goal") or "break_frontier")
    horizon = safe_int(council.get("horizon", _ai_director_horizon(player)), _ai_director_horizon(player), 5, 10)
    utility = safe_dict(council.get("utility"))

    if utility:
        top = sorted(utility.items(), key=lambda kv: safe_int(kv[1], 0), reverse=True)[:3]
        rui_info("AI Director utility: " + ", ".join(f"{name}={score}" for name, score in top), C.PURPLE)
    rui_info(f"AI Director goal: {goal}; horizon {horizon} ход.", C.PURPLE)


# ─── v2.24.19-p4: AI DIRECTOR BREAK FRONTIER HOOK ──────────────────────────
# Первый поведенческий hook AI Director: только цель break_frontier.
# Старый enemy_ai_recon_and_orders выполняется первым; директор лишь точечно
# переназначает 2-3 подходящие армии на слабые приграничные провинции.

_enemy_ai_recon_and_orders_v22419_p4 = enemy_ai_recon_and_orders

def enemy_ai_recon_and_orders(player: "Player"):
    """После базовой логики усиливает давление на слабый фронтир при goal=break_frontier."""
    _enemy_ai_recon_and_orders_v22419_p4(player)

    council = _ai_update_war_council_memory(player)
    if council.get("goal") != "break_frontier":
        return

    fronts = _v224_frontier_targets(player, include_rome=False)
    if not fronts:
        return

    limit = 3 if getattr(player, "difficulty", "normal") in {"hard", "hardcore", "madness"} else 2
    load: dict[str, int] = {}

    def target_score(army: dict, prov: dict) -> int:
        name = prov.get("name")
        garrison = safe_int(prov.get("garrison", 0), 0)
        unrest = safe_int(prov.get("unrest", 0), 0)
        wealth = safe_int(prov.get("wealth", 0), 0)
        distance = _v224_distance(army.get("province"), name)
        recent_fail = _ai_recent_failure_rate(player, name)
        score = 80
        score += max(0, 4 - garrison) * 18
        score += unrest * 12
        score += wealth * 6
        score -= min(60, distance * 10)
        score -= load.get(name, 0) * 22
        score -= int(recent_fail * 35)
        return max(1, score)

    eligible = [
        a for a in sorted(getattr(player, "enemy_armies", []), key=enemy_army_battle_power, reverse=True)
        if not a.get("campaign_id")
        and safe_int(a.get("cooldown", 0), 0) <= 0
        and safe_int(a.get("strength", 0), 0) >= 20
        and safe_int(a.get("supply", 0), 0) >= 25
    ]

    changed = 0
    for army in eligible:
        if changed >= limit:
            break
        ranked = sorted(fronts, key=lambda p: target_score(army, p), reverse=True)[:3]
        if not ranked:
            continue
        target = ranked[0].get("name")
        if not target:
            continue

        load[target] = load.get(target, 0) + 1
        if _v224_army_can_siege_now(player, army, target):
            army["order"] = "siege"
        else:
            army["order"] = "recon"
        army["target"] = target
        army["ai_focus"] = "director_break_frontier"

        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {
            "order": army.get("order"),
            "target": target,
            "turn": getattr(player, "turn", 0),
            "score": target_score(army, ranked[0]),
            "focus": "director_break_frontier",
        }
        changed += 1


# ─── v2.24.20: AI DIRECTOR — ЧЕТЫРЕ НОВЫХ ПОВЕДЕНЧЕСКИХ РЕЖИМА ─────────────
# hunt_legions / weaken_economy / raise_revolt / recover уже участвовали в
# utility-оценке AI Director (v2.24.19-p1..p4), но реальными приказами армий
# управлял только break_frontier. Патч добавляет по одному точечному хуку на
# каждую цель — в том же стиле, что и director_break_frontier: 2-3 подходящие
# армии переназначаются, базовая логика enemy_ai_recon_and_orders не трогается.
#
#   hunt_legions   — точечный удар по самым слабым легионам игрока (order=strike,
#                    резолюция боя — новое событие _ai_director_hunt_legions_strike_event).
#   weaken_economy — рейды по самым богатым фронтирным провинциям и по провинциям
#                    с активным торговым путём («узлам» экономики).
#   raise_revolt   — рейды и подкуп смутьянов в провинциях, где и так неспокойно.
#   recover        — армии отзываются из кампаний и уходят на перегруппировку,
#                    пока не восстановят силы; после нескольких ходов утилита
#                    recover искусственно гаснет, чтобы ИИ не «залечивался» вечно.


def _ai_director_eligible_armies(player: "Player") -> list[dict]:
    """Армии, свободные для точечного перенацеливания AI Director: не в кампании,
    отдохнувшие и достаточно снабжённые, чтобы взяться за отдельное поручение.
    Тот же порог, что и у director_break_frontier — держим критерии в одном месте.
    """
    return [
        a for a in sorted(getattr(player, "enemy_armies", []), key=enemy_army_battle_power, reverse=True)
        if not a.get("campaign_id")
        and safe_int(a.get("cooldown", 0), 0) <= 0
        and safe_int(a.get("strength", 0), 0) >= 20
        and safe_int(a.get("supply", 0), 0) >= 25
    ]


def _ai_director_trade_hub_provinces(player: "Player") -> set[str]:
    """Провинции, где заканчивается действующий торговый путь — экономические узлы державы."""
    v24 = getattr(player, "v24", None)
    routes = safe_list(v24.get("trade_routes")) if isinstance(v24, dict) else []
    hubs = set()
    for route in routes:
        if not isinstance(route, dict) or not route.get("active", True):
            continue
        name = str(route.get("name", "")).split("↔")[-1].strip()
        if name:
            hubs.add(name)
    return hubs


def _ai_director_hunt_legions_hook(player: "Player", council: dict) -> None:
    """Цель hunt_legions: пара-тройка армий целенаправленно нацеливается на
    самые уязвимые легионы игрока (приказ 'strike'). Сама атака резолвится
    отдельным событием _ai_director_hunt_legions_strike_event ниже."""
    if council.get("goal") != "hunt_legions":
        return
    weak_legions = [l for l in _weak_legions_sorted(player) if safe_int(getattr(l, "strength", 0), 0) > 0]
    if not weak_legions:
        return
    pool = weak_legions[:2]
    limit = 3 if getattr(player, "difficulty", "normal") in {"hard", "hardcore", "madness"} else 2
    load: dict[str, int] = {}

    eligible = _ai_director_eligible_armies(player)
    changed = 0
    for army in eligible:
        if changed >= limit:
            break
        legion = min(pool, key=lambda l: load.get(l.name, 0))
        load[legion.name] = load.get(legion.name, 0) + 1
        army["order"] = "strike"
        army["target"] = legion.name
        army["ai_focus"] = "director_hunt_legions"

        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {
            "order": "strike",
            "target": legion.name,
            "turn": getattr(player, "turn", 0),
            "focus": "director_hunt_legions",
        }
        changed += 1


def _ai_director_hunt_legions_strike_event(player: "Player") -> None:
    """Резолюция удара по легиону для armies с ai_focus=director_hunt_legions.

    Раньше приказ 'strike' был только меткой в отчёте штаба без последствий —
    теперь он реально сводит помеченные армии в один бой против легиона-цели,
    по образцу старого enemy_ai_joint_attack (см. v2.17-v2.22.5 выше), который
    в текущей архитектуре бьёт по ауксилии, а не по конкретному легиону.
    """
    strikers = [
        a for a in getattr(player, "enemy_armies", [])
        if a.get("order") == "strike"
        and a.get("ai_focus") == "director_hunt_legions"
        and safe_int(a.get("cooldown", 0), 0) <= 0
        and a.get("target")
    ]
    if not strikers:
        return
    chance = float(_enemy_ai_setting_player(player, "enemy_ai_director_strike_chance", 0.24))
    if random.random() >= chance:
        return

    by_target: dict[str, list[dict]] = {}
    for a in strikers:
        by_target.setdefault(a.get("target"), []).append(a)
    target_name = max(by_target, key=lambda name: sum(enemy_army_battle_power(a) for a in by_target[name]))
    armies = by_target[target_name]

    legion = next(
        (l for l in getattr(player, "legions", []) if l.name == target_name and safe_int(getattr(l, "strength", 0), 0) > 0),
        None,
    )
    if not legion:
        # Легион уже переместился, погиб или сменил имя — отряды возвращаются к разведке.
        for a in armies:
            a["order"] = "recon"
            a["target"] = None
        return

    enemy = _build_joint_enemy(armies)
    legion_estimate = safe_int(legion.strength, 50) + safe_int(legion.morale, 70) // 3 + safe_int(getattr(legion, "quality", 1), 1) * 8
    if enemy["strength"] < legion_estimate * 0.55 and random.random() < 0.65:
        # Осторожный ИИ не бросает заведомо слабый отряд в проигранный бой.
        for a in armies:
            a["order"] = "regroup"
        return

    print(clr(f"\n  ☠ ОХОТА НА ЛЕГИОН: враг наносит удар по {legion.name}!", C.BOLD + C.RED))
    print(clr(f"  Состав: {enemy.get('unit_summary', 'вражеский отряд')}", C.GRAY))
    if enemy.get("commanders"):
        print(clr(f"  Полководцы: {', '.join(enemy['commanders'])}", C.PURPLE))
    log_event(player, f"AI Director: удар по легиону {legion.name}")

    won = resolve_battle(player, legion, enemy, is_civil_war=False)
    if won:
        _remember_failed_ai_target(player, legion.name)
        _ai_record_attack_result(player, legion.name, success=False, kind="strike")
        enemy_ai_apply_army_losses(player, enemy, victory=True)
    else:
        enemy_ai_pursuit_counterattack(player, legion, enemy)
        enemy_ai_apply_army_losses(player, enemy, victory=False)
        _ai_record_attack_result(player, legion.name, success=True, kind="strike")


def _ai_director_weaken_economy_hook(player: "Player", council: dict) -> None:
    """Цель weaken_economy: рейды по самым богатым фронтирным провинциям и по
    провинциям с активным торговым путём. Успешный рейд уже сам по себе бьёт
    по золоту/зерну и поднимает волнения (см. enemy_ai_raid_event) — здесь же
    добавлена шансовая диверсия против самого торгового пути."""
    if council.get("goal") != "weaken_economy":
        return
    fronts = _v224_frontier_targets(player, include_rome=False)
    if not fronts:
        return
    hubs = _ai_director_trade_hub_provinces(player)
    v24 = getattr(player, "v24", None)
    routes = safe_list(v24.get("trade_routes")) if isinstance(v24, dict) else []
    limit = 3 if getattr(player, "difficulty", "normal") in {"hard", "hardcore", "madness"} else 2
    sabotage_chance = float(_enemy_ai_setting_player(player, "enemy_ai_director_route_sabotage_chance", 0.30))
    load: dict[str, int] = {}

    def econ_score(prov: dict) -> int:
        name = prov.get("name")
        score = 40 + safe_int(prov.get("wealth", 0), 0) * 14
        score += 30 if name in hubs else 0
        score -= safe_int(prov.get("garrison", 0), 0) * 12
        score -= load.get(name, 0) * 25
        score -= int(_ai_recent_failure_rate(player, name) * 30)
        return max(1, score)

    eligible = _ai_director_eligible_armies(player)
    changed = 0
    for army in eligible:
        if changed >= limit:
            break
        ranked = sorted(fronts, key=econ_score, reverse=True)
        target = ranked[0].get("name") if ranked else None
        if not target:
            continue

        load[target] = load.get(target, 0) + 1
        army["order"] = "raid"
        army["target"] = target
        army["ai_focus"] = "director_weaken_economy"

        if target in hubs and random.random() < sabotage_chance:
            for route in routes:
                if isinstance(route, dict) and route.get("active", True) and str(route.get("name", "")).split("↔")[-1].strip() == target:
                    route["active"] = False
                    print(clr(f"\n  💰 ТОРГОВЫЙ ПУТЬ ПЕРЕРЕЗАН: рейдеры у {target} перекрыли маршрут «{route.get('name')}».", C.BOLD + C.RED))
                    log_event(player, f"AI Director: перекрыт торговый путь у {target}")
                    break

        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {
            "order": "raid",
            "target": target,
            "turn": getattr(player, "turn", 0),
            "score": econ_score(ranked[0]),
            "focus": "director_weaken_economy",
        }
        changed += 1


def _ai_director_raise_revolt_hook(player: "Player", council: dict) -> None:
    """Цель raise_revolt: рейды по провинциям, где и так неспокойно, плюс
    шансовый подкуп смутьянов — прямая прибавка к волнениям провинции,
    независимо от исхода самого рейда."""
    if council.get("goal") != "raise_revolt":
        return
    fronts = _v224_frontier_targets(player, include_rome=False)
    targets = [p for p in fronts if safe_int(p.get("unrest", 0), 0) >= 3]
    if not targets:
        return
    limit = 3 if getattr(player, "difficulty", "normal") in {"hard", "hardcore", "madness"} else 2
    threshold = safe_int(SETTINGS.get("province_revolt_threshold", 7), 7)
    incite_chance = float(_enemy_ai_setting_player(player, "enemy_ai_director_incite_chance", 0.22))
    load: dict[str, int] = {}

    def unrest_score(prov: dict) -> int:
        name = prov.get("name")
        score = 30 + safe_int(prov.get("unrest", 0), 0) * 20
        score -= safe_int(prov.get("garrison", 0), 0) * 10
        score -= load.get(name, 0) * 25
        score -= int(_ai_recent_failure_rate(player, name) * 25)
        return max(1, score)

    eligible = _ai_director_eligible_armies(player)
    changed = 0
    for army in eligible:
        if changed >= limit:
            break
        ranked = sorted(targets, key=unrest_score, reverse=True)
        prov = ranked[0] if ranked else None
        name = prov.get("name") if prov else None
        if not name:
            continue

        load[name] = load.get(name, 0) + 1
        army["order"] = "raid"
        army["target"] = name
        army["ai_focus"] = "director_raise_revolt"

        if random.random() < incite_chance:
            before = safe_int(prov.get("unrest", 0), 0)
            prov["unrest"] = min(10, before + 1)
            if before < threshold <= prov["unrest"]:
                print(clr(f"\n  🔥 ВРАЖЕСКИЕ АГИТАТОРЫ: в {name} подкуплены смутьяны, волнения выходят из-под контроля.", C.BOLD + C.RED))
            else:
                print(clr(f"\n  🗣 Вражеские лазутчики подкупают недовольных в {name}: волнения растут.", C.RED))
            log_event(player, f"AI Director: подкуп смутьянов в {name}")

        mem = ensure_ai_memory_state(player)
        mem.setdefault("last_orders", {})[army.get("id")] = {
            "order": "raid",
            "target": name,
            "turn": getattr(player, "turn", 0),
            "score": unrest_score(prov),
            "focus": "director_raise_revolt",
        }
        changed += 1


def _ai_director_recover_hook(player: "Player", council: dict) -> None:
    """Цель recover: ИИ прекращает наступление, отзывает армии из кампаний и
    переводит их на перегруппировку с усиленным восстановлением, пока утилита
    recover не будет искусственно погашена в _ai_goal_utilities ниже."""
    if council.get("goal") != "recover":
        return
    director = ensure_ai_director_state(player)
    if safe_int(director.get("recover_streak", 0), 0) == 1:
        print(clr("\n  🏳 ВРАГ СВОРАЧИВАЕТ НАСТУПЛЕНИЕ: армии отходят с фронта, чтобы восполнить силы.", C.BOLD + C.CYAN))
        log_event(player, "AI Director: враг переходит к восстановлению сил")

    # Отзываем армии из кампаний: поход прерван, отряды уходят зализывать раны.
    withdrawn = 0
    for camp in list(getattr(player, "enemy_ai_campaigns", [])):
        army_ids = set(safe_list(camp.get("army_ids", [])))
        if not army_ids:
            continue
        for army in getattr(player, "enemy_armies", []):
            if army.get("id") in army_ids:
                army["campaign_id"] = None
                army["order"] = "regroup"
                army["target"] = None
                army["ai_focus"] = "director_recover"
                withdrawn += 1
        if camp in player.enemy_ai_campaigns:
            player.enemy_ai_campaigns.remove(camp)
    if withdrawn:
        print(clr(f"  🏳 Кампании свёрнуты, {withdrawn} отрядов отведены на перегруппировку.", C.CYAN))
        log_event(player, f"AI Director: отступление с фронта ({withdrawn} отрядов)")

    # Все прочие армии (не только критично слабые) тоже переходят к восстановлению —
    # иначе фаза recover ничем не отличалась бы от обычного авто-regroup по усталости.
    for army in getattr(player, "enemy_armies", []):
        if army.get("campaign_id"):
            continue
        strength = safe_int(army.get("strength", 25), 25)
        morale = safe_int(army.get("morale", 70), 70)
        supply = safe_int(army.get("supply", 80), 80)
        army["order"] = "regroup"
        army["target"] = None
        army["ai_focus"] = "director_recover"
        army["strength"] = min(125, strength + random.randint(6, 14))
        army["morale"] = min(120, morale + random.randint(9, 16))
        army["supply"] = min(120, supply + random.randint(15, 26))


_ai_goal_utilities_v22420 = _ai_goal_utilities

def _ai_goal_utilities(player: "Player") -> dict[str, int]:
    """Не даёт цели recover залипать навечно: пока идёт восстановление, армии
    не атакуют и не проигрывают, поэтому failure_rate из p1 сам себя не лечит.
    После enemy_ai_director_recover_min_turns подряд утилита recover гасится,
    и state-machine в _ai_select_goal естественно уходит на другую цель."""
    utilities = _ai_goal_utilities_v22420(player)
    director = ensure_ai_director_state(player)
    min_turns = safe_int(SETTINGS.get("enemy_ai_director_recover_min_turns", 3), 3, 1, 12)
    streak = safe_int(director.get("recover_streak", 0), 0)
    if streak >= min_turns:
        utilities["recover"] = max(0, int(utilities.get("recover", 0) * 0.30))
    return utilities


_enemy_ai_recon_and_orders_v22420 = enemy_ai_recon_and_orders

def enemy_ai_recon_and_orders(player: "Player"):
    """v2.24.20: подключает реальные приказы для hunt_legions/weaken_economy/
    raise_revolt/recover. До этого патча только break_frontier (p4) управлял
    армиями — три цели участвовали в utility-оценке, но не влияли на игру."""
    _enemy_ai_recon_and_orders_v22420(player)

    mem = ensure_ai_memory_state(player)
    council = safe_dict(mem.get("war_council")) or _ai_update_war_council_memory(player)
    goal = council.get("goal")

    director = ensure_ai_director_state(player)
    director["recover_streak"] = safe_int(director.get("recover_streak", 0), 0) + 1 if goal == "recover" else 0

    _ai_director_hunt_legions_hook(player, council)
    _ai_director_weaken_economy_hook(player, council)
    _ai_director_raise_revolt_hook(player, council)
    _ai_director_recover_hook(player, council)


_enemy_ai_campaign_start_v22420 = enemy_ai_campaign_start

def enemy_ai_campaign_start(player: "Player"):
    """v2.24.20: пока действует цель recover, армия не начинает новых крупных походов —
    иначе 'отступление' тут же перечёркивалось бы свежесобранной кампанией."""
    mem = ensure_ai_memory_state(player)
    council = safe_dict(mem.get("war_council"))
    if council.get("goal") == "recover":
        return
    _enemy_ai_campaign_start_v22420(player)


_enemy_ai_grand_strategy_tick_v22420 = enemy_ai_grand_strategy_tick

def enemy_ai_grand_strategy_tick(player: "Player"):
    """v2.24.20: добавляет резолюцию охоты на легионы поверх фронтовой модели v2.24."""
    _enemy_ai_grand_strategy_tick_v22420(player)
    _ai_director_hunt_legions_strike_event(player)


def _ai_director_goal_label(goal: str) -> str:
    return {
        "recover": "отвод войск и восстановление сил",
        "weaken_economy": "рейды по богатству и торговым узлам",
        "raise_revolt": "разжигание мятежа в неспокойных провинциях",
        "break_frontier": "продавливание фронтира",
        "hunt_legions": "охота на слабые легионы",
        "coalition": "сбор коалиции",
    }.get(str(goal), str(goal))


_show_enemy_ai_report_v22420 = show_enemy_ai_report

def show_enemy_ai_report(player: "Player"):
    """v2.24.20: расшифровывает текущую цель AI Director по-русски."""
    _show_enemy_ai_report_v22420(player)
    mem = ensure_ai_memory_state(player)
    council = safe_dict(mem.get("war_council"))
    goal = council.get("goal")
    if goal:
        rui_info(f"Режим AI Director: {_ai_director_goal_label(goal)}.", C.PURPLE)



