def ensure_turn_summary_state(player) -> list[str]:
    if not hasattr(player, "turn_summary") or not isinstance(player.turn_summary, list):
        player.turn_summary = []
    if not hasattr(player, "pending_interactions") or not isinstance(player.pending_interactions, list):
        player.pending_interactions = []
    return player.turn_summary


def turn_summary_add(player, text: str) -> None:
    ensure_turn_summary_state(player)
    if text:
        player.turn_summary.append(str(text))


def pending_interaction_add(player, item: dict) -> None:
    ensure_turn_summary_state(player)
    if isinstance(item, dict):
        player.pending_interactions.append(item)


def ensure_lost_city_state(player) -> None:
    ensure_city_campaigns(player)
    if not hasattr(player, "enemy_ai_lost_cities") or not isinstance(player.enemy_ai_lost_cities, dict):
        player.enemy_ai_lost_cities = {}


def ensure_siege_arsenal(player) -> dict:
    if not hasattr(player, "siege_arsenal") or not isinstance(player.siege_arsenal, dict):
        player.siege_arsenal = {}
    for key in SIEGE_ARSENAL:
        player.siege_arsenal[key] = safe_int(player.siege_arsenal.get(key, 0), 0, 0, 999)
    return player.siege_arsenal


def _lost_city_names(player, province_name: str) -> list[str]:
    ensure_lost_city_state(player)
    return safe_list(player.enemy_ai_lost_cities.get(province_name, []))


def _roman_city_roster_names(province_name: str) -> list[str]:
    roster = CITY_ROSTERS.get(province_name, [])
    if roster:
        return [str(row[0]) for row in roster if row]
    prov = province_by_name(province_name) or {}
    return [str(c.get("name")) for c in safe_list(prov.get("cities")) if isinstance(c, dict) and c.get("name")]


def _enemy_ai_forget_roman_city(player: "Player", province_name: str, city_name: str | None) -> None:
    """Удаляет город из римского контроля и синхронизирует реестр потерь."""
    if not province_name or not city_name:
        return
    ensure_lost_city_state(player)
    ensure_city_campaigns(player)

    all_names = _roman_city_roster_names(province_name)
    held = safe_list(player.city_campaigns.get(province_name, []))
    if not held and all_names:
        held = list(all_names)
    player.city_campaigns[province_name] = [c for c in held if c != city_name]

    lost = _lost_city_names(player, province_name)
    if city_name not in lost:
        lost.append(city_name)
    player.enemy_ai_lost_cities[province_name] = lost[-20:]


def enemy_ai_register_city_capture(player: "Player", province_name: str, city_name: str | None, *, source: str = "осада") -> bool:
    """Финальная логика v2.24.5: Roma может пасть, обычный город теряется без автоотрыва провинции."""
    ensure_rome_fall_state(player)
    ensure_lost_city_state(player)

    if not province_name:
        return False

    if province_name == "Latium":
        city_name = city_name or "Roma"
        if str(city_name).lower() in {"roma", "rome", "рим"}:
            player.rome_fallen = True
            player.enemy_ai_rome_pressure = 100
            player.unrest = 100
            player.morale = max(0, safe_int(getattr(player, "morale", 70), 70) - 45)
            player.senate_rep = 0
            player.people_rep = max(0, safe_int(getattr(player, "people_rep", 50), 50) - 35)
            player.provinces = [
                p for p in getattr(player, "provinces", [])
                if isinstance(p, dict) and p.get("name") != "Latium"
            ]
            player.governors.pop("Latium", None)
            player.city_campaigns.pop("Latium", None)
            player.enemy_ai_capital_siege = None
            player.enemy_ai_sieges = [
                s for s in safe_list(getattr(player, "enemy_ai_sieges", []))
                if not (isinstance(s, dict) and s.get("province") == "Latium")
            ]
            player.enemy_ai_lost_cities.setdefault("Latium", [])
            if "Roma" not in player.enemy_ai_lost_cities["Latium"]:
                player.enemy_ai_lost_cities["Latium"].append("Roma")
            turn_summary_add(player, "☠ Roma capta est: столица пала, республика гибнет")
            print(clr("\n  ☠ ROMA CAPTA EST: враг ворвался в столицу. Сенат разбегается, республика гибнет.", C.BOLD + C.RED))
            log_event(player, f"Roma пала после {source}: игра проиграна")
            return True
        return False

    target = next(
        (p for p in getattr(player, "provinces", [])
         if isinstance(p, dict) and p.get("name") == province_name),
        None,
    )
    if not target:
        return False

    city_name = city_name or province_name
    _enemy_ai_forget_roman_city(player, province_name, city_name)
    lost = _lost_city_names(player, province_name)
    if city_name not in lost:
        lost.append(city_name)
    player.enemy_ai_lost_cities[province_name] = lost[-20:]
    target["unrest"] = min(10, safe_int(target.get("unrest", 0), 0) + 1)

    total = max(1, _enemy_ai_total_cities(province_name))
    held = len(safe_list(player.city_campaigns.get(province_name, [])))
    msg = f"{province_name}: враг занял город {city_name}; провинция удержана Римом ({held}/{total} городов под контролем)"
    turn_summary_add(player, "⚠ " + msg)
    pending_interaction_add(player, {"type": "recapture_city", "province": province_name, "city": city_name})
    print(clr(f"  ⚠ {msg}.", C.GOLD))
    print(clr("  Сенат предлагает отбить город легионом после сводки хода.", C.CYAN))
    log_event(player, f"Враг занял {city_name} в {province_name}; доступен реванш легионом")
    return False

def _auto_auxilia_pick(player, context: str = "", enemy: dict | None = None) -> dict | None:
    """Выбирает не просто самый сильный, а наиболее подходящий к угрозе отряд."""
    units = [u for u in safe_list(getattr(player, "aux_units", [])) if isinstance(u, dict)]
    if not units:
        return None

    context_l = str(context or "").lower()
    enemy_l = " ".join(
        str((enemy or {}).get(key, "")).lower()
        for key in ("name", "unit_name", "type", "doctrine")
    )

    def score(unit: dict) -> int:
        value = aux_unit_power(unit)
        unit_type = str(unit.get("type", "")).lower()
        if "конниц" in unit_type and any(x in context_l + enemy_l for x in ("рейд", "набег", "кавалер", "конниц")):
            value += 16
        if any(x in unit_type for x in ("стрел", "луч", "пращ")) and any(x in enemy_l for x in ("пехот", "копей", "слон")):
            value += 11
        if any(x in unit_type for x in ("пехот", "тяж")) and any(x in context_l for x in ("осад", "штурм", "оборона")):
            value += 12
        if any(x in unit_type for x in ("развед", "лёгк")) and "засад" in context_l:
            value += 9
        value += safe_int(unit.get("morale", 70), 70) // 10
        return value

    return max(units, key=score)


def auxiliary_defense_battle(
    player,
    enemy: dict,
    context: str,
    province_name: str | None = None,
    army: dict | None = None,
    reward_glory: int = 10,
) -> bool | None:
    """v2.24.1: автобой ауксилии без вопросов, тактик и длинных прогнозов."""
    enemy = enemy or {}
    enemy_name = enemy.get("name") or enemy.get("unit_name") or (army or {}).get("unit_name") or "вражеская армия"
    unit = _auto_auxilia_pick(player, context=context, enemy=enemy)
    if unit is None:
        turn_summary_add(player, f"Ауксилия недоступна против угрозы: {context} ({enemy_name})")
        return None

    aux_raw_power = aux_unit_power(unit)
    type_bonus = 0
    if "конница" in unit.get("type", "") and context in ("рейд", "кампания", "варварский набег"):
        type_bonus += 3
    if "пехота" in unit.get("type", "") and context in ("осада", "штурм"):
        type_bonus += 2
    artillery_bonus = _siege_arsenal_bonus(player, context)
    aux_power = max(
        8,
        aux_raw_power // 4
        + safe_int(unit.get("morale", 70), 70) // 12
        + type_bonus
        + artillery_bonus
        + player.battle_tech_bonus() // 4,
    )
    enemy_power = _enemy_power_for_aux_defense(enemy, army=army)
    aux_total, aux_dice, enemy_total, enemy_dice, margin = table_3d6_duel_totals(aux_power, enemy_power)
    won = aux_total >= enemy_total
    battle_margin = aux_total - enemy_total
    auxiliary_unit_after_battle(player, unit, won, battle_margin)

    brief = (
        f"Ауксилия: {unit.get('name','отряд')} против {enemy_name} — "
        f"{'победа' if won else 'поражение'} ({aux_total}:{enemy_total}"
        f"; арсенал +{artillery_bonus})"
    )
    turn_summary_add(player, brief)

    if won:
        enemy_loss = random.randint(8, 18) + max(0, battle_margin) // 4 + artillery_bonus // 2
        if "варвар" in str(context).lower() or "набег" in str(context).lower():
            enemy_loss += artillery_bonus
        if army:
            army["strength"] = max(0, safe_int(army.get("strength", 25), 25) - enemy_loss)
            army["morale"] = max(0, safe_int(army.get("morale", 70), 70) - random.randint(8, 18) - artillery_bonus // 3)
            army["cooldown"] = 2
            if safe_int(army.get("strength", 0), 0) <= 6 or safe_int(army.get("morale", 0), 0) <= 5:
                try:
                    player.enemy_armies.remove(army)
                except (ValueError, AttributeError):
                    pass
        elif isinstance(enemy, dict) and enemy.get("army_ids"):
            enemy_ai_apply_army_losses(player, enemy, victory=True)
        glory_gain = reward_glory + max(0, battle_margin // 2)
        player.glory += glory_gain
        add_battlepass_xp(player, 6)
        log_event(player, f"Ауксилия автобоем отбила {context}: {unit.get('name', 'отряд')} против {enemy_name}")
        if province_name:
            try:
                _remember_failed_ai_target(player, province_name)
            except NameError:
                pass
        return True

    player.morale = max(10, safe_int(getattr(player, "morale", 70), 70) - random.randint(2, 5))
    if army:
        army["experience"] = min(160, safe_int(army.get("experience", 0), 0) + 4)
        army["morale"] = min(100, safe_int(army.get("morale", 70), 70) + random.randint(2, 6))
    elif isinstance(enemy, dict) and enemy.get("army_ids"):
        enemy_ai_apply_army_losses(player, enemy, victory=False)
    log_event(player, f"Ауксилия автобоем проиграла {context}: {unit.get('name', 'отряд')} против {enemy_name}")
    return False


def show_turn_summary(player) -> None:
    ensure_turn_summary_state(player)
    print(clr("\n  📜 СВОДКА ХОДА", C.BOLD + C.GOLD))
    print(hr())
    if player.turn_summary:
        for line in player.turn_summary[-18:]:
            print("  " + str(line))
    else:
        print(clr("  Существенных происшествий нет.", C.GRAY))


def _recapture_lost_city_with_legion(player, province_name: str, city_name: str) -> bool:
    ensure_lost_city_state(player)
    target = next((p for p in getattr(player, "provinces", []) if p.get("name") == province_name), None)
    if not target:
        print(clr("  Провинция уже не под прямым управлением Рима.", C.RED))
        return False
    if city_name not in _lost_city_names(player, province_name):
        print(clr("  Этот город уже не числится потерянным.", C.GRAY))
        return False
    if not getattr(player, "legions", []):
        print(clr("  Нет легионов для реванша.", C.RED))
        return False

    print(clr(f"\n  ⚔ Реванш: отбить {city_name} в {province_name}", C.BOLD + C.GOLD))
    for i, legion in enumerate(player.legions, 1):
        print(f"  {i}. {legion.name} — сила {legion.strength}, качество {legion.quality}, ОД {getattr(legion, 'action_points', max_legion_action_points())}")
    ch = read_choice(f"{clr('  Выберите легион (или Q): ', C.CYAN)}", [str(i) for i in range(1, len(player.legions) + 1)] + ["Q"])
    if ch == "Q":
        return False
    legion = player.legions[int(ch) - 1]
    city_stub = {"name": city_name, "type": "город", "difficulty": 4}
    can_attack, reason = can_legion_attack_city(legion, city_stub)
    if not can_attack:
        print(clr(f"  ✗ {reason}", C.RED))
        return False

    enemy = {
        "name": f"Оккупационный гарнизон {city_name}",
        "strength": 42 + safe_int(target.get("unrest", 0), 0) * 3,
        "region": province_name,
    }
    won = resolve_battle(player, legion, enemy)
    spend_legion_attack_action(legion, city_stub)
    if won:
        lost = [c for c in _lost_city_names(player, province_name) if c != city_name]
        player.enemy_ai_lost_cities[province_name] = lost
        held = safe_list(player.city_campaigns.get(province_name, []))
        if city_name not in held:
            held.append(city_name)
        player.city_campaigns[province_name] = held
        target["unrest"] = max(0, safe_int(target.get("unrest", 0), 0) - 1)
        print(clr(f"  ✓ {city_name} возвращён под власть Рима.", C.GREEN))
        log_event(player, f"Легион {legion.name} отбил {city_name} в {province_name}")
        return True
    print(clr(f"  ✗ Штурм {city_name} провалился.", C.RED))
    log_event(player, f"Легион {legion.name} не смог отбить {city_name} в {province_name}")
    return False


def process_pending_interactions(player) -> None:
    ensure_turn_summary_state(player)
    # Убираем дубли по одному и тому же городу.
    unique = []
    seen = set()
    for item in player.pending_interactions:
        if not isinstance(item, dict):
            continue
        key = (item.get("type"), item.get("province"), item.get("city"))
        if key not in seen:
            seen.add(key)
            unique.append(item)
    player.pending_interactions = []

    recaptures = [i for i in unique if i.get("type") == "recapture_city"]
    if not recaptures:
        return
    print(clr("\n  ⚔ ИНТЕРАКТИВНЫЕ РЕШЕНИЯ", C.BOLD + C.CYAN))
    for item in recaptures[:3]:
        prov = item.get("province")
        city = item.get("city")
        if not prov or not city:
            continue
        if read_choice(f"  Отбить {city} в {prov} легионом сейчас? (Y/N): ", ["Y", "N"]) == "Y":
            _recapture_lost_city_with_legion(player, prov, city)


_end_turn_v240_original = end_turn

def end_turn(player: Player):
    # v2.24.4: сначала последствия хода, затем сводка и интерактив,
    # и только после решений игрока — финальное сохранение.
    player.turn_summary = []
    player.pending_interactions = []

    _end_turn_v240_original(player)

    apply_siege_arsenal_upkeep(player)
    resource_economy_turn_tick(player)
    show_turn_summary(player)
    process_pending_interactions(player)
    process_resource_economy_interactions(player)
    player.turn_summary = []
    autosave_interval = max(1, safe_int(SETTINGS.get("autosave_interval", 5), 5))
    if player.turn % autosave_interval == 0:
        save_game(player, autosave=True)
    else:
        debug_log("Autosave skipped on turn %s (interval=%s)", player.turn, autosave_interval)


def _legacy_siege_arsenal_menu_basic(player) -> None:
    ensure_siege_arsenal(player)
    ensure_expansion_state(player)
    while True:
        rui_screen_start()
        rui_header("ОСАДНЫЙ АРСЕНАЛ", "🏗", C.GOLD)
        arsenal = ensure_siege_arsenal(player)
        rui_info(f"Мощь арсенала: {siege_arsenal_power(player)} | против варваров: {siege_arsenal_power(player, anti_barbarian=True)} | содержание: {_siege_arsenal_upkeep(player)} золота/ход", C.CYAN)
        for i, (key, spec) in enumerate(SIEGE_ARSENAL.items(), 1):
            have = arsenal.get(key, 0)
            print(f"  {i}. {spec['name']} — есть {have}; цена {spec['cost_gold']} зол., железо {spec['cost_iron']}, медь {spec['cost_copper']}; {spec['desc']}")
        print(f"  {clr('B', C.GOLD)} Обстрелять варварское племя")
        print(f"  {clr('Q', C.GOLD)} Назад")
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", [str(i) for i in range(1, len(SIEGE_ARSENAL)+1)] + ["B", "Q"])
        if ch == "Q":
            return
        if ch == "B":
            tribes = list(getattr(player, "barbarian_tribes", {}).items())
            if not tribes:
                print(clr("  Племён нет.", C.GRAY)); pause(); continue
            for i, (_key, t) in enumerate(tribes, 1):
                print(f"  {i}. {t['name']} — сила {t['strength']}, отношение {t['relation']}")
            ti = read_choice(f"{clr('  Цель (или Q): ', C.CYAN)}", [str(i) for i in range(1, len(tribes)+1)] + ["Q"])
            if ti != "Q":
                bombard_barbarian_tribe(player, tribes[int(ti)-1][0])
            pause(); continue
        key = list(SIEGE_ARSENAL.keys())[int(ch)-1]
        build_siege_engine(player, key)
        pause()


_barbarian_menu_v240_original = _legacy_barbarian_menu_core

def _legacy_barbarian_menu_v240(player):
    ensure_expansion_state(player)
    while True:
        rui_screen_start()
        rui_header("ВАРВАРСКИЕ ПЛЕМЕНА", "🪓", C.RED)
        for i, (key, t) in enumerate(player.barbarian_tribes.items(), 1):
            pact = clr(" [договор]", C.GREEN) if t.get("pact") else ""
            rel_color = C.GREEN if t["relation"] >= 60 else C.GOLD if t["relation"] >= 35 else C.RED
            print(f"  {i}. {clr(t['name'], C.CYAN)}{pact} — вождь {t['chief']}, сила {t['strength']}, отношение {clr(str(t['relation']), rel_color)}/100")
        rui_info(f"Осадный арсенал: мощь {siege_arsenal_power(player, anti_barbarian=True)} против варваров", C.GOLD)
        rui_menu([
            ("1-10", "Переговоры с племенем", "дары, договоры, наём", "🤝"),
            ("S", "Осадный арсенал", "пращи, баллисты, катапульты, башни", "🏗"),
            ("Q", "Назад", "", "🚪"),
        ])
        valid = [str(i) for i in range(1, len(player.barbarian_tribes)+1)] + ["S", "Q"]
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", valid)
        if ch == "Q":
            return
        if ch == "S":
            siege_arsenal_menu(player)
            continue
        # Для переговоров используем старое меню, чтобы не переписывать весь блок дипломатии.
        # Старое меню начнётся сначала; это не идеально, но сохраняет всю проверенную логику.
        # Быстрый выход вернёт игрока сюда.
        return _barbarian_menu_v240_original(player)


