_ARTILLERY_MIGRATION_FROM_OLD = {
    "slingers": "umbrian_slingers",
    "ballistae": "syrian_ballistae",
    "catapults": "alexandrian_catapults",
    "towers": "carthaginian_towers",
}


def _owned_province_names(player) -> set[str]:
    return {str(p.get("name")) for p in getattr(player, "provinces", []) if isinstance(p, dict)}


def ensure_artillery_state(player) -> dict:
    if not hasattr(player, "artillery_inventory") or not isinstance(player.artillery_inventory, dict):
        player.artillery_inventory = {}
    # Миграция старого абстрактного арсенала v2.24.1.
    old = getattr(player, "siege_arsenal", None)
    if isinstance(old, dict) and not getattr(player, "artillery_v242_migrated", False):
        for old_key, new_key in _ARTILLERY_MIGRATION_FROM_OLD.items():
            qty = safe_int(old.get(old_key, 0), 0, 0, 999)
            if qty:
                player.artillery_inventory[new_key] = safe_int(player.artillery_inventory.get(new_key, 0), 0) + qty
        player.artillery_v242_migrated = True
    for key in ARTILLERY_TYPES:
        player.artillery_inventory[key] = safe_int(player.artillery_inventory.get(key, 0), 0, 0, 999)
    if not hasattr(player, "artillery_supplies"):
        player.artillery_supplies = 0
    player.artillery_supplies = safe_int(getattr(player, "artillery_supplies", 0), 0, 0, 9999)
    if not hasattr(player, "artillery_prepared_bombardments") or not isinstance(player.artillery_prepared_bombardments, list):
        player.artillery_prepared_bombardments = []

    # Миграция старой системы "пролом + поддержка" в единый процентный урон.
    legacy_bombardments = [
        x for x in player.artillery_prepared_bombardments
        if isinstance(x, dict)
    ][-12:]
    if legacy_bombardments:
        for item in legacy_bombardments:
            province_name = str(item.get("province", ""))
            city_name = str(item.get("city", ""))
            if province_name and city_name:
                legacy_damage = max(
                    1,
                    min(
                        45,
                        safe_int(item.get("breach", 0), 0)
                        + safe_int(item.get("support", 0), 0) // 4,
                    ),
                )
                apply_city_siege_damage(player, province_name, city_name, legacy_damage)
        player.artillery_prepared_bombardments = []
    return player.artillery_inventory


def artillery_unlock_reason(player, spec: dict) -> tuple[bool, str]:
    owned = _owned_province_names(player)
    needed_provs = safe_list(spec.get("province", []))
    needed_techs = safe_list(spec.get("tech", []))
    has_province = not needed_provs or any(p in owned for p in needed_provs)
    has_tech = not needed_techs or any(t in getattr(player, "tech_researched", []) for t in needed_techs)
    if has_province and has_tech:
        return True, "доступно"
    parts = []
    if not has_province:
        parts.append("провинция: " + "/".join(needed_provs))
    if not has_tech:
        parts.append("технология: " + "/".join(needed_techs))
    return False, "; ".join(parts)


def artillery_role_power(player, role: str) -> int:
    inv = ensure_artillery_state(player)
    total = 0
    for key, qty in inv.items():
        spec = ARTILLERY_TYPES.get(key)
        if spec:
            total += safe_int(qty, 0) * safe_int(spec.get(role, 0), 0)
    return max(0, total)


def artillery_total_count(player) -> int:
    return sum(ensure_artillery_state(player).values())


def siege_arsenal_power(player, *, anti_barbarian: bool = False) -> int:
    return artillery_role_power(player, "anti_barbarian" if anti_barbarian else "siege")


def _siege_arsenal_bonus(player, context: str) -> int:
    ctx = str(context).lower()
    role = "anti_barbarian" if ("варвар" in ctx or "набег" in ctx or "рейд" in ctx) else "support"
    raw = artillery_role_power(player, role)
    # Бонус ощутимый, но не превращает любой бой в автопобеду.
    return min(36, raw // 9)


def _siege_arsenal_upkeep(player) -> int:
    inv = ensure_artillery_state(player)
    raw = sum(safe_int(qty, 0) * safe_int(ARTILLERY_TYPES[key].get("upkeep", 0), 0) for key, qty in inv.items() if key in ARTILLERY_TYPES)
    return game_price(player, raw, upkeep=True, market=True, minimum=0)


def apply_siege_arsenal_upkeep(player) -> int:
    ensure_artillery_state(player)
    cost = _siege_arsenal_upkeep(player)
    if cost > 0:
        player.gold = max(0, safe_int(getattr(player, "gold", 0), 0) - cost)
        turn_summary_add(player, f"Артиллерийские корпуса: содержание -{cost} золота")
        log_event(player, f"Содержание артиллерии: -{cost} золота")
    return cost


def buy_artillery_supplies(player, packs: int = 1) -> bool:
    ensure_artillery_state(player)
    packs = max(1, safe_int(packs, 1, 1, 99))
    gold_cost = game_price(player, 25 * packs, market=True)
    grain_cost = 15 * packs
    supplies = 10 * packs
    if player.gold < gold_cost:
        print(clr(f"  Нужно {gold_cost} золота.", C.RED)); return False
    if player.grain < grain_cost:
        print(clr(f"  Нужно {grain_cost} зерна для обозов.", C.RED)); return False
    player.gold -= gold_cost
    player.grain -= grain_cost
    player.artillery_supplies += supplies
    print(clr(f"  ✓ Боезапас пополнен: +{supplies} снабжения артиллерии.", C.GREEN))
    log_event(player, f"Пополнен артиллерийский боезапас: +{supplies}")
    return True


def _artillery_spend_supplies(player, amount: int) -> bool:
    ensure_artillery_state(player)
    amount = max(0, safe_int(amount, 0))
    if player.artillery_supplies < amount:
        print(clr(f"  Недостаточно артиллерийского снабжения: нужно {amount}, есть {player.artillery_supplies}.", C.RED))
        return False
    player.artillery_supplies -= amount
    return True


def _artillery_summary_lines(player) -> list[str]:
    inv = ensure_artillery_state(player)
    lines = []
    for key, spec in ARTILLERY_TYPES.items():
        qty = inv.get(key, 0)
        if qty:
            lines.append(f"{spec['name']} ×{qty}")
    return lines or ["нет машин"]


def artillery_prepare_bombardment(player) -> None:
    """Наносит выбранному городу процентный урон без возможности захвата."""
    ensure_artillery_state(player)
    ensure_city_siege_damage(player)
    power = artillery_role_power(player, "siege")
    if power <= 0:
        print(clr("  Нет осадной артиллерии.", C.RED))
        return

    valid_targets: list[tuple[dict, dict]] = []
    for prov in frontier_provinces(player):
        city = next_city_to_attack(player, prov)
        if city and city_siege_damage(player, prov["name"], city["name"]) < CITY_SIEGE_MAX_DAMAGE:
            valid_targets.append((prov, city))

    if not valid_targets:
        print(clr("  Нет городов, требующих обстрела.", C.GRAY))
        return

    print(clr("\n  🎯 Выберите город для артиллерийского обстрела:", C.BOLD + C.GOLD))
    valid = []
    for i, (prov, city) in enumerate(valid_targets, 1):
        done, total = city_campaign_progress(player, prov["name"])
        damage = city_siege_damage(player, prov["name"], city["name"])
        remaining = CITY_SIEGE_MAX_DAMAGE - damage
        print(
            f"  {i}. {prov['name']} — {city['name']} ({done}/{total}), "
            f"оборона {remaining}%, повреждение {damage}%, сложность {city.get('difficulty', 3)}/10"
        )
        valid.append(str(i))

    ch = read_choice(clr("  Цель (или Q): ", C.CYAN), valid + ["Q"])
    if ch == "Q":
        return

    prov, city = valid_targets[int(ch) - 1]
    supply_cost = max(4, min(35, power // 10 + safe_int(city.get("difficulty", 3), 3)))
    if not _artillery_spend_supplies(player, supply_cost):
        return

    rolled_damage = calculate_artillery_city_damage(player, city)
    actual, total_damage, remaining = apply_city_siege_damage(
        player, prov["name"], city["name"], rolled_damage
    )
    print(clr(
        f"  ☄ {city['name']}: артиллерия наносит {actual}% урона. "
        f"Повреждение {total_damage}%, оборона {remaining}%. Боезапас -{supply_cost}.",
        C.BOLD + C.GREEN,
    ))
    if total_damage >= CITY_SIEGE_MAX_DAMAGE:
        print(clr(
            "  Стены и оборонительные сооружения уничтожены, но город не занят: "
            "для захвата нужен успешный штурм легиона.",
            C.GOLD,
        ))
    log_event(
        player,
        f"Артиллерия обстреляла {city['name']} в {prov['name']}: "
        f"+{actual}% урона, всего {total_damage}%",
    )


_resolve_battle_v242_original = _legacy_resolve_battle_aux_gate_v225


def bombard_barbarian_tribe(player, tribe_key: str) -> None:
    ensure_artillery_state(player)
    tribe = getattr(player, "barbarian_tribes", {}).get(tribe_key)
    if not tribe:
        return
    power = artillery_role_power(player, "anti_barbarian")
    if power <= 0:
        print(clr("  Нет артиллерии против варваров. Купи пращников, скорпионы, баллисты или полиболы.", C.RED))
        return
    supply_cost = max(3, min(35, power // 10))
    if not _artillery_spend_supplies(player, supply_cost):
        return
    damage = max(2, min(35, power // 10 + random.randint(2, 8)))
    old = safe_int(tribe.get("strength", 0), 0)
    tribe["strength"] = max(0, old - damage)
    tribe["relation"] = max(0, safe_int(tribe.get("relation", 50), 50) - random.randint(10, 22))
    glory = damage * 3
    player.glory += glory
    print(clr(f"  ☄ Артиллерия накрыла лагерь: {tribe['name']} теряет силу -{damage}, слава +{glory}, боезапас -{supply_cost}.", C.BOLD + C.GREEN))
    if tribe["strength"] <= 0:
        tribe["relation"] = 0
        print(clr(f"  ☠ {tribe['name']} рассеяны. На этом фронтире станет тише.", C.RED))
    log_event(player, f"Артиллерийский удар по племени {tribe['name']}: сила -{damage}")


def artillery_barrage_all_tribes(player) -> None:
    ensure_artillery_state(player)
    tribes = [(k, t) for k, t in getattr(player, "barbarian_tribes", {}).items() if safe_int(t.get("strength", 0), 0) > 0]
    if not tribes:
        print(clr("  Активных племён нет.", C.GRAY)); return
    power = artillery_role_power(player, "anti_barbarian")
    if power <= 0:
        print(clr("  Нет артиллерии против варваров.", C.RED)); return
    supply_cost = max(12, min(80, power // 4))
    if not _artillery_spend_supplies(player, supply_cost):
        return
    print(clr("\n  ☄ ОБЩИЙ ОГНЕВОЙ НАЛЁТ ПО ФРОНТИРУ", C.BOLD + C.RED))
    total_damage = 0
    for key, tribe in tribes:
        damage = max(1, min(18, power // 24 + random.randint(1, 6)))
        tribe["strength"] = max(0, safe_int(tribe.get("strength", 0), 0) - damage)
        tribe["relation"] = max(0, safe_int(tribe.get("relation", 50), 50) - random.randint(4, 10))
        total_damage += damage
        print(f"  • {tribe['name']}: сила -{damage}, осталось {tribe['strength']}")
    glory = total_damage * 2
    player.glory += glory
    print(clr(f"  Итог: общий урон {total_damage}, слава +{glory}, боезапас -{supply_cost}.", C.GREEN))
    log_event(player, f"Общий артиллерийский налёт по фронтиру: суммарный урон {total_damage}")


def artillery_status_screen(player) -> None:
    ensure_artillery_state(player)
    rui_screen_start()
    rui_header("АРТИЛЛЕРИЙСКИЙ ШТАБ", "☄", C.GOLD)
    rui_info(f"Машины: {artillery_total_count(player)} | Боезапас: {player.artillery_supplies} | Содержание: {_siege_arsenal_upkeep(player)} золота/ход", C.CYAN)
    rui_info(f"Сила: осада {artillery_role_power(player,'siege')} | варвары {artillery_role_power(player,'anti_barbarian')} | поддержка {artillery_role_power(player,'support')}", C.GOLD)
    rows = []
    for key, spec in ARTILLERY_TYPES.items():
        qty = ensure_artillery_state(player).get(key, 0)
        if qty:
            rows.append((spec["name"], str(qty), ", ".join(spec.get("province", [])), spec["desc"]))
    if rows:
        rui_table("В строю", ["Корпус", "Кол-во", "Школа", "Назначение"], rows, color=C.GOLD)
    else:
        rui_info("Артиллерии пока нет.", C.GRAY)
    if getattr(player, "artillery_prepared_bombardments", []):
        rui_section("Подготовленные обстрелы", C.CYAN)
        for b in player.artillery_prepared_bombardments:
            print(f"  • {b.get('city')} / {b.get('province')}: пролом {b.get('breach')}, поддержка {b.get('support')}")
    pause()


def show_artillery_status(player) -> None:
    return artillery_status_screen(player)

def siege_arsenal_menu(player) -> None:
    ensure_artillery_state(player)
    ensure_expansion_state(player)
    while True:
        rui_screen_start()
        rui_header("АРТИЛЛЕРИЯ РИМА", "☄", C.GOLD, "провинциальные школы, боезапас, обстрелы и зачистка варваров")
        rui_info("В строю: " + "; ".join(_artillery_summary_lines(player)), C.CYAN)
        rui_info(f"Боезапас: {player.artillery_supplies} | Содержание: {_siege_arsenal_upkeep(player)} зол./ход | Осада {artillery_role_power(player,'siege')} | Варвары {artillery_role_power(player,'anti_barbarian')}", C.GOLD)
        rui_menu([
            ("1", "Купить артиллерию", "мастерские открываются провинциями и технологиями", "🏗"),
            ("2", "Подготовить штурм города", "ослабить следующий гарнизон перед легионом", "🎯"),
            ("3", "Обстрелять одно племя", "точечный удар по варварскому лагерю", "☄"),
            ("4", "Накрыть весь фронтир", "дорого, но бьёт сразу по всем племенам", "🔥"),
            ("5", "Состояние артиллерии", "корпуса, боезапас, подготовленные обстрелы", "📜"),
            ("Q", "Назад", "", "🚪"),
        ])
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", ["1","2","3","4","5","Q"])
        if ch == "Q":
            return
        if ch == "1":
            artillery_purchase_menu(player)
        elif ch == "2":
            artillery_prepare_bombardment(player); pause()
        elif ch == "3":
            tribes = list(getattr(player, "barbarian_tribes", {}).items())
            if not tribes:
                print(clr("  Племён нет.", C.GRAY)); pause(); continue
            for i, (_key, t) in enumerate(tribes, 1):
                print(f"  {i}. {t['name']} — сила {t['strength']}, отношение {t['relation']}")
            ti = read_choice(f"{clr('  Цель (или Q): ', C.CYAN)}", [str(i) for i in range(1, len(tribes)+1)] + ["Q"])
            if ti != "Q":
                bombard_barbarian_tribe(player, tribes[int(ti)-1][0])
            pause()
        elif ch == "4":
            artillery_barrage_all_tribes(player); pause()
        elif ch == "5":
            artillery_status_screen(player)


def build_siege_engine(player, key: str) -> bool:
    # Совместимость со старыми вызовами: если пришёл старый ключ, переводим в новую систему.
    new_key = _ARTILLERY_MIGRATION_FROM_OLD.get(key, key)
    return build_artillery(player, new_key, 1)


# v2.24.3: финальное меню варваров без каскадного отката в старые barbarian_menu.
# Старые версии выше оставлены только как исторические алиасы для совместимости,
# но пользовательский путь больше через них не проходит.

def barbarian_tribe_negotiation_menu(player, tribe_key: str) -> None:
    ensure_expansion_state(player)
    t = player.barbarian_tribes.get(tribe_key)
    if not t:
        return
    while True:
        rui_screen_start()
        rui_header(f"Переговоры: {t['name']}", "🪓", C.RED)
        rui_info(f"Вождь: {t['chief']}  Сила: {t['strength']}  Отношение: {t['relation']}/100")
        gift_cost = game_price(player, 35, market=True)
        hire_cost = game_price(player, 50, market=True)
        rui_menu([
            ("1", "Дары племени", f"{gift_cost} золота, +12 к отношениям", "🎁"),
            ("2", "Заключить договор", "отношение ≥60", "📜"),
            ("3", "Попросить помощь/дар", "отношение ≥70 или договор", "🤲"),
            ("4", "Нанять варварский отряд", f"{hire_cost} золота, отношение ≥45", "🪓"),
            ("Q", "Назад", "", "🚪"),
        ], title="Действия")
        act = read_choice(f"\n{clr('  Действие: ', C.CYAN)}", ["1", "2", "3", "4", "Q"])
        if act == "Q":
            return
        if act == "1":
            if player.gold >= gift_cost:
                player.gold -= gift_cost
                t["relation"] = min(100, safe_int(t.get("relation", 50), 50) + 12)
                print(clr("\n  Дары приняты. Отношения улучшились.", C.GREEN))
            else:
                print(clr("\n  Недостаточно золота.", C.RED))
        elif act == "2":
            if safe_int(t.get("relation", 0), 0) >= 60:
                t["pact"] = True
                player.senate_rep = max(0, safe_int(getattr(player, "senate_rep", 50), 50) - 2)
                print(clr("\n  Договор заключён. Сенаторы недовольны мягкостью к варварам (-2 Сенат).", C.GREEN))
                log_event(player, f"Договор с племенем {t['name']}")
            else:
                print(clr("\n  Племя не доверяет Риму.", C.RED))
        elif act == "3":
            if safe_int(t.get("relation", 0), 0) >= 70 or t.get("pact"):
                old_chance = SETTINGS.get("barbarian_gift_chance", 0.18)
                SETTINGS["barbarian_gift_chance"] = 1.0
                try:
                    maybe_barbarian_gifts(player)
                finally:
                    SETTINGS["barbarian_gift_chance"] = old_chance
                t["relation"] = max(0, safe_int(t.get("relation", 50), 50) - 15)
            else:
                print(clr("\n  Нужны лучшие отношения или договор.", C.RED))
        elif act == "4":
            if player.gold >= hire_cost and safe_int(t.get("relation", 0), 0) >= 45:
                player.gold -= hire_cost
                unit = random.choice(BARBARIAN_UNITS)
                add_aux_unit(player, unit, free=True)
                if unit["key"] not in player.unlocked_aux_units:
                    player.unlocked_aux_units.append(unit["key"])
                print(clr(f"\n  Нанят отряд: {unit['name']}.", C.GREEN))
                log_event(player, f"Нанят варварский отряд у {t['name']}: {unit['name']}")
            else:
                print(clr(f"\n  Нужно {hire_cost} золота и отношение ≥45.", C.RED))
        pause()


