# ─── v2.24.6: тревоги на любые заметные действия варваров/вражеских походов ──
# Идея: игрок сначала видит сводку, затем получает короткие интерактивные
# реакции на угрозы, а не просто читает летопись последствий.

_BARBARIC_ALERT_TERMS = (
    "варвар", "плем", "набег", "налёт", "налет", "кочев", "карательная рать",
    "вожд", "caledonia", "caledon", "germania", "gallia", "галл", "герман",
    "великий поход врагов", "вражеская кампания", "осадные лагеря", "поход врагов",
    "враг", "врагов", "вражеск",
)

_BARBARIC_ALERT_EXCLUDE = (
    "содержание", "добыча металлов", "технологическое величие", "осадный арсенал: содержание",
    "боезапас", "артиллерийские корпуса",
)


def _barbarian_alert_extract_tribe(player, text: str) -> tuple[str | None, dict | None]:
    tribes = getattr(player, "barbarian_tribes", {})
    if not isinstance(tribes, dict):
        return None, None
    low = str(text).lower()
    for key, tribe in tribes.items():
        if not isinstance(tribe, dict):
            continue
        names = [str(tribe.get("name", "")), str(tribe.get("chief", "")), str(key)]
        if any(name and name.lower() in low for name in names):
            return key, tribe
    return None, None


def _barbarian_alert_extract_province(player, text: str) -> str | None:
    low = str(text).lower()
    names = []
    for p in getattr(player, "provinces", []):
        if isinstance(p, dict) and p.get("name"):
            names.append(str(p.get("name")))
    for p in PROVINCES_DATA:
        if isinstance(p, dict) and p.get("name"):
            names.append(str(p.get("name")))
    for name in sorted(set(names), key=len, reverse=True):
        if name.lower() in low:
            return name
    return None


def _barbarian_alert_should_trigger(player, text: str) -> bool:
    low = str(text).lower()
    if not low.strip():
        return False
    if any(term in low for term in _BARBARIC_ALERT_EXCLUDE):
        return False
    if _barbarian_alert_extract_tribe(player, text)[0]:
        return True
    return any(term in low for term in _BARBARIC_ALERT_TERMS)


def barbarian_alert_add(player, text: str, *, severity: int = 1, source: str = "summary") -> None:
    ensure_turn_summary_state(player)
    turn = safe_int(getattr(player, "turn", 0), 0)
    if safe_int(getattr(player, "_barbarian_alert_turn", -1), -1) != turn:
        player._barbarian_alert_turn = turn
        player._barbarian_alert_seen = []
    seen = getattr(player, "_barbarian_alert_seen", [])
    if isinstance(seen, set):
        seen = list(seen)
    if not isinstance(seen, list):
        seen = []
    player._barbarian_alert_seen = seen
    key_tribe, tribe = _barbarian_alert_extract_tribe(player, text)
    province = _barbarian_alert_extract_province(player, text)
    code = (source, key_tribe or "?", province or "?", re.sub(r"\s+", " ", str(text).strip())[:96])
    if code in seen:
        return
    # Не превращаем конец хода в допрос Сената: максимум 5 тревог за ход.
    if len(seen) >= 5:
        return
    seen.append(code)
    pending_interaction_add(player, {
        "type": "barbarian_alert",
        "text": str(text),
        "tribe_key": key_tribe,
        "province": province,
        "severity": max(1, safe_int(severity, 1, 1, 5)),
        "source": source,
    })


_turn_summary_add_v245 = turn_summary_add

def turn_summary_add(player, text: str) -> None:
    _turn_summary_add_v245(player, text)
    try:
        if _barbarian_alert_should_trigger(player, str(text)):
            severity = 3 if any(x in str(text).lower() for x in ("latium", "roma", "осад", "великий поход")) else 1
            barbarian_alert_add(player, str(text), severity=severity)
    except Exception as exc:
        debug_log("barbarian alert trigger failed: %s", exc, exc_info=True, level=logging.WARNING)


def _barbarian_alert_apply_military(player, item: dict) -> None:
    cost_gold = game_price(player, 18 + 6 * safe_int(item.get("severity", 1), 1), market=True)
    cost_grain = 12 + 4 * safe_int(item.get("severity", 1), 1)
    if safe_int(getattr(player, "gold", 0), 0) < cost_gold or safe_int(getattr(player, "grain", 0), 0) < cost_grain:
        print(clr(f"  ✗ Нужны {cost_gold} золота и {cost_grain} зерна для тревожной мобилизации.", C.RED))
        return
    player.gold -= cost_gold
    player.grain -= cost_grain
    player.morale = min(100, safe_int(getattr(player, "morale", 70), 70) + 2)
    province_name = item.get("province")
    if province_name:
        province = next((p for p in getattr(player, "provinces", []) if isinstance(p, dict) and p.get("name") == province_name), None)
        if province:
            province["unrest"] = max(0, safe_int(province.get("unrest", 0), 0) - 1)
    if hasattr(player, "enemy_ai_rome_pressure"):
        player.enemy_ai_rome_pressure = max(0, safe_int(player.enemy_ai_rome_pressure, 0) - 3)
    print(clr("  ✓ Поднята тревожная мобилизация: гарнизоны усилены, мораль +2.", C.GREEN))
    log_event(player, "Рим ответил на варварскую тревогу военной мобилизацией")


def _barbarian_alert_apply_recon(player, item: dict) -> None:
    cost = game_price(player, 14 + 4 * safe_int(item.get("severity", 1), 1), market=True)
    if safe_int(getattr(player, "gold", 0), 0) < cost:
        print(clr(f"  ✗ Для разведчиков нужно {cost} золота.", C.RED))
        return
    player.gold -= cost
    if hasattr(player, "enemy_ai_pressure"):
        player.enemy_ai_pressure = max(0, safe_int(player.enemy_ai_pressure, 0) - 2)
    if hasattr(player, "enemy_ai_rome_pressure") and str(item.get("province", "")).lower() == "latium":
        player.enemy_ai_rome_pressure = max(0, safe_int(player.enemy_ai_rome_pressure, 0) - 5)
    print(clr("  ✓ Разведчики ушли к фронтиру: давление врага немного снижено.", C.GREEN))
    log_event(player, "Рим ответил на варварскую тревогу разведкой")


def _barbarian_alert_apply_diplomacy(player, item: dict) -> None:
    tribe_key = item.get("tribe_key")
    tribes = getattr(player, "barbarian_tribes", {})
    tribe = tribes.get(tribe_key) if isinstance(tribes, dict) else None
    if not isinstance(tribe, dict):
        print(clr("  ✗ Неясно, с каким племенем вести переговоры. Нужна разведка.", C.RED))
        return
    cost = game_price(player, 22 + 5 * safe_int(item.get("severity", 1), 1), market=True)
    if safe_int(getattr(player, "gold", 0), 0) < cost:
        print(clr(f"  ✗ Для посольства и даров нужно {cost} золота.", C.RED))
        return
    player.gold -= cost
    tribe["relation"] = min(100, safe_int(tribe.get("relation", 50), 50) + random.randint(4, 9))
    tribe["strength"] = max(0, safe_int(tribe.get("strength", 0), 0) - random.choice([0, 1]))
    print(clr(f"  ✓ Послы отправлены к {tribe.get('name', 'племени')}: отношения улучшены.", C.GREEN))
    log_event(player, f"Рим ответил на тревогу дипломатией: {tribe.get('name', tribe_key)}")



def _foreign_crisis_priority(crisis: dict) -> int:
    order = {
        "ultimatum": 6, "border": 5, "insult": 4, "aid": 3,
        "client": 3, "trade": 2, "gift": 1,
    }
    return order.get(str(crisis.get("kind", "")), 2)


def _process_pending_foreign_crises_after_turn(player) -> None:
    """Показывает один дипломатический кризис только после гражданской войны.

    Раньше событие могло вклиниться между заголовком мятежа и выбором легиона.
    Теперь международная канцелярия ждёт завершения внутренних и военных дел.
    Остальные кризисы сохраняются в очереди Consilium Externum.
    """
    ensure_external_policy_state(player)
    state = player.foreign_policy
    crises = [c for c in state.get("crises", []) if isinstance(c, dict)]
    if not crises:
        return

    turn = safe_int(getattr(player, "turn", 0), 0)
    # Просроченная нота не исчезает молча: дипломатические последствия
    # применяются до рассмотрения следующего дела.
    expired = [c for c in crises if turn > safe_int(c.get("expires_turn", turn + 1), turn + 1)]
    for crisis in expired:
        key = crisis.get("target")
        d = player.diplomacy.get(key, {})
        kind = crisis.get("kind")
        if kind in ("ultimatum", "border", "insult"):
            d["tension"] = min(100, safe_int(d.get("tension", 0), 0) + 12)
            d["trust"] = max(0, safe_int(d.get("trust", 50), 50) - 8)
        else:
            d["disposition"] = max(0, safe_int(d.get("disposition", 50), 50) - 5)
            d["trust"] = max(0, safe_int(d.get("trust", 50), 50) - 4)
        _foreign_dispatch(
            player,
            "Кризис оставлен без ответа",
            f"{d.get('name', key)} истолковала молчание Рима как отказ от переговоров.",
            key,
            "bad",
        )
        if crisis in state["crises"]:
            state["crises"].remove(crisis)

    crises = [c for c in state.get("crises", []) if isinstance(c, dict)]
    if not crises:
        return
    crises.sort(
        key=lambda c: (_foreign_crisis_priority(c), -safe_int(c.get("created_turn", turn), turn)),
        reverse=True,
    )
    crisis = crises[0]
    state["crises"].remove(crisis)

    rui_screen_start()
    rui_header("СОВЕТ ПОСЛЕ ХОДА", "🏛", C.GOLD)
    target = player.diplomacy.get(crisis.get("target"), {})
    rui_info(
        f"После завершения внутренних дел Сенат рассматривает ноту державы "
        f"{target.get('name', crisis.get('target', '?'))}.",
        C.CYAN,
    )
    if state.get("crises"):
        rui_info(f"В очереди останется ещё кризисов: {len(state['crises'])}.", C.GRAY)
    pause("Нажмите Enter, чтобы открыть заседание канцелярии...")
    _resolve_foreign_crisis(player, crisis)


_process_pending_interactions_v245 = process_pending_interactions

def process_pending_interactions(player) -> None:
    ensure_turn_summary_state(player)
    unique = []
    seen = set()
    for item in player.pending_interactions:
        if not isinstance(item, dict):
            continue
        key = (
            item.get("type"), item.get("province"), item.get("city"),
            item.get("tribe_key"), re.sub(r"\s+", " ", str(item.get("text", "")))[:96]
        )
        if key not in seen:
            seen.add(key)
            unique.append(item)
    player.pending_interactions = unique

    recaptures = [i for i in unique if i.get("type") == "recapture_city"]
    alerts = [i for i in unique if i.get("type") == "barbarian_alert"]

    # Сначала старый городской реванш, затем новая система тревог.
    if recaptures:
        print(clr("\n  ⚔ ИНТЕРАКТИВНЫЕ РЕШЕНИЯ", C.BOLD + C.CYAN))
        for item in recaptures[:3]:
            prov = item.get("province")
            city = item.get("city")
            if not prov or not city:
                continue
            if read_choice(f"  Отбить {city} в {prov} легионом сейчас? (Y/N): ", ["Y", "N"]) == "Y":
                _recapture_lost_city_with_legion(player, prov, city)

    # Международные события обрабатываются здесь, уже после завершения
    # гражданской войны и до отдельного Совета пограничных легатов.
    _process_pending_foreign_crises_after_turn(player)
    _process_barbarian_alerts(player, alerts)
    player.pending_interactions = []


_barbarian_ai_tick_v245 = barbarian_ai_tick

def barbarian_ai_tick(player: "Player"):
    # Чистим маркер текущего хода, чтобы тревоги не протекали между ходами.
    if hasattr(player, "_barbarian_alert_seen"):
        player._barbarian_alert_seen = []
    return _barbarian_ai_tick_v245(player)


