def _normalize_tech_quotes_v22410() -> None:
    for _key, _value in list(TECH_QUOTES.items()):
        if isinstance(_value, tuple) and len(_value) >= 2:
            TECH_QUOTES[_key] = {"quote": str(_value[0]), "author": str(_value[1])}
        elif isinstance(_value, dict):
            TECH_QUOTES[_key] = {
                "quote": str(_value.get("quote", "Sapientia vincit.")),
                "author": str(_value.get("author", "Римская сентенция")),
            }
        else:
            TECH_QUOTES[_key] = {"quote": str(_value), "author": "Римская сентенция"}


_normalize_tech_quotes_v22410()

