def format_tech_effects(effects: dict) -> str:
    """Расширенное отображение эффектов v2.24.9."""
    parts = []
    for key, value in (effects or {}).items():
        label = SCIENCE_EFFECT_LABELS.get(key, key)
        inverted = key in SCIENCE_INVERTED_EFFECTS
        if isinstance(value, float):
            pct = int(round(value * 100))
            if inverted:
                sign = "−" if pct > 0 else "+"
                parts.append(f"{label}: {sign}{abs(pct)}%")
            else:
                sign = "+" if pct > 0 else ""
                parts.append(f"{label}: {sign}{pct}%")
        else:
            if inverted:
                sign = "−" if value > 0 else "+"
                parts.append(f"{label}: {sign}{abs(value)}")
            else:
                sign = "+" if value > 0 else ""
                parts.append(f"{label}: {sign}{value}")
    return "; ".join(parts) if parts else "особый эффект"


def science_era_for_tech(key: str) -> int:
    meta = SCIENCE_TECH_META.get(key, {})
    if "era" in meta:
        return safe_int(meta.get("era"), 1, 1, 5)
    cost = safe_int(TECH_TREE.get(key, {}).get("cost", 0), 0)
    if cost <= 75:
        return 1
    if cost <= 120:
        return 2
    if cost <= 155:
        return 3
    if cost <= 180:
        return 4
    return 5


def science_branch_for_tech(key: str) -> str:
    meta = SCIENCE_TECH_META.get(key, {})
    if meta.get("branch"):
        return str(meta["branch"])
    tech = TECH_TREE.get(key, {})
    return TECH_CATEGORY_LABELS.get(tech.get("category"), tech.get("category", "Другое"))


def ensure_science_state(player):
    if player is None:
        return
    if not hasattr(player, "science_points"):
        player.science_points = 0
    player.science_points = safe_int(getattr(player, "science_points", 0), 0, 0, 999999)
    if not hasattr(player, "last_science_income"):
        player.last_science_income = 0
    player.last_science_income = safe_int(getattr(player, "last_science_income", 0), 0, 0, 99999)
    if not hasattr(player, "science_patronage_total"):
        player.science_patronage_total = 0
    player.science_patronage_total = safe_int(getattr(player, "science_patronage_total", 0), 0, 0, 999999)


def science_points_per_turn(player) -> int:
    """Доход науки с нормализованным учётом городских научно-культурных центров."""
    ensure_science_state(player)
    ensure_wonders_state(player)

    base = safe_int(SETTINGS.get("science_base_income", 8), 8)
    provinces = [p for p in safe_list(getattr(player, "provinces", [])) if isinstance(p, dict)]
    province_gain = len(provinces) * safe_int(SETTINGS.get("science_per_province", 1), 1)

    # Не считаем каждое совпавшее слово отдельным зданием: максимум один
    # городской научный бонус на провинцию, что сохраняет умеренный масштаб.
    city_gain = 0
    role_markers = {
        "library", "библиот", "школ", "архив", "academy", "академ",
        "культурный", "административный",
    }
    name_markers = {"library", "библиот", "школ", "архив", "academy", "академ", "forum", "форум"}
    for province in provinces:
        has_science_center = False
        for city in safe_list(province.get("cities")):
            if not isinstance(city, dict):
                continue
            city_type = " ".join(str(city.get("type", "")).lower().split())
            city_name = " ".join(str(city.get("name", "")).lower().split())
            if any(marker in city_type for marker in role_markers) or any(
                marker in city_name for marker in name_markers
            ):
                has_science_center = True
                break
        if has_science_center:
            city_gain += 1

    flat = tech_effect(player, "science_flat", 0)
    wonder_count = len(safe_list(getattr(player, "world_wonders_built", [])))
    wonder_synergy = wonder_count if tech_has(player, "monument_commissions") else 0
    percent = max(
        -0.5,
        tech_effect(player, "science_percent", 0)
        + tech_effect(player, "research_percent", 0),
    )
    raw = base + province_gain + city_gain + flat + wonder_synergy
    return max(1, int(round(raw * (1.0 + percent))))


_ensure_all_states_v2249 = ensure_all_states
def ensure_all_states(player):
    result = _ensure_all_states_v2249(player)
    ensure_science_state(player)
    return result


_Player_apply_turn_economics_v2249 = Player.apply_turn_economics
def _science_apply_turn_economics(self):
    msg = _Player_apply_turn_economics_v2249(self)
    ensure_science_state(self)
    gain = science_points_per_turn(self)
    self.science_points += gain
    self.last_science_income = gain
    if gain:
        try:
            turn_summary_add(self, f"Научные школы и архивы: +{gain} очков науки")
        except Exception as exc:
            debug_log("Science income turn summary failed: %s", exc, exc_info=True, level=logging.WARNING)
    return msg
Player.apply_turn_economics = _science_apply_turn_economics


def buy_science_points(player, gold_amount: int) -> int:
    ensure_science_state(player)
    min_gold = safe_int(SETTINGS.get("science_patronage_min_gold", 25), 25, 1)
    max_gold = safe_int(SETTINGS.get("science_patronage_max_gold", 500), 500, min_gold)
    gold_amount = safe_int(gold_amount, 0, 0, max_gold)
    if gold_amount < min_gold:
        print(clr(f"  Минимальная поддержка школ: {min_gold} золота.", C.RED))
        return 0
    if player.gold < gold_amount:
        print(clr(f"  В казне только {player.gold} золота.", C.RED))
        return 0
    ratio = float(SETTINGS.get("science_patronage_ratio", 1.0))
    bonus = max(0.0, tech_effect(player, "research_percent", 0))
    gained = max(1, int(round(gold_amount * ratio * (1.0 + bonus))))
    player.gold -= gold_amount
    player.science_points += gained
    player.science_patronage_total += gold_amount
    print(clr(f"  ✓ Меценатство: -{gold_amount} золота, +{gained} очков науки.", C.GREEN))
    log_event(player, f"Профинансированы школы и мастерские: +{gained} науки")
    return gained


def invest_research_amount(player: Player, amount: int):
    """Вкладывает очки науки в текущую технологию и очередь.

    Название функции сохранено ради совместимости со старым кодом, но ресурс
    теперь не золото, а science_points. Золото можно превратить в науку через
    меценатство в science_menu().
    """
    ensure_science_state(player)
    amount = safe_int(amount, 0, 0)
    if amount <= 0:
        return 0
    amount = min(amount, player.science_points)
    if amount <= 0:
        return 0
    spent = 0
    while amount > 0:
        if not player.researching:
            queue = getattr(player, "research_queue", [])
            while queue and not player.tech_available(queue[0]):
                queue.pop(0)
            if queue:
                player.researching = queue.pop(0)
                player.research_progress = 0
            else:
                break
        tech = TECH_TREE[player.researching]
        need = max(0, tech["cost"] - safe_int(getattr(player, "research_progress", 0), 0))
        if need <= 0:
            completed = player.researching
            complete_research(player, completed)
            continue
        research_mult = max(0.1, 1.0 + tech_effect(player, "research_percent", 0))
        step = min(amount, max(1, math.ceil(need / research_mult)))
        progress_gain = min(need, int(round(step * research_mult)))
        player.science_points -= step
        amount -= step
        spent += step
        player.research_progress += progress_gain
        if player.research_progress >= tech["cost"]:
            completed = player.researching
            complete_research(player, completed)
        else:
            break
    return spent


def science_unlock_summary_for_tech(key: str) -> list[str]:
    parts = []
    unit = TECH_UNLOCKED_AUX_UNITS.get(key)
    if unit:
        parts.append(f"отряд: {unit['name']}")
    arts = [spec["name"] for spec in ARTILLERY_TYPES.values() if key in safe_list(spec.get("tech", []))]
    if arts:
        preview = ", ".join(arts[:3]) + (f" и ещё {len(arts)-3}" if len(arts) > 3 else "")
        parts.append(f"артиллерия: {preview}")
    wonders = [w["name"] for w in WORLD_WONDERS if key in safe_list(w.get("tech", []))]
    if wonders:
        preview = ", ".join(wonders[:3]) + (f" и ещё {len(wonders)-3}" if len(wonders) > 3 else "")
        parts.append(f"чудеса: {preview}")
    effects = TECH_TREE.get(key, {}).get("effects", {})
    if effects.get("science_flat") or effects.get("research_percent"):
        parts.append("ускоряет дальнейшие исследования")
    if effects.get("wonder_discount"):
        parts.append("удешевляет чудеса света")
    if effects.get("artillery_discount") or effects.get("artillery_power_percent"):
        parts.append("усиливает артиллерийский корпус")
    return parts


_show_tech_completion_card_v2249 = show_tech_completion_card
