_add_aux_unit_v2249 = add_aux_unit
def add_aux_unit(player, unit_def: dict, free: bool = False) -> bool:
    """Новые технологии повышают качество нанимаемой ауксилии."""
    if unit_def and isinstance(unit_def, dict):
        bonus = safe_int(tech_effect(player, "aux_training_bonus", 0), 0, 0, 30)
        if bonus:
            unit_def = dict(unit_def)
            unit_def["strength"] = safe_int(unit_def.get("strength", 10), 10) + bonus
            unit_def["attack"] = safe_int(unit_def.get("attack", unit_def["strength"] // 3), unit_def["strength"] // 3) + max(1, bonus // 3)
            unit_def["description"] = (unit_def.get("description", "") + f" | техподготовка +{bonus} силы").strip()
    return _add_aux_unit_v2249(player, unit_def, free)


_artillery_unlock_reason_v2249 = artillery_unlock_reason
def artillery_unlock_reason(player, spec: dict) -> tuple[bool, str]:
    owned = _owned_province_names(player)
    needed_provs = safe_list(spec.get("province", []))
    needed_techs = safe_list(spec.get("tech", []))
    has_province = not needed_provs or any(p in owned for p in needed_provs)
    missing_techs = [t for t in needed_techs if t not in getattr(player, "tech_researched", [])]
    if has_province and not missing_techs:
        return True, "доступно"
    parts = []
    if not has_province:
        parts.append("провинция: " + "/".join(needed_provs))
    if missing_techs:
        parts.append("технология: " + ", ".join(TECH_TREE.get(t, {}).get("name", t) for t in missing_techs))
    return False, "; ".join(parts)


def artillery_effective_cost(player, key: str) -> int:
    spec = ARTILLERY_TYPES[key]
    discount = max(0.0, min(0.50, tech_effect(player, "artillery_discount", 0)))
    base = max(1, int(round(spec["cost_gold"] * (1.0 - discount))))
    return game_price(player, base, market=True)


def _artillery_can_pay(player, key: str, qty: int = 1) -> tuple[bool, str]:
    if key not in ARTILLERY_TYPES:
        return False, "неизвестная машина"
    spec = ARTILLERY_TYPES[key]
    unlocked, reason = artillery_unlock_reason(player, spec)
    if not unlocked:
        return False, "заблокировано: " + reason
    qty = max(1, safe_int(qty, 1))
    need_gold = artillery_effective_cost(player, key) * qty
    if safe_int(getattr(player, "gold", 0), 0) < need_gold:
        return False, f"нужно золото: {need_gold}"
    return True, "можно купить"


def build_artillery(player, key: str, qty: int = 1) -> bool:
    ensure_artillery_state(player)
    if key not in ARTILLERY_TYPES:
        print(clr("  Неизвестный тип артиллерии.", C.RED)); return False
    qty = max(1, safe_int(qty, 1, 1, 99))
    ok, reason = _artillery_can_pay(player, key, qty)
    if not ok:
        print(clr(f"  ✗ {reason}", C.RED)); return False
    spec = ARTILLERY_TYPES[key]
    cost = artillery_effective_cost(player, key)
    player.gold -= cost * qty
    player.artillery_inventory[key] += qty
    print(clr(f"  ✓ Куплено: {spec['name']} ×{qty} за {cost * qty} золота.", C.GREEN))
    log_event(player, f"Куплена артиллерия: {spec['name']} ×{qty}")
    return True


def _artillery_choose_quantity(player, key: str) -> int | None:
    cost = artillery_effective_cost(player, key)
    max_gold = safe_int(getattr(player, "gold", 0), 0) // max(1, cost)
    maximum = max(0, min(99, max_gold))
    if maximum <= 0:
        print(clr("  Золота не хватает даже на 1.", C.RED)); return None
    raw = input(clr(f"  Сколько купить? 1-{maximum}, A — максимум, Q — отмена: ", C.CYAN)).strip().upper()
    if raw == "Q":
        return None
    if raw == "A":
        return maximum
    try:
        qty = int(raw)
    except ValueError:
        print(clr("  Нужно число.", C.RED)); return None
    return max(1, min(maximum, qty))


_artillery_role_power_v2249 = artillery_role_power
def artillery_role_power(player, role: str) -> int:
    raw = _artillery_role_power_v2249(player, role)
    pct = max(0.0, min(1.0, tech_effect(player, "artillery_power_percent", 0)))
    return int(round(raw * (1.0 + pct)))


def artillery_purchase_menu(player) -> None:
    """Магазин артиллерии теперь завязан на технологии и провинции."""
    ensure_artillery_state(player)
    while True:
        rui_screen_start()
        rui_header("МАГАЗИН АРТИЛЛЕРИИ", "🏹", C.GOLD, "машины открываются исследованиями и провинциями")
        rui_info(f"Казна: {player.gold} золота • Боезапас: {player.artillery_supplies} • Орудий всего: {artillery_total_count(player)}", C.CYAN)
        rows = []
        keys = list(ARTILLERY_TYPES.keys())
        inv = ensure_artillery_state(player)
        for i, key in enumerate(keys, 1):
            spec = ARTILLERY_TYPES[key]
            have = inv.get(key, 0)
            unlocked, reason = artillery_unlock_reason(player, spec)
            cost = artillery_effective_cost(player, key)
            status = "можно" if unlocked and player.gold >= cost else ("дорого" if unlocked else "закрыто")
            rows.append((
                str(i), spec["name"], str(have), f"{cost} зол.",
                f"осада {spec['siege']} / варвары {spec['anti_barbarian']} / поддержка {spec['support']}",
                status if unlocked else reason,
            ))
        rui_table("Уникальные орудия", ["#", "Орудие", "Есть", "Цена", "Сила", "Доступ"], rows, color=C.GOLD)
        print(f"  {clr('S', C.GOLD)} Купить боезапас артиллерии")
        print(f"  {clr('I', C.GOLD)} Инвентарь и параметры")
        print(f"  {clr('Q', C.GOLD)} Назад")
        ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", [str(i) for i in range(1, len(keys)+1)] + ["S", "I", "Q"])
        if ch == "Q":
            return
        if ch == "S":
            raw = input(clr("  Сколько обозов боезапаса купить? 1-99, Q — отмена: ", C.CYAN)).strip().upper()
            if raw != "Q":
                buy_artillery_supplies(player, safe_int(raw, 1, 1, 99))
            pause(); continue
        if ch == "I":
            show_artillery_status(player)
            pause(); continue
        key = keys[int(ch)-1]
        spec = ARTILLERY_TYPES[key]
        print(clr(f"\n  {spec['name']}", C.BOLD + C.GOLD))
        ui_wrap(spec.get("desc", ""), color=C.GRAY)
        unlocked, reason = artillery_unlock_reason(player, spec)
        if not unlocked:
            print(clr(f"  Закрыто: {reason}", C.RED)); pause(); continue
        qty = _artillery_choose_quantity(player, key)
        if qty:
            build_artillery(player, key, qty)
        pause()


def wonder_unlock_reason(player, wonder: dict) -> tuple[bool, str]:
    needed = safe_list(wonder.get("tech", []))
    missing = [t for t in needed if t not in getattr(player, "tech_researched", [])]
    if not missing:
        return True, "доступно"
    return False, "технология: " + ", ".join(TECH_TREE.get(t, {}).get("name", t) for t in missing)


def wonder_effective_cost(player, wonder: dict) -> int:
    discount = max(0.0, min(0.45, tech_effect(player, "wonder_discount", 0)))
    base = max(1, int(round(safe_int(wonder.get("cost", 0), 0) * (1.0 - discount))))
    return game_price(player, base, market=True)


def show_world_wonders_menu(player: "Player"):
    ensure_wonders_state(player)
    while True:
        rui_screen_start()
        player.status_bar()
        rui_header("ЧУДЕСА СВЕТА", "🏗", C.GOLD, "великие стройки требуют научной и инженерной базы")
        built = set(player.world_wonders_built)
        unlocked_count = sum(1 for w in WORLD_WONDERS if wonder_unlock_reason(player, w)[0])
        rui_info(f"Построено: {len(built)}/{len(WORLD_WONDERS)} • Технологически доступно: {unlocked_count}/{len(WORLD_WONDERS)}", C.CYAN)
        rui_info("Введите номер чуда, чтобы посмотреть и купить. Q — назад.", C.GRAY)
        rows = []
        for i, wonder in enumerate(WORLD_WONDERS, 1):
            ok, reason = wonder_unlock_reason(player, wonder)
            if wonder["id"] in built:
                status = "✓ построено"
            elif ok:
                status = f"{wonder_effective_cost(player, wonder)} зол."
            else:
                status = "закрыто: " + reason
            rows.append((str(i), wonder["name"], status))
        rui_table("Чудеса и требования", ["#", "Чудо", "Статус"], rows, color=C.GOLD, show_header=True)
        raw = input(f"\n{clr('  Ваш выбор: ', C.CYAN)}").strip().upper()
        if raw == "Q":
            return
        try:
            idx = int(raw)
        except ValueError:
            print(clr("  Нужно ввести номер чуда или Q.", C.RED)); pause(); continue
        if idx < 1 or idx > len(WORLD_WONDERS):
            print(clr("  Такого чуда нет в списке.", C.RED)); pause(); continue
        wonder = WORLD_WONDERS[idx - 1]
        rui_screen_start()
        rui_header(wonder["name"], "🏗", C.GOLD)
        print(clr(WONDER_ASCII.get(wonder.get("art"), WONDER_ASCII["temple"]), C.GOLD))
        ui_wrap(wonder.get("quote", ""), indent="  ❝ ", subsequent="    ", color=C.CYAN)
        ok, reason = wonder_unlock_reason(player, wonder)
        cost = wonder_effective_cost(player, wonder)
        rui_info(f"Стоимость: {cost} золота" + (f" (база {wonder['cost']})" if cost != wonder['cost'] else ""), C.GOLD)
        rui_info(f"Бафф: {wonder.get('desc', wonder_effects_text(wonder.get('effects', {})))}", C.GREEN)
        if wonder["id"] in built:
            print(clr("\n  Это чудо уже построено.", C.GRAY)); pause(); continue
        if not ok:
            print(clr(f"\n  Чудо пока недоступно: {reason}.", C.RED)); pause(); continue
        ch = read_choice(f"\n{clr('  Построить это чудо? (Y/N): ', C.CYAN)}", ["Y", "N"])
        if ch == "N":
            continue
        if player.gold < cost:
            print(clr(f"\n  Недостаточно золота. Нужно {cost}, в казне {player.gold}.", C.RED)); pause(); continue
        player.gold -= cost
        player.world_wonders_built.append(wonder["id"])
        apply_wonder_instant_effects(player, wonder)
        log_event(player, f"Построено чудо света: {wonder['name']}")
        show_wonder_completion_screen(player, wonder)


def science_locked_tech_keys(player) -> list[str]:
    result = []
    researched = set(getattr(player, "tech_researched", []))
    queued = set(getattr(player, "research_queue", []))
    for key, tech in TECH_TREE.items():
        if key in researched or key in queued or key == getattr(player, "researching", None):
            continue
        prereq = safe_list(tech.get("prereq", []))
        if prereq and not all(p in researched for p in prereq):
            result.append(key)
    return result


def _science_progress_text(player) -> str:
    if not player.researching:
        return "Активного исследования нет."
    tech = TECH_TREE.get(player.researching, {})
    return f"В разработке: {tech.get('name', player.researching)} ({player.research_progress}/{tech.get('cost', 0)} науки)"


def science_menu(player: Player):
    ensure_science_state(player)
    if not hasattr(player, "research_queue") or not isinstance(player.research_queue, list):
        player.research_queue = []

    rui_screen_start()
    rui_header("НАУКА И СТРОИТЕЛЬСТВО", "📐", C.GREEN, "эпохи • очки науки • юниты • артиллерия • чудеса")
    rui_info(f"Очки науки: {player.science_points}  (+{science_points_per_turn(player)}/ход) • Исследовано: {len(player.tech_researched)}/{len(TECH_TREE)}", C.CYAN)
    rui_info(_science_progress_text(player), C.GOLD if player.researching else C.GRAY)
    if player.research_queue:
        queue_names = [TECH_TREE[k]["name"] for k in player.research_queue if k in TECH_TREE]
        rui_info("Очередь: " + " → ".join(queue_names), C.PURPLE)

    available_keys = available_tech_keys(player)
    if available_keys:
        rows = []
        for i, k in enumerate(available_keys):
            t = TECH_TREE[k]
            cat = t.get("category", "other")
            cat_label = TECH_CATEGORY_LABELS.get(cat, cat)
            era = SCIENCE_ERA_LABELS.get(science_era_for_tech(k), "Эпоха")
            unlocks = science_unlock_summary_for_tech(k)
            unlock_text = "; ".join(unlocks[:2]) if unlocks else "—"
            style = SCIENCE_CATEGORY_RICH.get(cat, "gold1")
            name = f"[{style}]{t['name']}[/]" if RICH_AVAILABLE else t["name"]
            rows.append((str(i + 1), name, str(t["cost"]), era.replace("I. ", "").replace("II. ", "").replace("III. ", "").replace("IV. ", "").replace("V. ", ""), cat_label, unlock_text))
        rui_table("Доступные технологии", ["#", "Технология", "Наука", "Эпоха", "Ветка", "Открывает"], rows, color=C.GOLD)
    else:
        rui_info("Все доступные технологии изучены или стоят в очереди.", C.GRAY)

    rui_menu([
        ("1-N", "Выбрать/сменить исследование", "начать тему из списка", "🔬"),
        ("I", "Вложить очки науки", "в текущее исследование и очередь", "📚"),
        ("F", "Завершить исследование", "если хватает науки", "✅"),
        ("P", "Меценатство", "обмен золота на очки науки", "💰"),
        ("A", "В очередь", "добавить технологию", "➕"),
        ("L", "Заблокированные", "посмотреть требования", "🔒"),
        ("C", "Очистить очередь", "", "🗑"),
        ("Q", "Назад", "", "🚪"),
    ], title="Действия")
    valid = [str(i + 1) for i in range(len(available_keys))] + ["I", "F", "P", "A", "L", "C", "Q"]
    ch = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", valid)

    if ch == "Q":
        return
    if ch.isdigit() and 1 <= int(ch) <= len(available_keys):
        key = available_keys[int(ch) - 1]
        if player.researching and player.researching != key:
            print(clr(f"\n  Сейчас изучается {TECH_TREE[player.researching]['name']}.", C.GOLD))
            confirm = read_choice(f"{clr('  Сменить тему и потерять текущий прогресс? (Y/N): ', C.CYAN)}", ["Y", "N"])
            if confirm != "Y":
                pause(); return
            player.research_progress = 0
        player.researching = key
        print(clr(f"\n  Начато исследование: {TECH_TREE[key]['name']}", C.GREEN))

    elif ch == "I":
        if not player.researching and not player.research_queue:
            print(clr("\n  Сначала выберите технологию или добавьте в очередь.", C.RED))
        else:
            amount = read_int(f"{clr('  Сколько очков науки вложить? 0 = всё доступное, Q = отмена: ', C.CYAN)}", 0, player.science_points)
            if amount is not None:
                if amount == 0:
                    amount = player.science_points
                spent = invest_research_amount(player, amount)
                if spent:
                    if player.researching:
                        t = TECH_TREE[player.researching]
                        print(clr(f"\n  Вложено {spent} науки. {t['name']}: {player.research_progress}/{t['cost']}.", C.GREEN))
                    else:
                        print(clr(f"\n  Вложено {spent} науки. Очередь выполнена или остановлена.", C.GREEN))
                else:
                    print(clr("\n  Нечего изучать или нет очков науки.", C.RED))

    elif ch == "F":
        if not player.researching:
            print(clr("\n  Нет активного исследования.", C.RED))
        else:
            t = TECH_TREE[player.researching]
            need = max(0, t["cost"] - player.research_progress)
            needed_points = max(1, math.ceil(need / max(0.1, 1.0 + tech_effect(player, "research_percent", 0))))
            if player.science_points >= needed_points:
                invest_research_amount(player, needed_points)
            else:
                print(clr(f"\n  Недостаточно науки. Нужно {needed_points}, есть {player.science_points}.", C.RED))

    elif ch == "P":
        max_gold = min(player.gold, safe_int(SETTINGS.get("science_patronage_max_gold", 500), 500))
        min_gold = safe_int(SETTINGS.get("science_patronage_min_gold", 25), 25, 1)
        prompt = clr(
            f"  Сколько золота отдать школам? {min_gold}-{max_gold}, Q = отмена: ",
            C.CYAN,
        )
        amount = read_int(prompt, 0, max_gold)
        if amount:
            buy_science_points(player, amount)

    elif ch == "A":
        if not available_keys:
            print(clr("\n  Нет доступных технологий для добавления в очередь.", C.GRAY))
        else:
            print(clr("\n  Что добавить в очередь?", C.GOLD))
            for i, k in enumerate(available_keys):
                print(f"  {i+1}. {TECH_TREE[k]['name']}")
            valid_add = [str(i + 1) for i in range(len(available_keys))] + ["Q"]
            pick = read_choice(f"{clr('  Технология: ', C.CYAN)}", valid_add)
            if pick != "Q":
                key = available_keys[int(pick) - 1]
                player.research_queue.append(key)
                print(clr(f"\n  В очередь добавлено: {TECH_TREE[key]['name']}", C.GREEN))

    elif ch == "L":
        locked = science_locked_tech_keys(player)
        if not locked:
            print(clr("\n  Нет заблокированных технологий: всё открыто или уже изучено.", C.GREEN))
        else:
            rows = []
            researched = set(getattr(player, "tech_researched", []))
            for k in locked[:30]:
                t = TECH_TREE[k]
                missing = [TECH_TREE[p]["name"] for p in safe_list(t.get("prereq", [])) if p not in researched and p in TECH_TREE]
                rows.append((t["name"], SCIENCE_ERA_LABELS.get(science_era_for_tech(k), ""), ", ".join(missing) or "—"))
            rui_table("Заблокированные технологии", ["Технология", "Эпоха", "Нужно изучить"], rows, color=C.PURPLE)

    elif ch == "C":
        player.research_queue.clear()
        print(clr("\n  Очередь исследований очищена.", C.GOLD))

    pause()


