def _owned_province_names_v25(player):
    return {p.get("name") for p in getattr(player, "provinces", []) if isinstance(p, dict)}

def _port_available_v25(player, port_id):
    req = PORTS_DATA.get(port_id, {}).get("province")
    return not req or req in _owned_province_names_v25(player)

def _new_squadron_v25(kind, number=1, name=None, xp=0, damage=0, zone="tyrrhenian"):
    data = FLEET_SQUADRON_TYPES[kind]
    return {"type":kind, "name":name or f"{data['name']} {number}", "xp":safe_int(xp,0,0), "damage":_v24_clamp(damage,0,0,100), "zone":zone if zone in SEA_ZONES else "tyrrhenian", "order":"reserve", "morale":70}

def default_mare_nostrum_fleet_v25():
    return {"squadrons":[], "flagships":[], "ships":[], "admiral":"Гай Дуилий", "naval_tradition":0, "pirate_threat":24, "sea_control":10, "captured_islands":[], "sea_zone_control":{z:0 for z in SEA_ZONES}, "zone_piracy":{z:d["base_pirates"] for z,d in SEA_ZONES.items()}, "zone_blockade":{z:0 for z in SEA_ZONES}, "zone_weather":{z:d.get("weather","calm") for z,d in SEA_ZONES.items()}, "ports":{}, "sea_routes":[], "convoy_readiness":35, "landing_preparations":{z:0 for z in SEA_ZONES}, "naval_intel":0, "last_naval_report":[]}

def _normalize_squadrons_v25(fleet):
    squadrons=[]
    for sq in safe_list(fleet.get("squadrons")):
        if not isinstance(sq, dict): continue
        kind = sq.get("type") if sq.get("type") in FLEET_SQUADRON_TYPES else LEGACY_FLAGSHIP_TO_SQUADRON.get(str(sq.get("type")))
        if kind not in FLEET_SQUADRON_TYPES: continue
        squadrons.append({"type":kind, "name":str(sq.get("name") or FLEET_SQUADRON_TYPES[kind]["name"]), "xp":safe_int(sq.get("xp",0),0,0), "damage":_v24_clamp(sq.get("damage",0),0,0,100), "zone":sq.get("zone") if sq.get("zone") in SEA_ZONES else "tyrrhenian", "order":sq.get("order") if sq.get("order") in NAVAL_ORDERS else "reserve", "morale":_v24_clamp(sq.get("morale",70),70,0,100)})
    if not squadrons:
        used={}
        for fs in safe_list(fleet.get("flagships")) + safe_list(fleet.get("ships")):
            if not isinstance(fs, dict): continue
            kind = LEGACY_FLAGSHIP_TO_SQUADRON.get(str(fs.get("type")))
            if kind not in FLEET_SQUADRON_TYPES: continue
            used[kind]=used.get(kind,0)+1
            squadrons.append(_new_squadron_v25(kind, used[kind], str(fs.get("name") or "") or None, fs.get("xp",0), fs.get("damage",0)))
    return squadrons

def ensure_v24_state(player):
    if not hasattr(player, "v24") or not isinstance(player.v24, dict): player.v24 = {}
    state = player.v24
    state["dynasty"] = _normalize_v24_dynasty(player, state)
    gentes = state.get("gentes") if isinstance(state.get("gentes"), dict) else {}
    for k,v in ROMAN_GENTES.items():
        row = gentes.get(k) if isinstance(gentes.get(k), dict) else v.copy(); row["name"]=v["name"]; row["loyalty"]=_v24_clamp(row.get("loyalty",v["loyalty"]),v["loyalty"],0,100); row["prestige"]=safe_int(row.get("prestige",v["prestige"]),v["prestige"],0); gentes[k]=row
    state["gentes"] = gentes
    parties = state.get("senate_parties") if isinstance(state.get("senate_parties"), dict) else {}
    for k,v in SENATE_PARTIES.items():
        row = parties.get(k) if isinstance(parties.get(k), dict) else v.copy(); row["name"]=v["name"]; row["influence"]=_v24_clamp(row.get("influence",v["influence"]),v["influence"],5,70); parties[k]=row
    state["senate_parties"] = parties
    state["trade_routes"] = [{"name":str(r.get("name") or ""), "value":safe_int(r.get("value",0),0,0), "active":bool(r.get("active",True))} for r in safe_list(state.get("trade_routes")) if isinstance(r, dict) and str(r.get("name") or "")]
    old = state.get("fleet") if isinstance(state.get("fleet"), dict) else {}
    base = default_mare_nostrum_fleet_v25(); base["squadrons"] = _normalize_squadrons_v25(old)
    for island in safe_list(old.get("captured_islands")):
        if island in ISLANDS_DATA and island not in base["captured_islands"]: base["captured_islands"].append(island)
    old_ctrl = old.get("sea_zone_control") if isinstance(old.get("sea_zone_control"), dict) else {}
    old_pir = old.get("zone_piracy") if isinstance(old.get("zone_piracy"), dict) else {}
    old_blk = old.get("zone_blockade") if isinstance(old.get("zone_blockade"), dict) else {}
    old_wth = old.get("zone_weather") if isinstance(old.get("zone_weather"), dict) else {}
    for z,d in SEA_ZONES.items():
        base["sea_zone_control"][z]=_v24_clamp(old_ctrl.get(z,0),0,0,100)
        base["zone_piracy"][z]=_v24_clamp(old_pir.get(z,d["base_pirates"]),d["base_pirates"],0,100)
        base["zone_blockade"][z]=_v24_clamp(old_blk.get(z,0),0,0,100)
        base["zone_weather"][z]=old_wth.get(z,d.get("weather","calm")) if old_wth.get(z,d.get("weather","calm")) in ("calm","windy","storm") else d.get("weather","calm")
    ports = old.get("ports") if isinstance(old.get("ports"), dict) else {}
    for pid in PORTS_DATA:
        if _port_available_v25(player, pid):
            p = ports.get(pid) if isinstance(ports.get(pid), dict) else {}
            base["ports"][pid]={"level":_v24_clamp(p.get("level",1),1,1,5), "damage":_v24_clamp(p.get("damage",0),0,0,100)}
    for rid in safe_list(old.get("sea_routes")):
        if rid in SEA_TRADE_ROUTES and rid not in base["sea_routes"]: base["sea_routes"].append(rid)
    for key in ("admiral","naval_tradition","pirate_threat","sea_control","convoy_readiness","naval_intel"):
        if key in old: base[key] = old[key]
    if isinstance(old.get("landing_preparations"), dict):
        for z in SEA_ZONES: base["landing_preparations"][z] = _v24_clamp(old["landing_preparations"].get(z,0),0,0,100)
    base["last_naval_report"] = safe_list(old.get("last_naval_report"))[-8:]
    old.clear(); old.update(base); state["fleet"] = old; state["resources"] = calculate_resources(player)

def _squadron_value_v25(sq, key):
    data=FLEET_SQUADRON_TYPES.get(sq.get("type"),{}); raw=safe_int(data.get(key,0),0); dmg=_v24_clamp(sq.get("damage",0),0,0,100); morale=_v24_clamp(sq.get("morale",70),70,0,100); xp=safe_int(sq.get("xp",0),0,0)
    return max(0, int(round((raw + (xp//2 if key in ("power","maneuver","marines","escort") else 0)) * max(0.15,(100-dmg)/100) * (0.75 + morale/250))))

def _squadrons_in_zone_v25(player, zone_id=None, order=None):
    fleet=player.v24["fleet"]; out=[]
    for sq in fleet.get("squadrons",[]):
        if zone_id and sq.get("zone") != zone_id: continue
        if order and sq.get("order") != order: continue
        if sq.get("damage",0) >= 100: continue
        out.append(sq)
    return out

def _port_projection_v25(player, zone_id):
    ensure_v24_state(player); power=0
    for pid,pdata in player.v24["fleet"].get("ports",{}).items():
        port=PORTS_DATA.get(pid)
        if port and port.get("zone") == zone_id:
            power += int(round(_v24_clamp(pdata.get("level",1),1,1,5)*6*max(0.3,(100-_v24_clamp(pdata.get("damage",0),0,0,100))/100)))
    return power

def v24_fleet_upkeep(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    raw=sum(safe_int(FLEET_SQUADRON_TYPES.get(sq.get("type"),{}).get("upkeep",0),0) for sq in fleet.get("squadrons",[]))
    raw += sum(max(0,_v24_clamp(p.get("level",1),1,1,5)-1)*3 for p in fleet.get("ports",{}).values())
    raw = max(0, raw - (4 if "naval_supply" in getattr(player,"tech_researched",[]) else 0))
    return game_price(player, raw, upkeep=True, market=True, minimum=0)

def v24_fleet_maneuver(player): ensure_v24_state(player); return sum(_squadron_value_v25(sq,"maneuver") for sq in player.v24["fleet"].get("squadrons",[]))
def v24_marine_power(player): ensure_v24_state(player); return sum(_squadron_value_v25(sq,"marines") for sq in player.v24["fleet"].get("squadrons",[]))
def v25_transport_capacity(player): ensure_v24_state(player); return sum(_squadron_value_v25(sq,"cargo") for sq in player.v24["fleet"].get("squadrons",[]))

def v24_home_sea_bonus(player, zone_id):
    ensure_v24_state(player); zone=SEA_ZONES.get(zone_id,{}); owned=_owned_province_names_v25(player)
    coastal=sum(1 for p in zone.get("provinces",[]) if p in owned)
    island=sum(ISLANDS_DATA[i]["wealth"] for i in player.v24["fleet"].get("captured_islands",[]) if ISLANDS_DATA.get(i,{}).get("zone")==zone_id)
    return coastal*4 + _port_projection_v25(player,zone_id) + island*2

def v24_sea_power(player, zone_id=None):
    ensure_v24_state(player); fleet=player.v24["fleet"]; sqs=_squadrons_in_zone_v25(player,zone_id) if zone_id else fleet.get("squadrons",[])
    power=sum(_squadron_value_v25(sq,"power") for sq in sqs) + fleet.get("naval_tradition",0)//4 + max(0,getattr(player,"morale",70)-50)//5
    if "world_wonder_effect" in globals(): power += safe_int(world_wonder_effect(player,"navy_power",0),0)*4
    if "tech_effect" in globals(): power += safe_int(tech_effect(player,"navy_power"),0)*4
    if "admiralty" in getattr(player,"tech_researched",[]): power += 6
    if "mare_nostrum" in getattr(player,"tech_researched",[]): power += 10
    if zone_id:
        power += fleet["sea_zone_control"].get(zone_id,0)//3 + v24_home_sea_bonus(player,zone_id)
        power -= fleet["zone_piracy"].get(zone_id,0)//8 + fleet["zone_blockade"].get(zone_id,0)//10
        weather=fleet["zone_weather"].get(zone_id,"calm"); power -= 2 if weather=="windy" else 6 if weather=="storm" else 0
    return max(0,int(power))

def v24_update_sea_control(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    for z,d in SEA_ZONES.items():
        cur=fleet["sea_zone_control"].get(z,0); target=max(0,min(100,15+v24_sea_power(player,z)//2+_port_projection_v25(player,z)-fleet["zone_piracy"].get(z,d["base_pirates"])//2-fleet["zone_blockade"].get(z,0)//3))
        cur += min(5,target-cur) if target>cur else -min(6,cur-target)
        fleet["sea_zone_control"][z]=max(0,min(100,cur))
    fleet["pirate_threat"] = max(0,min(100,sum(fleet["zone_piracy"].values())//max(1,len(SEA_ZONES))))
    fleet["sea_control"] = max(0,min(100,sum(fleet["sea_zone_control"].values())//max(1,len(SEA_ZONES)) + v24_fleet_maneuver(player)//10 + fleet.get("naval_tradition",0)//8))

def _route_available_v25(player, rid): return all(p in _owned_province_names_v25(player) for p in SEA_TRADE_ROUTES[rid].get("required",[]))

def _sea_route_factor_v25(player, rid):
    fleet=player.v24["fleet"]; route=SEA_TRADE_ROUTES[rid]
    controls=[fleet["sea_zone_control"].get(z,0) for z in route["zones"]]; pir=[fleet["zone_piracy"].get(z,SEA_ZONES[z]["base_pirates"]) for z in route["zones"]]; blk=[fleet["zone_blockade"].get(z,0) for z in route["zones"]]
    factor=0.35+sum(controls)/max(1,len(controls))/120+fleet.get("convoy_readiness",35)/260-sum(pir)/max(1,len(pir))/180-sum(blk)/max(1,len(blk))/160
    if "pirate_suppression" in getattr(player,"tech_researched",[]): factor += 0.08
    if "grain_fleet" in getattr(player,"tech_researched",[]): factor += 0.08
    return max(0.0,min(1.35,factor))

def v24_trade_income(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    income=sum(r.get("value",0) for r in player.v24.get("trade_routes",[]) if r.get("active",True))
    for rid in safe_list(fleet.get("sea_routes")):
        if rid in SEA_TRADE_ROUTES and _route_available_v25(player,rid): income += int(round(SEA_TRADE_ROUTES[rid]["gold"]*_sea_route_factor_v25(player,rid)))
    income += sum(ISLANDS_DATA[i]["wealth"]*3 for i in fleet.get("captured_islands",[]) if i in ISLANDS_DATA)
    return max(0,income)

def v25_sea_grain_income(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]; grain=0
    for rid in safe_list(fleet.get("sea_routes")):
        if rid in SEA_TRADE_ROUTES and _route_available_v25(player,rid): grain += int(round(SEA_TRADE_ROUTES[rid]["grain"]*_sea_route_factor_v25(player,rid)))
    grain += sum(_squadron_value_v25(sq,"cargo") for sq in fleet.get("squadrons",[]) if sq.get("order")=="convoy")//2
    return max(0,grain)

def v24_repair_flagship(player, idx):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    if idx<0 or idx>=len(fleet.get("squadrons",[])): return False,"Такой эскадры нет."
    sq=fleet["squadrons"][idx]; dmg=_v24_clamp(sq.get("damage",0),0,0,100)
    if dmg<=0: return False,"Эскадра не нуждается в ремонте."
    port_bonus=max([_v24_clamp(p.get("level",1),1,1,5) for p in fleet.get("ports",{}).values()] or [1])
    cost=game_price(player, max(12,int(round(dmg*(2.0-port_bonus*0.18)))), market=True)
    if player.gold<cost: return False,f"Недостаточно золота для ремонта: нужно {cost}."
    player.gold-=cost; sq["damage"]=0; sq["morale"]=min(100,sq.get("morale",70)+8); return True,f"{sq['name']} отремонтирована за {cost} золота."

def v24_damage_random_flagship(player, severity):
    ensure_v24_state(player); fleet=player.v24["fleet"]; cand=[sq for sq in fleet.get("squadrons",[]) if sq.get("damage",0)<100]
    if not cand: return "боеспособных эскадр не осталось"
    weights=[3 if sq.get("type") in ("grain_convoy","transport_classis","fleet_train") else 1 for sq in cand]
    sq=random.choices(cand,weights=weights,k=1)[0]; dmg=random.randint(max(4,severity//3),max(6,severity)); sq["damage"]=min(100,sq.get("damage",0)+dmg); sq["morale"]=max(0,sq.get("morale",70)-random.randint(3,10))
    if sq["damage"]>=100:
        name=sq.get("name","эскадра"); fleet["squadrons"].remove(sq); return f"{name} потеряна в море."
    return f"{sq.get('name','Эскадра')} получила {dmg}% повреждений."

def v24_naval_enemy_strength(player, zone_id, mission="pirates"):
    ensure_v24_state(player); fleet=player.v24["fleet"]; zone=SEA_ZONES[zone_id]; diff=player.diff().get("enemy_strength_mult",1.0); era=v24_naval_era_multiplier(player) if "v24_naval_era_multiplier" in globals() else 1.0
    base=zone["difficulty"]+fleet["zone_piracy"].get(zone_id,zone["base_pirates"])//2+fleet["zone_blockade"].get(zone_id,0)//2+zone["trade_value"]//5
    if mission=="pirates": base += fleet["zone_piracy"].get(zone_id,0)//2
    elif mission=="blockade": base += 12
    elif mission in ("landing","island"): base += 18
    if fleet.get("naval_intel",0)>=50: base -= 5
    return max(8,int(round(base*diff*era)))

def v24_naval_intro_lines(player, zone_id, roman, enemy, mission):
    fleet=player.v24["fleet"]; zone=SEA_ZONES[zone_id]; objective={"pirates":"Охота на пиратов","blockade":"Блокада побережья","landing":"Прикрытие десанта","island":"Островная экспедиция"}.get(mission,"Морская операция")
    return [NAVAL_BATTLE_ART, f"⚓ {objective}: {zone['name']}.", f"🧭 Погода: {fleet['zone_weather'].get(zone_id,'calm')}; пиратство: {fleet['zone_piracy'].get(zone_id,0)}; блокада: {fleet['zone_blockade'].get(zone_id,0)}.", f"📊 Контроль зоны: {fleet['sea_zone_control'].get(zone_id,0)}; порты дают +{_port_projection_v25(player,zone_id)}.", random.choice(NAVAL_PHASE_TEXTS), random.choice(NAVAL_PHASE_TEXTS), f"⚔ Римская сила: {roman} против вражеской силы: {enemy}."]

def v24_resolve_naval_battle(player, zone_id, mission="pirates"):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    if zone_id not in SEA_ZONES: return False,["Неизвестная морская зона."]
    local=_squadrons_in_zone_v25(player,zone_id)
    if not local: return False,["В этой зоне нет римских эскадр. Сначала отдайте приказ флоту."]
    roman=max(8,v24_sea_power(player,zone_id)//3)+v24_fleet_maneuver(player)//8+v24_marine_power(player)//12
    if mission=="pirates": roman += sum(_squadron_value_v25(sq,"maneuver") for sq in local if sq.get("order") in ("hunt_pirates","patrol"))//5
    if mission=="landing": roman += fleet["landing_preparations"].get(zone_id,0)//7
    if mission=="blockade": roman += sum(_squadron_value_v25(sq,"power") for sq in local if sq.get("order")=="blockade")//7
    enemy=max(10,v24_naval_enemy_strength(player,zone_id,mission)//3+8)
    rt,rd,et,ed,margin=table_3d6_duel_totals(roman,enemy); forecast=advanced_table_3d6_forecast(roman,enemy); lines=v24_naval_intro_lines(player,zone_id,rt,et,mission)
    lines.append(f"📐 Прогноз флота 3d6: {forecast['win_rate']*100:.0f}% победы, средняя разница {forecast['avg_margin']:+.1f}, риск катастрофы {forecast['catastrophe']*100:.0f}%.")
    lines.append(f"🎲 Рим: {format_3d6(rd)} ×3 + {roman} = {rt}; враг: {format_3d6(ed)} ×3 + {enemy} = {et}.")
    if rt>=et:
        gain=random.randint(8,16)+max(0,margin//8); fleet["sea_zone_control"][zone_id]=min(100,fleet["sea_zone_control"].get(zone_id,0)+gain); fleet["zone_piracy"][zone_id]=max(0,fleet["zone_piracy"].get(zone_id,0)-random.randint(10,22))
        if mission=="blockade": fleet["zone_blockade"][zone_id]=min(100,fleet["zone_blockade"].get(zone_id,0)+random.randint(8,18))
        if mission=="landing": fleet["landing_preparations"][zone_id]=min(100,fleet["landing_preparations"].get(zone_id,0)+random.randint(12,24))
        reward=random.randint(25,55)+SEA_ZONES[zone_id]["trade_value"]; player.gold+=reward; player.glory+=8+SEA_ZONES[zone_id]["difficulty"]//8; trad=random.randint(5,11); fleet["naval_tradition"]+=trad
        for sq in local: sq["xp"]=sq.get("xp",0)+1; sq["morale"]=min(100,sq.get("morale",70)+random.randint(1,4))
        if random.random() < (0.20 if margin>=18 else 0.42):
            dmg=v24_damage_random_flagship(player,14 if margin>=18 else 26)
            if dmg: lines.append("🔧 "+dmg)
        lines.append(f"🏆 Победа на море: +{reward} золота, +{trad} морской традиции, контроль зоны +{gain}."); lines.append("🌊 Торговые суда снова выходят в море; пираты уходят к дальним стоянкам."); log_event(player,f"Морская победа: {SEA_ZONES[zone_id]['name']}"); v24_update_sea_control(player); return True,lines
    fleet["zone_piracy"][zone_id]=min(100,fleet["zone_piracy"].get(zone_id,0)+random.randint(5,13)); fleet["sea_zone_control"][zone_id]=max(0,fleet["sea_zone_control"].get(zone_id,0)-random.randint(6,14)); dmg=v24_damage_random_flagship(player,30 if abs(margin)<=8 else 44)
    if dmg: lines.append("🔧 "+dmg)
    if abs(margin)<=8: fleet["naval_tradition"]+=2; lines.append("📜 Поражение было близким: +2 морской традиции.")
    lines.append("☠ Поражение: строй распался, торговые корабли ищут убежища в портах."); log_event(player,f"Флот потерпел поражение: {SEA_ZONES[zone_id]['name']}"); v24_update_sea_control(player); return False,lines

def v24_capture_island(player, island_id):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    if island_id not in ISLANDS_DATA: return False,["Такого острова нет."]
    island=ISLANDS_DATA[island_id]
    if island_id in fleet.get("captured_islands",[]): return False,["Этот остров уже под властью Рима."]
    victory,lines=v24_resolve_naval_battle(player,island["zone"],mission="island")
    if not victory: return False,lines+["🚫 Высадка сорвалась: море осталось за врагом."]
    ap=max(8,v24_marine_power(player)//3+v25_transport_capacity(player)//4)+fleet["sea_zone_control"].get(island["zone"],0)//8; dp=max(10,island["garrison"]//3+8); at,ad,dt,dd,margin=table_3d6_duel_totals(ap,dp)
    lines.append("🏝 Лодки с морской пехотой идут к берегу."); lines.append(f"⚔ Высадка: {format_3d6(ad)} ×3 + {ap} = {at} против {format_3d6(dd)} ×3 + {dp} = {dt}.")
    if at>=dt:
        fleet["captured_islands"].append(island_id); glory=25+island["wealth"]*5; gold=island["wealth"]*20; player.glory+=glory; player.gold+=gold; fleet["sea_zone_control"][island["zone"]]=min(100,fleet["sea_zone_control"].get(island["zone"],0)+8); lines.append(f"🏛 Остров {island['name']} взят: +{glory} славы, +{gold} золота, +8 контроля зоны."); log_event(player,f"Захвачен остров {island['name']}"); v24_update_sea_control(player); return True,lines
    dmg=v24_damage_random_flagship(player,24)
    if dmg: lines.append("🔧 "+dmg)
    lines.append("🛡 Гарнизон отбил высадку. Нужны транспорты, морская пехота и больший контроль моря."); return False,lines

def _weather_roll_v25(base):
    roll=random.random()
    if base=="storm": return "storm" if roll<0.42 else "windy" if roll<0.78 else "calm"
    if base=="windy": return "storm" if roll<0.18 else "windy" if roll<0.62 else "calm"
    return "storm" if roll<0.08 else "windy" if roll<0.30 else "calm"

def v25_enemy_naval_pressure(player, report):
    ensure_v24_state(player); fleet=player.v24["fleet"]; chance=0.10 if player.difficulty=="normal" else 0.22 if player.difficulty=="hardcore" else 0.30 if player.difficulty=="madness" else 0.06
    if random.random()>=chance: return
    choices=[z for z in SEA_ZONES if fleet["sea_zone_control"].get(z,0)<70]
    if not choices: return
    z=random.choice(choices); action=random.choice(["пиратская база","вражеская блокада","рейд на конвой"])
    if action=="пиратская база": fleet["zone_piracy"][z]=min(100,fleet["zone_piracy"].get(z,0)+random.randint(8,18)); report.append(f"В {SEA_ZONES[z]['name']} возникла новая пиратская база.")
    elif action=="вражеская блокада": fleet["zone_blockade"][z]=min(100,fleet["zone_blockade"].get(z,0)+random.randint(8,16)); report.append(f"Вражеский флот давит побережье: {SEA_ZONES[z]['name']}.")
    else: loss=random.randint(10,35); player.gold=max(0,player.gold-loss); fleet["convoy_readiness"]=max(0,fleet.get("convoy_readiness",35)-random.randint(8,18)); report.append(f"Рейд на конвой в зоне {SEA_ZONES[z]['name']}: -{loss} золота.")
    log_event(player,"Флот: "+report[-1])

def v25_resolve_squadron_orders(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]; report=[]
    for z,d in SEA_ZONES.items():
        fleet["zone_weather"][z]=_weather_roll_v25(d.get("weather","calm")); growth=random.randint(0,5)+(2 if player.difficulty=="hardcore" else 4 if player.difficulty=="madness" else 0); fleet["zone_piracy"][z]=min(100,fleet["zone_piracy"].get(z,d["base_pirates"])+growth); fleet["zone_blockade"][z]=max(0,fleet["zone_blockade"].get(z,0)-random.randint(0,4)); fleet["landing_preparations"][z]=max(0,fleet["landing_preparations"].get(z,0)-random.randint(0,3))
    for sq in fleet.get("squadrons",[]):
        if sq.get("damage",0)>=100: continue
        z=sq.get("zone") if sq.get("zone") in SEA_ZONES else "tyrrhenian"; order=sq.get("order") if sq.get("order") in NAVAL_ORDERS else "reserve"; weather=fleet["zone_weather"].get(z,"calm"); pen=3 if weather=="windy" else 8 if weather=="storm" else 0
        if order=="reserve" and sq.get("damage",0)>0: sq["damage"]=max(0,sq.get("damage",0)-random.randint(1,5))
        elif order=="refit": sq["damage"]=max(0,sq.get("damage",0)-random.randint(6,13)-_port_projection_v25(player,z)//12); sq["morale"]=min(100,sq.get("morale",70)+2)
        elif order=="patrol": gain=max(1,_squadron_value_v25(sq,"maneuver")//9-pen//3); fleet["sea_zone_control"][z]=min(100,fleet["sea_zone_control"].get(z,0)+gain); fleet["zone_piracy"][z]=max(0,fleet["zone_piracy"].get(z,0)-gain); sq["xp"] += 1 if random.random()<0.20 else 0
        elif order=="hunt_pirates":
            if random.random()<0.35:
                victory,lines=v24_resolve_naval_battle(player,z,"pirates"); report.append(("✓ " if victory else "✗ ")+f"{sq['name']}: "+lines[-1])
            else: fleet["zone_piracy"][z]=max(0,fleet["zone_piracy"].get(z,0)-max(3,_squadron_value_v25(sq,"maneuver")//6-pen))
        elif order=="convoy": escort=_squadron_value_v25(sq,"escort")+_squadron_value_v25(sq,"cargo"); fleet["convoy_readiness"]=min(100,fleet.get("convoy_readiness",35)+max(2,escort//10)); fleet["zone_piracy"][z]=max(0,fleet["zone_piracy"].get(z,0)-max(1,escort//18))
        elif order=="blockade": fleet["zone_blockade"][z]=min(100,fleet["zone_blockade"].get(z,0)+max(1,_squadron_value_v25(sq,"power")//8-pen//2))
        elif order=="escort_landing": fleet["landing_preparations"][z]=min(100,fleet["landing_preparations"].get(z,0)+max(2,(_squadron_value_v25(sq,"marines")+_squadron_value_v25(sq,"cargo"))//8-pen//2))
        if weather=="storm" and order not in ("reserve","refit") and random.random()<0.10: sq["damage"]=min(100,sq.get("damage",0)+random.randint(4,12)); report.append(f"Шторм повредил {sq['name']} в зоне {SEA_ZONES[z]['name']}.")
    fleet["convoy_readiness"]=max(0,min(100,fleet.get("convoy_readiness",35)-random.randint(0,4))); v25_enemy_naval_pressure(player,report); v24_update_sea_control(player); fleet["last_naval_report"]=report[-8:]; return report

def v24_tick_trade_and_fleet(player):
    ensure_v24_state(player); report=v25_resolve_squadron_orders(player); fleet=player.v24["fleet"]
    dangerous=[z for z in SEA_ZONES if fleet["sea_zone_control"].get(z,0)<25 and fleet["zone_piracy"].get(z,0)>55]
    if dangerous and random.random()<0.22: player.grain=max(0,player.grain-20); log_event(player,"Пираты нарушили морские поставки зерна")
    for line in report[-3:]: log_event(player,"Флот: "+line[:90])

def v24_end_turn_tick(player):
    ensure_v24_state(player); res_gold,res_grain=v24_resource_income(player); trade_gold=v24_trade_income(player); sea_grain=v25_sea_grain_income(player); fleet_cost=v24_fleet_upkeep(player)
    player.gold += res_gold+trade_gold-fleet_cost; player.grain += res_grain+sea_grain; v24_tick_senate(player); v24_tick_trade_and_fleet(player)
    if res_gold or res_grain or trade_gold or sea_grain or fleet_cost: log_event(player,f"Mare Nostrum: +{res_gold+trade_gold-fleet_cost} золота, +{res_grain+sea_grain} зерна")

def _print_lines_v25(lines, success=None):
    for line in lines:
        color=C.GREEN if success is True and any(x in str(line) for x in ("Победа","взят","+")) else C.RED if success is False and any(x in str(line) for x in ("Поражение","сорвал","отбил","☠")) else C.WHITE
        print(clr("  "+str(line), color))

def v25_buy_squadron_menu(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]; rui_screen_start(); rui_header("ВЕРФИ: ПОСТРОИТЬ ЭСКАДРУ","🏗",C.BLUE)
    keys=list(FLEET_SQUADRON_TYPES.keys()); owned=_owned_province_names_v25(player); rows=[]; valid=[]
    for i,k in enumerate(keys,1):
        d=FLEET_SQUADRON_TYPES[k]; req=d.get("requires_province"); ok=not req or req in owned; shown_cost=game_price(player,d["cost"],market=True); rows.append((str(i),d["name"],f"{shown_cost} зол.",f"бой {d['power']} / ман. {d['maneuver']} / груз {d['cargo']}","доступна" if ok else f"нужна {req}")); valid.append(str(i)) if ok else None
    rui_table("Эскадры",["#","Тип","Цена","Параметры","Статус"],rows,color=C.CYAN); pick=read_choice(f"\n{clr('  Ваш выбор: ',C.CYAN)}",valid+["Q"])
    if pick=="Q": return
    kind=keys[int(pick)-1]; d=FLEET_SQUADRON_TYPES[kind]; cost=game_price(player,d["cost"],market=True)
    if player.gold<cost: print(clr(f"  Недостаточно золота: нужно {cost}.",C.RED)); pause(); return
    player.gold-=cost; fleet["squadrons"].append(_new_squadron_v25(kind,len(fleet["squadrons"])+1)); v24_update_sea_control(player); log_event(player,f"Построена эскадра: {d['name']}"); print(clr(f"  На воду спущена эскадра: {d['name']} за {cost} золота.",C.GREEN)); pause()

def v25_orders_menu(player):
    ensure_v24_state(player); fleet=player.v24["fleet"]
    if not fleet.get("squadrons"): print(clr("  Нет эскадр.",C.RED)); pause(); return
    rui_screen_start(); rui_header("ПРИКАЗЫ ЭСКАДРАМ","📜",C.BLUE); rows=[]
    for i,sq in enumerate(fleet["squadrons"],1): rows.append((str(i),sq["name"],FLEET_SQUADRON_TYPES[sq["type"]]["name"],SEA_ZONES[sq.get("zone","tyrrhenian")]["name"],NAVAL_ORDERS.get(sq.get("order"),NAVAL_ORDERS["reserve"])["name"],f"повр. {sq.get('damage',0)}%"))
    rui_table("Эскадры",["#","Имя","Тип","Зона","Приказ","Сост."],rows,color=C.CYAN); pick=read_choice(f"\n{clr('  Эскадра: ',C.CYAN)}",[str(i) for i in range(1,len(fleet["squadrons"])+1)]+["Q"])
    if pick=="Q": return
    sq=fleet["squadrons"][int(pick)-1]; zones=list(SEA_ZONES.keys())
    for i,z in enumerate(zones,1): print(f"  {i}. {SEA_ZONES[z]['name']} — контроль {fleet['sea_zone_control'].get(z,0)}, пираты {fleet['zone_piracy'].get(z,0)}")
    zp=read_choice(f"\n{clr('  Зона: ',C.CYAN)}",[str(i) for i in range(1,len(zones)+1)]+["Q"])
