# ─── ПАТЧ v2.24.21: HARD AI DIRECTOR PRESSURE FIX ──────────────────────────
# Цели фикса после плейтеста Hard:
#   • ИИ больше не залипает в массовой вечной перегруппировке;
#   • цель recover лечит только реально слабые армии, а не весь фронт;
#   • если на Hard много боеспособных армий и нет активной осады — директор
#     принудительно превращает часть давления в осаду/удар;
#   • экран Вражеского штаба показывает причину режима и долю regroup.



def _ai_director_regroup_ratio(player: "Player") -> float:
    armies = [a for a in safe_list(getattr(player, "enemy_armies", [])) if isinstance(a, (dict, EnemyArmy))]
    if not armies:
        return 0.0
    regroup = sum(1 for a in armies if a.get("order") == "regroup" or a.get("ai_focus") == "director_recover")
    return regroup / max(1, len(armies))


def _ai_director_healthy_armies(player: "Player") -> list[dict]:
    armies = [a for a in safe_list(getattr(player, "enemy_armies", [])) if isinstance(a, (dict, EnemyArmy))]
    healthy = []
    for army in armies:
        if army.get("campaign_id"):
            continue
        if safe_int(army.get("cooldown", 0), 0) > 0:
            continue
        if safe_int(army.get("strength", 25), 25) >= 30 and safe_int(army.get("morale", 70), 70) >= 45 and safe_int(army.get("supply", 80), 80) >= 38:
            healthy.append(army)
    return sorted(healthy, key=enemy_army_battle_power, reverse=True)


def _ai_director_pressure_targets(player: "Player") -> list[dict]:
    fronts = []
    if "_v224_frontier_targets" in globals():
        try:
            fronts = _v224_frontier_targets(player, include_rome=False)
        except Exception:
            fronts = []
    if not fronts:
        fronts = [p for p in safe_list(getattr(player, "provinces", [])) if isinstance(p, dict) and p.get("name") != "Latium"]
    def score(prov: dict) -> int:
        name = prov.get("name")
        return (
            safe_int(prov.get("wealth", 0), 0) * 8
            + safe_int(prov.get("unrest", 0), 0) * 14
            + max(0, 65 - safe_int(prov.get("romanization", 50), 50)) // 2
            - safe_int(prov.get("garrison", 0), 0) * 10
            - int(_ai_recent_failure_rate(player, name) * 35)
        )
    return sorted(fronts, key=score, reverse=True)


def _ai_director_force_pressure_from_regroup(player: "Player", reason: str = "mass_regroup") -> int:
    """Снимает здоровые армии с regroup, соблюдая расстояние до фронта."""
    diff = getattr(player, "difficulty", "normal")
    if diff not in {"hard", "hardcore", "madness"}:
        return 0

    armies = _ai_director_healthy_armies(player)
    if len(armies) < 2:
        return 0
    ratio = _ai_director_regroup_ratio(player)
    active_sieges = len(safe_list(getattr(player, "enemy_ai_sieges", [])))
    if ratio < 0.50 and active_sieges > 0:
        return 0

    targets = _ai_director_pressure_targets(player)
    if not targets:
        return 0

    limit = 4 if diff in {"hardcore", "madness"} else 3
    changed = 0
    memory = ensure_ai_memory_state(player)
    for index, army in enumerate(armies[:limit]):
        target = targets[index % len(targets)].get("name")
        if not target:
            continue

        if _v224_army_can_siege_now(player, army, target):
            order = "siege" if index == 0 or active_sieges == 0 else ("strike" if index % 2 else "raid")
            army["order"] = order
            army["target"] = target
            army["ai_focus"] = "director_pressure_fix"
        else:
            _v224_move_army_towards(player, army, target)
            order = army.get("order", "recon")
            army["ai_focus"] = "director_pressure_march"

        memory.setdefault("last_orders", {})[army.get("id")] = {
            "order": order,
            "target": army.get("target"),
            "turn": getattr(player, "turn", 0),
            "score": 999,
            "focus": f"director_pressure_fix:{reason}",
        }
        changed += 1

    if changed:
        director = ensure_ai_director_state(player)
        director["last_pressure_fix"] = {
            "turn": getattr(player, "turn", 0),
            "changed": changed,
            "reason": reason,
            "regroup_ratio": round(ratio, 2),
        }
        log_event(player, f"AI Director: {changed} арм. сняты с перегруппировки ({reason})")
    return changed


_ai_goal_utilities_v22421 = _ai_goal_utilities

def _ai_goal_utilities(player: "Player") -> dict[str, int]:
    utilities = _ai_goal_utilities_v22421(player)
    ratio = _ai_director_regroup_ratio(player)
    armies = [
        a for a in safe_list(getattr(player, "enemy_armies", []))
        if isinstance(a, (dict, EnemyArmy))
    ]
    healthy_count = len(_ai_director_healthy_armies(player))
    active_sieges = len(safe_list(getattr(player, "enemy_ai_sieges", [])))
    director = ensure_ai_director_state(player)

    depleted_count = sum(
        1 for army in armies
        if safe_int(army.get("strength", 25), 25) < 24
        or safe_int(army.get("morale", 70), 70) < 38
        or safe_int(army.get("supply", 80), 80) < 32
    )

    if ratio >= 0.55 and healthy_count >= 2:
        # Recover не обнуляется, если значительная часть армии действительно истощена.
        recover_factor = 0.55 if depleted_count >= max(2, len(armies) // 3) else 0.25
        utilities["recover"] = max(8, int(utilities.get("recover", 0) * recover_factor))
        utilities["break_frontier"] = utilities.get("break_frontier", 0) + 35
        utilities["hunt_legions"] = utilities.get("hunt_legions", 0) + 18
        director["last_goal_reason"] = "здоровые армии выходят из regroup; истощённые сохраняют восстановление"

    if getattr(player, "difficulty", "normal") in {"hard", "hardcore", "madness"} and len(armies) >= 4 and active_sieges == 0:
        utilities["break_frontier"] = utilities.get("break_frontier", 0) + 28
        utilities["raise_revolt"] = utilities.get("raise_revolt", 0) + 10
        director["last_goal_reason"] = "нет активных осад при крупной армии; нужен фронтовой нажим"

    aux_count = len(safe_list(getattr(player, "aux_units", [])))
    if aux_count == 0 and len(armies) >= 3:
        utilities["hunt_legions"] = utilities.get("hunt_legions", 0) + 24
        utilities["break_frontier"] = utilities.get("break_frontier", 0) + 18
        if depleted_count < max(2, len(armies) // 3):
            utilities["recover"] = int(utilities.get("recover", 0) * 0.65)
        director["last_goal_reason"] = "ауксилия Рима выбита; окно для наступления"

    return utilities


_ai_director_recover_hook_v22421 = _ai_director_recover_hook

def _ai_director_recover_hook(player: "Player", council: dict) -> None:
    """Recover теперь лечит только слабые армии. Здоровые силы на Hard остаются в давлении."""
    if council.get("goal") != "recover":
        return

    director = ensure_ai_director_state(player)
    streak = safe_int(director.get("recover_streak", 0), 0)
    armies = [a for a in safe_list(getattr(player, "enemy_armies", [])) if isinstance(a, (dict, EnemyArmy)) and not a.get("campaign_id")]
    if not armies:
        return

    weak = []
    healthy = []
    for army in armies:
        strength = safe_int(army.get("strength", 25), 25)
        morale = safe_int(army.get("morale", 70), 70)
        supply = safe_int(army.get("supply", 80), 80)
        if strength < 42 or morale < 58 or supply < 55:
            weak.append(army)
        else:
            healthy.append(army)

    if streak == 1:
        print(clr("\n  🏳 ВРАГ ОТВОДИТ ИЗМОТАННЫЕ ЧАСТИ: слабые отряды восстанавливаются, боеспособные остаются у фронта.", C.BOLD + C.CYAN))
        log_event(player, "AI Director: частичное восстановление измотанных сил")

    max_recover = max(1, min(len(weak), max(2, len(armies) // 3)))
    for army in sorted(weak, key=enemy_army_battle_power)[:max_recover]:
        strength = safe_int(army.get("strength", 25), 25)
        morale = safe_int(army.get("morale", 70), 70)
        supply = safe_int(army.get("supply", 80), 80)
        army["order"] = "regroup"
        army["target"] = None
        army["ai_focus"] = "director_recover_limited"
        army["strength"] = min(125, strength + random.randint(6, 13))
        army["morale"] = min(120, morale + random.randint(8, 15))
        army["supply"] = min(120, supply + random.randint(14, 24))

    # Если восстановление затянулось или здоровых армий больше одной — часть армии снова давит.
    if healthy and (streak >= 2 or getattr(player, "difficulty", "normal") in {"hard", "hardcore", "madness"}):
        _ai_director_force_pressure_from_regroup(player, reason="limited_recover")


_enemy_ai_execute_operational_orders_v22421 = enemy_ai_execute_operational_orders

def enemy_ai_execute_operational_orders(player: "Player"):
    """Hard AI создаёт осады только с достижимой позиции, иначе марширует к фронту."""
    _enemy_ai_execute_operational_orders_v22421(player)
    diff = getattr(player, "difficulty", "normal")
    if diff not in {"hard", "hardcore", "madness"}:
        return

    active = safe_list(getattr(player, "enemy_ai_sieges", []))
    healthy = _ai_director_healthy_armies(player)
    targets = _ai_director_pressure_targets(player)
    if not healthy or not targets:
        return

    if len(active) == 0:
        army = healthy[0]
        target = targets[0].get("name")
        if target:
            if _v224_army_can_siege_now(player, army, target):
                army["order"] = "siege"
                army["target"] = target
                army["ai_focus"] = "director_forced_siege"
                enemy_ai_start_siege(player, target, army)
            else:
                _v224_move_army_towards(player, army, target)
                army["ai_focus"] = "director_forced_march"

    if len(active) < 2 and len(getattr(player, "provinces", [])) >= 5 and len(healthy) >= 3:
        active_names = {s.get("province") for s in active if isinstance(s, dict)}
        for army in healthy[1:]:
            target = next(
                (p.get("name") for p in targets if p.get("name") not in active_names),
                None,
            )
            if not target:
                break
            if _v224_army_can_siege_now(player, army, target):
                army["order"] = "siege"
                army["target"] = target
                army["ai_focus"] = "director_parallel_siege"
                enemy_ai_start_siege(player, target, army)
                break
            _v224_move_army_towards(player, army, target)
            army["ai_focus"] = "director_parallel_march"


_enemy_ai_grand_strategy_tick_v22421 = enemy_ai_grand_strategy_tick

def enemy_ai_grand_strategy_tick(player: "Player"):
    """После основного тика ломает залипание regroup и принудительно закрепляет давление."""
    _enemy_ai_grand_strategy_tick_v22421(player)
    changed = _ai_director_force_pressure_from_regroup(player, reason="post_tick_regroup_guard")
    if changed:
        enemy_ai_execute_operational_orders(player)


_show_enemy_ai_report_v22421 = show_enemy_ai_report

def show_enemy_ai_report(player: "Player"):
    _show_enemy_ai_report_v22421(player)
    director = ensure_ai_director_state(player)
    ratio = _ai_director_regroup_ratio(player)
    armies = len([a for a in safe_list(getattr(player, "enemy_armies", [])) if isinstance(a, (dict, EnemyArmy))])
