def main_menu(player: Player):
    """Главное меню Roma Aeterna: ало-золотой Textual со скриншота."""
    ensure_all_states(player)
    sections = _main_menu_sections_v2257()

    # Последняя страховка: кнопка летописи должна существовать даже тогда,
    # когда roma_annals.py отсутствует, повреждён или не смог установить свои
    # обёртки. Сам обработчик ниже покажет точную причину недоступности модуля.
    try:
        has_annals = any(
            getattr(item, "key", None) == "N"
            for section in sections
            for item in getattr(section, "items", ())
        )
        if not has_annals:
            for i, section in enumerate(sections):
                if getattr(section, "title", "") == "Кампания":
                    items = list(getattr(section, "items", ()))
                    items.append(MenuItem("N", "Летопись Империи", "события, причины и хроника", "📜"))
                    sections[i] = MenuSection(
                        getattr(section, "title", "Кампания"),
                        getattr(section, "icon", "⚔"),
                        getattr(section, "color", C.RED),
                        tuple(items),
                    )
                    break
    except Exception as _annals_menu_error:
        debug_log(
            "Annales menu fallback failed: %s",
            _annals_menu_error,
            exc_info=True,
            level=logging.WARNING,
        )

    # Textual-меню является полной drop-in заменой: возвращает те же приказы
    # ("1", "P", "Q" и т.д.), поэтому вся игровая логика ниже не меняется.
    if roma_textual_menu and getattr(roma_textual_menu, "TEXTUAL_AVAILABLE", False):
        choice = roma_textual_menu.run_textual_menu(
            player,
            sections,
            caller_globals=globals(),
        )
        if choice:
            return choice
        # None = Textual недоступен/упал. Продолжаем во встроенное меню.
        debug_log(
            "Imperial Textual menu returned None; import_error=%s; textual_available=%s",
            TEXTUAL_MENU_IMPORT_ERROR,
            bool(roma_textual_menu and getattr(roma_textual_menu, "TEXTUAL_AVAILABLE", False)),
            level=logging.WARNING,
        )

    clear()
    player.status_bar()
    ui_panel("ГЛАВНОЕ МЕНЮ", "☰", C.GOLD)
    render_classic_menu_sections(sections)
    return read_choice_secret(
        f"\n{clr('  ➤ Ваш приказ: ', C.CYAN)}",
        menu_valid_keys(sections),
        SECRET_UNLOCK_CODE,
        "CHEAT",
    )



# ─── LUA CONTENT MODS v2.26 ─────────────────────────────────────────────────
# Содержимое игры можно вынести в mods/core/*.lua. Python остаётся движком:
# он проверяет типы, запускает меню, сохраняет игру и применяет эффекты.
LUA_CONTENT_DIR = os.path.join(SCRIPT_DIR, "mods", "core")
LUA_CONTENT_FILES = {
    "PROVINCES_DATA": "provinces.lua",
    "RELIGION_CHOICES": "religions.lua",
    "TECH_TREE": "technologies.lua",
    "WORLD_WONDERS": "wonders.lua",
    "BATTLEPASS_REWARDS": "battlepass.lua",
}


def _lua_table_to_python(value, _depth: int = 0):
    """Рекурсивно переводит таблицы lupa в обычные dict/list Python."""
    if _depth > 20:
        return value
    if hasattr(value, "keys") and hasattr(value, "__getitem__"):
        keys = list(value.keys())
        if keys and all(isinstance(k, int) for k in keys) and sorted(keys) == list(range(1, len(keys) + 1)):
            return [_lua_table_to_python(value[i], _depth + 1) for i in range(1, len(keys) + 1)]
        return {k: _lua_table_to_python(value[k], _depth + 1) for k in keys}
    return value


def _load_lua_content_file(lua, filename: str):
    path = os.path.join(LUA_CONTENT_DIR, filename)
    if not os.path.exists(path):
        return None
    with open(path, "r", encoding="utf-8") as f:
        return _lua_table_to_python(lua.execute(f.read()))


def _restore_battlepass_apply_functions(lua_rewards: list) -> list:
    """Lua хранит текст/метаданные пасса, а Python оставляет безопасные apply-функции."""
    old_by_level = {safe_int(r.get("level"), i + 1): r for i, r in enumerate(BATTLEPASS_REWARDS) if isinstance(r, dict)}
    restored = []
    for i, item in enumerate(lua_rewards, 1):
        if not isinstance(item, dict):
            continue
        level = safe_int(item.get("level"), i, 1, 100)
        base = dict(old_by_level.get(level, {}))
        base.update(item)
        if "apply" not in base and level in old_by_level and "apply" in old_by_level[level]:
            base["apply"] = old_by_level[level]["apply"]
        restored.append(base)
    return restored if len(restored) == 100 else BATTLEPASS_REWARDS



def validate_runtime_content() -> list[str]:
    """Проверяет уникальность ID и связи динамически загруженных справочников."""
    errors: list[str] = []

    province_names = []
    for province in PROVINCES_DATA if isinstance(PROVINCES_DATA, list) else []:
        if not isinstance(province, dict) or not province.get("name"):
            errors.append("PROVINCES_DATA: провинция без имени/не объект")
            continue
        province_names.append(str(province["name"]))
    province_set = set(province_names)
    if len(province_names) != len(province_set):
        errors.append("PROVINCES_DATA: повторяющиеся имена провинций")
    for province in PROVINCES_DATA if isinstance(PROVINCES_DATA, list) else []:
        if isinstance(province, dict):
            for neighbor in safe_list(province.get("neighbors")):
                if neighbor not in province_set:
                    errors.append(f"{province.get('name')}: неизвестный сосед {neighbor!r}")

    if not isinstance(TECH_TREE, dict):
        errors.append("TECH_TREE должен быть словарём")
    else:
        for key, tech in TECH_TREE.items():
            if not isinstance(tech, dict):
                errors.append(f"Технология {key!r}: не объект")
                continue
            for prereq in safe_list(tech.get("prereq")):
                if prereq not in TECH_TREE:
                    errors.append(f"Технология {key!r}: неизвестная предпосылка {prereq!r}")

    wonder_ids: set[str] = set()
    if not isinstance(WORLD_WONDERS, list):
        errors.append("WORLD_WONDERS должен быть списком")
    else:
        for wonder in WORLD_WONDERS:
            if not isinstance(wonder, dict):
                errors.append("WORLD_WONDERS: несловарная запись")
                continue
            wonder_id = str(wonder.get("id", "")).strip()
            if not wonder_id:
                errors.append("WORLD_WONDERS: чудо без id")
            elif wonder_id in wonder_ids:
                errors.append(f"WORLD_WONDERS: повторяющийся id {wonder_id!r}")
            wonder_ids.add(wonder_id)

    levels: set[int] = set()
    if not isinstance(BATTLEPASS_REWARDS, list):
        errors.append("BATTLEPASS_REWARDS должен быть списком")
    else:
        for index, reward in enumerate(BATTLEPASS_REWARDS, 1):
            if not isinstance(reward, dict):
                errors.append(f"BATTLEPASS_REWARDS[{index}]: не объект")
                continue
            level = safe_int(reward.get("level"), index, 1, 10000)
            if level in levels:
                errors.append(f"BATTLEPASS_REWARDS: повторяющийся уровень {level}")
            levels.add(level)
            if not callable(reward.get("apply")):
                errors.append(f"BATTLEPASS_REWARDS {level}: apply не вызываем")

    return errors


def load_lua_content_mods(strict: bool = False) -> bool:
    """Загружает Lua-контент транзакционно; при ошибке возвращает встроенные данные."""
    global PROVINCES_DATA, RELIGION_CHOICES, TECH_TREE, WORLD_WONDERS, BATTLEPASS_REWARDS
    try:
        from lupa import LuaRuntime
    except Exception as exc:
        debug_log("Lua content skipped: lupa unavailable: %s", exc, level=logging.INFO)
        if strict:
            print(clr("  ⚠ lupa не найдена: использую встроенные данные Python.", C.RED))
        return False

    snapshot = (
        PROVINCES_DATA,
        RELIGION_CHOICES,
        TECH_TREE,
        WORLD_WONDERS,
        BATTLEPASS_REWARDS,
    )
    lua = LuaRuntime(unpack_returned_tuples=True)
    loaded_any = False
    try:
        provinces = _load_lua_content_file(lua, LUA_CONTENT_FILES["PROVINCES_DATA"])
        if isinstance(provinces, list) and provinces:
            PROVINCES_DATA = provinces
            loaded_any = True

        religions = _load_lua_content_file(lua, LUA_CONTENT_FILES["RELIGION_CHOICES"])
        if isinstance(religions, dict) and religions:
            RELIGION_CHOICES = religions
            loaded_any = True

        tech = _load_lua_content_file(lua, LUA_CONTENT_FILES["TECH_TREE"])
        if isinstance(tech, dict) and tech:
            TECH_TREE = tech
            loaded_any = True

        wonders = _load_lua_content_file(lua, LUA_CONTENT_FILES["WORLD_WONDERS"])
        if isinstance(wonders, list) and wonders:
            WORLD_WONDERS = wonders
            loaded_any = True

        battlepass = _load_lua_content_file(lua, LUA_CONTENT_FILES["BATTLEPASS_REWARDS"])
        if isinstance(battlepass, list) and battlepass:
            BATTLEPASS_REWARDS = _restore_battlepass_apply_functions(battlepass)
            loaded_any = True

        errors = validate_runtime_content()
        if errors:
            raise ValueError("; ".join(errors[:8]))
    except Exception as exc:
        (
            PROVINCES_DATA,
            RELIGION_CHOICES,
            TECH_TREE,
            WORLD_WONDERS,
            BATTLEPASS_REWARDS,
        ) = snapshot
        debug_log("Lua content load failed and rolled back: %s", exc, exc_info=True, level=logging.WARNING)
        if strict:
            print(clr(
                f"  ⚠ Lua-контент отклонён ({type(exc).__name__}: {exc}). Использую встроенные данные.",
                C.RED,
            ))
        return False

    if loaded_any:
        debug_log("Lua content loaded and validated from %s", LUA_CONTENT_DIR, level=logging.INFO)
    return loaded_any


# ─── RUNTIME GUARD v2.29.4 ──────────────────────────────────────────────────
# Локальный монитор ошибок для Termux/Pydroid. Он не отправляет данные наружу:
# traceback сохраняется рядом с игрой в roma_crash.log.

CRASH_LOG_FILE = os.path.join(SCRIPT_DIR, "roma_crash.log")
_RUNTIME_MONITOR_INSTALLED = False


def _player_bug_snapshot(player) -> dict:
    """Короткий безопасный снимок партии для журнала падений."""
    if player is None:
        return {}
    return {
        "name": str(getattr(player, "name", "")),
        "turn": safe_int(getattr(player, "turn", 0), 0),
        "year": safe_int(getattr(player, "year", 0), 0),
        "gold": safe_int(getattr(player, "gold", 0), 0),
        "grain": safe_int(getattr(player, "grain", 0), 0),
        "glory": safe_int(getattr(player, "glory", 0), 0),
        "difficulty": str(getattr(player, "difficulty", "")),
        "provinces": len(safe_list(getattr(player, "provinces", []))),
        "legions": len(safe_list(getattr(player, "legions", []))),
    }


def write_runtime_bug_report(exc, *, context: str = "runtime", player=None, tb=None) -> str:
    """Записывает полную ошибку в roma_crash.log и возвращает путь к журналу."""
    try:
        exc_type = type(exc)
        trace_text = "".join(
            traceback.format_exception(exc_type, exc, tb or exc.__traceback__)
        )
        record = {
            "time": time.strftime("%Y-%m-%d %H:%M:%S"),
            "version": GAME_VERSION,
            "context": context,
            "python": sys.version.replace("\n", " "),
            "platform": platform.platform(),
            "exception": f"{exc_type.__name__}: {exc}",
            "player": _player_bug_snapshot(player),
        }
        with open(CRASH_LOG_FILE, "a", encoding="utf-8") as f:
            f.write("\n" + "=" * 78 + "\n")
            f.write(json.dumps(record, ensure_ascii=False, indent=2))
            f.write("\n\n")
            f.write(trace_text)
            f.write("\n")
        debug_log(
            "Runtime bug captured (%s): %s",
            context,
            record["exception"],
            level=logging.ERROR,
        )
    except Exception as report_exc:
        # Сам журнал не должен стать причиной нового падения.
        try:
            sys.stderr.write(f"ROMA AETERNA crash logger failed: {report_exc}\n")
        except Exception:
            pass
    return CRASH_LOG_FILE


def install_runtime_bug_monitor() -> None:
    """Подключает журналирование всех необработанных исключений."""
    global _RUNTIME_MONITOR_INSTALLED
    if _RUNTIME_MONITOR_INSTALLED:
        return

    previous_hook = sys.excepthook

    def _hook(exc_type, exc_value, exc_tb):
        if issubclass(exc_type, KeyboardInterrupt):
            previous_hook(exc_type, exc_value, exc_tb)
            return
        write_runtime_bug_report(
            exc_value,
            context="uncaught",
            player=None,
            tb=exc_tb,
        )
        previous_hook(exc_type, exc_value, exc_tb)

    sys.excepthook = _hook
    _RUNTIME_MONITOR_INSTALLED = True


def repair_player_runtime_state(player) -> list[str]:
    """Мягко чинит типовые повреждения сейва/состояния, не меняя баланс партии."""
    repairs: list[str] = []
    if player is None:
        return repairs

    legions = getattr(player, "legions", [])
    if not isinstance(legions, list):
        player.legions = []
        legions = player.legions
        repairs.append("legions: сброшено повреждённое значение")

    for index, legion in enumerate(legions):
        general = getattr(legion, "general", None)

        if isinstance(general, dict):
            legion.general = General.from_dict(general)
            general = legion.general
            repairs.append(f"legion[{index}].general: восстановлен из словаря")
        elif not isinstance(general, General):
            legion.general = General()
            general = legion.general
            repairs.append(f"legion[{index}].general: создан заново")

        if getattr(general, "talent_key", None) not in ALL_TALENTS:
            old = getattr(general, "talent_key", None)
            general.talent_key = "tactician" if "tactician" in ALL_TALENTS else next(iter(ALL_TALENTS))
            repairs.append(
                f"legion[{index}].general.talent_key: {old!r} → {general.talent_key!r}"
            )

        general.loyalty = safe_int(
            getattr(general, "loyalty", SETTINGS.get("general_loyalty_start", 70)),
            SETTINGS.get("general_loyalty_start", 70),
            0,
            100,
        )
        legion.quality = safe_int(getattr(legion, "quality", 3), 3, 1, 10)
        legion.strength = safe_int(
            getattr(legion, "strength", legion.quality * 10),
            legion.quality * 10,
            1,
            100,
        )
        legion.morale = safe_int(getattr(legion, "morale", 80), 80, 0, 100)
        legion.fatigue = safe_int(getattr(legion, "fatigue", 0), 0, 0, 100)
        legion.action_points = safe_int(
            getattr(legion, "action_points", SETTINGS.get("legion_action_points_per_turn", 5)),
            SETTINGS.get("legion_action_points_per_turn", 5),
            0,
            20,
        )

    if getattr(player, "difficulty", "normal") not in DIFFICULTY_PRESETS:
        player.difficulty = "normal"
        repairs.append("difficulty: восстановлена normal")

    for attr in ("provinces", "event_log", "tech_researched", "research_queue"):
        value = getattr(player, attr, None)
        if not isinstance(value, list):
            setattr(player, attr, [])
            repairs.append(f"{attr}: восстановлен пустой список")

    if repairs:
        debug_log(
            "Runtime state repaired: %s",
            "; ".join(repairs),
            level=logging.WARNING,
        )
    return repairs


# Последняя обёртка ensure_all_states: после всех исторических слоёв миграции.
_ensure_all_states_v2294 = ensure_all_states
def ensure_all_states(player):
    result = _ensure_all_states_v2294(player)
    repair_player_runtime_state(player)
    if RESOURCE_ECONOMY is not None:
        try:
            RESOURCE_ECONOMY.ensure_state(player, resource_economy_context(player))
        except Exception as exc:
            debug_log(
                "Resource economy state migration failed: %s",
                exc,
                exc_info=True,
                level=logging.WARNING,
            )
    return result


def run_internal_self_tests(verbose: bool = False) -> tuple[bool, list[str], list[str]]:
    """Проверяет ключевые справочники и стартовые режимы без запуска интерфейса."""
    errors: list[str] = []
    warnings: list[str] = []

    def fail(message: str) -> None:
        errors.append(message)

    def warn(message: str) -> None:
        warnings.append(message)

    required_talent_fields = {"name", "atk", "def_", "loyalty_decay", "upkeep_mult", "desc"}
    if "veteran" not in ALL_TALENTS:
        fail("Отсутствует талант veteran, используемый стартовым легатом.")

    for key, talent in ALL_TALENTS.items():
        if not isinstance(talent, dict):
            fail(f"Талант {key!r} не является словарём.")
            continue
        missing = required_talent_fields - set(talent)
        if missing:
            fail(f"Талант {key!r}: нет полей {sorted(missing)}.")

    province_names = [p.get("name") for p in PROVINCES_DATA if isinstance(p, dict)]
    province_set = {name for name in province_names if name}
    if len(province_names) != len(province_set):
        fail("В PROVINCES_DATA есть повторяющиеся или пустые имена провинций.")
    for province in PROVINCES_DATA:
        if not isinstance(province, dict):
            fail("PROVINCES_DATA содержит несловарную запись.")
            continue
        for neighbor in province.get("neighbors", []):
            if neighbor not in province_set:
                fail(f"{province.get('name')}: неизвестный сосед {neighbor!r}.")

    for tech_key, tech in TECH_TREE.items():
        if not isinstance(tech, dict):
            fail(f"Технология {tech_key!r} не является словарём.")
            continue
        for prereq in tech.get("prereq", []):
            if prereq not in TECH_TREE:
                fail(f"Технология {tech_key!r}: неизвестная предпосылка {prereq!r}.")

    wonder_ids: set[str] = set()
    for wonder in WORLD_WONDERS:
        if not isinstance(wonder, dict):
            fail("WORLD_WONDERS содержит несловарную запись.")
            continue
        wonder_id = wonder.get("id")
        if not wonder_id:
            fail("Чудо света без id.")
        elif wonder_id in wonder_ids:
            fail(f"Повторяющийся id чуда: {wonder_id!r}.")
        else:
            wonder_ids.add(wonder_id)
        for tech_key in wonder.get("tech", []):
            if tech_key not in TECH_TREE:
                fail(f"Чудо {wonder_id!r}: неизвестная технология {tech_key!r}.")

    levels: set[int] = set()
    for reward in BATTLEPASS_REWARDS:
        if not isinstance(reward, dict):
            fail("BATTLEPASS_REWARDS содержит несловарную запись.")
            continue
        level = safe_int(reward.get("level"), -1)
        if level in levels:
            fail(f"Повторяющийся уровень баттл-пасса: {level}.")
        levels.add(level)
        if not callable(reward.get("apply")):
            fail(f"Уровень баттл-пасса {level}: награда apply не вызываема.")

    displayed_keys = set(menu_valid_keys(_main_menu_sections_v2257()))
    handled_keys = {
        "1", "2", "4", "5", "6", "7", "8", "9",
        "E", "R", "H", "X", "A", "B", "V", "C", "L", "W", "Y", "Z",
        "T", "D", "P", "F", "N", "S", "Q",
    }
    missing_handlers = displayed_keys - handled_keys
    if missing_handlers:
        fail(f"У пунктов меню нет обработчиков: {sorted(missing_handlers)}.")

    state = random.getstate()
    random.seed(2294)
    try:
        for office in STARTING_OFFICES.values():
            player = Player("Testus", "optimates", "normal")
            player.provinces = [
                captured_province_copy("Latium"),
                captured_province_copy("Campania"),
            ]
            player.legions = [Legion("Legio I Test", quality=5)]
            player.starting_office = office["key"]
            apply_starting_office(player)
            ensure_all_states(player)
            player.income()
            player.upkeep()
            for legion in player.legions:
                legion.general.talent()
                legion.general.upkeep_mult()
                legion.description()
    except Exception as exc:
        fail(f"Стартовый сценарий упал: {type(exc).__name__}: {exc}")
    finally:
        random.setstate(state)

    # Регрессии Consilium Externum v2.31.
    try:
        diplomat = Player("Diplomaticus", "optimates", "normal")
        diplomat.provinces = [captured_province_copy("Latium")]
        ensure_external_policy_state(diplomat)
        if diplomat.foreign_policy["doctrine"] not in FOREIGN_POLICY_DOCTRINES:
            fail("Consilium Externum: неизвестная стартовая доктрина.")
        if diplomat.foreign_policy["capital_max"] != FOREIGN_POLICY_DOCTRINES[diplomat.foreign_policy["doctrine"]]["capital_max"]:
            fail("Consilium Externum: лимит дипломатического капитала не соответствует доктрине.")
        first_key = next(iter(diplomat.diplomacy))
        diplomat.gold = 1000
        diplomat.foreign_policy["capital"] = diplomat.foreign_policy["capital_max"]
        started, start_message = _commit_foreign_mission(diplomat, first_key, "embassy")
        if not started or len(diplomat.foreign_policy["active_missions"]) != 1:
            fail(f"Consilium Externum: миссия не добавилась в active_missions ({start_message}).")
        before = diplomat.diplomacy[first_key]["disposition"]
        diplomat.foreign_policy["active_missions"][0]["chance"] = 100
        diplomat.foreign_policy["active_missions"][0]["remaining"] = 1
        diplomat.foreign_policy["last_crisis_turn"] = diplomat.turn + 100
        diplomat.turn += 1
        mission_rng_state = random.getstate()
        random.seed(1)
        try:
            foreign_policy_end_turn(diplomat)
        finally:
            random.setstate(mission_rng_state)
        if diplomat.foreign_policy["active_missions"]:
            fail("Consilium Externum: завершённая миссия осталась активной.")
        if diplomat.diplomacy[first_key]["disposition"] <= before:
            fail("Consilium Externum: успешное посольство не улучшило отношения.")
        saved = diplomat.to_dict()
        restored = Player.from_dict(saved)
        ensure_external_policy_state(restored)
        if restored.foreign_policy["doctrine"] != diplomat.foreign_policy["doctrine"]:
            fail("Consilium Externum: доктрина не переживает save/load.")
        if first_key not in restored.diplomacy or "trust" not in restored.diplomacy[first_key]:
            fail("Consilium Externum: дипломатическое досье не переживает save/load.")
        for event in FOREIGN_CRISIS_EVENTS:
            if _foreign_event_weight(restored, restored.diplomacy[first_key], event) <= 0:
                fail(f"Consilium Externum: нулевой вес события {event['kind']}.")
    except Exception as exc:
        fail(f"Consilium Externum self-test упал: {type(exc).__name__}: {exc}")

    # Регрессии stability patch.
    try:
        cycle = []
        cycle.append(cycle)
        serialized_cycle = json_safe_data(cycle)
        if serialized_cycle != ["<cycle>"]:
            fail(f"json_safe_data: неверная защита от цикла: {serialized_cycle!r}")
    except Exception as exc:
        fail(f"json_safe_data упал на циклической ссылке: {exc}")

    try:
        try:
            read_choice("", [])
            fail("read_choice не отклонил пустой список вариантов.")
        except ValueError:
            pass
        try:
            read_choice_secret("", [], "FORTUNA", "CHEAT")
            fail("read_choice_secret не отклонил пустой список вариантов.")
        except ValueError:
            pass
    except Exception as exc:
        fail(f"Проверка пустых вариантов ввода упала: {exc}")

    try:
        sample = {"gold": 100, "grain": 100, "turn": 1, "year": 700, "provinces": [], "legions": []}
        signed = sign_save_data(sample)
        if verify_save_data_signature(signed) is not True:
            fail("Подпись или контрольные поля свежего сейва не проходят проверку.")
        encrypted = encrypt_save_payload(signed)
        decrypted = decrypt_save_payload(encrypted)
        if decrypted != signed:
            fail("Шифрование/дешифрование сейва не является обратимым.")

        legacy_nonce = "0123456789abcdef"
        legacy_base = _derive_save_key(
            "xor-save",
            _portable_save_fallback_id(),
            game_version="2.29.6-imperial-onefile",
        )
        legacy_key = hashlib.sha256(legacy_base + legacy_nonce.encode("ascii")).digest()
        legacy_encrypted = {
            SAVE_ENCRYPTED_FIELD: {
                "version": 2,
                "algorithm": "XOR-SHA256-v2-portable-primary",
                "nonce": legacy_nonce,
                "payload": base64.b64encode(
                    _xor_bytes(_canonical_json(signed).encode("utf-8"), legacy_key)
                ).decode("ascii"),
            }
        }
        if decrypt_save_payload(legacy_encrypted) != signed:
            fail("Сейв v2.29.6 не расшифровывается после обновления версии.")
    except Exception as exc:
        fail(f"Проверка encrypted-save упала: {type(exc).__name__}: {exc}")

    content_errors = validate_runtime_content()
    for message in content_errors:
        fail(message)

    # Регрессии Roma Economica v2.60.
    try:
        if ADVANCED_ECONOMY is None:
            fail(f"Модуль roma_economy не импортирован: {ECONOMY_IMPORT_ERROR}")
        else:
            macro_player = Player("Oeconomicus", "optimates", "normal")
            macro_player.provinces = [dict(PROVINCES_DATA[0]), dict(PROVINCES_DATA[1])]
            ensure_all_states(macro_player)
            macro_context = advanced_economy_context(macro_player)
            ADVANCED_ECONOMY.ensure_economy_state(macro_player, macro_context)

            laffer = []
            for rate in (0.15, 0.35, 0.65):
                macro_player.economy["tax_rate"] = rate
                laffer.append(ADVANCED_ECONOMY.preview_turn(macro_player, macro_context)["revenues"]["direct_tax"])
            if not (laffer[1] > laffer[0] and laffer[1] > laffer[2]):
                fail(f"Кривая Лаффера не имеет внутреннего максимума: {laffer}.")

            macro_player.economy["tax_rate"] = 0.22
            base_price = macro_player.economy["price_level"]
            ADVANCED_ECONOMY.mint_currency(macro_player, 2000)
            for _ in range(4):
                ADVANCED_ECONOMY.apply_turn(macro_player, advanced_economy_context(macro_player))
            if macro_player.economy["price_level"] <= base_price:
                fail("Дополнительная чеканка не повысила уровень цен.")

            shares = ADVANCED_ECONOMY.normalize_budget_shares({"military": 70, "science": 30})
            if abs(sum(shares.values()) - 1.0) > 1e-9:
                fail("Бюджетные доли не нормируются до 100%.")
            trial = ADVANCED_ECONOMY.trial_balance(macro_player)
            if not trial["balanced"]:
                fail("Двойная бухгалтерская запись не сходится.")
            macro_report = ADVANCED_ECONOMY.preview_turn(macro_player, advanced_economy_context(macro_player))
            if set(macro_report.get("sectors", {}).get("output", {})) != set(ADVANCED_ECONOMY.SECTOR_KEYS):
                fail("Отраслевой выпуск не содержит все пять секторов.")
            if abs(sum(macro_report["sectors"]["labor_shares"].values()) - 1.0) > 1e-7:
                fail("Отраслевые доли труда не суммируются в 100%.")
            demo = macro_report.get("demographics", {})
            if abs(demo.get("free_population", 0) + demo.get("slave_population", 0) - macro_report["macro"]["population"]) > 0.1:
                fail("Демографический баланс свободных и рабов нарушен.")
            accounts = macro_report.get("national_accounts", {}).get("expenditure", {})
            expenditure_gdp = sum(accounts.get(k, 0) for k in ("consumption", "investment", "government", "net_exports", "statistical_discrepancy"))
            if abs(expenditure_gdp - accounts.get("gdp", 0)) > 0.1:
                fail("Тождество ВВП C+I+G+NX нарушено.")
            if not 0 <= macro_report["macro"].get("banking_health", -1) <= 1:
                fail("Здоровье банков вне диапазона 0-1.")
            # Bellum Oeconomicum: трофеи начисляются один раз, а провинция получает режим.
            conquest_target = province_by_name("Etruria")
            if conquest_target:
                before_gold = macro_player.gold
                city = conquest_target.get("cities", [])[0]
                first = city_conquest_reward(macro_player, conquest_target, city, announce=False)
                second = city_conquest_reward(macro_player, conquest_target, city, announce=False)
                if first.get("gold", 0) <= 0 or not second.get("duplicate") or macro_player.gold <= before_gold:
                    fail("Bellum Oeconomicum: городские трофеи не начисляются однократно.")

            for message in ADVANCED_ECONOMY.audit_invariants(macro_player, advanced_economy_context(macro_player)):
                fail("Roma Economica: " + message)
    except Exception as exc:
        fail(f"Регрессии Roma Economica v2.60 упали: {type(exc).__name__}: {exc}")

    # Регрессия Pretium Universale v2.61.
    try:
        if game_price(None, 100) != 200:
            fail(f"Глобальный множитель покупок не равен ×2: {game_price(None, 100)}.")
        if game_price(None, 100, upkeep=True) != 150:
            fail(f"Глобальный множитель содержания не равен ×1.5: {game_price(None, 100, upkeep=True)}.")
        price_player = Player("Mercator", "optimates", "normal")
        price_player.provinces = [dict(PROVINCES_DATA[0])]
        ensure_all_states(price_player)
        if game_price(price_player, 100, market=True) < 200:
            fail("Динамический рыночный множитель отменил глобальное удорожание.")
    except Exception as exc:
        fail(f"Регрессия Pretium Universale v2.61 упала: {type(exc).__name__}: {exc}")

    # Регрессии аудита v2.36.0.
    try:
        economy_player = Player("Audit", "optimates", "normal")
        economy_player.provinces = [dict(PROVINCES_DATA[0]), dict(PROVINCES_DATA[1])]
        first_cost = legion_recruitment_cost(economy_player)
        economy_player.legions.extend(Legion(f"Test Legion {i}") for i in range(6))
        later_cost = legion_recruitment_cost(economy_player)
        if later_cost <= first_cost:
            fail(f"Цена легиона не растёт: {first_cost} → {later_cost}.")
        economy_player.gold = 250000
        upkeep_gold, _ = economy_player.upkeep()
        if upkeep_gold <= 0:
            fail("Поздняя экономика не создаёт расходов при огромной казне.")
    except Exception as exc:
        fail(f"Экономические регрессии v2.36.0 упали: {type(exc).__name__}: {exc}")

    try:
        senate_player = Player("Audit", "optimates", "easy")
        senate_player.provinces = [dict(PROVINCES_DATA[0]), dict(PROVINCES_DATA[1])]
        senate_player.senate_rep = 0
        if check_endgame(senate_player):
            fail("Первое падение senate_rep до 0 всё ещё мгновенно завершает игру.")
        if not senate_player.senate_last_chance_used or senate_player.senate_rep <= 0:
            fail("Последний шанс Сената не восстановил управляемое состояние.")
    except Exception as exc:
        fail(f"Регрессия Сената v2.36.0 упала: {type(exc).__name__}: {exc}")

    try:
        if safe_int(SETTINGS.get("autosave_interval", 0), 0) < 2:
            fail("Автосохранение снова настроено на каждый ход.")
        if ANTICHEAT_LIMITS.get("gold", 0) < 1000000:
            fail("Античит-потолок золота снова достижим обычной длинной партией.")
    except Exception as exc:
        fail(f"Регрессия сохранений v2.36.0 упала: {type(exc).__name__}: {exc}")

    try:
        allowed_versioned_duplicates = {
            '_ai_director_recover_hook',
            '_ai_goal_utilities',
            '_ai_update_war_council_memory',
            '_calculate_order_score',
            '_target_for_order',
            'add_aux_unit',
            'artillery_role_power',
            'artillery_unlock_reason',
            'barbarian_ai_tick',
            'check_endgame',
            'complete_research',
            'end_turn',
            'enemy_ai_campaign_start',
            'enemy_ai_execute_operational_orders',
            'enemy_ai_grand_strategy_tick',
            'enemy_ai_headquarters_menu',
            'enemy_ai_joint_attack',
            'enemy_ai_pray_and_buff',
            'enemy_ai_raid_event',
            'enemy_ai_recapture_city_event',
            'enemy_ai_recon_and_orders',
            'enemy_ai_siege_tick',
            'enemy_ai_start_siege',
            'ensure_all_states',
            'load_game',
            'process_pending_interactions',
            'show_enemy_ai_report',
            'show_tech_completion_card',
            'turn_summary_add',
            'v24_end_turn_tick'
        }
        with open(__file__, "r", encoding="utf-8") as audit_source:
            audit_tree = ast.parse(audit_source.read())
        duplicate_map = {}
        for node in audit_tree.body:
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                duplicate_map.setdefault(node.name, []).append(node.lineno)
        unexpected_duplicates = {
            name: lines
            for name, lines in duplicate_map.items()
            if len(lines) > 1 and name not in allowed_versioned_duplicates
        }
        if unexpected_duplicates:
            fail(f"Появились новые неразрешённые дубликаты функций: {unexpected_duplicates}")
    except Exception as exc:
        fail(f"Аудит дублирующихся функций упал: {type(exc).__name__}: {exc}")

    # Проверяем защиту от неизвестного ключа таланта.
    try:
        test_general = General("Testus Ignotus", "__missing_talent__", 70)
        test_general.talent()
        test_general.upkeep_mult()
    except Exception as exc:
        fail(f"Защита General от неизвестного таланта не сработала: {exc}")

    # Регрессии Opes Imperii v2.70: автоматическая добыча без микроменеджмента.
    try:
        if RESOURCE_ECONOMY is None:
            fail(f"Модуль roma_resources не импортирован: {RESOURCE_ECONOMY_IMPORT_ERROR}")
        else:
            resource_player = Player("Mercator", "optimates", "normal")
            resource_player.provinces = [dict(PROVINCES_DATA[0]), dict(PROVINCES_DATA[1])]
            resource_context = resource_economy_context(resource_player)
            resource_state = RESOURCE_ECONOMY.ensure_state(resource_player, resource_context)
            before_turn = int(resource_state.get("last_processed_turn", 0))
            resource_flow = RESOURCE_ECONOMY.apply_turn(resource_player, resource_context)
            if not resource_flow.get("production"):
                fail("Opes Imperii не произвёл ни одного ресурса в стартовых провинциях.")
            stock_after_first = dict(resource_state.get("stockpiles", {}))
            RESOURCE_ECONOMY.apply_turn(resource_player, resource_context)
            if stock_after_first != resource_state.get("stockpiles", {}):
                fail("Ресурсный ход не идемпотентен: повторный вызов начисляет добычу дважды.")
            if int(resource_state.get("last_processed_turn", 0)) <= before_turn:
                fail("Opes Imperii не обновил номер обработанного хода.")
            for message in RESOURCE_ECONOMY.audit_invariants(resource_player, resource_context):
                fail(f"Opes Imperii: {message}")
    except Exception as exc:
        fail(f"Проверка Opes Imperii упала: {type(exc).__name__}: {exc}")

    # Регрессии v2.70.1: накопительный урон городам и роль сложности.
    try:
        random_state = random.getstate()
        siege_city = {"name": "Testopolis", "difficulty": 4, "type": "город"}
        test_legion = Legion("Legio Test", quality=6)
        test_legion.strength = 60
        test_legion.morale = 80

        easy_player = Player("Easy", "optimates", "easy")
        normal_player = Player("Normal", "optimates", "normal")
        madness_player = Player("Mad", "optimates", "madness")
        random.seed(2701)
        easy_damage = calculate_legion_city_damage(easy_player, test_legion, siege_city, True)
        random.seed(2701)
        normal_damage = calculate_legion_city_damage(normal_player, test_legion, siege_city, True)
        random.seed(2701)
        madness_damage = calculate_legion_city_damage(madness_player, test_legion, siege_city, True)
        if not (easy_damage > normal_damage > madness_damage):
            fail(
                f"Сложность не масштабирует урон города: "
                f"easy={easy_damage}, normal={normal_damage}, madness={madness_damage}."
            )

        actual, total_damage, remaining = apply_city_siege_damage(
            normal_player, "Test Province", "Testopolis", 37
        )
        if (actual, total_damage, remaining) != (37, 37, 63):
            fail(
                "Накопительный урон города работает неверно: "
                f"{(actual, total_damage, remaining)}."
            )
        actual2, total2, remaining2 = apply_city_siege_damage(
            normal_player, "Test Province", "Testopolis", 90
        )
        if (actual2, total2, remaining2) != (63, 100, 0):
            fail(
                "Урон города не ограничивается 100%: "
                f"{(actual2, total2, remaining2)}."
            )
        clear_city_siege_damage(normal_player, "Test Province", "Testopolis")
        if city_siege_damage(normal_player, "Test Province", "Testopolis") != 0:
            fail("Повреждение захваченного города не очищается.")
        random.setstate(random_state)
    except Exception as exc:
        try:
            random.setstate(random_state)
        except Exception:
            pass
        fail(f"Проверка осадного урона v2.70.1 упала: {type(exc).__name__}: {exc}")

    if verbose:
        print(clr("\n  SELF-TEST ROMA AETERNA", C.BOLD + C.GOLD))
        if errors:
            for message in errors:
                print(clr(f"  ❌ {message}", C.RED))
        else:
            print(clr("  ✅ Критических ошибок не найдено.", C.GREEN))
        for message in warnings:
            print(clr(f"  ⚠ {message}", C.GOLD))

    return not errors, errors, warnings


def handle_self_test_cli() -> bool:
    args = {str(arg).strip().lower() for arg in sys.argv[1:]}
    if "--self-test" not in args:
        return False
    ok, _, _ = run_internal_self_tests(verbose=True)
    sys.exit(0 if ok else 1)



# ─── ROMA ECONOMICA: БЮДЖЕТНОЕ МЕНЮ И ОТЧЁТНОСТЬ ───────────────────────────

def _economy_percent(value: float) -> str:
    return f"{float(value) * 100:.1f}%"


def _economy_money(value: Any) -> str:
    return f"{safe_int(value, 0):,}".replace(",", " ")


def show_passive_income_report(player: Player):
    if ADVANCED_ECONOMY is None:
        return _legacy_show_passive_income_report(player) if "_legacy_show_passive_income_report" in globals() else None
    report = ADVANCED_ECONOMY.preview_turn(player, advanced_economy_context(player))
    macro = report["macro"]
    expenses = report["expenditures"]
    rui_screen_start()
    rui_header("AERARIUM POPULI ROMANI — НАЦИОНАЛЬНЫЕ СЧЕТА", "📜", C.GOLD)
    rui_info(
        f"Реальный выпуск: {_economy_money(macro['real_output'])} • "
        f"номинальный: {_economy_money(macro['nominal_output'])} • "
        f"население: {macro['population']:.1f} тыс.",
        C.CYAN,
    )
    rui_info(
        f"Уровень цен: {macro['price_level']:.3f} • инфляция {_economy_percent(macro['inflation'])} • "
        f"денежная масса {_economy_money(macro['money_supply'])} • V={macro['velocity']:.2f}",
        C.GOLD,
    )
    revenue_rows = [(row["label"], f"+{_economy_money(row['amount'])}", row.get("note", "")) for row in report["rows"]]
    rui_table("Доходы бюджета", ["Статья", "Сумма", "Основание"], revenue_rows or [("Нет доходов", "0", "")], color=C.GREEN)
    programme_rows = [
        (ADVANCED_ECONOMY.BUDGET_LABELS.get(key, key), _economy_money(value))
        for key, value in expenses["programmes"].items()
    ]
    fixed_rows = [
        ("Управление", _economy_money(expenses["administration"])),
        ("Содержание легионов", _economy_money(expenses["military_upkeep"])),
        ("Флот", _economy_money(expenses["fleet_upkeep"])),
        ("Проценты по долгу", _economy_money(expenses["interest"])),
        ("Хранение и управление казной", _economy_money(expenses.get("treasury_management", 0))),
    ]
    rui_table("Обязательные расходы", ["Статья", "Сумма"], fixed_rows, color=C.RED)
    rui_table("Ассигнования развития", ["Ведомство", "Сумма"], programme_rows, color=C.CYAN)
    balance_color = C.GREEN if report["overall_balance"] >= 0 else C.RED
    rui_info(
        f"Доходы {_economy_money(report['revenue_total'])} • расходы {_economy_money(report['expense_total'])} • "
        f"первичный баланс {report['primary_balance']:+} • итог {report['overall_balance']:+}",
        balance_color,
    )
    rui_info(
        f"Долг {_economy_money(macro['debt'])} ({_economy_percent(macro['debt_ratio'])} выпуска) • "
        f"ставка {_economy_percent(macro['interest_rate'])} • коррупция {_economy_percent(macro['corruption'])} • "
        f"собираемость {_economy_percent(report['revenues']['compliance'])}",
        C.PURPLE,
    )
    rui_info(
        f"Зерно: производство {report['final_grain']}, потребление {report['upkeep_grain']}, "
        f"цена {report['grain']['price']:.2f}, запас на {report['grain']['stock_cover']:.1f} хода",
        C.GREEN if report["final_grain"] >= report["upkeep_grain"] else C.RED,
    )
    sector_rows = [
        (
            ADVANCED_ECONOMY.SECTOR_LABELS.get(key, key),
            _economy_money(report["sectors"]["output"][key]),
            _economy_money(report["sectors"]["capital"][key]),
            _economy_percent(report["sectors"]["labor_shares"][key]),
            _economy_percent(report["sectors"]["bottlenecks"][key]),
        )
        for key in ADVANCED_ECONOMY.SECTOR_KEYS
    ]
    rui_table("Выпуск по секторам", ["Сектор", "Выпуск", "Капитал", "Труд", "Снабжение"], sector_rows, color=C.CYAN)
    accounts = report["national_accounts"]["expenditure"]
    rui_table(
        "ВВП по расходам",
        ["Компонент", "Сумма"],
        [
            ("Потребление C", _economy_money(accounts["consumption"])),
            ("Инвестиции I", _economy_money(accounts["investment"])),
            ("Государство G", _economy_money(accounts["government"])),
            ("Чистый экспорт NX", _economy_money(accounts["net_exports"])),
            ("Статистическое расхождение", _economy_money(accounts["statistical_discrepancy"])),
        ],
        color=C.PURPLE,
    )
    rui_info(
        f"Частный кредит {_economy_money(macro['private_credit'])} ({_economy_percent(macro['credit_to_gdp'])} ВВП) • "
        f"здоровье банков {_economy_percent(macro['banking_health'])} • рыночная ставка {_economy_percent(macro['market_rate'])}",
        C.GOLD,
    )
    rui_info(
        f"Торговый баланс {macro['trade_balance']:+.1f} • текущий счёт {macro['current_account']:+.1f} • "
        f"импортная зависимость {_economy_percent(macro['import_dependency'])} • условия торговли {macro['terms_of_trade']:.2f}",
        C.GREEN if macro["trade_balance"] >= 0 else C.RED,
    )
    pause()


def _economy_budget_editor(player: Player) -> None:
    state = ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
    shares: dict[str, float] = {}
    print(clr("\n  Введите желаемые доли. Итог будет автоматически нормирован до 100%.", C.CYAN))
    for key in ADVANCED_ECONOMY.BUDGET_KEYS:
        current = int(round(state["budget_shares"].get(key, 0) * 100))
        shares[key] = read_int(
            f"  {ADVANCED_ECONOMY.BUDGET_LABELS.get(key, key)} (сейчас {current}%): ",
            0,
            100,
        ) / 100.0
    normalized = ADVANCED_ECONOMY.set_budget_shares(player, shares)
    print(clr("  ✓ Новый бюджет: " + ", ".join(
        f"{ADVANCED_ECONOMY.BUDGET_LABELS[k]} {v:.0%}" for k, v in normalized.items()
    ), C.GREEN))
    pause()


def _economy_investment_menu(player: Player) -> None:
    rui_screen_start(); rui_header("КАПИТАЛЬНЫЕ ВЛОЖЕНИЯ", "🏗", C.GOLD)
    options = [
        ("1", "infrastructure", "Дороги и общий капитал"),
        ("2", "administration", "Ценз, суды и налоговая служба"),
        ("3", "human_capital", "Школы, архивы и ремесленные знания"),
        ("4", "welfare", "Аннона и общественное спокойствие"),
        ("5", "agriculture", "Латифундии, ирригация и орудия"),
        ("6", "mining", "Рудники, каменоломни и солеварни"),
        ("7", "manufacturing", "Оружейные, текстильные и керамические мастерские"),
        ("8", "construction", "Строительные артели и общественные работы"),
        ("9", "commerce", "Порты, склады, караваны и услуги"),
        ("B", "banking", "Argentarii, храмовые кассы и ликвидность"),
    ]
    rui_menu([(key, label, "убывающая предельная отдача", "•") for key, _, label in options] + [("Q", "Назад", "", "↩")])
    choice = read_choice(f"\n{clr('  Направление: ', C.CYAN)}", [x[0] for x in options] + ["Q"])
    if choice == "Q": return
    amount = read_int(f"  Сколько золота вложить? (1-{max(1, player.gold)}): ", 1, max(1, player.gold))
    target = next(target for key, target, _ in options if key == choice)
    spent = ADVANCED_ECONOMY.direct_investment(player, target, amount)
    print(clr(f"  ✓ Освоено {spent} золота. Предельная отдача зависит от уже накопленного капитала.", C.GREEN))
    pause()


def _economy_sector_report(player: Player) -> None:
    while True:
        report = ADVANCED_ECONOMY.preview_turn(player, advanced_economy_context(player))
        state = ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
        rui_screen_start(); rui_header("SECTORES — ОТРАСЛЕВАЯ ЭКОНОМИКА", "🏭", C.GOLD)
        rows = []
        for item in ADVANCED_ECONOMY.sector_report(player, advanced_economy_context(player)):
            rows.append((
                item["label"], _economy_money(item["output"]), _economy_money(item["capital"]),
                _economy_percent(item["labor_share"]), f"{item['technology']:.3f}", _economy_percent(item["bottleneck"]),
            ))
        rui_table("Производственная структура", ["Сектор", "Выпуск", "Капитал", "Труд", "Технология", "Снабжение"], rows, color=C.CYAN)
        rui_info(
            f"Политика: {ADVANCED_ECONOMY.SECTOR_POLICIES[state['sector_policy']]['label']} • "
            f"мобильность труда {_economy_percent(report['sectors']['labor_mobility'])} • "
            f"капитала {_economy_percent(report['sectors']['capital_mobility'])}", C.PURPLE,
        )
        rui_menu([("P", "Изменить отраслевую политику", "влияет на новые инвестиции и перемещение труда", "⚙"), ("Q", "Назад", "", "↩")])
        choice = read_choice(f"\n{clr('  Ваш выбор: ', C.CYAN)}", ["P", "Q"])
