def _economy_shock_report(player: Player) -> None:
    state = ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
    rui_screen_start(); rui_header("FORTUNA OECONOMICA — ШОКИ И ЦИКЛЫ", "⚡", C.GOLD)
    active_rows = [
        (str(item.get("title", item.get("kind", "—"))), str(item.get("remaining", 0)), _economy_percent(item.get("magnitude", 0)), str(item.get("detail", "")))
        for item in state.get("active_shocks", []) if isinstance(item, dict)
    ]
    rui_table("Активные шоки", ["Событие", "Ходов", "Сила", "Последствие"], active_rows or [("Нет", "—", "—", "Экономика развивается без крупного шока")], color=C.RED)
    history = ADVANCED_ECONOMY.economic_shock_log(player)[-12:]
    rows = [(str(item.get("turn", "")), str(item.get("message", ""))) for item in history]
    rui_table("Последние события", ["Ход", "Событие"], rows or [("—", "Событий пока нет")], color=C.CYAN)
    pause()


def _economy_interest_groups_report(player: Player) -> None:
    report = ADVANCED_ECONOMY.preview_turn(player, advanced_economy_context(player))
    state = ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
    rui_screen_start(); rui_header("ORDINES — ПОЛИТИЧЕСКАЯ ЭКОНОМИЯ", "🏛", C.GOLD)
    rows = []
    for key in ADVANCED_ECONOMY.INTEREST_GROUPS:
        group = state["interest_groups"][key]
        rows.append((
            ADVANCED_ECONOMY.INTEREST_GROUP_LABELS.get(key, key),
            _economy_percent(group.get("influence", 0)),
            _economy_percent(group.get("satisfaction", 0)),
            _economy_money(group.get("rents", 0)),
        ))
    rui_table("Группы интересов", ["Группа", "Влияние", "Удовлетворённость", "Ренты"], rows, color=C.PURPLE)
    eff_rows = [
        (ADVANCED_ECONOMY.BUDGET_LABELS.get(key, key), _economy_percent(value))
        for key, value in report["political_economy"]["programme_efficiency"].items()
    ]
    rui_table("Эффективность бюджетных программ", ["Ведомство", "Эффективность"], eff_rows, color=C.CYAN)
    rui_info(
        f"Рентный поиск поглощает {_economy_money(report['political_economy']['rent_seeking'])} золота эквивалента за ход. "
        "Легитимность, коррупция и структура бюджета определяют, кто получает выгоду.", C.GOLD,
    )
    pause()



def _economy_conquest_report(player: Player) -> None:
    """Сводка военных трофеев, контрибуций и хозяйства новых провинций."""
    rui_screen_start()
    rui_header("BELLUM OECONOMICUM — ЗАВОЁВАННЫЕ ЗЕМЛИ", "⚔", C.GOLD)
    local = ensure_conquest_economy_state(player)
    external = {}
    if ADVANCED_ECONOMY is not None and hasattr(ADVANCED_ECONOMY, "conquest_report"):
        try:
            external = ADVANCED_ECONOMY.conquest_report(player)
        except Exception as exc:
            debug_log("conquest_report failed: %s", exc, exc_info=True, level=logging.WARNING)

    city_spoils = safe_int(external.get("city_spoils", local.get("city_spoils_total", 0)), 0)
    indemnities = safe_int(external.get("province_indemnities", local.get("province_indemnities_total", 0)), 0)
    grain = safe_int(external.get("grain_requisitions", local.get("grain_requisitions_total", 0)), 0)
    captives = float(external.get("captives", local.get("captives_total", 0.0)) or 0.0)
    capital = float(external.get("capital_transfers", 0.0) or 0.0)
    rui_info(
        f"Городские трофеи {_economy_money(city_spoils)} • провинциальные контрибуции {_economy_money(indemnities)} • "
        f"зерновые реквизиции {_economy_money(grain)}",
        C.GOLD,
    )
    rui_info(
        f"Пленные {captives:.1f} тыс. • вывезенный капитал {capital:.1f} • "
        f"последний автоматический доход {safe_int(local.get('last_occupation_income', 0), 0):+}/ход",
        C.PURPLE,
    )

    province_rows = []
    for province in getattr(player, "provinces", []):
        if not isinstance(province, dict) or "economic_policy" not in province:
            continue
        spec = province_policy_spec(province)
        province_rows.append((
            str(province.get("name", "Provincia")),
            str(spec.get("short", "—")),
            f"{100.0 * float(province.get('war_damage', 0.0) or 0.0):.0f}%",
            f"{100.0 * float(province.get('occupation_progress', 0.0) or 0.0):.0f}%",
            f"{safe_int(province.get('last_policy_income', 0), 0):+}",
            f"{safe_int(province.get('last_policy_grain', 0), 0):+}",
            str(safe_int(province.get("unrest", 0), 0)),
            str(safe_int(province.get("romanization", 0), 0)),
        ))
    rui_table(
        "Экономические режимы провинций",
        ["Провинция", "Режим", "Ущерб", "Интегр.", "Зол./ход", "Зер./ход", "Волн.", "Роман."],
        province_rows or [("—", "Нет завоёванных провинций", "—", "—", "0", "0", "—", "—")],
        color=C.CYAN,
    )

    history_rows = []
    for row in [x for x in local.get("history", []) if isinstance(x, dict)][-12:]:
        kind = "Город" if row.get("kind") == "city" else "Провинция"
        place = str(row.get("city") or row.get("province") or "—")
        if row.get("city") and row.get("province"):
            place = f"{row.get('city')} / {row.get('province')}"
        history_rows.append((
            str(row.get("turn", "—")),
            kind,
            place,
            f"+{safe_int(row.get('gold', 0), 0)}",
            f"+{safe_int(row.get('grain', 0), 0)}",
            f"{float(row.get('slaves', 0.0) or 0.0):.1f}",
        ))
    rui_table(
        "Последние военные поступления",
        ["Ход", "Источник", "Место", "Золото", "Зерно", "Пленные, тыс."],
        history_rows or [("—", "Событий пока нет", "—", "0", "0", "0.0")],
        color=C.GOLD,
    )
    rui_info(
        "Трофеи поступают сразу после взятия города; контрибуция — после присоединения провинции. "
        "Регулярный доход новых земель включается в государственный бюджет в конце каждого хода.",
        C.GRAY,
    )
    pause()

def _economy_ledger(player: Player) -> None:
    rui_screen_start(); rui_header("RATIONES — ДВОЙНАЯ БУХГАЛТЕРИЯ", "⚖", C.GOLD)
    state = ADVANCED_ECONOMY.ensure_economy_state(player, advanced_economy_context(player))
    entries = [row for row in state.get("ledger", []) if isinstance(row, dict)][-25:]
    rows = [
        (str(row.get("turn", "")), str(row.get("debit", "")), str(row.get("credit", "")), _economy_money(row.get("amount", 0)), str(row.get("memo", "")))
        for row in entries
    ]
    rui_table("Последние проводки", ["Ход", "Дебет", "Кредит", "Сумма", "Основание"], rows or [("—", "Проводок пока нет", "—", "0", "")], color=C.CYAN)
    trial = ADVANCED_ECONOMY.trial_balance(player)
